def _deco_make_token(user) -> tuple[str, int]:
    """Gera token base64-urlsafe com dados do usuário + expiração embutida.

    Inclui a decoração de avatar real do Discord (avatar_decoration) quando
    disponível, para que o site possa renderizar a animação corretamente.
    """
    av  = str(user.display_avatar.with_size(256).url)
    dn  = user.display_name or user.name
    dt  = user.name
    exp = int(time.time()) + _DECO_TTL

    data: dict = {"av": av, "dn": dn, "dt": dt, "exp": exp}

    # Decoração real do perfil Discord (ex: frames Nitro animados)
    try:
        deco_asset = user.avatar_decoration
        if deco_asset is not None:
            data["deco"] = str(deco_asset.url)
    except Exception:
        pass

    # SKU ID da decoração (útil para identificar o asset no site)
    try:
        sku = user.avatar_decoration_sku_id
        if sku is not None:
            data["sku"] = str(sku)
    except Exception:
        pass

    raw   = json.dumps(data, separators=(",", ":"))
    token = base64.urlsafe_b64encode(raw.encode()).decode().rstrip("=")
    return token, exp

