# ── GuildChannelSelect ────────────────────────────────────────────────────────
# Drop-in replacement para GuildChannelSelect que SEMPRE mostra canais do
# guild alvo (via _dev_guild_ctx override), não do servidor onde a interação ocorre.
# Backward compatible: self.values[0].id, self.values[0].mention, ch.name funcionam.

class _ChannelProxy:
    """Proxy que faz um channel_id (str) se comportar como discord.TextChannel."""
    __slots__ = ("_id",)
    def __init__(self, channel_id: str | int):
        self._id = int(channel_id)
    @property
    def id(self) -> int:
        return self._id
    @property
    def mention(self) -> str:
        return f"<#{self._id}>"
    @property
    def name(self) -> str:
        ch = bot.get_channel(self._id)
        return ch.name if ch else str(self._id)
    def __int__(self):
        return self._id
    def __str__(self):
        return str(self._id)
    def __eq__(self, other):
        if isinstance(other, int):   return self._id == other
        if isinstance(other, str):   return str(self._id) == other
        if hasattr(other, "id"):     return self._id == other.id
        return NotImplemented


class GuildChannelSelect(discord.ui.Select):
    """
    Drop-in replacement para GuildChannelSelect.
    Popula as opções com os canais de texto do guild alvo (cliente),
    não do servidor onde a interação ocorre.
    API idêntica: aceita os mesmos kwargs de ChannelSelect (channel_types ignorado).
    self.values[0].id / .mention / .name funcionam exatamente como no ChannelSelect.
    """

    def __init__(self, placeholder: str = "Selecione um canal...",
                 min_values: int = 1, max_values: int = 1,
                 channel_types=None, row: int | None = None,
                 guild: "discord.Guild | None" = None, **kw):
        self._raw_values: list[str] = []          # inicializa ANTES do super()
        # Determina o guild alvo: explícito → dev override → guild da interação → None
        if not guild:
            guild_id = _dev_guild_ctx.get(0) or _interaction_guild_ctx.get(0)
            guild    = bot.get_guild(guild_id) if guild_id else None
        if guild:
            want_voice = channel_types and discord.ChannelType.voice in channel_types
            if want_voice:
                raw_chs = sorted(guild.voice_channels,
                                 key=lambda c: (c.category.position if c.category else 0, c.position))
            else:
                raw_chs = sorted(guild.text_channels,
                                 key=lambda c: (c.category.position if c.category else 0, c.position))
            if raw_chs:
                options = [
                    discord.SelectOption(
                        label=f"{'🔊' if want_voice else '#'} {ch.name}"[:100],
                        value=str(ch.id),
                        description=(ch.category.name[:50] if ch.category else None),
                    )
                    for ch in raw_chs[:25]
                ]
            else:
                tipo = "voz" if want_voice else "texto"
                options = [discord.SelectOption(label=f"Nenhum canal de {tipo} encontrado", value="0")]
        else:
            options = [discord.SelectOption(label="Sem servidor alvo — abra o painel do cliente", value="0")]
        # max_values não pode exceder o número de opções disponíveis
        effective_max = min(max_values, max(1, len(options)))
        init_kw: dict = dict(placeholder=placeholder, min_values=min_values,
                             max_values=effective_max, options=options)
        if row is not None:
            init_kw["row"] = row
        init_kw.update(kw)
        super().__init__(**init_kw)

    # ── Intercepta leitura de values ─────────────────────────────────────────
    @property
    def values(self) -> list:                     # type: ignore[override]
        """Retorna objetos canal (ou proxy) — compatível com ChannelSelect.
        Lê do ContextVar selected_values do discord.py (fonte correta),
        caindo de volta em _raw_values/_values para compatibilidade.
        """
        from discord.ui.select import selected_values as _disc_sv
        # ContextVar do discord.py: dict[custom_id -> list[str]]
        raw: list = _disc_sv.get({}).get(self.custom_id) or self._raw_values or getattr(self, '_values', [])
        result = []
        for v in raw:
            if v == "0":
                continue
            try:
                cid = int(v)
                ch  = bot.get_channel(cid)
                result.append(ch if ch else _ChannelProxy(cid))
            except (ValueError, TypeError):
                pass
        return result

    @values.setter
    def values(self, v: list) -> None:            # type: ignore[override]
        self._raw_values = list(v) if v else []
_dev_guild_override: dict[int, int] = {}  # user_id → target_guild_id

_orig_view_task = discord.ui.View._scheduled_task


async def _patched_view_task(self, item, interaction):  # type: ignore[override]
    """Monkey-patch: injeta guild context antes de cada callback de View/Select."""
    uid  = getattr(getattr(interaction, "user", None), "id", 0)
    tgid = _dev_guild_override.get(uid, 0)
    # Sempre injeta o guild da interação como fallback (resolve GuildChannelSelect sem dev override)
    _cur_gid = getattr(getattr(interaction, "guild", None), "id", 0)
    ig_token = _interaction_guild_ctx.set(_cur_gid) if _cur_gid else None
    try:
        if tgid:
            # Renova TTL da sessão a cada interação (mantém viva enquanto o dev usa o painel)
            _s = _dev_sessions.get(uid)
            if _s:
                _s["expires"] = time.time() + _DEV_SESSION_TTL
            token = _dev_guild_ctx.set(tgid)
            try:
                await _orig_view_task(self, item, interaction)
            finally:
                _dev_guild_ctx.reset(token)
        else:
            await _orig_view_task(self, item, interaction)
    finally:
        if ig_token is not None:
            _interaction_guild_ctx.reset(ig_token)


discord.ui.View._scheduled_task = _patched_view_task  # type: ignore[method-assign]


def _effective_gid(interaction: discord.Interaction) -> int:
    """Retorna o guild_id correto considerando o dev-panel override."""
    ovr = _dev_guild_ctx.get(0)
    if ovr:
        return ovr
    return interaction.guild.id if interaction.guild else 0


# Patch de Modal._scheduled_task — injeta _dev_guild_ctx antes do on_submit
# (Modal tem _scheduled_task próprio, separado do View, por isso precisa de patch separado)
_orig_modal_task = discord.ui.Modal._scheduled_task  # type: ignore[attr-defined]


async def _patched_modal_task(self, interaction, components, resolved):  # type: ignore[override]
    """Monkey-patch: injeta guild context antes do on_submit de qualquer Modal."""
    uid  = getattr(getattr(interaction, "user", None), "id", 0)
    tgid = _dev_guild_override.get(uid, 0)
    _cur_gid = getattr(getattr(interaction, "guild", None), "id", 0)
    ig_token = _interaction_guild_ctx.set(_cur_gid) if _cur_gid else None
    try:
        if tgid:
            # Renova TTL da sessão a cada submissão de modal
            _s = _dev_sessions.get(uid)
            if _s:
                _s["expires"] = time.time() + _DEV_SESSION_TTL
            token = _dev_guild_ctx.set(tgid)
            try:
                await _orig_modal_task(self, interaction, components, resolved)
            finally:
                _dev_guild_ctx.reset(token)
        else:
            await _orig_modal_task(self, interaction, components, resolved)
    finally:
        if ig_token is not None:
            _interaction_guild_ctx.reset(ig_token)


discord.ui.Modal._scheduled_task = _patched_modal_task  # type: ignore[method-assign]

# Patch de LayoutView._scheduled_task — mesmo motivo do Modal: tem _scheduled_task próprio
if hasattr(discord.ui, "LayoutView") and hasattr(discord.ui.LayoutView, "_scheduled_task"):
    _orig_layout_task = discord.ui.LayoutView._scheduled_task  # type: ignore[attr-defined]

    async def _patched_layout_task(self, item, interaction):  # type: ignore[override]
        _cur_gid = getattr(getattr(interaction, "guild", None), "id", 0)
        ig_token = _interaction_guild_ctx.set(_cur_gid) if _cur_gid else None
        uid  = getattr(getattr(interaction, "user", None), "id", 0)
        tgid = _dev_guild_override.get(uid, 0)
        try:
            if tgid:
                _s = _dev_sessions.get(uid)
                if _s:
                    _s["expires"] = time.time() + _DEV_SESSION_TTL
                token = _dev_guild_ctx.set(tgid)
                try:
                    await _orig_layout_task(self, item, interaction)
                finally:
                    _dev_guild_ctx.reset(token)
            else:
                await _orig_layout_task(self, item, interaction)
        finally:
            if ig_token is not None:
                _interaction_guild_ctx.reset(ig_token)

    discord.ui.LayoutView._scheduled_task = _patched_layout_task  # type: ignore[method-assign]

