async def _global_view_on_error(self, interaction: discord.Interaction, error: Exception, item) -> None:
    """Tratamento global de erros para TODAS as Views — evita 'Esta interação falhou'."""
    import traceback
    traceback.print_exc()
    try:
        msg = f"❌ Erro interno: `{type(error).__name__}: {str(error)[:200]}`"
        if not interaction.response.is_done():
            await interaction.response.send_message(embed=_notif_embed(msg), ephemeral=True)
        else:
            await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)
    except Exception:
        pass

discord.ui.View.on_error = _global_view_on_error  # type: ignore[method-assign]
# LayoutView tem on_error próprio — precisa patch separado
if hasattr(discord.ui, "LayoutView"):
    discord.ui.LayoutView.on_error = _global_view_on_error  # type: ignore[method-assign]


