@tasks.loop(minutes=5)
async def _presence_task():
    # Usa _stream_prefix_current — já é atualizado no on_ready e quando o cliente muda o prefixo
    prefix = _stream_prefix_current or "n!"
    try:
        await bot.change_presence(
            status=discord.Status.online,
            activity=discord.Streaming(
                name=f"Prefixo: {prefix}",
                url="https://twitch.tv/hypebots",
            ),
        )
        print(f"[presence] OK streaming: Prefixo: {prefix}", flush=True)
    except Exception as e:
        print(f"[presence] erro: {e}", flush=True)

@_presence_task.before_loop
async def _presence_before():
    await bot.wait_until_ready()


