@tasks.loop(minutes=15)
async def _verif_auto_scan_task():
    """Varre automaticamente todos os servidores com verificação ativa a cada 12h."""
    for _guild in bot.guilds:
        _settings = get_settings(_guild.id)
        if not _settings.get("verif_enabled"):
            continue
        if not _settings.get("verif_token"):
            continue
        if not _settings.get("verif_urls"):
            continue
        print(f"[verif_auto_scan] iniciando varredura automática em {_guild.id}", flush=True)
        try:
            await _varredura_verif(_guild, _settings)
        except Exception as _e:
            print(f"[verif_auto_scan] erro em {_guild.id}: {_e}", flush=True)
        await asyncio.sleep(5)


@_verif_auto_scan_task.before_loop
async def _verif_auto_scan_before():
    await bot.wait_until_ready()


@bot.check
async def _global_guild_check(ctx: commands.Context) -> bool:
    """Ignora silenciosamente comandos fora do servidor autorizado."""
    if ctx.guild:
        # No servidor HYPE (835695342291779645): só permite n!dev e n!migrar_emojis para administradores
        if ctx.guild.id == _HYPE_GUILD_ID:
            return (
                ctx.command is not None
                and ctx.command.name in ("dev", "migrar_emojis", "migrar_emojis_cdn", "migrar_canais")
                and ctx.author.guild_permissions.administrator
            )
        # n!dev é EXCLUSIVO do servidor HYPE — ignora silenciosamente em qualquer outro
        if ctx.command is not None and ctx.command.name == "dev":
            return False
        # Se um servidor específico foi configurado, só responde lá
        if _BOT_GUILD_ID and ctx.guild.id != _BOT_GUILD_ID:
            # Fallback: se o bot NÃO está no BOT_GUILD_ID configurado (guild_id errado/desatualizado),
            # permite comandos em qualquer servidor onde o bot realmente está — exceto HYPE.
            # Isso evita que um guild_id incorreto bloqueie o bot inteiro.
            _configured_guild = bot.get_guild(_BOT_GUILD_ID)
            if _configured_guild is None:
                # BOT_GUILD_ID não encontrado no cache — permite o servidor atual
                return True
            if ctx.command is not None and ctx.command.name in ("perm", "migrar_emojis", "exportar_config", "clonar_config", "migrar_canais"):
                return True  # sempre liberado para o dono do servidor
            return False
    return True


