bot_settings: dict[int, dict] = {}

SETTINGS_FILE  = os.environ.get("BOT_SETTINGS_FILE") or os.path.join(os.path.dirname(os.path.abspath(__file__)), "bot_settings.json")
PREFIX_FILE    = os.environ.get("BOT_PREFIX_FILE")   or os.path.join(os.path.dirname(os.path.abspath(__file__)), "bot_prefix.txt")
_CLIENT_DIR    = os.path.dirname(SETTINGS_FILE)
DESC_REQ_FILE   = os.path.join(_CLIENT_DIR, "bot_desc_pending.txt")
DESC_RES_FILE   = os.path.join(_CLIENT_DIR, "bot_desc_result.txt")
DESC_SAVED_FILE = os.path.join(_CLIENT_DIR, "bot_desc_saved.txt")

# ── Streaming prefix dinâmico ─────────────────────────────────────────────────
_stream_prefix_current: str = "n!"
_stream_prefix_last_ts: float = 0.0

async def _set_streaming_prefix(prefix: str) -> None:
    """Aplica o prefixo no status de streaming imediatamente e persiste no arquivo."""
    global _stream_prefix_current, _stream_prefix_last_ts
    import time

    # Sempre atualiza a variável e o arquivo — mesmo se o Discord falhar agora,
    # o _presence_task vai aplicar na próxima rodada (≤5 min)
    _stream_prefix_current = prefix
    _stream_prefix_last_ts = time.time()
    try:
        with open(PREFIX_FILE, "w", encoding="utf-8") as _pf:
            _pf.write(prefix)
    except Exception:
        pass

    try:
        await bot.change_presence(
            status=discord.Status.online,
            activity=discord.Streaming(
                name=f"Prefixo: {prefix}",
                url="https://twitch.tv/hypebots",
            ),
        )
        print(f"[presence] OK streaming: Prefixo: {prefix}", flush=True)
    except Exception as e:
        print(f"[presence] change_presence falhou (vai tentar em 5min): {e}")

async def _update_streaming_prefix(guild_id: int) -> None:
    """Atualiza o status de streaming passivamente (rate limit 30s — usado no on_message)."""
    global _stream_prefix_last_ts
    import time
    prefix = get_settings(guild_id).get("prefix", "n!")
    # Nunca sobrescreve um prefixo personalizado com o padrão "n!"
    # Isso evita que mensagens de outros servidores resetem o prefixo do cliente
    if not prefix or prefix == "n!":
        return
    if prefix == _stream_prefix_current:
        return  # prefixo igual, não precisa atualizar
    now = time.time()
    if now - _stream_prefix_last_ts < 30:
        return  # rate limit ainda ativo
    await _set_streaming_prefix(prefix)


def save_settings_to_disk() -> None:
    global _settings_last_mtime
    try:
        snapshot = {}
        for gid, data in bot_settings.items():
            cleaned = {}
            for k, v in data.items():
                try:
                    json.dumps(v)
                    cleaned[k] = v
                except (TypeError, ValueError):
                    cleaned[k] = str(v)
            snapshot[str(gid)] = cleaned
        with open(SETTINGS_FILE, "w", encoding="utf-8") as f:
            json.dump(snapshot, f, ensure_ascii=False, indent=2)
        # Atualiza mtime para que o watchdog não faça reload desnecessário desta gravação
        try:
            _settings_last_mtime = os.path.getmtime(SETTINGS_FILE)
        except Exception:
            pass
    except Exception as e:
        print(f"[settings] erro ao salvar: {e}")
    # Quando dev panel está ativo, persiste também no arquivo do bot cliente
    ovr = _dev_guild_ctx.get(0)
    if ovr:
        _dev_save_client_settings(ovr)


# ── Dev Panel: leitura/escrita no bot_settings.json do cliente ─────────────────
# Rastreia quais guilds já foram carregados do arquivo do cliente
_dev_loaded_guilds: set[int] = set()
# Snapshot do estado no momento do carregamento — usado para calcular o diff ao salvar
_dev_guild_snapshots: dict[int, dict] = {}


def _dev_get_client_settings_path(guild_id: int):
    """Retorna o Path do bot_settings.json do cliente que tem esse guild_id, ou None.

    Estratégia em 3 etapas:
    1. Lookup rápido por guild_id em customers.json
    2. Varredura nos arquivos de settings de todos os clientes (fallback)
    3. Se o próprio processo é o cliente (mesmo guild_id), usa SETTINGS_FILE local
    """
    from pathlib import Path as _Path
    _code = _Path(os.path.dirname(os.path.abspath(__file__)))
    _data = _Path(os.environ.get("DATA_DIR", str(_code)))

    # ── Etapa 1: lookup rápido por guild_id em customers.json ──────────────────
    for _cf in (_data / "customers.json", _code / "customers.json"):
        if not _cf.exists():
            continue
        try:
            with open(_cf, encoding="utf-8") as _f:
                customers = json.load(_f)
            for c in customers:
                if str(c.get("guild_id", "")).strip() == str(guild_id):
                    sf = _data / "clientes" / str(c["id"]) / "bot_settings.json"
                    return sf
        except Exception:
            pass

    # ── Etapa 2: varredura nos arquivos de settings de todos os clientes ────────
    # Necessário quando guild_id não está explícito em customers.json
    clients_dir = _data / "clientes"
    if clients_dir.exists():
        for cdir in sorted(clients_dir.iterdir()):
            if not cdir.is_dir():
                continue
            sf = cdir / "bot_settings.json"
            if not sf.exists():
                continue
            try:
                with open(sf, encoding="utf-8") as _f:
                    data = json.load(_f)
                if str(guild_id) in data:
                    return sf
            except Exception:
                continue

    # ── Etapa 3: se o próprio arquivo de settings já contém esse guild ──────────
    # (situação de instância única onde dev e cliente são o mesmo processo)
    try:
        if os.path.exists(SETTINGS_FILE):
            with open(SETTINGS_FILE, encoding="utf-8") as _f:
                data = json.load(_f)
            if str(guild_id) in data:
                from pathlib import Path as _PF
                return _PF(SETTINGS_FILE)
    except Exception:
        pass

    return None


def _dev_load_client_settings(guild_id: int, force: bool = False) -> None:
    """Carrega as settings do bot cliente para esse guild_id na memória do dev bot.
    force=True sempre relê do disco (ignora cache) — usado ao abrir/atualizar o painel."""
    if not force and guild_id in _dev_loaded_guilds:
        return
    # Remove do cache para garantir que próximas chamadas sem force também recarreguem
    # (o cache é reabastecido logo abaixo após leitura bem-sucedida)
    _dev_loaded_guilds.discard(guild_id)
    client_file = _dev_get_client_settings_path(guild_id)
    if client_file is None or not client_file.exists():
        _dev_loaded_guilds.add(guild_id)  # marca como "tentado" para não ficar em loop
        return
    try:
        with open(client_file, encoding="utf-8") as f:
            data = json.load(f)
        for k, v in data.items():
            try:
                bot_settings[int(k)] = v
            except (ValueError, TypeError):
                pass
        _dev_loaded_guilds.add(guild_id)
        # Salva snapshot do estado carregado para calcular diff exato ao salvar
        import copy as _copy
        _dev_guild_snapshots[guild_id] = _copy.deepcopy(bot_settings.get(guild_id, {}))
        tag = "forçado" if force else "inicial"
        print(f"[dev] settings do cliente carregadas ({tag}): {client_file}", flush=True)
    except Exception as e:
        print(f"[dev] erro ao carregar settings do cliente: {e}", flush=True)


def _dev_save_client_settings(guild_id: int) -> None:
    """Persiste as settings do guild alvo em TODOS os arquivos bot_settings.json
    de clientes que gerenciam esse guild.
    O bot cliente detectará a mudança de mtime e recarregará automaticamente (~8s)."""
    # Coleta todos os arquivos de cliente que contêm esse guild
    targets: list = []
    client_file = _dev_get_client_settings_path(guild_id)
    if client_file is not None:
        targets.append(client_file)

    # Busca arquivos adicionais (outros clientes que também gerenciam esse guild)
    from pathlib import Path as _Path
    _data = _Path(os.environ.get("DATA_DIR", os.path.dirname(os.path.abspath(__file__))))
    clients_dir = _data / "clientes"
    if clients_dir.exists():
        for cdir in sorted(clients_dir.iterdir()):
            if not cdir.is_dir():
                continue
            sf = cdir / "bot_settings.json"
            if not sf.exists() or sf in targets:
                continue
            try:
                with open(sf, encoding="utf-8") as _f:
                    data = json.load(_f)
                if str(guild_id) in data:
                    targets.append(sf)
            except Exception:
                continue

    if not targets:
        # Fallback: nenhum arquivo de cliente encontrado.
        # Garante que ao menos o SETTINGS_FILE local (processo do bot cliente) seja alvo.
        from pathlib import Path as _PF
        _local = _PF(SETTINGS_FILE)
        targets.append(_local)
        print(f"[dev] nenhum arquivo cliente localizado para guild {guild_id}; salvando em {_local}", flush=True)

    # ── Calcula apenas o diff: o que o dev realmente alterou nesta sessão ────────
    # Compara o estado atual com o snapshot do momento do carregamento.
    # Salvar só o diff evita sobrescrever mudanças feitas pelo cliente no intervalo.
    import copy as _copy
    snapshot   = _dev_guild_snapshots.get(guild_id, {})
    current    = bot_settings.get(guild_id, {})
    dev_changes: dict = {}
    all_keys = set(list(snapshot.keys()) + list(current.keys()))
    for k in all_keys:
        if current.get(k) != snapshot.get(k):
            v = current.get(k)
            try:
                json.dumps(v)
                dev_changes[k] = v
            except (TypeError, ValueError):
                dev_changes[k] = str(v)

    # Salva em cada arquivo: parte de base mais recente no disco + aplica diff do dev
    for cf in targets:
        try:
            existing: dict = {}
            if cf.exists():
                with open(cf, encoding="utf-8") as f:
                    existing = json.load(f)
            # Base = versão mais recente do arquivo do cliente; diff do dev sobrescreve só o que mudou
            latest_guild = existing.get(str(guild_id), {})
            latest_guild.update(dev_changes)
            existing[str(guild_id)] = latest_guild
            cf.parent.mkdir(parents=True, exist_ok=True)
            with open(cf, "w", encoding="utf-8") as f:
                json.dump(existing, f, ensure_ascii=False, indent=2)
            print(f"[dev] settings salvas no cliente (diff {len(dev_changes)} campo(s)): {cf}", flush=True)
        except Exception as e:
            print(f"[dev] erro ao salvar em {cf}: {e}", flush=True)

    # Atualiza snapshot para que o próximo save compute o diff correto
    _dev_guild_snapshots[guild_id] = _copy.deepcopy(current)


def load_settings_from_disk() -> None:
    if not os.path.exists(SETTINGS_FILE):
        return
    try:
        with open(SETTINGS_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        bot_settings.clear()
        for k, v in data.items():
            try:
                bot_settings[int(k)] = v
            except ValueError:
                continue
        print(f"[settings] carregado {len(bot_settings)} servidor(es) do disco.")
        for _gid, _gs in bot_settings.items():
            if _gs.get("protecao_cargos_enabled"):
                _bl = _gs.get("protecao_cargo_bloqueado", {})
                _ac = _gs.get("protecao_cargos_acesso", [])
                print(f"[settings] guild={_gid} protecao=ON bloqueado={list(_bl.keys())[:10]} acesso={_ac[:5]}", flush=True)
                for _rid, _racesso in list(_bl.items())[:10]:
                    print(f"[settings]   cargo={_rid} acesso_especifico={_racesso[:5]}", flush=True)
    except Exception as e:
        print(f"[settings] erro ao carregar: {e}")


# ── Auto-reload: detecta mudanças externas no arquivo de settings ───────────────
# Quando o painel dev salva no bot_settings.json do cliente, o bot cliente
# detecta a mudança de mtime e recarrega automaticamente sem precisar reiniciar.
_settings_last_mtime: float = 0.0


async def _settings_watchdog_loop() -> None:
    """Verifica a cada 8 segundos se o arquivo de settings foi modificado externamente.
    Isso permite que alterações feitas pelo painel dev reflitam imediatamente no cliente."""
    global _settings_last_mtime
    await asyncio.sleep(8)
    # Inicializa o mtime para não recarregar na primeira iteração
    try:
        _settings_last_mtime = os.path.getmtime(SETTINGS_FILE) if os.path.exists(SETTINGS_FILE) else 0.0
    except Exception:
        _settings_last_mtime = 0.0

    while True:
        try:
            await asyncio.sleep(8)
            if not os.path.exists(SETTINGS_FILE):
                continue
            mtime = os.path.getmtime(SETTINGS_FILE)
            if mtime > _settings_last_mtime:
                _settings_last_mtime = mtime
                _guilds_before = set(bot_settings.keys())
                load_settings_from_disk()
                _guilds_after  = set(bot_settings.keys())
                print("[settings] recarga automática — arquivo modificado externamente", flush=True)
                # Sai dos servidores que foram removidos das settings pelo dashboard
                for _removed_gid in (_guilds_before - _guilds_after):
                    _g = bot.get_guild(_removed_gid)
                    if _g:
                        try:
                            await _g.leave()
                            print(f"[guild] saiu de '{_g.name}' ({_removed_gid}) — removido das settings", flush=True)
                        except Exception as _le:
                            print(f"[guild] erro ao sair de {_removed_gid}: {_le}", flush=True)
                # Sincroniza _stream_prefix_current com o novo prefixo carregado do disco
                _reload_gid = _BOT_GUILD_ID or next(iter(bot_settings), 0)
                if _reload_gid:
                    _new_p = bot_settings.get(_reload_gid, {}).get("prefix", "")
                    if _new_p and _new_p != _stream_prefix_current:
                        asyncio.create_task(_set_streaming_prefix(_new_p))

            # ── Pedido de atualização de descrição do bot ──────────────────────
            if os.path.exists(DESC_REQ_FILE):
                try:
                    _desc = open(DESC_REQ_FILE, encoding="utf-8").read().strip()
                    os.remove(DESC_REQ_FILE)
                    _tok = os.environ.get("DISCORD_TOKEN", "").strip()
                    if not _tok:
                        # fallback: lê do .env file se a var não estiver no ambiente
                        _env_f = os.environ.get("BOT_ENV_FILE", "")
                        if _env_f and os.path.exists(_env_f):
                            for _l in open(_env_f, encoding="utf-8"):
                                if _l.startswith("DISCORD_TOKEN="):
                                    _tok = _l.split("=", 1)[1].strip()
                                    break
                    if _tok:
                        async with aiohttp.ClientSession() as _s:
                            async with _s.patch(
                                "https://discord.com/api/v10/applications/@me",
                                json={"description": _desc[:400]},
                                headers={"Authorization": f"Bot {_tok}"},
                            ) as _r:
                                _body = await _r.text()
                                _ok   = _r.status in (200, 201)
                                _msg  = "ok" if _ok else f"HTTP {_r.status}: {_body[:200]}"
                        open(DESC_RES_FILE, "w", encoding="utf-8").write(_msg)
                        print(f"[desc] descrição atualizada: {_msg}", flush=True)
                        # Persiste localmente para reaplica no próximo restart
                        if _ok:
                            if _desc:
                                try:
                                    open(DESC_SAVED_FILE, "w", encoding="utf-8").write(_desc)
                                except Exception:
                                    pass
                            else:
                                try:
                                    os.remove(DESC_SAVED_FILE)
                                except FileNotFoundError:
                                    pass
                    else:
                        open(DESC_RES_FILE, "w", encoding="utf-8").write("error: token não encontrado")
                except Exception as _de:
                    print(f"[desc] erro ao atualizar descrição: {_de}", flush=True)
                    try:
                        open(DESC_RES_FILE, "w", encoding="utf-8").write(f"error: {_de}")
                    except Exception:
                        pass
        except asyncio.CancelledError:
            break
        except Exception as _e:
            print(f"[settings] watchdog erro: {_e}", flush=True)


load_settings_from_disk()


