def _bn(settings: dict) -> str:
    """Return the bot's branded name for this guild (default: HypeBot)."""
    return settings.get("bot_name", "HypeBot")


def _apply_name(text: str, settings: dict) -> str:
    """Replace NATA® / A NATA in embed titles with the guild's stored bot name."""
    name = _bn(settings)
    return text.replace("NATA®", name).replace("A NATA", name)


def _apply_embed_banner(embed: discord.Embed, settings: dict) -> discord.Embed:
    """Applies the guild's banner image (set_image) to the embed if configured."""
    banner = settings.get("embed_banner_url") or os.environ.get("DEFAULT_EMBED_BANNER", "")
    if banner:
        embed.set_image(url=banner)
    return embed


def _format_remaining(seconds: float) -> str:
    if seconds < 0:
        seconds = 0
    days = int(seconds // 86400)
    seconds %= 86400
    hours = int(seconds // 3600)
    seconds %= 3600
    minutes = int(seconds // 60)
    secs = int(seconds % 60)
    return f"{days}d {hours}h {minutes}m {secs}s"


