def get_perm_data(settings: dict, perm_key: str) -> dict:
    pdata = settings.setdefault("permissions_data", {})
    return pdata.setdefault(perm_key, {"roles": [], "users": []})


def take_guild_backup(guild: discord.Guild) -> dict:
    return {
        "channels": [
            {
                "id": c.id,
                "name": c.name,
                "type": str(c.type),
                "category_id": c.category_id,
                "position": c.position,
            }
            for c in guild.channels
        ],
        "roles": [
            {
                "id": r.id,
                "name": r.name,
                "color": r.color.value,
                "permissions": r.permissions.value,
                "hoist": r.hoist,
                "mentionable": r.mentionable,
                "position": r.position,
            }
            for r in guild.roles
            if not r.is_default()
        ],
    }


antspam_history: dict[tuple[int, int], list[float]] = {}
mod_role_history: dict[tuple[int, int], list[float]] = {}
bot_role_actions: dict[tuple[int, int, str], float] = {}
target_manual_add_history: dict[tuple[int, int], list[float]] = {}


def _register_bot_role_action(member_id: int, role_id: int, action: str) -> None:
    bot_role_actions[(member_id, role_id, action)] = datetime.now().timestamp()


def _consume_bot_role_action(member_id: int, role_id: int, action: str) -> bool:
    key = (member_id, role_id, action)
    ts = bot_role_actions.get(key)
    if ts is None:
        return False
    now = datetime.now().timestamp()
    if now - ts > 30:
        bot_role_actions.pop(key, None)
        return False
    bot_role_actions.pop(key, None)
    return True


