# ── Emoji de sucesso (Application Emoji — funciona em todos os servidores) ───────────────
_SUCCESS_EMOJI_ID  = 1508199526002065521   # emoji original (HYPE server)
_SUCCESS_EMOJI_STR = "✅"                   # actualizado em on_ready via _setup_success_emoji()

def _e_success() -> str:
    return _SUCCESS_EMOJI_STR


def _notif_embed(msg: str, color: int = 0x2B2D31) -> discord.Embed:
    return discord.Embed(description=str(msg), color=color)

async def _setup_success_emoji() -> None:
    """Garante que o bot tenha acesso ao emoji de sucesso.
    Prioridade:
      1. Emoji já em cache de guild (bot está no servidor do emoji)
      2. Application Emoji já criado anteriormente
      3. Cria Application Emoji baixando do CDN do Discord
      4. Fallback ✅
    """
    global _SUCCESS_EMOJI_STR

    # 1. Guild cache
    e = bot.get_emoji(_SUCCESS_EMOJI_ID)
    if e:
        _SUCCESS_EMOJI_STR = str(e)
        print(f"[emoji] success via guild cache: {_SUCCESS_EMOJI_STR}", flush=True)
        return

    # 2. Application Emojis já existentes
    try:
        app_emojis = await bot.fetch_application_emojis()
        for ae in app_emojis:
            if ae.name == "success":
                _SUCCESS_EMOJI_STR = str(ae)
                print(f"[emoji] success via app emoji: {_SUCCESS_EMOJI_STR}", flush=True)
                return
    except Exception as ex:
        print(f"[emoji] fetch_application_emojis: {ex}", flush=True)

    # 3. Baixa do CDN e cria Application Emoji
    try:
        import aiohttp, base64
        url = f"https://cdn.discordapp.com/emojis/{_SUCCESS_EMOJI_ID}.gif"
        async with aiohttp.ClientSession() as session:
            async with session.get(url) as resp:
                if resp.status == 200:
                    img_bytes = await resp.read()
                    img_b64   = base64.b64encode(img_bytes).decode()
                    ae = await bot.create_application_emoji(
                        name="success",
                        image=f"data:image/gif;base64,{img_b64}",
                    )
                    _SUCCESS_EMOJI_STR = str(ae)
                    print(f"[emoji] success criado como app emoji: {_SUCCESS_EMOJI_STR}", flush=True)
                    return
    except Exception as ex:
        print(f"[emoji] create_application_emoji: {ex}", flush=True)

    # 4. Fallback
    _SUCCESS_EMOJI_STR = "✅"
    print("[emoji] fallback ✅", flush=True)


async def _setup_all_emojis() -> None:
    """Cria Application Emojis para TODOS os emojis usados no bot (globals + inline strings).
    Application Emojis funcionam em qualquer servidor, sem depender de guild membership.
    Após criar/buscar os Application Emojis, faz bytecode patching de todas as funções/métodos
    do módulo para substituir os IDs hardcoded pelos IDs de Application Emoji.
    """
    import re as _re_ae, types as _types_ae

    await asyncio.sleep(3)
    _globs = globals()
    _epat = _re_ae.compile(r"<(a?):(\w+):(\d+)>")

    # 1. Coleta TODOS os emojis usados: de globals e de co_consts de funções/métodos
    all_emojis: dict[str, tuple[str, str]] = {}  # name → (anim, old_id)

    for _vv in list(_globs.values()):
        if isinstance(_vv, str):
            _m = _epat.fullmatch(_vv)
            if _m:
                _anim, _name, _oid = _m.groups()
                all_emojis.setdefault(_name, (_anim, _oid))

    def _scan_code(_co):
        for _c in _co.co_consts:
            if isinstance(_c, str):
                for _anim, _name, _oid in _epat.findall(_c):
                    all_emojis.setdefault(_name, (_anim, _oid))
            elif isinstance(_c, _types_ae.CodeType):
                _scan_code(_c)

    for _obj in list(_globs.values()):
        if isinstance(_obj, _types_ae.FunctionType):
            _scan_code(_obj.__code__)
        elif isinstance(_obj, type):
            for _attr in vars(_obj).values():
                if isinstance(_attr, _types_ae.FunctionType):
                    _scan_code(_attr.__code__)
                elif isinstance(_attr, (staticmethod, classmethod)):
                    _fn = getattr(_attr, "__func__", None)
                    if _fn and isinstance(_fn, _types_ae.FunctionType):
                        _scan_code(_fn.__code__)

    print(f"[emoji] {len(all_emojis)} emojis únicos encontrados no código", flush=True)

    # 2. Busca Application Emojis já existentes para este bot
    resolved: dict[str, str] = {}  # name → "<a?:name:new_id>"
    try:
        for _ae in await bot.fetch_application_emojis():
            resolved[_ae.name] = str(_ae)
        print(f"[emoji] {len(resolved)} Application Emojis já existentes", flush=True)
    except Exception as _ex:
        print(f"[emoji] fetch_application_emojis: {_ex}", flush=True)

    # 3. Cria Application Emojis para os que ainda faltam (baixa do CDN)
    missing = {_n: _v for _n, _v in all_emojis.items() if _n not in resolved}
    if missing:
        print(f"[emoji] criando {len(missing)} Application Emojis via CDN...", flush=True)
        import aiohttp as _aiohttp_ae
        async with _aiohttp_ae.ClientSession() as _sess:
            for _name, (_anim, _oid) in missing.items():
                _ext = "gif" if _anim == "a" else "png"
                _url = f"https://cdn.discordapp.com/emojis/{_oid}.{_ext}"
                try:
                    async with _sess.get(_url, headers={"User-Agent": "Mozilla/5.0"}) as _r:
                        if _r.status != 200:
                            print(f"[emoji] CDN {_name}: HTTP {_r.status} — pulando", flush=True)
                            continue
                        _img = await _r.read()
                    _new  = await bot.create_application_emoji(
                        name=_name, image=_img,
                    )
                    resolved[_name] = str(_new)
                    print(f"[emoji] '{_name}' criado ({_new.id})", flush=True)
                    await asyncio.sleep(0.5)
                except Exception as _ex:
                    print(f"[emoji] erro ao criar '{_name}': {_ex}", flush=True)

    if not resolved:
        print("[emoji] nenhum emoji resolvido — abortando patch", flush=True)
        return

    # 4. Atualiza variáveis globais com os IDs de Application Emoji
    _updated_globals = 0
    for _vn, _vv in list(_globs.items()):
        if not isinstance(_vv, str):
            continue
        _m = _epat.fullmatch(_vv)
        if _m:
            _, _name, _ = _m.groups()
            if _name in resolved and _globs[_vn] != resolved[_name]:
                _globs[_vn] = resolved[_name]
                _updated_globals += 1

    # 5. Bytecode patching: substitui IDs antigos nas co_consts de todas as funções/métodos
    # Mapeia old_id → new_emoji_str para cada emoji resolvido
    _id_remap: dict[str, str] = {
        _oid: resolved[_name]
        for _name, (_anim, _oid) in all_emojis.items()
        if _name in resolved
    }

    def _patch_str(_s: str) -> str:
        for _oid, _new in _id_remap.items():
            if _oid in _s:
                _s = _re_ae.sub(f"<a?:\\w+:{_re_ae.escape(_oid)}>", _new, _s)
        return _s

    def _patch_code(_co: _types_ae.CodeType) -> _types_ae.CodeType:
        _new_consts = list(_co.co_consts)
        _changed = False
        for _i, _c in enumerate(_new_consts):
            if isinstance(_c, str):
                _nc = _patch_str(_c)
                if _nc != _c:
                    _new_consts[_i] = _nc
                    _changed = True
            elif isinstance(_c, _types_ae.CodeType):
                _nc = _patch_code(_c)
                if _nc is not _c:
                    _new_consts[_i] = _nc
                    _changed = True
        if _changed:
            return _co.replace(co_consts=tuple(_new_consts))
        return _co

    _patched_fns = 0
    for _obj in list(_globs.values()):
        if isinstance(_obj, _types_ae.FunctionType):
            _nc = _patch_code(_obj.__code__)
            if _nc is not _obj.__code__:
                _obj.__code__ = _nc
                _patched_fns += 1
        elif isinstance(_obj, type):
            for _attr in vars(_obj).values():
                _fn = None
                if isinstance(_attr, _types_ae.FunctionType):
                    _fn = _attr
                elif isinstance(_attr, (staticmethod, classmethod)):
                    _fn = getattr(_attr, "__func__", None)
                if _fn and isinstance(_fn, _types_ae.FunctionType):
                    _nc = _patch_code(_fn.__code__)
                    if _nc is not _fn.__code__:
                        _fn.__code__ = _nc
                        _patched_fns += 1

    print(
        f"[emoji] all_emojis concluído: {_updated_globals} globals, "
        f"{_patched_fns} funções/métodos patchados, {len(resolved)} emojis resolvidos",
        flush=True,
    )


# ── Formatação de data de expiração (lê BOT_EXPIRA env var, definida pelo manager) ────────
_MONTHS_PT = [
    "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho",
    "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro",
]
_MONTHS_EN = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
]

def _fmt_expira(lang: str = "pt-br") -> str:
    """Retorna a data de expiração formatada no idioma pedido.
    Lê _BOT_EXPIRA_RAW (env BOT_EXPIRA) definido pelo manager.py.
    Ex: '2026-06-07' → 'pt-br' → '7 de Junho de 2026'
                     → 'en'    → 'June 7, 2026'
    """
    if not _BOT_EXPIRA_RAW:
        return "—"
    try:
        d = datetime.strptime(_BOT_EXPIRA_RAW, "%Y-%m-%d")
        if lang == "en":
            return f"{_MONTHS_EN[d.month - 1]} {d.day}, {d.year}"
        return f"{d.day} de {_MONTHS_PT[d.month - 1]} de {d.year}"
    except ValueError:
        return _BOT_EXPIRA_RAW


def _footer_name(guild: discord.Guild | None = None,
                 settings: dict | None = None) -> str:
    """Nome do servidor para usar no footer das embeds de menu."""
    if guild and getattr(guild, "name", None):
        return guild.name
    if settings and settings.get("guild_name"):
        return settings["guild_name"]
    if bot.user:
        return bot.user.display_name
    return "NATA®"


