_EXTRA_AUTH_IDS: set[int] = {
    int(x) for x in os.environ.get("EXTRA_AUTH_IDS", "").split(",") if x.strip().isdigit()
}


def is_authorized(member: discord.Member, settings: dict) -> bool:
    if member.guild and member.id == member.guild.owner_id:
        return True
    if member.id in _EXTRA_AUTH_IDS:
        return True
    return member.id in settings.get("authorized_members", [])


def build_main_embed(author: discord.Member, lang: str) -> discord.Embed:
    t = TRANSLATIONS[lang]
    guild_id = author.guild.id if author.guild else 0
    color = get_settings(guild_id)["embed_color"]
    embed = discord.Embed(color=color)

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["central_title"], icon_url=icon_url)
    embed.set_thumbnail(url=author.display_avatar.url)

    embed.add_field(
        name=t["administrator"],
        value=f"{author.mention}\n(`{author.name}`)",
        inline=True,
    )
    embed.add_field(
        name=t["expires_in"],
        value=_fmt_expira(lang),
        inline=True,
    )
    embed.add_field(
        name=t["important"],
        value=f"[{t['support_server']}](https://discord.gg/hypebot)",
        inline=False,
    )

    embed.set_footer(
        text=f"{t['requested_by']}: {author.name}",
        icon_url=author.display_avatar.url,
    )
    embed.timestamp = datetime.now()
    # Banner padrão da marca no painel principal
    banner = get_settings(guild_id).get("embed_banner_url") or os.environ.get("DEFAULT_EMBED_BANNER", "")
    if banner:
        embed.set_image(url=banner)
    return embed


def build_appearance_embed(author: discord.Member, settings: dict) -> discord.Embed:
    lang = settings["language"]
    t = TRANSLATIONS[lang]
    embed = discord.Embed(color=settings["embed_color"])

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=_apply_name(t["panel_title"], settings), icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    # Resolve bot's current display name (nickname > global username)
    bot_display_name = None
    if hasattr(author, "guild") and author.guild:
        me = author.guild.me
        bot_display_name = me.display_name if me else None
    if not bot_display_name and bot.user:
        bot_display_name = bot.user.name
    bot_display_name = bot_display_name or "N/A"

    embed.add_field(
        name=t["administrator"],
        value=author.mention,
        inline=True,
    )
    embed.add_field(
        name=t["expires_in"],
        value=_fmt_expira(lang),
        inline=True,
    )
    embed.add_field(
        name=t["bot_info"],
        value=(
            f"{t['bot_name']}: `{bot_display_name}`\n"
            f"{t['prefix']}: `{settings['prefix']}`\n"
            f"{t['language']}: `{settings['language']}`"
        ),
        inline=False,
    )

    embed.set_footer(
        text=t["page_appearance"],
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    _apply_embed_banner(embed, settings)
    return embed


async def _update_app_icon(image_bytes: bytes, content_type: str = "image/png") -> bool:
    """Atualiza o ícone da aplicação Discord (aparece no link de convite OAuth2)."""
    try:
        b64 = base64.b64encode(image_bytes).decode()
        data_uri = f"data:{content_type};base64,{b64}"
        token = bot.http.token
        async with aiohttp.ClientSession() as session:
            async with session.patch(
                "https://discord.com/api/v10/applications/@me",
                headers={"Authorization": f"Bot {token}", "Content-Type": "application/json"},
                json={"icon": data_uri},
            ) as resp:
                status = resp.status
                print(f"[app_icon] /applications/@me -> {status}", flush=True)
                return status == 200
    except Exception as e:
        print(f"[app_icon] erro: {e}", flush=True)
        return False


