def _yes_no(t: dict, value: bool) -> str:
    icon = "<a:online:1518271945550856295>" if value else "<a:alerta:1518271939460857968>"
    label = t["ticket_sim"] if value else t["ticket_nao"]
    return f"{icon} `{label}`"


def build_ticket_config_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    log_channel_id = settings.get("ticket_log_channel")
    if log_channel_id and author.guild:
        ch = author.guild.get_channel(log_channel_id)
        log_value = ch.mention if ch else f"<#{log_channel_id}>"
    else:
        log_value = f"`{t['not_defined']}`"

    marcar_value = _yes_no(t, settings.get("ticket_marcar", True))

    motivo_abrir = _yes_no(t, settings.get("ticket_motivo_abrir", False))
    motivo_fechar = _yes_no(t, settings.get("ticket_motivo_fechar", False))

    panels = settings.get("ticket_panels", [])
    tickets_count = len(panels)
    tickets_value = f"`{tickets_count} {t['ticket_count_unit']}`"

    trava_enabled = settings.get("ticket_trava_enabled", False)
    trava_roles = settings.get("ticket_trava_immune_roles", [])
    if not trava_enabled and not trava_roles:
        trava_value = f"`{t['ticket_na']}`"
    elif trava_enabled and not trava_roles:
        trava_value = _yes_no(t, True)
    else:
        immune_text = _format_roles_list(author.guild, trava_roles) or f"`{t['not_defined']}`"
        trava_value = (
            f"{_yes_no(t, trava_enabled)} • **Imunes:** {immune_text}"
        )

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"**{t['ticket_canal_logs_label']}:** {log_value}\n"
            f"**{t['ticket_marcar_label']}:** {marcar_value}\n"
            f"**{t['ticket_motivo_obg_label']}:** "
            f"**{t['ticket_motivo_abrir_label']}:** {motivo_abrir}  |  "
            f"**{t['ticket_motivo_fechar_label']}:** {motivo_fechar}\n"
            f"**{t['ticket_configurados_label']}:** {tickets_value}\n"
            f"**{t['ticket_trava_label']}:** {trava_value}"
        ),
        inline=False,
    )

    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['ticket_config_observations_title']}",
        value=(
            f"`1.` {t['ticket_config_obs_1']}\n"
            f"`2.` {t['ticket_config_obs_2']}\n"
            f"`3.` {t['ticket_config_obs_3']}"
        ),
        inline=False,
    )

    embed.set_footer(
        text=f"NATA® • {t['solicitado_por']} {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


