def _ticket_status_label(t: dict, on: bool) -> str:
    return t["ticket_status_ativado"] if on else t["ticket_status_desativado"]


def _ticket_status_value(t: dict, on: bool) -> str:
    return f"`{_ticket_status_label(t, on)}`"


