class TicketMarcacaoView(discord.ui.View):
    def __init__(self, parent_view: "TicketConfigView"):
        super().__init__(timeout=None)
        self.parent_view = parent_view
        self._build()

    def _build(self):
        settings = get_settings(self.parent_view.author.guild.id)
        t = TRANSLATIONS[settings["language"]]
        self.clear_items()

        on = settings.get("ticket_marcar", True)
        emoji = discord.PartialEmoji.from_str(
            "<a:online:1518271945550856295>" if on
            else "<a:alerta:1518271939460857968>"
        )
        btn = discord.ui.Button(
            label=t["ticket_marcacao_btn"],
            style=discord.ButtonStyle.secondary,
            emoji=emoji,
        )
        btn.callback = self._toggle
        self.add_item(btn)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["ticket_marcar"] = not settings.get("ticket_marcar", True)
        new_on = settings["ticket_marcar"]

        new_embed = build_ticket_marcacao_embed(settings)
        new_view = TicketMarcacaoView(self.parent_view)
        await interaction.response.edit_message(embed=new_embed, view=new_view)
        await self.parent_view._refresh_main(interaction)
        await interaction.followup.send(
            t["ticket_marcacao_changed"].format(value=t["ticket_sim"] if new_on else t["ticket_nao"]),
            ephemeral=True,
        )


