class TicketTravaImmuneRoleSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "TicketConfigView", placeholder: str):
        super().__init__(placeholder=placeholder, min_values=1, max_values=25, row=1)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        target = settings.setdefault("ticket_trava_immune_roles", [])
        for r in self.values:
            if r.id in target:
                target.remove(r.id)
            else:
                target.append(r.id)

        new_embed = build_ticket_trava_embed(settings, interaction.guild)
        new_view = TicketTravaView(self.parent_view)
        await interaction.response.edit_message(embed=new_embed, view=new_view)
        await self.parent_view._refresh_main(interaction)
        await interaction.followup.send(embed=_notif_embed(t["ticket_trava_roles_updated"]), ephemeral=True)


