class TicketConfigView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self.main_message: discord.Message | None = None
        self._build_buttons()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_buttons(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]
        self.clear_items()

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (t["btn_canal_logs_ticket"], discord.ButtonStyle.secondary, self._define_logs),
            (t["btn_marcacao"], discord.ButtonStyle.secondary, self._define_marcacao),
            (t["btn_motivo"], discord.ButtonStyle.secondary, self._define_motivo),
            (t["btn_travar_ticket"], discord.ButtonStyle.secondary, self._define_trava),
        ]
        row1 = [
            (t["btn_resetar_tudo"], discord.ButtonStyle.danger, self._reset_all),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _refresh_main(self, interaction: discord.Interaction):
        """Refresh the main config panel after a child ephemeral view changed settings."""
        if self.main_message is None:
            return
        try:
            settings = get_settings(interaction.guild.id)
            embed = build_ticket_config_embed(self.author, settings)
            new_view = TicketConfigView(self.author)
            new_view.main_message = self.main_message
            await self.main_message.edit(embed=embed, view=new_view)
        except (discord.HTTPException, discord.NotFound):
            pass

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_tickets_embed(self.author, settings)
        view = TicketsView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _define_logs(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = TicketLogChannelView(self, t["ticket_select_log_placeholder"])
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed = discord.Embed(description=t["ticket_select_log_prompt"], color=settings["embed_color"])
        embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        embed.set_thumbnail(url=icon_url)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _define_marcacao(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_marcacao_embed(settings)
        view = TicketMarcacaoView(self)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _define_motivo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_motivo_embed(settings)
        view = TicketMotivoView(self)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _define_trava(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_trava_embed(settings, interaction.guild)
        view = TicketTravaView(self)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _reset_all(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["ticket_log_channel"] = None
        settings["ticket_marcar"] = True
        settings["ticket_motivo_abrir"] = False
        settings["ticket_motivo_fechar"] = False
        settings["ticket_trava_enabled"] = False
        settings["ticket_trava_immune_roles"] = []
        embed = build_ticket_config_embed(self.author, settings)
        new_view = TicketConfigView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["ticket_reset_done"]), ephemeral=True)


