def _get_ticket_panels(settings: dict) -> list[dict]:
    """Return the list of ticket panel dicts. Each panel: {id, name, channel_id}."""
    return settings.get("ticket_panels", [])


def _get_ticket_ia_cfg(settings: dict, panel_id: str) -> dict:
    cfgs = settings.setdefault("ticket_ia_configs", {})
    return cfgs.setdefault(panel_id, {"enabled": False, "prompt": None})


def _get_ticket_aval_cfg(settings: dict, panel_id: str) -> dict:
    cfgs = settings.setdefault("ticket_aval_configs", {})
    return cfgs.setdefault(panel_id, {
        "enabled": False,
        "log_channel": None,
        "ranking_channel": None,
        "atendentes": [],
    })


