class TicketAvalSelect(discord.ui.Select):
    def __init__(self, parent_view: "TicketAvalView", placeholder: str):
        settings = get_settings(parent_view.author.guild.id)
        panels = _get_ticket_panels(settings)
        t = TRANSLATIONS[settings["language"]]
        if panels:
            options = [
                discord.SelectOption(
                    label=p.get("name", f"Ticket {p.get('id', '?')}")[:100],
                    description=p.get("description", "")[:100] or None,
                    value=str(p["id"]),
                    emoji=_make_select_emoji("<:tickets:1518271952526250155>"),
                )
                for p in panels
            ]
            disabled = False
        else:
            options = [
                discord.SelectOption(
                    label=t["ticket_ia_no_tickets"],
                    description=t["ticket_ia_no_tickets_desc"],
                    value="__none__",
                    emoji=_make_select_emoji("<a:alerta:1518271939460857968>"),
                )
            ]
            disabled = True
        super().__init__(placeholder=placeholder, min_values=1, max_values=1, options=options)
        self.parent_view = parent_view
        self.disabled = disabled

    async def callback(self, interaction: discord.Interaction):
        if self.values[0] == "__none__":
            await interaction.response.defer()
            return
        settings = get_settings(interaction.guild.id)
        panel_id = self.values[0]
        embed = build_ticket_aval_config_embed(self.parent_view.author, settings, panel_id)
        view = TicketAvalConfigView(self.parent_view.author, panel_id)
        await interaction.response.edit_message(embed=embed, view=view)


