def build_ticket_aval_config_embed(
    author: discord.Member, settings: dict, panel_id: str
) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["ticket_aval_config_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    panel = next((p for p in _get_ticket_panels(settings) if str(p.get("id")) == panel_id), None)
    ticket_channel = f"`{t['ticket_unknown_channel']}`"
    if panel and author.guild:
        ch = author.guild.get_channel(panel.get("channel_id") or 0)
        ticket_channel = ch.mention if ch else f"`{t['ticket_unknown_channel']}`"

    cfg = _get_ticket_aval_cfg(settings, panel_id)
    enabled = cfg.get("enabled", False)
    status_value = (
        f"<a:online:1518271945550856295> `{t['ticket_ia_status_ativada']}`"
        if enabled
        else f"<a:alerta:1518271939460857968> `{t['ticket_ia_status_desativada']}`"
    )

    log_id = cfg.get("log_channel")
    rank_id = cfg.get("ranking_channel")
    log_value = (
        author.guild.get_channel(log_id).mention if (author.guild and log_id and author.guild.get_channel(log_id))
        else (f"<#{log_id}>" if log_id else f"`{t['ticket_na']}`")
    )
    rank_value = (
        author.guild.get_channel(rank_id).mention if (author.guild and rank_id and author.guild.get_channel(rank_id))
        else (f"<#{rank_id}>" if rank_id else f"`{t['ticket_na']}`")
    )

    atendentes = cfg.get("atendentes", [])
    atendentes_value = f"`{len(atendentes)} {t['ticket_aval_atendentes_unit']}`"

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"**{t['ticket_aval_ticket_atual']}:** {ticket_channel}\n"
            f"**{t['ticket_aval_status_label']}:** {status_value}\n"
            f"**{t['ticket_aval_canal_logs']}:** {log_value}\n"
            f"**{t['ticket_aval_canal_ranking']}:** {rank_value}\n"
            f"**{t['ticket_aval_atendentes']}:** {atendentes_value}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['ticket_aval_obs_title']}",
        value=t["ticket_aval_obs_text"],
        inline=False,
    )

    embed.set_footer(
        text=f"NATA® ® • {t['solicitado_por']} {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


