class TicketAvalConfigView(discord.ui.View):
    def __init__(self, author: discord.Member, panel_id: str):
        super().__init__(timeout=None)
        self.author = author
        self.panel_id = panel_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        self.clear_items()
        cfg = _get_ticket_aval_cfg(settings, self.panel_id)
        enabled = cfg.get("enabled", False)
        activate_label = t["btn_desativar_simples"] if enabled else t["btn_ativar_simples"]
        activate_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back, 0),
            (activate_label, activate_style, self._toggle, 0),
            (t["btn_configurar_canais"], discord.ButtonStyle.secondary, self._configurar_canais, 0),
            (t["btn_listar_atendentes"], discord.ButtonStyle.primary, self._listar_atendentes, 0),
            (t["btn_resetar_ranking"], discord.ButtonStyle.danger, self._reset_ranking, 0),
        ]
        row1 = [
            (t["btn_resetar_avaliacoes"], discord.ButtonStyle.danger, self._reset_avals, 1),
            (t["btn_resetar_tudo_aval"], discord.ButtonStyle.danger, self._reset_all, 1),
        ]
        for label, style, cb, row in row0 + row1:
            emoji = None
            if style == discord.ButtonStyle.primary and label == t["back"]:
                emoji = _button_emoji(style)
            elif style == discord.ButtonStyle.danger:
                emoji = _button_emoji(style)
            elif style == discord.ButtonStyle.success:
                emoji = _button_emoji(style)
            btn = discord.ui.Button(label=label, style=style, row=row, emoji=emoji)
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_aval_embed(self.author, settings)
        view = TicketAvalView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        cfg = _get_ticket_aval_cfg(settings, self.panel_id)
        cfg["enabled"] = not cfg.get("enabled", False)
        embed = build_ticket_aval_config_embed(self.author, settings, self.panel_id)
        new_view = TicketAvalConfigView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=new_view)
        msg = t["ticket_aval_toggled_on"] if cfg["enabled"] else t["ticket_aval_toggled_off"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _configurar_canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = TicketAvalCanaisView(self.panel_id, t)
        embed = discord.Embed(
            description=t["ticket_aval_canais_prompt"],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(
            embed=embed, view=view, ephemeral=True
        )

    async def _listar_atendentes(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        cfg = _get_ticket_aval_cfg(settings, self.panel_id)
        ids = cfg.get("atendentes", [])
        if not ids:
            await interaction.response.send_message(embed=_notif_embed(t["ticket_aval_no_atendentes"]), ephemeral=True)
            return
        lines = [f"• <@{uid}> (`{uid}`)" for uid in ids]
        embed = discord.Embed(
            title=t["ticket_aval_atendentes_title"],
            description="\n".join(lines)[:4000],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _reset_ranking(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        cfg = _get_ticket_aval_cfg(settings, self.panel_id)
        cfg.pop("ranking_scores", None)
        await interaction.response.send_message(embed=_notif_embed(t["ticket_aval_ranking_reset_done"]), ephemeral=True)

    async def _reset_avals(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        cfg = _get_ticket_aval_cfg(settings, self.panel_id)
        cfg.pop("avaliacoes", None)
        await interaction.response.send_message(embed=_notif_embed(t["ticket_aval_avals_reset_done"]), ephemeral=True)

    async def _reset_all(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        cfgs = settings.setdefault("ticket_aval_configs", {})
        cfgs[self.panel_id] = {
            "enabled": False, "log_channel": None,
            "ranking_channel": None, "atendentes": [],
        }
        embed = build_ticket_aval_config_embed(self.author, settings, self.panel_id)
        new_view = TicketAvalConfigView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["ticket_aval_all_reset_done"]), ephemeral=True)


