def _new_ticket_panel(channel: discord.TextChannel, guild: discord.Guild | None) -> dict:
    pid = str(int(datetime.now().timestamp() * 1000))
    return {
        "id": pid,
        "name": f"#{channel.name}",
        "channel_id": channel.id,
        "category_id": None,
        "log_channel_id": None,
        "responsible_roles": [],
        "usar_topico": False,
        "usar_botao": False,
        "menus_selecao": False,
        "horarios": None,
        "menu_opcoes": [],
        "horarios_config": {"inicio": None, "termino": None},
        "embed": {
            "title": None,
            "description": None,
            "color": None,
            "button_label": None,
            "button_emoji": None,
        },
    }


def _find_panel(settings: dict, panel_id: str) -> dict | None:
    for p in settings.get("ticket_panels", []):
        if str(p.get("id")) == str(panel_id):
            return p
    return None


class TicketCadastrarChannelSelect(GuildChannelSelect):
    def __init__(self, parent_view: "TicketCadastrarView", placeholder: str):
        super().__init__(
            placeholder=placeholder, min_values=1, max_values=1,
            channel_types=[discord.ChannelType.text],
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if not self.values:
            await interaction.response.send_message("❌ Canal inválido. Tente novamente.", ephemeral=True)
            return
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        ch = self.values[0]
        panel = _new_ticket_panel(ch, interaction.guild)
        settings.setdefault("ticket_panels", []).append(panel)
        save_settings_to_disk()
        embed = discord.Embed(
            description=t["ticket_cadastrar_created"].format(channel=ch.mention),
            color=settings["embed_color"],
        )
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        embed.set_thumbnail(url=icon_url)
        # Edita a mensagem com o dropdown em vez de criar uma nova
        await interaction.response.edit_message(
            content=None,
            embed=embed,
            view=None,
        )


