def build_ticket_per_manager_embed(
    author: discord.Member, settings: dict, panel_id: str
) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["ticket_manager_per_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    panel = _find_panel(settings, panel_id) or {}
    na = f"`{t['ticket_na']}`"

    if author.guild:
        ch = author.guild.get_channel(panel.get("channel_id") or 0)
        canal_painel = ch.mention if ch else f"`{t['ticket_unknown_channel']}`"
        log_ch_id = panel.get("log_channel_id")
        log_ch = author.guild.get_channel(log_ch_id) if log_ch_id else None
        canal_logs = log_ch.mention if log_ch else na
        cat_id = panel.get("category_id")
        category = author.guild.get_channel(cat_id) if cat_id else None
        categoria = f"`{category.name}`" if category else na
    else:
        canal_painel = na
        canal_logs = na
        categoria = na

    role_ids = panel.get("responsible_roles", [])
    cargos_resp = _format_roles_list(author.guild, role_ids) or na

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"**{t['ticket_manager_canal_painel']}:** {canal_painel}\n"
            f"**{t['ticket_manager_canal_logs']}:** {canal_logs}\n"
            f"**{t['ticket_manager_categoria']}:** {categoria}\n"
            f"**{t['ticket_manager_cargos_resp']}:** {cargos_resp}"
        ),
        inline=False,
    )

    horarios = panel.get("horarios")
    horarios_value = f"`{horarios}`" if horarios else na

    embed.add_field(
        name=f"<:ferramentas_:1518271998613131274>  {t['ticket_manager_personalizar']}",
        value=(
            f"**{t['ticket_manager_usar_topico']}:** `{_yes_no_label(t, panel.get('usar_topico', False))}`\n"
            f"**{t['ticket_manager_usar_botao']}:** `{_yes_no_label(t, panel.get('usar_botao', False))}`\n"
            f"**{t['ticket_manager_menus_selecao']}:** `{_yes_no_label(t, panel.get('menus_selecao', False))}`\n"
            f"**{t['ticket_manager_horarios']}:** {horarios_value}"
        ),
        inline=False,
    )

    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['ticket_config_observations_title']}",
        value=t["ticket_manager_obs"],
        inline=False,
    )

    embed.set_footer(
        text=f"NATA® ® • {t['solicitado_por']} {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


