# ── Horários Config ─────────────────────────────────────────────────────────

def build_ticket_horarios_config_embed(author: discord.Member, settings: dict, panel: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(
        title=t["ticket_horarios_config_title"],
        description=t["ticket_horarios_config_desc"],
        color=settings["embed_color"],
    )
    icon_url = bot.user.display_avatar.url if bot.user else None
    hcfg = panel.get("horarios_config") or {}
    # Backward compat: if horarios is a plain string "09:00|18:00"
    if not hcfg and isinstance(panel.get("horarios"), str) and panel["horarios"]:
        parts = panel["horarios"].split("|")
        if len(parts) == 2:
            hcfg = {"inicio": parts[0].strip(), "termino": parts[1].strip()}
    nc = f"`{t['ticket_horarios_nao_config']}`"
    inicio   = f"`{hcfg['inicio']}`"   if hcfg.get("inicio")   else nc
    termino  = f"`{hcfg['termino']}`"  if hcfg.get("termino")  else nc
    dias     = hcfg.get("dias", [])
    dias_str = f"`{', '.join(dias)}`"  if dias else f"`{t['ticket_horarios_dias_nenhum']}`"
    embed.add_field(
        name=t["ticket_horarios_inicio_section"],
        value=f"**{t['ticket_horarios_inicio_sub']}:** {inicio}\n**{t['ticket_horarios_termino_sub']}:** {termino}",
        inline=False,
    )
    embed.add_field(name=t["ticket_horarios_dias_section"], value=dias_str, inline=False)
    embed.add_field(
        name=t["ticket_horarios_como_config"],
        value=t["ticket_horarios_como_config_text"],
        inline=False,
    )
    embed.set_thumbnail(url=icon_url)
    embed.set_footer(text=f"NATA® ® • Hoje às {datetime.now().strftime('%H:%M')}", icon_url=icon_url)
    return embed


class TicketHorariosHoraModal(discord.ui.Modal):
    def __init__(self, panel_id: str, t: dict, author: discord.Member):
        super().__init__(title=t["ticket_horarios_hora_modal_title"], timeout=300)
        self.panel_id = panel_id
        self.author   = author
        self.inp = discord.ui.TextInput(
            label=t["ticket_horarios_hora_label"],
            placeholder=t["ticket_horarios_hora_placeholder"],
            required=True, max_length=11,
        )
        self.add_item(self.inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        val = self.inp.value.strip()
        parts = val.split("|")
        if len(parts) != 2:
            await interaction.response.send_message(embed=_notif_embed(t["ticket_horarios_invalid"]), ephemeral=True)
            return
        inicio, termino = parts[0].strip(), parts[1].strip()
        panel = _find_panel(settings, self.panel_id)
        if panel is not None:
            panel.setdefault("horarios_config", {})
            panel["horarios_config"]["inicio"]  = inicio
            panel["horarios_config"]["termino"] = termino
            panel["horarios"] = val  # backward compat
            save_settings_to_disk()
        # Re-show horários embed with updated data
        embed = build_ticket_horarios_config_embed(self.author, settings, panel or {})
        view  = TicketHorariosConfigView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=view)


class TicketHorariosConfigView(discord.ui.View):
    def __init__(self, author: discord.Member, panel_id: str):
        super().__init__(timeout=300)
        self.author   = author
        self.panel_id = panel_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        hora_btn = discord.ui.Button(
            label=t["btn_hora_atendimento"], style=discord.ButtonStyle.secondary,
        )
        hora_btn.callback = self._hora_atendimento
        self.add_item(hora_btn)
        reset_btn = discord.ui.Button(
            label=t["btn_resetar_horarios"], style=discord.ButtonStyle.danger,
        )
        reset_btn.callback = self._resetar
        self.add_item(reset_btn)

    async def _hora_atendimento(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = TicketHorariosHoraModal(self.panel_id, t, self.author)
        await interaction.response.send_modal(modal)

    async def _resetar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id)
        if panel is not None:
            panel["horarios_config"] = {"inicio": None, "termino": None, "dias": []}
            panel["horarios"] = None
            save_settings_to_disk()
        embed = build_ticket_horarios_config_embed(self.author, settings, panel or {})
        view  = TicketHorariosConfigView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=view)
        icon_url = bot.user.display_avatar.url if bot.user else None
        fb = discord.Embed(description=f"✅ {t['ticket_horarios_reset_done']}", color=settings["embed_color"])
        fb.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        await interaction.followup.send(embed=fb, ephemeral=True)


