class TicketMenuAddOpcaoView(discord.ui.View):
    """View para adicionar uma nova opção ao menu de seleção."""

    def __init__(self, author: discord.Member, panel_id: str, draft: dict | None = None):
        super().__init__(timeout=300)
        self.author   = author
        self.panel_id = panel_id
        self.draft    = draft or {"id": _new_menu_opcao_id(), "label": "", "description": "", "emoji": "", "responsible_roles": []}
        self.message: discord.Message | None = None
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_embed(self, settings: dict) -> discord.Embed:
        t = TRANSLATIONS[settings["language"]]
        na = t["ticket_menu_na"]
        embed = discord.Embed(description=t["ticket_menu_add_prompt"], color=settings["embed_color"])
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed.add_field(name=t["ticket_menu_descricao_label"], value=self.draft.get("description") or na, inline=True)
        embed.add_field(name=t["ticket_menu_emoji_label"],     value=self.draft.get("emoji")       or na, inline=True)
        embed.add_field(name=t["ticket_menu_titulo_label"],    value=self.draft.get("label")       or na, inline=True)
        embed.set_thumbnail(url=icon_url)
        return embed

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        for label, style, cb in [
            (t["btn_adicionar_titulo"],    discord.ButtonStyle.secondary, self._add_titulo),
            (t["btn_adicionar_descricao"], discord.ButtonStyle.secondary, self._add_descricao),
            (t["btn_adicionar_emoji_op"],  discord.ButtonStyle.secondary, self._add_emoji),
            (t["btn_finalizar"],           discord.ButtonStyle.success,   self._finalizar),
        ]:
            btn = discord.ui.Button(label=label, style=style)
            btn.callback = cb
            self.add_item(btn)

    async def _refresh(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = self._build_embed(settings)
        new_view = TicketMenuAddOpcaoView(self.author, self.panel_id, self.draft)
        new_view.message = self.message
        try:
            await interaction.edit_original_response(embed=embed, view=new_view)
        except (discord.HTTPException, discord.NotFound):
            if self.message:
                try:
                    await self.message.edit(embed=embed, view=new_view)
                except Exception:
                    pass

    async def _add_titulo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        prompt_embed = discord.Embed(
            description="Envie no chat o título para a nova opção do menu de seleção, você pode digitar até **20 caracteres**!",
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=prompt_embed, ephemeral=True)
        def check(m):
            return m.author.id == interaction.user.id and m.channel.id == interaction.channel.id
        try:
            msg = await bot.wait_for("message", check=check, timeout=120.0)
        except asyncio.TimeoutError:
            return
        try:
            await msg.delete()
        except Exception:
            pass
        self.draft["label"] = msg.content.strip()[:20]
        embed = self._build_embed(settings)
        new_view = TicketMenuAddOpcaoView(self.author, self.panel_id, self.draft)
        new_view.message = self.message
        if self.message:
            try:
                await self.message.edit(embed=embed, view=new_view)
            except Exception:
                pass

    async def _add_descricao(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        prompt_embed = discord.Embed(
            description="Envie no chat o texto que irá embaixo da descrição, você pode digitar até **60 caracteres**!",
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=prompt_embed, ephemeral=True)
        def check(m):
            return m.author.id == interaction.user.id and m.channel.id == interaction.channel.id
        try:
            msg = await bot.wait_for("message", check=check, timeout=120.0)
        except asyncio.TimeoutError:
            return
        try:
            await msg.delete()
        except Exception:
            pass
        self.draft["description"] = msg.content.strip()[:60]
        embed = self._build_embed(settings)
        new_view = TicketMenuAddOpcaoView(self.author, self.panel_id, self.draft)
        new_view.message = self.message
        if self.message:
            try:
                await self.message.edit(embed=embed, view=new_view)
            except Exception:
                pass

    async def _add_emoji(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        prompt_embed = discord.Embed(
            description="Envie no chat o emoji desejado para o menu de seleção ou digite `cancelar` para cancelar a operação.",
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=prompt_embed, ephemeral=True)
        def check(m):
            return m.author.id == interaction.user.id and m.channel.id == interaction.channel.id
        try:
            msg = await bot.wait_for("message", check=check, timeout=120.0)
        except asyncio.TimeoutError:
            return
        try:
            await msg.delete()
        except Exception:
            pass
        if msg.content.strip().lower() == "cancelar":
            return
        self.draft["emoji"] = msg.content.strip()
        embed = self._build_embed(settings)
        new_view = TicketMenuAddOpcaoView(self.author, self.panel_id, self.draft)
        new_view.message = self.message
        if self.message:
            try:
                await self.message.edit(embed=embed, view=new_view)
            except Exception:
                pass

    async def _finalizar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if not self.draft.get("label"):
            await interaction.response.send_message(embed=_notif_embed(t["ticket_menu_titulo_faltando"]), ephemeral=True)
            return
        panel = _find_panel(settings, self.panel_id)
        if panel is not None:
            opcoes = panel.setdefault("menu_opcoes", [])
            # Update existing if same id, otherwise append
            for i, op in enumerate(opcoes):
                if op.get("id") == self.draft["id"]:
                    opcoes[i] = self.draft
                    break
            else:
                opcoes.append(self.draft)
            save_settings_to_disk()
        icon_url = bot.user.display_avatar.url if bot.user else None
        fb = discord.Embed(description=f"✅ {t['ticket_menu_opcao_saved']}", color=settings["embed_color"])
        fb.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        # Re-open the main menu management view
        view = TicketMenuSelecaoView(self.author, self.panel_id)
        embed = build_ticket_menu_selecao_embed(settings, panel or {})
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=fb, ephemeral=True)


class TicketMenuRemoverSelect(discord.ui.Select):
    def __init__(self, author: discord.Member, panel_id: str, opcoes: list, t: dict):
        self.author   = author
        self.panel_id = panel_id
        options = []
        for op in opcoes[:25]:
            emoji = _parse_menu_emoji(op.get("emoji"))
            options.append(discord.SelectOption(
                label=op.get("label", "?")[:100],
                value=op.get("id", op.get("label", "?")),
                description=(op.get("description") or "")[:100] or None,
                emoji=emoji if isinstance(emoji, discord.PartialEmoji) else None,
            ))
        super().__init__(
            placeholder=t["ticket_menu_selecao_placeholder"],
            options=options, min_values=1, max_values=1,
        )

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id)
        if panel is not None:
            panel["menu_opcoes"] = [
                op for op in panel.get("menu_opcoes", [])
                if op.get("id") != self.values[0] and op.get("label") != self.values[0]
            ]
            save_settings_to_disk()
        icon_url = bot.user.display_avatar.url if bot.user else None
        fb = discord.Embed(description=f"✅ {t['ticket_menu_remover_confirm']}", color=settings["embed_color"])
        fb.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        view = TicketMenuSelecaoView(self.author, self.panel_id)
        embed = build_ticket_menu_selecao_embed(settings, panel or {})
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=fb, ephemeral=True)


