class TicketMenuEmbedInternaView(discord.ui.View):
    def __init__(self, author: discord.Member, panel_id: str, opcao_id: str):
        super().__init__(timeout=300)
        self.author   = author
        self.panel_id = panel_id
        self.opcao_id = opcao_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        for label, style, cb in [
            (t["btn_editar_descricao_menu"], discord.ButtonStyle.secondary, self._edit_desc),
            (t["btn_editar_emoji_menu"],     discord.ButtonStyle.secondary, self._edit_emoji),
        ]:
            btn = discord.ui.Button(label=label, style=style)
            btn.callback = cb
            self.add_item(btn)

    async def _edit_desc(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id)
        opcao = next((op for op in (panel or {}).get("menu_opcoes", []) if op.get("id") == self.opcao_id), {})
        await interaction.response.send_modal(
            TicketMenuDescricaoEditModal(self.author, self.panel_id, self.opcao_id, t, opcao.get("description"))
        )

    async def _edit_emoji(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id)
        opcao = next((op for op in (panel or {}).get("menu_opcoes", []) if op.get("id") == self.opcao_id), {})
        await interaction.response.send_modal(
            TicketMenuEmojiEditModal(self.author, self.panel_id, self.opcao_id, t, opcao.get("emoji"))
        )


