class TicketMenuGerenciarOpcaoView(discord.ui.View):
    def __init__(self, author: discord.Member, panel_id: str, opcao_id: str):
        super().__init__(timeout=300)
        self.author   = author
        self.panel_id = panel_id
        self.opcao_id = opcao_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        for label, style, cb in [
            (t["back"],           discord.ButtonStyle.primary,   self._back),
            (t["btn_editar_menu"],discord.ButtonStyle.secondary, self._editar_menu),
            (t["btn_cargos_responsaveis"], discord.ButtonStyle.secondary, self._cargos),
            (t["btn_embed_interna"],        discord.ButtonStyle.blurple, self._embed_interna),
        ]:
            btn = discord.ui.Button(label=label, style=style)
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel = _find_panel(settings, self.panel_id) or {}
        embed = build_ticket_menu_selecao_embed(settings, panel)
        view  = TicketMenuSelecaoView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _editar_menu(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel = _find_panel(settings, self.panel_id) or {}
        opcao = next((op for op in panel.get("menu_opcoes", []) if op.get("id") == self.opcao_id), None)
        if opcao is None:
            await interaction.response.defer()
            return
        import copy
        draft = copy.deepcopy(opcao)
        view  = TicketMenuAddOpcaoView(self.author, self.panel_id, draft)
        embed = view._build_embed(settings)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)
        try:
            view.message = await interaction.original_response()
        except Exception:
            pass

    async def _cargos(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed = discord.Embed(description=t["ticket_cargos_resp_prompt"], color=settings["embed_color"])
        embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        view = discord.ui.View(timeout=120)
        select = TicketMenuCargosSelect(self.author, self.panel_id, self.opcao_id, t["ticket_cargos_resp_placeholder"])
        view.add_item(select)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _embed_interna(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel = _find_panel(settings, self.panel_id) or {}
        view  = TicketOpcaoInternaV2View(self.author, panel, self.panel_id, self.opcao_id)
        await interaction.response.send_message(view=view, ephemeral=True)


class TicketMenuOpcoesSelect(discord.ui.Select):
    """Select menu mostrando as opções configuradas — clicar em uma abre o gerenciador."""
    def __init__(self, author: discord.Member, panel_id: str, opcoes: list, t: dict):
        self.author   = author
        self.panel_id = panel_id
        options = []
        if opcoes:
            for op in opcoes[:25]:
                emoji = _parse_menu_emoji(op.get("emoji"))
                options.append(discord.SelectOption(
                    label=op.get("label", "?")[:100],
                    value=op.get("id", op.get("label", "?")),
                    description=(op.get("description") or "")[:100] or None,
                    emoji=emoji if isinstance(emoji, discord.PartialEmoji) else None,
                ))
        else:
            options = [discord.SelectOption(label=t["ticket_menu_selecao_placeholder"], value="__empty__", default=True)]
        super().__init__(
            placeholder=t["ticket_menu_selecao_placeholder"],
            options=options,
            disabled=not bool(opcoes),
        )

    async def callback(self, interaction: discord.Interaction):
        if self.values[0] == "__empty__":
            await interaction.response.defer()
            return
        settings = get_settings(interaction.guild.id)
        panel = _find_panel(settings, self.panel_id) or {}
        opcao = next((op for op in panel.get("menu_opcoes", []) if op.get("id") == self.values[0] or op.get("label") == self.values[0]), None)
        if not opcao:
            await interaction.response.defer()
            return
        embed = build_ticket_menu_gerenciar_embed(settings, opcao)
        view  = TicketMenuGerenciarOpcaoView(self.author, self.panel_id, opcao["id"])
        await interaction.response.edit_message(embed=embed, view=view)


class TicketMenuSelecaoView(discord.ui.View):
    """View principal de gerenciamento do menu de seleção do ticket."""

    def __init__(self, author: discord.Member, panel_id: str):
        super().__init__(timeout=300)
        self.author   = author
        self.panel_id = panel_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id) or {}
        opcoes = panel.get("menu_opcoes", [])
        # Row 0: Select menu with options
        select = TicketMenuOpcoesSelect(self.author, self.panel_id, opcoes, t)
        select.row = 0
        self.add_item(select)
        # Row 1: Voltar, Adicionar Opções, Remover Opções
        for label, style, cb in [
            (t["back"],                discord.ButtonStyle.primary,   self._back),
            (t["btn_adicionar_opcoes"], discord.ButtonStyle.secondary, self._adicionar),
            (t["btn_remover_opcoes"],   discord.ButtonStyle.secondary, self._remover),
        ]:
            btn = discord.ui.Button(label=label, style=style, row=1)
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_per_manager_embed(self.author, settings, self.panel_id)
        view  = TicketPerManagerView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _adicionar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        view  = TicketMenuAddOpcaoView(self.author, self.panel_id)
        embed = view._build_embed(settings)
        view.message = interaction.message
        await interaction.response.edit_message(embed=embed, view=view)

    async def _remover(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id) or {}
        opcoes = panel.get("menu_opcoes", [])
        if not opcoes:
            icon_url = bot.user.display_avatar.url if bot.user else None
            fb = discord.Embed(description=t["ticket_menu_sem_opcoes_remover"], color=settings["embed_color"])
            fb.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
            await interaction.response.send_message(embed=fb, ephemeral=True)
            return
        embed = discord.Embed(description=t["ticket_menu_remover_prompt"], color=settings["embed_color"])
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        view = TicketMenuRemoverView(self.author, self.panel_id, opcoes, t)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)


