# Editar Embed ---------------------------------------------------------------

def _panel_embed_field(panel: dict, key: str, default: str | None = None) -> str | None:
    return (panel.get("embed") or {}).get(key) or default


def build_ticket_embed_preview(panel: dict, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    title = _panel_embed_field(panel, "title", t["ticket_embed_preview_default_title"])
    desc = _panel_embed_field(panel, "description", t["ticket_embed_preview_default_desc"])
    color_value = _panel_embed_field(panel, "color")
    try:
        color = int(color_value) if color_value else settings["embed_color"]
    except (TypeError, ValueError):
        color = settings["embed_color"]
    embed = discord.Embed(title=title, description=f"{desc}\n\n{t['ticket_embed_preview_obs']}", color=color)
    embed.set_thumbnail(url=bot.user.display_avatar.url if bot.user else None)
    embed.set_footer(text=_footer_name(settings=settings))
    return embed


