            embed_cfg = panel.setdefault("embed", {})
            embed_cfg["title"] = self.title_inp.value.strip()
            embed_cfg["description"] = self.desc_inp.value.strip()
            embed_cfg["button_label"] = self.btn_inp.value.strip()
