    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        raw = self.inp.value.strip().lstrip("#")
        try:
            color_int = int(raw, 16)
            if color_int < 0 or color_int > 0xFFFFFF:
                raise ValueError
        except ValueError:
            icon_url = bot.user.display_avatar.url if bot.user else None
            err_embed = discord.Embed(description=f"❌ {t['ticket_embed_invalid_color']}", color=discord.Color.red())
            err_embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
            await interaction.response.send_message(embed=err_embed, ephemeral=True)
            return
        panel = _find_panel(settings, self.panel_id)
        if panel:
            panel.setdefault("embed", {})["color"] = color_int
        new_embed = build_ticket_embed_preview(panel or {}, settings)
        new_view = TicketEditEmbedView(interaction.user, self.panel_id)
        await interaction.response.edit_message(embed=new_embed, view=new_view)


