def _ticket_menu_emoji(op: dict, index: int) -> "discord.PartialEmoji | None":
    e = _parse_menu_emoji(op.get("emoji"))
    if isinstance(e, discord.PartialEmoji):
        return e
    fallback = _parse_menu_emoji(_TICKET_MENU_DEFAULT_EMOJIS[index % len(_TICKET_MENU_DEFAULT_EMOJIS)])
    return fallback if isinstance(fallback, discord.PartialEmoji) else None


def _build_ticket_panel_menu_view(panel: dict) -> discord.ui.View | None:
    """Builds the persistent select menu view for the ticket panel channel message."""
    opcoes = panel.get("menu_opcoes", [])
    if not opcoes:
        return None
    panel_id = str(panel.get("id", ""))
    options = []
    for i, op in enumerate(opcoes[:25]):
        options.append(discord.SelectOption(
            label=op.get("label", "Opção")[:100],
            description=(op.get("description") or "")[:100] or None,
            emoji=_ticket_menu_emoji(op, i),
            value=op.get("id", op.get("label", "opcao")),
        ))
    if not options:
        return None
    v = discord.ui.View(timeout=None)
    select = discord.ui.Select(
        placeholder="Selecione uma opção...",
        options=options,
        custom_id=f"ticket_panel_menu_{panel_id}",
    )
    v.add_item(select)
    return v


class TicketPainelLeiaView(discord.ui.View):
    def __init__(self, author: discord.Member, panel_id: str):
        super().__init__(timeout=300)
        self.author = author
        self.panel_id = panel_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        back_btn = discord.ui.Button(
            label=t["back"], style=discord.ButtonStyle.primary,
            emoji=_button_emoji(discord.ButtonStyle.primary),
        )
        back_btn.callback = self._back
        self.add_item(back_btn)

        painel_btn = discord.ui.Button(
            label=t["btn_embed_painel"], style=discord.ButtonStyle.secondary,
        )
        painel_btn.callback = self._embed_painel
        self.add_item(painel_btn)

        interna_btn = discord.ui.Button(
            label=t["btn_embed_interna"], style=discord.ButtonStyle.secondary,
        )
        interna_btn.callback = self._embed_interna
        self.add_item(interna_btn)

        enviar_btn = discord.ui.Button(
            label=t["btn_enviar_painel"], style=discord.ButtonStyle.success,
            emoji="<a:online:1518271945550856295>",
        )
        enviar_btn.callback = self._enviar_painel
        self.add_item(enviar_btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_per_manager_embed(self.author, settings, self.panel_id)
        view = TicketPerManagerView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=view)

    def _get_target_channel(self, settings: dict) -> discord.TextChannel | None:
        panel = _find_panel(settings, self.panel_id)
        if not panel:
            return None
        if not self.author.guild:
            return None
        ch = self.author.guild.get_channel(panel.get("channel_id") or 0)
        return ch if isinstance(ch, discord.TextChannel) else None

    async def _embed_painel(self, interaction: discord.Interaction):
        panel = _find_panel(get_settings(interaction.guild.id), self.panel_id) or {}
        view = TicketPanelV2View(self.author, panel, self.panel_id)
        await interaction.response.send_message(view=view, ephemeral=True)

    async def _embed_interna(self, interaction: discord.Interaction):
        panel = _find_panel(get_settings(interaction.guild.id), self.panel_id) or {}
        view = TicketInternaV2View(self.author, panel, self.panel_id)
        await interaction.response.send_message(view=view, ephemeral=True)

    async def _enviar_painel(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id) or {}
        target = self._get_target_channel(settings)
        if target is None:
            await interaction.response.send_message(embed=_notif_embed(t["ticket_painel_missing"]), ephemeral=True)
            return

        v2_data  = panel.get("embed_painel_v2")
        ep       = panel.get("embed_painel")
        ei       = panel.get("embed_interna")
        ei_v2    = panel.get("embed_interna_v2")

        # Verifica se há conteúdo para enviar
        has_v2      = bool(v2_data and v2_data.get("blocks"))
        has_classic = bool(ep and (ep.get("title") or ep.get("description")))
        if not (has_v2 or has_classic):
            await interaction.response.send_message(embed=_notif_embed(t["ticket_painel_missing"]), ephemeral=True)
            return
        has_interna_v2 = bool(ei_v2 and (ei_v2.get("blocks") or ei_v2.get("title") or ei_v2.get("description")))
        has_interna    = bool(ei    and (ei.get("title")      or ei.get("description")))
        # Aceita se alguma opcao do menu já tem embed_interna própria
        has_opcao_interna = any(
            (op.get("embed_interna_v2") and op["embed_interna_v2"].get("blocks"))
            or (op.get("embed_interna") and (op["embed_interna"].get("title") or op["embed_interna"].get("description")))
            for op in panel.get("menu_opcoes", [])
        )
        if not (has_interna_v2 or has_interna or has_opcao_interna):
            await interaction.response.send_message(embed=_notif_embed(t["ticket_painel_missing"]), ephemeral=True)
            return

        try:
            menu_view = None
            if panel.get("menus_selecao") and panel.get("menu_opcoes"):
                menu_view = _build_ticket_panel_menu_view(panel)
            if has_v2:
                # Envia como LayoutView V2 com separadores nativos
                layout = build_panel_v2_layout(v2_data, settings, ticket_panel=panel)
                await target.send(view=layout)
            else:
                embed = _draft_to_embed(ep, settings["embed_color"])
                buttons_view = _draft_view_from_buttons(ep)
                # Merge: if we have both menu and buttons view, prefer menu_view
                await target.send(embed=embed, view=menu_view or buttons_view)
        except Exception as e:
            await interaction.response.send_message(f"Erro: {str(e)[:200]}", ephemeral=True)
            return

        icon_url = bot.user.display_avatar.url if bot.user else None
        sent_embed = discord.Embed(description=f"✅ {t['ticket_painel_sent']}", color=settings["embed_color"])
        sent_embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        await interaction.response.send_message(embed=sent_embed, ephemeral=True)


