# Per-ticket Manager View ----------------------------------------------------

class TicketPerManagerView(discord.ui.View):
    def __init__(self, author: discord.Member, panel_id: str):
        super().__init__(timeout=None)
        self.author = author
        self.panel_id = panel_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        self.clear_items()

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (t["btn_setar_categoria"], discord.ButtonStyle.secondary, self._setar_categoria),
            (t["btn_cargos_responsaveis"], discord.ButtonStyle.secondary, self._cargos_resp),
            (t["btn_usar_topico_canal"], discord.ButtonStyle.secondary, self._toggle_topico),
            (t["btn_usar_botao"], discord.ButtonStyle.secondary, self._toggle_botao),
        ]
        row1 = [
            (t["btn_menus_selecao"], discord.ButtonStyle.secondary, self._toggle_menus),
            (t["btn_horarios"], discord.ButtonStyle.secondary, self._horarios),
            (t["btn_definir_logs_ticket"], discord.ButtonStyle.secondary, self._define_logs),
            (t["btn_editar_embed"], discord.ButtonStyle.secondary, self._editar_embed),
            (t["btn_deletar_ticket"], discord.ButtonStyle.danger, self._deletar),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_manager_embed(self.author, settings)
        view = TicketManagerView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _setar_categoria(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id) or {}
        # Bloqueia se usar_topico estiver ativo
        if panel.get("usar_topico"):
            await interaction.response.send_message(embed=_notif_embed(t["ticket_topico_cant_cat"]), ephemeral=True)
            return
        view = TicketCategoriaView(self.panel_id, t)
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed = discord.Embed(description=t["ticket_setar_categoria_prompt"], color=settings["embed_color"])
        embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        embed.set_thumbnail(url=icon_url)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _cargos_resp(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = TicketCargosRespView(self.panel_id, t)
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed = discord.Embed(description=t["ticket_cargos_resp_prompt"], color=settings["embed_color"])
        embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        embed.set_thumbnail(url=icon_url)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _toggle_topico(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id)
        if not panel:
            await interaction.response.defer()
            return
        panel["usar_topico"] = not panel.get("usar_topico", False)
        save_settings_to_disk()
        new_embed = build_ticket_per_manager_embed(self.author, settings, self.panel_id)
        new_view = TicketPerManagerView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=new_embed, view=new_view)
        icon_url = bot.user.display_avatar.url if bot.user else None
        fb_embed = discord.Embed(
            description=t["ticket_topico_changed"].format(value=_yes_no_label(t, panel["usar_topico"])),
            color=settings["embed_color"],
        )
        fb_embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        await interaction.followup.send(embed=fb_embed, ephemeral=True)

    async def _toggle_botao(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panel = _find_panel(settings, self.panel_id)
        if not panel:
            await interaction.response.defer()
            return
        # Sempre ativa o botão e abre o editor de embed/botão
        panel["usar_botao"] = True
        save_settings_to_disk()
        preview_embed = build_ticket_embed_preview(panel, settings)
        editor_view = TicketEditEmbedView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=preview_embed, view=editor_view)

    async def _toggle_menus(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel = _find_panel(settings, self.panel_id)
        if not panel:
            await interaction.response.defer()
            return
        # Garante que menus_selecao está ativo e abre o gerenciador
        panel["menus_selecao"] = True
        save_settings_to_disk()
        embed = build_ticket_menu_selecao_embed(settings, panel)
        view  = TicketMenuSelecaoView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _horarios(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel = _find_panel(settings, self.panel_id) or {}
        embed = build_ticket_horarios_config_embed(self.author, settings, panel)
        view  = TicketHorariosConfigView(self.author, self.panel_id)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _define_logs(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = TicketPerLogChannelView(self.panel_id, t["ticket_select_log_placeholder"])
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed = discord.Embed(description=t["ticket_select_log_prompt"], color=settings["embed_color"])
        embed.set_author(name=t["ticket_config_panel_title"], icon_url=icon_url)
        embed.set_thumbnail(url=icon_url)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _editar_embed(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ticket_painel_leia_embed(self.author, settings)
        view = TicketPainelLeiaView(self.author, self.panel_id)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _deletar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        panels = settings.get("ticket_panels", [])
        settings["ticket_panels"] = [p for p in panels if str(p.get("id")) != str(self.panel_id)]
        # Also clean up IA and Aval configs for this panel
        settings.get("ticket_ia_configs", {}).pop(self.panel_id, None)
        settings.get("ticket_aval_configs", {}).pop(self.panel_id, None)
        # Volta para a seção Tickets (mais natural após deletar)
        embed = build_tickets_embed(self.author, settings)
        view = TicketsView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        # Ephemeral com botão "Voltar ao Menu"
        ephemeral_view = TicketDeletedView(self.author)
        await interaction.followup.send(embed=_notif_embed(t["ticket_deleted"]), view=ephemeral_view, ephemeral=True)


