def build_comunidade_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["comunidade_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    embed.add_field(name=t["administrator"], value=author.mention, inline=True)
    embed.add_field(name=t["expires_in"], value=_fmt_expira(settings["language"]), inline=True)
    embed.add_field(
        name=t["contato"],
        value=(
            f"[{t['support_server']}](https://discord.gg/hypebot)"
        ),
        inline=False,
    )

    embed.set_footer(text=t["page_comunidade"], icon_url=icon_url)
    embed.timestamp = datetime.now()
    _apply_embed_banner(embed, settings)
    return embed


