def build_verificacao_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["verif_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    enabled = settings.get("verif_enabled", False)
    status_value = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else "<a:alerta:1518271939460857968> `(Desativado)`"
    )

    urls = settings.get("verif_urls", [])
    url_value = ", ".join(f"`{u}`" for u in urls[:10]) if urls else f"`{t['not_defined']}`"

    token_value = (
        f"`{t['verif_token_configured']}`"
        if settings.get("verif_token") else f"`{t['verif_token_not_set']}`"
    )

    guild = author.guild
    log_id = settings.get("verif_log_channel")
    if log_id and guild:
        ch = guild.get_channel(log_id)
        log_value = ch.mention if ch else f"`{t['ticket_unknown_channel']}`"
    else:
        log_value = f"`{t['not_defined']}`"

    add_value = _format_roles_list(guild, settings.get("verif_add_roles", [])) or f"`{t['not_defined']}`"
    rm_value = _format_roles_list(guild, settings.get("verif_remove_roles", [])) or f"`{t['not_defined']}`"
    url_roles_value = _format_roles_list(guild, settings.get("verif_url_command_roles", [])) or f"`{t['not_defined']}`"

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"┃ **Status:** {status_value}\n"
            f"**{t['verif_url_label']}:** {url_value}\n"
            f"**{t['verif_token_label']}:** {token_value}\n"
            f"**{t['verif_log_label']}:** {log_value}\n"
            f"**{t['verif_add_label']}:** {add_value}\n"
            f"**{t['verif_remove_label']}:** {rm_value}\n"
            f"**{t['verif_url_roles_label']}:** {url_roles_value}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['advertencia_observations']}",
        value=t["verif_obs_text"],
        inline=False,
    )
    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class VerifURLModal(discord.ui.Modal):
    def __init__(self, parent_view: "VerificacaoView", t: dict):
        super().__init__(title=t["verif_url_modal_title"], timeout=300)
        self.parent_view = parent_view
        settings = get_settings(parent_view.author.guild.id)
        urls = settings.get("verif_urls", [])
        self.inp = discord.ui.TextInput(
            label=t["verif_url_input_label"],
            placeholder=t["verif_url_input_placeholder"],
            required=True, max_length=1000, style=discord.TextStyle.paragraph,
            default=", ".join(urls) if urls else None,
        )
        self.add_item(self.inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        raw = self.inp.value or ""
        urls = [u.strip() for u in raw.replace("\n", ",").split(",") if u.strip()]
        settings["verif_urls"] = urls[:50]
        embed = build_verificacao_embed(self.parent_view.author, settings)
        view = VerificacaoView(self.parent_view.author, from_servidor=self.parent_view.from_servidor)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["verif_url_set"]), ephemeral=True)
        # Dispara varredura imediata ao configurar nova URL
        if settings.get("verif_enabled") and settings.get("verif_token"):
            asyncio.create_task(_varredura_verif(interaction.guild, settings))


