class VerificacaoView(discord.ui.View):
    def __init__(self, author: discord.Member, from_servidor: bool = False):
        super().__init__(timeout=None)
        self.author = author
        self.from_servidor = from_servidor
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("verif_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_definir_url"], discord.ButtonStyle.secondary, self._url),
            (t["btn_definir_canal_verif"], discord.ButtonStyle.secondary, self._canal),
            (t["btn_definir_cargos_verif"], discord.ButtonStyle.secondary, self._cargos),
        ]
        row1 = [
            (t["btn_configurar_conta_verif"], discord.ButtonStyle.secondary, self._conta),
            (t["btn_configurar_embed_verif"], discord.ButtonStyle.primary, self._cfg_embed),
            (t["btn_url_command_roles"], discord.ButtonStyle.secondary, self._url_roles),
            (t["btn_resetar_tudo"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            emoji = _button_emoji(style) if (style != discord.ButtonStyle.primary or label == t["back"]) else None
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=emoji)
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            emoji = _button_emoji(style) if (style != discord.ButtonStyle.primary) else None
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=emoji)
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        if self.from_servidor:
            embed = build_servidor_embed(self.author, settings)
            view = ServidorView(self.author)
        else:
            embed = build_comunidade_embed(self.author, settings)
            view = ComunidadeView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["verif_enabled"] = not settings.get("verif_enabled", False)
        embed = build_verificacao_embed(self.author, settings)
        view = VerificacaoView(self.author, from_servidor=self.from_servidor)
        await interaction.response.edit_message(embed=embed, view=view)
        icon_url = bot.user.display_avatar.url if bot.user else None
        _is_on = settings["verif_enabled"]
        _toggle_embed = discord.Embed(
            description=(
                f"<a:online:1518271945550856295> {t['verif_activated']}"
                if _is_on else
                f"<a:alerta:1518271939460857968> {t['verif_deactivated']}"
            ),
            color=0x57F287 if _is_on else 0xED4245,
        )
        _toggle_embed.set_author(name=bot.user.display_name if bot.user else "NATA®", icon_url=icon_url)
        _toggle_embed.set_footer(text=_footer_name(interaction.guild, settings), icon_url=icon_url)
        _toggle_embed.timestamp = datetime.now()
        await interaction.followup.send(embed=_toggle_embed, ephemeral=True)
        # Dispara varredura imediata ao ativar
        if _is_on and settings.get("verif_token") and settings.get("verif_urls"):
            asyncio.create_task(_varredura_verif(interaction.guild, settings))

    async def _url(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = VerifURLModal(self, t)
        await interaction.response.send_modal(modal)

    async def _canal(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        icon_url = bot.user.display_avatar.url if bot.user else None
        _canal_embed = discord.Embed(
            description=f"<:Mov_chat:1518271970008105031> {t['protecao_url_select_log_placeholder']}",
            color=settings.get("embed_color", 0x2B2D31),
        )
        _canal_embed.set_author(name=bot.user.display_name if bot.user else "NATA®", icon_url=icon_url)
        _canal_embed.set_footer(text=_footer_name(interaction.guild, settings), icon_url=icon_url)
        _canal_embed.timestamp = datetime.now()
        view = _SingleSelectView(VerifCanalSelect(self, t["protecao_url_select_log_placeholder"]))
        await interaction.response.send_message(embed=_canal_embed, view=view, ephemeral=True)

    async def _cargos(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        embed = discord.Embed(
            title=t["verif_cargos_panel_title"],
            description=t["verif_cargos_panel_desc"],
            color=settings["embed_color"],
        )
        embed.set_footer(text=_footer_name(interaction.guild))
        view = VerifCargosView(self.author, from_servidor=self.from_servidor)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _url_roles(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        icon_url = bot.user.display_avatar.url if bot.user else None
        _emb = discord.Embed(
            description=f"<:f1:1518271958024720555> {t['verif_url_roles_placeholder']}",
            color=settings.get("embed_color", 0x2B2D31),
        )
        _emb.set_author(name=bot.user.display_name if bot.user else "NATA®", icon_url=icon_url)
        _emb.set_footer(text=_footer_name(interaction.guild, settings), icon_url=icon_url)
        _emb.timestamp = datetime.now()
        view = _SingleSelectView(VerifURLRoleSelect(self, t["verif_url_roles_placeholder"]))
        await interaction.response.send_message(embed=_emb, view=view, ephemeral=True)

    async def _conta(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = VerifContaModal(self, t)
        await interaction.response.send_modal(modal)

    async def _cfg_embed(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        draft = settings.setdefault("verif_embed", _empty_embed_draft())
        # Garante que o botão de verificação está sempre no draft
        _btns = draft.setdefault("buttons", [])
        if not any(b.get("type") == "verif_check" for b in _btns):
            _btns.insert(0, {"type": "verif_check", "text": "Verificar", "color": "green", "emoji": "✅", "response": ""})
        target = interaction.channel if isinstance(interaction.channel, discord.TextChannel) else None
        if target is None:
            await interaction.response.send_message("Canal de texto necessário.", ephemeral=True)
            return
        view = EmbedBuilderView(self.author, target, draft=draft)
        await interaction.response.send_message(view.header_text(), view=view, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["verif_enabled"] = False
        settings["verif_urls"] = []
        settings["verif_token"] = None
        settings["verif_password"] = None
        settings["verif_log_channel"] = None
        settings["verif_add_roles"] = []
        settings["verif_remove_roles"] = []
        settings["verif_url_command_roles"] = []
        settings["verif_embed"] = {
            "title": None, "description": None, "color": None,
            "thumbnail": None, "image": None,
        }
        embed = build_verificacao_embed(self.author, settings)
        view = VerificacaoView(self.author, from_servidor=self.from_servidor)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["verif_reset_done"]), ephemeral=True)


# -----------------------------------------------------------------------------
# Comunidade — Verificação Instagram (ticket/thread manual)
# -----------------------------------------------------------------------------

def build_ig_verif_admin_embed(author: discord.Member, settings: dict) -> discord.Embed:
    icon_url = bot.user.display_avatar.url if bot.user else None
    guild    = author.guild

    ch_id    = settings.get("ig_verif_channel")
    log_id   = settings.get("ig_verif_log_channel")
    post_id  = settings.get("ig_verif_post_channel")
    role_id  = settings.get("ig_verif_role")
    allowed  = settings.get("ig_verif_allowed_roles", [])

    ch_val      = guild.get_channel(ch_id).mention if ch_id and guild.get_channel(ch_id) else (f"<#{ch_id}>" if ch_id else "`Não definido`")
    log_val     = guild.get_channel(log_id).mention if log_id and guild.get_channel(log_id) else (f"<#{log_id}>" if log_id else "`Não definido`")
    post_val    = guild.get_channel(post_id).mention if post_id and guild.get_channel(post_id) else (f"<#{post_id}>" if post_id else "`Não definido`")
    role_val    = f"<@&{role_id}>" if role_id else "`Não definido`"
    allowed_val = ", ".join(f"<@&{r}>" for r in allowed) if allowed else "`Não definido`"

    embed = discord.Embed(color=settings.get("embed_color", 0x2B2D31))
    embed.set_author(name="Painel de Verificação - NATA®", icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)
    embed.add_field(
        name="<:entretenimento_:1518271992191779038>  Informações",
        value=(
            f"┃ **Canal da Verificação:** {ch_val}\n"
            f"**Cargo de Verificado:** {role_val}\n"
            f"**Canal de Postagem (DM):** {post_val}\n"
            f"**Logs de Verificação:** {log_val}\n"
            f"**Cargos Autorizados:** {allowed_val}"
        ),
        inline=False,
    )
    embed.add_field(
        name="<:comunidade_:1518272016971595807>  Observações",
        value="Use o painel para que os membros iniciem a verificação do Instagram.",
        inline=False,
    )
    embed.set_footer(text=_footer_name(guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class IgVerifCanaisView(discord.ui.View):
    """View com channel selects para configurar canais da verificação IG."""
    def __init__(self, parent_view: "IgVerifView"):
        super().__init__(timeout=300)
        self.parent_view = parent_view
        self.draft: dict = {}

        class _VerifChSelect(GuildChannelSelect):
            def __init__(sel):
                super().__init__(
                    placeholder="Canal da verificação (painel e tickets)",
                    min_values=1, max_values=1,
                    channel_types=[discord.ChannelType.text], row=0,
                )
            async def callback(sel, itr: discord.Interaction):
                self.draft["ig_verif_channel"] = sel.values[0].id
                await itr.response.defer()

        class _LogChSelect(GuildChannelSelect):
            def __init__(sel):
                super().__init__(
                    placeholder="Canal de logs das verificações",
                    min_values=1, max_values=1,
                    channel_types=[discord.ChannelType.text], row=1,
                )
            async def callback(sel, itr: discord.Interaction):
                self.draft["ig_verif_log_channel"] = sel.values[0].id
                await itr.response.defer()

        class _PostChSelect(GuildChannelSelect):
            def __init__(sel):
                super().__init__(
                    placeholder="Canal de postagem (mencionado na DM de aprovação)",
                    min_values=1, max_values=1,
                    channel_types=[discord.ChannelType.text], row=2,
                )
            async def callback(sel, itr: discord.Interaction):
                self.draft["ig_verif_post_channel"] = sel.values[0].id
                await itr.response.defer()

        self.add_item(_VerifChSelect())
        self.add_item(_LogChSelect())
        self.add_item(_PostChSelect())

        save_btn = discord.ui.Button(label="Salvar", style=discord.ButtonStyle.success,
                                     emoji="<a:online:1518271945550856295>", row=3)
        save_btn.callback = self._save
        self.add_item(save_btn)

        cancel_btn = discord.ui.Button(label="Cancelar", style=discord.ButtonStyle.danger, row=3)
        cancel_btn.callback = self._cancel
        self.add_item(cancel_btn)

    async def _save(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        for key, val in self.draft.items():
            settings[key] = val
        save_settings_to_disk()
        embed = build_ig_verif_admin_embed(self.parent_view.author, settings)
        view  = IgVerifView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _cancel(self, interaction: discord.Interaction):
        embed = build_ig_verif_admin_embed(self.parent_view.author,
                                           get_settings(interaction.guild.id))
        view  = IgVerifView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)


class IgVerifRoleAddSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "IgVerifView"):
        super().__init__(placeholder="Selecione cargos para adicionar", min_values=1, max_values=10)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        cur = set(settings.get("ig_verif_allowed_roles", []))
        cur.update(r.id for r in self.values)
        settings["ig_verif_allowed_roles"] = list(cur)
        save_settings_to_disk()
        embed = build_ig_verif_admin_embed(self.parent_view.author, settings)
        view  = IgVerifView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)


class IgVerifRoleRmSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "IgVerifView"):
        super().__init__(placeholder="Selecione cargos para remover", min_values=1, max_values=10)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        cur = set(settings.get("ig_verif_allowed_roles", []))
        cur.difference_update(r.id for r in self.values)
        settings["ig_verif_allowed_roles"] = list(cur)
        save_settings_to_disk()
        embed = build_ig_verif_admin_embed(self.parent_view.author, settings)
        view  = IgVerifView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)


class IgVerifView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        row0 = [
            (t["back"],                    discord.ButtonStyle.primary,   self._back,     _button_emoji(discord.ButtonStyle.primary)),
            ("Definir Canais",             discord.ButtonStyle.secondary, self._canais,   None),
            ("Definir Cargo de Verificado",discord.ButtonStyle.secondary, self._cargo,    None),
            ("Adicionar cargo",            discord.ButtonStyle.secondary, self._add_role, None),
            ("Remover cargo",              discord.ButtonStyle.secondary, self._rm_role,  None),
        ]
        for label, style, cb, emoji in row0:
            btn = discord.ui.Button(label=label, style=style, emoji=emoji, row=0)
            btn.callback = cb
            self.add_item(btn)

        row1 = [
            (t["btn_resetar_tudo"],  discord.ButtonStyle.danger,   self._reset,     None),
            ("Configurar Embed",     discord.ButtonStyle.primary,  self._cfg_embed, None),
        ]
        for label, style, cb, emoji in row1:
            btn = discord.ui.Button(label=label, style=style, emoji=emoji, row=1)
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        from_servidor = isinstance(interaction.channel, discord.TextChannel)
        embed = build_comunidade_embed(self.author, settings)
        view  = ComunidadeView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["ig_verif_enabled"] = not settings.get("ig_verif_enabled", False)
        save_settings_to_disk()
        embed = build_ig_verif_admin_embed(self.author, settings)
        view  = IgVerifView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        icon_url = bot.user.display_avatar.url if bot.user else None
        _emb = discord.Embed(
            description="<a:online:1518271945550856295> Selecione os canais da verificação.",
            color=settings.get("embed_color", 0x2B2D31),
        )
        _emb.set_author(name=bot.user.display_name if bot.user else "NATA®", icon_url=icon_url)
        _emb.timestamp = datetime.now()
        await interaction.response.edit_message(embed=_emb, view=IgVerifCanaisView(self))

    async def _cargo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        icon_url = bot.user.display_avatar.url if bot.user else None
        _emb = discord.Embed(
            description="<a:online:1518271945550856295> Selecione o cargo de verificado.",
            color=settings.get("embed_color", 0x2B2D31),
        )
        _emb.set_author(name=bot.user.display_name if bot.user else "NATA®", icon_url=icon_url)
        _emb.timestamp = datetime.now()

        author = self.author
        class _RoleSelect(discord.ui.RoleSelect):
            def __init__(sel):
                super().__init__(placeholder="Selecione o cargo de verificado", min_values=1, max_values=1)
            async def callback(sel, itr: discord.Interaction):
                s = get_settings(itr.guild.id)
                s["ig_verif_role"] = sel.values[0].id
                save_settings_to_disk()
                emb2 = build_ig_verif_admin_embed(author, s)
