class VendasCanaisModal(discord.ui.Modal):
    def __init__(self, parent_view: "VendasView", t: dict):
        super().__init__(title=t["vendas_canais_modal_title"], timeout=300)
        self.parent_view = parent_view
        settings = get_settings(parent_view.author.guild.id)
        self.log_inp = discord.ui.TextInput(
            label=t["vendas_canal_logs_input"], required=False, max_length=30,
            default=str(settings.get("vendas_log_channel") or "") or None,
        )
        self.cat_inp = discord.ui.TextInput(
            label=t["vendas_categoria_input"], required=False, max_length=30,
            default=str(settings.get("vendas_categoria") or "") or None,
        )
        self.add_item(self.log_inp)
        self.add_item(self.cat_inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        for key, inp in [("vendas_log_channel", self.log_inp), ("vendas_categoria", self.cat_inp)]:
            raw = inp.value.strip().strip("<#>").strip("# ")
            if not raw:
                settings[key] = None
                continue
            try:
                settings[key] = int(raw)
            except ValueError:
                pass
        embed = build_vendas_embed(self.parent_view.author, settings)
        view = VendasView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["vendas_canais_set"]), ephemeral=True)


