class VendasView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (t["btn_vender_vips"], discord.ButtonStyle.secondary, self._vender_vips),
            (t["btn_vender_cargos"], discord.ButtonStyle.secondary, self._vender_cargos),
            (t["btn_pix_manual"], discord.ButtonStyle.secondary, self._pix),
            (t["btn_definir_canais_vendas"], discord.ButtonStyle.secondary, self._canais),
        ]
        row1 = [
            (t["btn_cargos_suporte"], discord.ButtonStyle.secondary, self._suporte),
            (t["btn_ver_cargos_vips"], discord.ButtonStyle.secondary, self._ver),
            (t["btn_resetar_vendas"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_main_embed(self.author, settings["language"])
        view = MenuView(self.author.id, lang=settings["language"])
        await interaction.response.edit_message(embed=embed, view=view)

    async def _vender_vips(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(VendasRoleSelect(self, True, t["vendas_nada_selecionado"]))
        await interaction.response.send_message(
            f"**{t['vendas_escolha_vip']}**", view=view, ephemeral=True
        )

    async def _vender_cargos(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(VendasRoleSelect(self, False, t["vendas_nada_selecionado"]))
        await interaction.response.send_message(
            f"**{t['vendas_escolha_cargo']}**", view=view, ephemeral=True
        )

    async def _pix(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = VendasPixModal(self, t)
        await interaction.response.send_modal(modal)

    async def _canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = VendasCanaisModal(self, t)
        await interaction.response.send_modal(modal)

    async def _suporte(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(VendasSuporteSelect(self, t["bp_cargos_resp_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["bp_cargos_resp_placeholder"]), view=view, ephemeral=True)

    async def _ver(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        vips = settings.get("vendas_vips", [])
        cargos = settings.get("vendas_cargos", [])
        all_items = [("VIP", e) for e in vips] + [("Cargo", e) for e in cargos]
        if not all_items:
            await interaction.response.send_message(embed=_notif_embed(t["vendas_no_items"]), ephemeral=True)
            return
        lines = []
        for tipo, e in all_items[:50]:
            r = interaction.guild.get_role(e["role_id"]) if interaction.guild else None
            mention = r.mention if r else f"<@&{e['role_id']}>"
            emj = e.get("emoji") or ""
            lines.append(f"{emj} `{tipo}` {mention} — `R$ {e['price']:.2f}`")
        embed = discord.Embed(
            title=t["vendas_ver_title"],
            description="\n".join(lines)[:4000],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["vendas_vips"] = []
        settings["vendas_cargos"] = []
        settings["vendas_cargos_suporte"] = []
        settings["vendas_pix"] = None
