def build_mencao_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["mencao_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    enabled = settings.get("mencao_enabled", False)
    status_value = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else "<a:alerta:1518271939460857968> `(Desativado)`"
    )
    guild = author.guild
    chans = settings.get("mencao_channels", [])
    if chans and guild:
        mentions = []
        for cid in chans[:5]:
            ch = guild.get_channel(cid)
            mentions.append(ch.mention if ch else f"<#{cid}>")
        canais_value = " ".join(mentions)
        if len(chans) > 5:
            canais_value += f" `+{len(chans) - 5}`"
    else:
        canais_value = "`Nenhum`"

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"┃ **Status:** {status_value}\n"
            f"<:Mov_chat:1518271970008105031> **{t['mencao_canais_label']}:** {canais_value}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['advertencia_observations']}",
        value=t["mencao_obs_text"],
        inline=False,
    )
    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class MencaoAddSelect(GuildChannelSelect):
    def __init__(self, parent_view: "MencaoView", placeholder: str):
        super().__init__(
            placeholder=placeholder, min_values=1, max_values=1,
            channel_types=[discord.ChannelType.text],
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        ch = self.values[0]
        chans = settings.setdefault("mencao_channels", [])
        if ch.id in chans:
            await interaction.response.send_message(embed=_notif_embed(t["mencao_canal_already_in"]), ephemeral=True)
            return
        chans.append(ch.id)
        embed = build_mencao_embed(self.parent_view.author, settings)
        view = MencaoView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(
            t["mencao_canal_added"].format(channel=ch.mention), ephemeral=True
        )


class MencaoRemoveSelect(discord.ui.Select):
    def __init__(self, parent_view: "MencaoView", t: dict, guild: discord.Guild):
        chans = get_settings(parent_view.author.guild.id).get("mencao_channels", [])
        options = []
        for cid in chans[:25]:
            ch = guild.get_channel(cid) if guild else None
            options.append(discord.SelectOption(
                label=(ch.name if ch else f"#{cid}")[:100], value=str(cid),
            ))
        if not options:
            options = [discord.SelectOption(label=t["mencao_no_canais"], value="__none__")]
        super().__init__(placeholder=t["mencao_rm_placeholder"],
                         min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if self.values[0] == "__none__":
            await interaction.response.defer()
            return
        cid = int(self.values[0])
        chans = settings.get("mencao_channels", [])
        if cid in chans:
            chans.remove(cid)
        embed = build_mencao_embed(self.parent_view.author, settings)
        view = MencaoView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["mencao_canal_removed"]), ephemeral=True)


class MencaoView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("mencao_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_adicionar_canal"], discord.ButtonStyle.secondary, self._add),
            (t["btn_remover_canal_mencao"], discord.ButtonStyle.secondary, self._remove),
            (t["btn_reset_config"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row:
            btn = discord.ui.Button(label=label, style=style, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["mencao_enabled"] = not settings.get("mencao_enabled", False)
        embed = build_mencao_embed(self.author, settings)
        view = MencaoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["mencao_activated"] if settings["mencao_enabled"] else t["mencao_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _add(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(MencaoAddSelect(self, t["mencao_add_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["mencao_add_placeholder"]), view=view, ephemeral=True)

    async def _remove(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(MencaoRemoveSelect(self, t, interaction.guild))
        await interaction.response.send_message(embed=_notif_embed(t["mencao_rm_placeholder"]), view=view, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["mencao_enabled"] = False
        settings["mencao_channels"] = []
        embed = build_mencao_embed(self.author, settings)
        view = MencaoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["mencao_reset_done"]), ephemeral=True)


