class GifsMenuSelect(discord.ui.Select):
    def __init__(self, placeholder: str, lang: str = "pt-br"):
        t = TRANSLATIONS[lang]
        options = [
            discord.SelectOption(
                label=t[label_key],
                description=t[desc_key],
                emoji=_make_select_emoji(emoji),
                value=value,
            )
            for value, label_key, emoji, desc_key in GIFS_MENU_OPTIONS
        ]
        # custom_id fixo → view pode ser re-registrada após restart (persistent)
        super().__init__(
            custom_id="hype_gifs_menu_v1",
            placeholder=placeholder,
            min_values=1,
            max_values=1,
            options=options,
        )

    async def callback(self, interaction: discord.Interaction):
        try:
            guild_id = interaction.guild.id if interaction.guild else 0
            settings = get_settings(guild_id)
            selected = self.values[0]

            if selected == "home_gifs":
                embed = build_main_embed(interaction.user, settings["language"])
                view = MenuView(interaction.user.id, lang=settings["language"])
                await interaction.response.edit_message(embed=embed, view=view)
                return

            if selected == "gifs_conversor":
                embed = build_gifs_conversor_embed(interaction.user, settings)
                view = GifsConversorView(interaction.user)
                await interaction.response.edit_message(embed=embed, view=view)
                return

            if selected == "gifs_decoracoes":
                embed = build_gifs_decoracoes_embed(interaction.user, settings)
                view = GifsDecoracoesView(interaction.user)
                await interaction.response.edit_message(embed=embed, view=view)
                return

            if selected == "gifs_postadores":
                embed = build_gifs_postadores_embed(interaction.user, settings)
                view = GifsPostadoresView(interaction.user)
                await interaction.response.edit_message(embed=embed, view=view)
                return

            if selected == "gifs_autopostador":
                embed = build_gifs_autopostador_embed(interaction.user, settings)
                view = GifsAutoPostadorView(interaction.user)
                await interaction.response.edit_message(embed=embed, view=view)
                return

            labels = {opt.value: opt.label for opt in self.options}
            await interaction.response.send_message(
                f"{TRANSLATIONS[settings['language']]['coming_soon']} (**{labels[selected]}**)",
                ephemeral=True,
            )
        except Exception as _exc:
            import traceback
            err_txt = traceback.format_exc()
            print(f"[GifsMenuSelect.callback ERROR]\n{err_txt}", flush=True)
            try:
                msg = f"❌ Erro interno: `{type(_exc).__name__}: {_exc}`"
                if not interaction.response.is_done():
                    await interaction.response.send_message(embed=_notif_embed(msg), ephemeral=True)
                else:
                    await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)
            except Exception:
                pass


