def build_gifs_conversor_embed(author: discord.Member, settings: dict) -> discord.Embed:
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed = discord.Embed(color=settings["embed_color"])
    embed.set_author(name="Central de Gifs - NATA®", icon_url=icon_url)
    _thumb = settings.get("gifs_conversor_banner") or icon_url
    if _thumb:
        embed.set_thumbnail(url=_thumb)

    # Canal da embed
    ch_id = settings.get("gifs_conversor_channel")
    if ch_id and author.guild:
        ch = author.guild.get_channel(ch_id)
        ch_val = ch.mention if ch else f"<#{ch_id}>"
    else:
        ch_val = "`Não definido.`"

    # Cargos sem limite
    no_limit_roles = settings.get("gifs_conversor_no_limit_roles", [])
    if no_limit_roles and author.guild:
        roles_fmt = ", ".join(
            (author.guild.get_role(r).mention if author.guild.get_role(r) else f"<@&{r}>")
            for r in no_limit_roles
        )
    else:
        roles_fmt = "`Nenhum`"

    # Banner
    banner_val = "`Nenhum`" if not settings.get("gifs_conversor_banner") else "`Configurado ✅`"

    embed.add_field(
        name="<a:alerta:1518271939460857968>  Informações",
        value=(
            f"Canal da Embed {ch_val}\n"
            f"Cargo sem Limite: {roles_fmt}\n"
            f"Banner Personalizado: {banner_val}"
        ),
        inline=False,
    )
    embed.add_field(
        name="<:bot_v3:1506343470242074785>  Observações",
        value=(
            "O canal da embed é onde será enviado a mensagem do conversor.\n"
            "Cargo sem limite é o cargo que poderá usar o conversor sem limites. "
            "**Sete o cargo de booster**\n"
            "O banner personalizado é o banner que será enviado na embed do conversor."
        ),
        inline=False,
    )
    embed.set_footer(text=f"NATA® © • {author.name}", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


# ── Preto e Branco — cooldown por usuário ────────────────────────────────────
_gifs_pb_cd:  dict[int, float] = {}   # uid → timestamp do último uso
_GIFS_PB_CD   = 300                    # 5 minutos


async def _gifs_pb_criar_canal(interaction: discord.Interaction) -> None:
    """Cria canal privado e envia embed do editor Preto e Branco."""
    import time as _t

    uid  = interaction.user.id
    now  = _t.time()
    last = _gifs_pb_cd.get(uid, 0)
    remaining = (last + _GIFS_PB_CD) - now

    settings = get_settings(interaction.guild.id)
    cor      = settings.get("embed_color", 0x5865F2)
    bot_name = bot.user.display_name if bot.user else "HypeBot"
    icon_url = bot.user.display_avatar.url if bot.user else None

    if remaining > 0:
        emb = discord.Embed(
            description=f"Você precisa aguardar **{remaining:.1f}s** antes de usar o editor novamente!",
            color=cor,
        )
        emb.set_footer(text=bot_name, icon_url=icon_url)
        await interaction.response.send_message(embed=emb, ephemeral=True)
        return

    guild  = interaction.guild
    member = interaction.user
    g      = guild

    # Categoria do canal configurado (para criar o canal na mesma categoria)
    ch_id    = settings.get("gifs_conversor_channel")
    category = None
    if ch_id:
        ch_ref = guild.get_channel(ch_id)
        if ch_ref and ch_ref.category:
            category = ch_ref.category

    overwrites = {
        guild.default_role: discord.PermissionOverwrite(read_messages=False),
        member:             discord.PermissionOverwrite(read_messages=True, send_messages=True, attach_files=True),
        guild.me:           discord.PermissionOverwrite(read_messages=True, send_messages=True, manage_channels=True),
    }

    try:
        canal = await guild.create_text_channel(
            name=f"editor-{member.name}",
            overwrites=overwrites,
            category=category,
            reason="Preto e Branco — Editor",
        )
    except discord.Forbidden:
        await interaction.response.send_message("❌ Sem permissão para criar canal.", ephemeral=True)
        return
    except discord.HTTPException as e:
        await interaction.response.send_message(f"❌ Erro ao criar canal: `{e}`", ephemeral=True)
        return

    _gifs_pb_cd[uid] = now  # registra cooldown

    # Thumbnail: banner do conversor (se configurado), senão avatar do bot
    banner   = settings.get("gifs_conversor_banner")
    thumb    = banner or icon_url

    # Embed do Editor dentro do canal privado
    ei_pb = _guild_emoji(g, "dama", "aparncia", fallback="<:aparncia_:1518271975317962895>")
    emb_editor = discord.Embed(
        description="Siga todos os passos a baixo para obter sucesso em sua edição!",
        color=cor,
    )
    emb_editor.set_author(name=f"{bot_name} - Editor", icon_url=icon_url)
    if thumb:
        emb_editor.set_thumbnail(url=thumb)
    emb_editor.add_field(
        name=f"{ei_pb}  Como funciona o Editor?",
        value=(
            "`1.` Clique no botão abaixo para **iniciar** a Editor.\n"
            "`2.` Tamanho máximo da imagem: **10MB**.\n"
            "`3.` Editor irá passar sua imagem para **preto/branco**.\n"
            "`4.` Formatos de imagens aceitos: `.png`, `.jpg`, `.jpeg`."
        ),
        inline=False,
    )
    emb_editor.set_footer(text="Este canal será excluído em 5 minutos!")

    view_editor = _GifsEditorView(member, canal)
    await canal.send(embed=emb_editor, view=view_editor)

    # Ephemeral com link para o canal
    link_view = discord.ui.View(timeout=None)
    link_view.add_item(discord.ui.Button(
        label="Ir para o canal",
        style=discord.ButtonStyle.link,
        url=canal.jump_url,
        emoji="↗️",
    ))
    cor_emb = discord.Embed(
        description=f"{member.mention}, seu canal foi criado com sucesso!",
        color=cor,
    )
    await interaction.response.send_message(embed=cor_emb, view=link_view, ephemeral=True)

    # Agendar exclusão após 5 minutos
    async def _deletar():
        await asyncio.sleep(300)
        try:
            await canal.delete(reason="Editor — 5 min expirado")
        except Exception:
            pass

    bot.loop.create_task(_deletar())


class _GifsEditorView(discord.ui.View):
    """Botões Iniciar / Cancelar enviados no canal privado do editor."""

    def __init__(self, member: discord.Member, canal: discord.TextChannel):
        super().__init__(timeout=290)
        self.member = member
        self.canal  = canal

        btn_start = discord.ui.Button(label="Iniciar", style=discord.ButtonStyle.primary, emoji="▶️")
        btn_start.callback = self._iniciar
        btn_cancel = discord.ui.Button(label="Cancelar", style=discord.ButtonStyle.danger, emoji="✖️")
        btn_cancel.callback = self._cancelar

        self.add_item(btn_start)
        self.add_item(btn_cancel)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.member.id:
            await interaction.response.send_message("Este canal é exclusivo para você.", ephemeral=True)
            return False
        return True

    async def _iniciar(self, interaction: discord.Interaction):
        import io

        settings = get_settings(interaction.guild.id)
        cor      = settings.get("embed_color", 0x5865F2)
        icon     = bot.user.display_avatar.url if bot.user else None
        bot_name = bot.user.display_name if bot.user else "HypeBot"

        self.stop()
        emb_send = discord.Embed(
            description="<:aparncia_:1518271975317962895> Envie a **imagem** para a edição.",
            color=cor,
        )
        emb_send.set_footer(text=bot_name, icon_url=icon)
        await interaction.response.send_message(embed=emb_send)

        def check(m: discord.Message) -> bool:
            return (
                m.author.id == self.member.id
                and m.channel.id == self.canal.id
                and bool(m.attachments)
            )

        try:
            msg = await bot.wait_for("message", check=check, timeout=120)
        except asyncio.TimeoutError:
            emb_to = discord.Embed(
                description="⏰ Tempo esgotado. O canal será excluído em breve.",
                color=cor,
            )
            await self.canal.send(embed=emb_to)
            return

        att = msg.attachments[0]
        if att.size > 10 * 1024 * 1024:
            await self.canal.send("❌ Imagem muito grande. Máximo de **10MB**.")
            return

        fname_lower = (att.filename or "").lower()
        if not any(fname_lower.endswith(ext) for ext in (".png", ".jpg", ".jpeg")):
            await self.canal.send("❌ Formato inválido. Use `.png`, `.jpg` ou `.jpeg`.")
            return

        await self.canal.send("<a:alerta:1518271939460857968> Processando sua imagem...")

        try:
            import PIL.Image as PILImage
            import aiohttp as _aiohttp

            async with _aiohttp.ClientSession() as session:
                async with session.get(att.url) as resp:
                    img_bytes = await resp.read()

            image     = PILImage.open(io.BytesIO(img_bytes)).convert("L")
            image_rgb = image.convert("RGB")

            output = io.BytesIO()
            fmt    = "PNG" if fname_lower.endswith(".png") else "JPEG"
            image_rgb.save(output, format=fmt, quality=95)
            output.seek(0)

            fname_out = "o melhor bot do discord hypebot." + ("png" if fmt == "PNG" else "jpg")
            dfile = discord.File(output, filename=fname_out)

            emb_done = discord.Embed(
                title="<a:online:1518271945550856295>  Edição concluída!",
                description="<:aparncia_:1518271975317962895> Você possui **5 minutos** para salvar sua imagem.",
                color=cor,
            )
            emb_done.set_author(name=f"{bot_name} - Editor", icon_url=icon)
            emb_done.set_footer(text="🛠️ Este canal será excluído em 5 minutos!")

            await self.canal.send(embed=emb_done, file=dfile, view=_FecharCanalView())

            async def _deletar_editor():
                await asyncio.sleep(300)
                try:
                    await self.canal.delete(reason="Editor — 5 min após entrega")
                except Exception:
                    pass
            asyncio.create_task(_deletar_editor())

        except ImportError:
            await self.canal.send("❌ Biblioteca `Pillow` não disponível. Contate o suporte.")
        except Exception as e:
            await self.canal.send(f"❌ Erro ao processar imagem: `{e}`")

    async def _cancelar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id) if interaction.guild else {}
        cor = settings.get("embed_color", 0x5865F2)
        emb = discord.Embed(
            description="Operação cancelada. O canal será excluído em breve.",
            color=cor,
        )
        await interaction.response.send_message(embed=emb)
        self.stop()
        await asyncio.sleep(5)
        try:
            await self.canal.delete(reason="Editor — cancelado pelo usuário")
        except Exception:
            pass


