async def _gifs_criar_canal(interaction: discord.Interaction, service: str) -> None:
    """Cria canal privado e envia embed do serviço (conversor/extrator/compressor)."""
    import time as _t

    uid       = interaction.user.id
    now       = _t.time()
    remaining = (_gifs_conv_cd.get(uid, 0) + _GIFS_CONV_CD) - now

    settings = get_settings(interaction.guild.id)
    cor      = settings.get("embed_color", 0x5865F2)
    bot_name = bot.user.display_name if bot.user else "HypeBot"
    icon_url = bot.user.display_avatar.url if bot.user else None

    if remaining > 0:
        emb = discord.Embed(
            description=f"Você precisa aguardar **{remaining:.1f}s** antes de usar o serviço novamente!",
            color=cor,
        )
        emb.set_footer(text=bot_name, icon_url=icon_url)
        await interaction.response.send_message(embed=emb, ephemeral=True)
        return

    meta   = _GIFS_SVC_META[service]
    guild  = interaction.guild
    member = interaction.user
    g      = guild

    # Categoria do canal configurado (colocar o canal privado na mesma categoria)
    ch_id    = settings.get("gifs_conversor_channel")
    category = None
    if ch_id:
        ch_ref = guild.get_channel(ch_id)
        if ch_ref and ch_ref.category:
            category = ch_ref.category

    overwrites = {
        guild.default_role: discord.PermissionOverwrite(read_messages=False),
        member:             discord.PermissionOverwrite(read_messages=True, send_messages=True, attach_files=True),
        guild.me:           discord.PermissionOverwrite(read_messages=True, send_messages=True, manage_channels=True),
    }

    try:
        canal = await guild.create_text_channel(
            name=f"{meta['channel_pfx']}-{member.name}",
            overwrites=overwrites,
            category=category,
            reason=meta["reason"],
        )
    except discord.Forbidden:
        await interaction.response.send_message("❌ Sem permissão para criar canal.", ephemeral=True)
        return
    except discord.HTTPException as e:
        await interaction.response.send_message(f"❌ Erro ao criar canal: `{e}`", ephemeral=True)
        return

    _gifs_conv_cd[uid] = now  # registra cooldown

    # Thumbnail: banner configurado ou avatar do bot
    banner = settings.get("gifs_conversor_banner")
    thumb  = banner or icon_url

    ei = _guild_emoji(g, *meta["emoji_keys"], fallback=meta["emoji_fb"])
    emb_svc = discord.Embed(
        description="Siga todos os passos a baixo para obter sucesso em sua conversão!",
        color=cor,
    )
    emb_svc.set_author(name=f"{bot_name} - {meta['name']}", icon_url=icon_url)
    if thumb:
        emb_svc.set_thumbnail(url=thumb)
    emb_svc.add_field(
        name=f"{ei}  {meta['field_title']}",
        value=meta["steps"],
        inline=False,
    )
    emb_svc.set_footer(text="Este canal será excluído em 5 minutos!")

    view_svc = _GifsConversorCanalView(member, canal, service)
    await canal.send(embed=emb_svc, view=view_svc)

    # Ephemeral com link para o canal privado
    link_view = discord.ui.View(timeout=None)
    link_view.add_item(discord.ui.Button(
        label="Ir para o canal",
        style=discord.ButtonStyle.link,
        url=canal.jump_url,
        emoji="↗️",
    ))
    cor_emb = discord.Embed(
        description=f"{member.mention}, seu canal foi criado com sucesso!",
        color=cor,
    )
    await interaction.response.send_message(embed=cor_emb, view=link_view, ephemeral=True)

    # Exclusão automática por inatividade (10 min) — garante que canais orfãos sejam limpos
    async def _deletar_idle():
        await asyncio.sleep(600)
        try:
            await canal.delete(reason=f"{meta['name']} — canal inativo")
        except Exception:
            pass

    bot.loop.create_task(_deletar_idle())


