class _GifsConversorRoleSelect(discord.ui.RoleSelect):
    def __init__(self):
        super().__init__(
            placeholder="Selecione cargos...",
            min_values=1,
            max_values=5,
        )

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        selected_ids = [r.id for r in self.values]
        existing = settings.get("gifs_conversor_no_limit_roles", [])
        added, removed = [], []
        for rid in selected_ids:
            if rid in existing:
                existing.remove(rid)
                removed.append(rid)
            else:
                existing.append(rid)
                added.append(rid)
        settings["gifs_conversor_no_limit_roles"] = existing
        save_settings_to_disk()
        embed = build_gifs_conversor_embed(interaction.user, settings)
        view = GifsConversorView(interaction.user)
        await interaction.response.edit_message(embed=embed, view=view)
        partes = []
        if added:
            partes.append(f"{_e_success()} Adicionados: {', '.join(f'<@&{r}>' for r in added)}")
        if removed:
            partes.append(f"❌ Removidos: {', '.join(f'<@&{r}>' for r in removed)}")
        await interaction.followup.send("\n".join(partes) or "Nenhuma alteração.", ephemeral=True)


