class GifsConversorView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    def _build(self):
        self.clear_items()
        row0 = [
            ("Voltar",              discord.ButtonStyle.primary,   self._back),
            ("Canal Embed",         discord.ButtonStyle.secondary, self._canal_embed),
            ("Cargo sem Limite",    discord.ButtonStyle.secondary, self._cargo_limite),
            ("Banner Personalizado",discord.ButtonStyle.secondary, self._banner),
            ("Enviar Embed Padrão", discord.ButtonStyle.blurple,   self._enviar_embed),
        ]
        row1 = [
            ("Editar Embed",  discord.ButtonStyle.secondary, self._editar_embed),
            ("Resetar Tudo",  discord.ButtonStyle.danger,    self._resetar),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0)
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1)
            btn.callback = cb
            self.add_item(btn)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            await interaction.response.send_message("Apenas quem abriu este painel pode usá-lo.", ephemeral=True)
            return False
        return True

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_gifs_embed(self.author, settings)
        view = GifsView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _canal_embed(self, interaction: discord.Interaction):
        view = _GifsConversorChannelView(self.author)
        await interaction.response.send_message(
            "Selecione canais que deseja adicionar ou remover.", view=view, ephemeral=True
        )

    async def _cargo_limite(self, interaction: discord.Interaction):
        view = _GifsConversorRoleView(self.author)
        await interaction.response.send_message(
            "Selecione cargos que deseja adicionar ou remover.", view=view, ephemeral=True
        )

    async def _banner(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        await interaction.response.send_message(
            f"{self.author.mention}, envie o **banner** que será usado na embed do conversor "
            "ou digite `resetar` para resetar o banner.\nPara cancelar, digite `cancelar`.",
            ephemeral=True,
        )

        def check(m: discord.Message) -> bool:
            return m.author.id == self.author.id and m.channel.id == interaction.channel.id

        try:
            msg = await bot.wait_for("message", check=check, timeout=60)
        except asyncio.TimeoutError:
            await interaction.followup.send("⏰ Tempo esgotado.", ephemeral=True)
            return

        content = msg.content.strip()
        try:
            await msg.delete()
        except Exception:
            pass

        if content.lower() == "cancelar":
            await interaction.followup.send("Operação cancelada.", ephemeral=True)
            return

        if content.lower() == "resetar":
            settings["gifs_conversor_banner"] = None
            save_settings_to_disk()
            embed = build_gifs_conversor_embed(self.author, settings)
            await interaction.edit_original_response(content=None, embed=embed, view=GifsConversorView(self.author))
            await interaction.followup.send("🔄 Banner resetado.", ephemeral=True)
            return

        # Tenta pegar imagem do anexo ou URL
        url = None
        if msg.attachments:
            url = msg.attachments[0].url
        elif content.startswith("http"):
            url = content

        if not url:
            await interaction.followup.send("❌ Envie uma imagem válida ou URL.", ephemeral=True)
            return

        settings["gifs_conversor_banner"] = url
        save_settings_to_disk()
        embed = build_gifs_conversor_embed(self.author, settings)
        await interaction.edit_original_response(content=None, embed=embed, view=GifsConversorView(self.author))
        await interaction.followup.send(f"{_e_success()} Banner personalizado definido!", ephemeral=True)

    async def _enviar_embed(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        ch_id = settings.get("gifs_conversor_channel")
        if not ch_id:
            await interaction.response.send_message(
                "Você ainda não configurou o `canal da embed`.", ephemeral=True
            )
            return

        channel = interaction.guild.get_channel(ch_id)
        if channel is None:
            await interaction.response.send_message("❌ Canal não encontrado.", ephemeral=True)
            return

        # ── Embed da mensagem enviada no canal ───────────────────────────────
        custom    = settings.get("gifs_conversor_embed", {})
        bot_name  = bot.user.display_name if bot.user else "HypeBot"
        icon_url  = bot.user.display_avatar.url if bot.user else None
        cor       = settings.get("embed_color", 0x5865F2)
        banner    = settings.get("gifs_conversor_banner")
        g         = interaction.guild

        ei_conv = _guild_emoji(g, "gif", "gifs",               fallback="<:gifs:1518272035762081835>")
        ei_ext  = _guild_emoji(g, "mov_call", "call", "audio", fallback="<a:mov_call:1518271964077232150>")
        ei_comp = _guild_emoji(g, "ferramenta", "tools",       fallback="<:ferramentas_:1518271998613131274>")
        ei_pb   = _guild_emoji(g, "dama", "aparncia",          fallback="<:aparncia_:1518271975317962895>")
        ei_obs  = _guild_emoji(g, "alerta", "alert", "bot",    fallback="<a:alerta:1518271939460857968>")

        emb = discord.Embed(
            title=custom.get("title") or "Central de Gifs",
            description=custom.get("description") or "Selecione uma opção abaixo para começar.",
            color=cor,
        )
        emb.set_author(name=f"Central de Gifs — {bot_name}", icon_url=icon_url)
        emb.set_thumbnail(url=icon_url)
        if banner:
            emb.set_image(url=banner)

        emb.add_field(
            name=f"{ei_conv}  Conversor de Vídeo → GIF",
            value=(
                "• Separe o **vídeo** que será transformado em **GIF**.\n"
                "• Um canal privado será criado para a conversão.\n"
                "• Envie seu **vídeo** no canal criado e receba o **GIF**."
            ),
            inline=False,
        )
        emb.add_field(
            name=f"{ei_ext}  Extrator de Áudio",
            value=(
                "• Separe o **vídeo** que será transformado em **áudio**.\n"
                "• Um canal privado será criado para a extração.\n"
                "• Envie seu **vídeo** no canal criado e receba o **áudio do vídeo**."
            ),
            inline=False,
        )
        emb.add_field(
            name=f"{ei_comp}  Compressor de GIF",
            value=(
                "• Separe o **GIF** que será comprimido para usar no seu perfil.\n"
                "• Um canal privado será criado para comprimir.\n"
                "• Envie o **GIF** no canal criado e receba o **GIF comprimido**."
            ),
            inline=False,
        )
        emb.add_field(
            name=f"{ei_pb}  Preto e Branco",
            value=(
                "• Separe a **imagem** que deseja converter para preto e branco.\n"
                "• Um canal privado será criado para a edição.\n"
                "• Envie sua **imagem** no canal criado e receba a versão **P&B**."
            ),
            inline=False,
        )
        emb.add_field(
            name=f"{ei_obs}  Observações",
            value=(
                "• Suporta até **5** canais criados.\n"
                "• Você pode utilizar nosso editor de **5 em 5 minutos**.\n"
                "• O vídeo enviado não pode ultrapassar **10MB**."
            ),
            inline=False,
        )
        emb.set_footer(text=f"{bot_name}", icon_url=icon_url)

        # Select menu do canal
        select_view = _GifsConversorPublicSelect()

        try:
            sent_msg = await channel.send(embed=emb, view=select_view)
        except (discord.Forbidden, discord.HTTPException) as e:
            await interaction.response.send_message(f"❌ Erro ao enviar: `{e}`", ephemeral=True)
            return

        # Botão "Conferir no canal" com link para a mensagem
        link_view = discord.ui.View(timeout=None)
        link_btn = discord.ui.Button(
            label="Conferir no canal",
            style=discord.ButtonStyle.link,
            url=sent_msg.jump_url,
            emoji="↗️",
        )
        link_view.add_item(link_btn)

        await interaction.response.send_message(
            "Embed enviada com sucesso!", view=link_view, ephemeral=True
        )

    async def _editar_embed(self, interaction: discord.Interaction):
        modal = _GifsConversorEmbedModal(self)
        await interaction.response.send_modal(modal)

    async def _resetar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["gifs_conversor_channel"] = None
        settings["gifs_conversor_no_limit_roles"] = []
        settings["gifs_conversor_banner"] = None
        settings["gifs_conversor_embed"] = {}
        save_settings_to_disk()
        embed = build_gifs_conversor_embed(self.author, settings)
        await interaction.response.edit_message(embed=embed, view=GifsConversorView(self.author))
        await interaction.followup.send("🔄 Tudo resetado com sucesso!", ephemeral=True)


class _GifsConversorEmbedModal(discord.ui.Modal):
    def __init__(self, parent_view: "GifsConversorView"):
        super().__init__(title="Editar Embed do Conversor", timeout=300)
        self.parent_view = parent_view
        settings = get_settings(parent_view.author.guild.id)
        custom = settings.get("gifs_conversor_embed", {})

        self.title_input = discord.ui.TextInput(
            label="Título",
            placeholder=custom.get("title", "Central de Gifs"),
            default=custom.get("title", ""),
            required=False,
            max_length=256,
        )
        self.desc_input = discord.ui.TextInput(
            label="Descrição",
            placeholder=custom.get("description", "Use os comandos de GIF do servidor!"),
            default=custom.get("description", ""),
            style=discord.TextStyle.paragraph,
            required=False,
            max_length=2048,
        )
        self.add_item(self.title_input)
        self.add_item(self.desc_input)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["gifs_conversor_embed"] = {
            "title": self.title_input.value or "Central de Gifs",
            "description": self.desc_input.value or "Use os comandos de GIF do servidor!",
        }
        save_settings_to_disk()
        embed = build_gifs_conversor_embed(self.parent_view.author, settings)
        await interaction.response.edit_message(embed=embed, view=GifsConversorView(self.parent_view.author))
        await interaction.followup.send(f"{_e_success()} Embed editada com sucesso!", ephemeral=True)


# ── Decorações ────────────────────────────────────────────────────────────────

def build_gifs_decoracoes_embed(author: discord.Member, settings: dict) -> discord.Embed:
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed = discord.Embed(color=settings["embed_color"])
    embed.set_author(name="Central de Decorações - NATA®", icon_url=icon_url)
    if icon_url:
        embed.set_thumbnail(url=icon_url)

    ch_id = settings.get("gifs_decoracoes_log_channel")
    if ch_id and author.guild:
        ch = author.guild.get_channel(ch_id)
        ch_val = ch.mention if ch else f"<#{ch_id}>"
    else:
        ch_val = "`Não definido.`"

    roles = settings.get("gifs_decoracoes_allowed_roles", [])
    roles_val = f"`{len(roles)} cargos`" if roles else "`Nenhum`"

    embed.add_field(
        name="<a:alerta:1518271939460857968>  Informações",
        value=f"Canal de logs: {ch_val}\nCargos permitidos: {roles_val}",
        inline=False,
    )
    embed.add_field(
        name="<:bot_v3:1506343470242074785>  Observações",
        value=(
            "O canal de logs é onde será enviado os logs de uso do sistema.\n"
            "Cargos permitidos são os cargos que poderão usar o sistema de decorações no seu servidor."
        ),
        inline=False,
    )
    embed.set_footer(text=f"NATA® © • {author.name}", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


