class _DecoracoesLogSelect(GuildChannelSelect):
    def __init__(self):
        super().__init__(
            placeholder="Selecione o canal de logs...",
            min_values=1, max_values=1,
            channel_types=[discord.ChannelType.text],
        )
    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["gifs_decoracoes_log_channel"] = self.values[0].id
        save_settings_to_disk()
        embed = build_gifs_decoracoes_embed(interaction.user, settings)
        view = GifsDecoracoesView(interaction.user)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(f"{_e_success()} Canal de logs definido: {self.values[0].mention}", ephemeral=True)

class _DecoracoesLogView(discord.ui.View):
    def __init__(self, author):
        super().__init__(timeout=60)
        self.author = author
        self.add_item(_DecoracoesLogSelect())
    async def interaction_check(self, interaction):
        return interaction.user.id == self.author.id

class _DecoracoesRoleSelect(discord.ui.RoleSelect):
    def __init__(self):
        super().__init__(placeholder="Selecione cargos...", min_values=1, max_values=5)
    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        existing = settings.get("gifs_decoracoes_allowed_roles", [])
        added, removed = [], []
        for r in self.values:
            if r.id in existing:
                existing.remove(r.id); removed.append(r.mention)
            else:
                existing.append(r.id); added.append(r.mention)
        settings["gifs_decoracoes_allowed_roles"] = existing
        save_settings_to_disk()
        embed = build_gifs_decoracoes_embed(interaction.user, settings)
        view = GifsDecoracoesView(interaction.user)
        await interaction.response.edit_message(embed=embed, view=view)
        partes = []
        if added:   partes.append(f"{_e_success()} Adicionados: {', '.join(added)}")
        if removed: partes.append(f"❌ Removidos: {', '.join(removed)}")
        await interaction.followup.send("\n".join(partes) or "Sem alterações.", ephemeral=True)

class _DecoracoesRoleView(discord.ui.View):
    def __init__(self, author):
        super().__init__(timeout=60)
        self.author = author
        self.add_item(_DecoracoesRoleSelect())
    async def interaction_check(self, interaction):
        return interaction.user.id == self.author.id


# ── View principal ────────────────────────────────────────────────────────────

class GifsDecoracoesView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    def _build(self):
        self.clear_items()
        row0 = [
            ("Voltar",           discord.ButtonStyle.primary,   self._back),
            ("Canal de Logs",    discord.ButtonStyle.secondary, self._canal_logs),
            ("Cargos permitidos",discord.ButtonStyle.secondary, self._cargos),
            ("Listar Cargos",    discord.ButtonStyle.secondary, self._listar),
            ("Enviar Painel",    discord.ButtonStyle.blurple,   self._enviar_painel),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0)
            btn.callback = cb
            self.add_item(btn)
        btn_reset = discord.ui.Button(label="Resetar Tudo", style=discord.ButtonStyle.danger, row=1)
        btn_reset.callback = self._resetar
        self.add_item(btn_reset)

    async def interaction_check(self, interaction):
        if interaction.user.id != self.author.id:
            await interaction.response.send_message("Apenas quem abriu este painel pode usá-lo.", ephemeral=True)
            return False
        return True

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_gifs_embed(self.author, settings)
        view = GifsView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _canal_logs(self, interaction: discord.Interaction):
        view = _DecoracoesLogView(self.author)
        await interaction.response.send_message(
            "Selecione o canal de logs do sistema de decorações.", view=view, ephemeral=True
        )

    async def _cargos(self, interaction: discord.Interaction):
        view = _DecoracoesRoleView(self.author)
        await interaction.response.send_message(
            "Selecione cargos que deseja adicionar ou remover.", view=view, ephemeral=True
        )

    async def _listar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        roles = settings.get("gifs_decoracoes_allowed_roles", [])
        if not roles:
            await interaction.response.send_message("Nenhum cargo configurado.", ephemeral=True)
            return
        linhas = []
        for i, rid in enumerate(roles, 1):
            role = interaction.guild.get_role(rid)
            linhas.append(f"{i}. {role.mention if role else f'Cargo removido ( {rid} )'}")
        embed = discord.Embed(
            title="Cargos Permitidos - Decorações",
            color=settings["embed_color"],
        )
        embed.add_field(
            name="Cargos configurados:",
            value="\n".join(linhas),
            inline=False,
        )
        embed.set_footer(text=f"Página 1/1 • Total: {len(roles)}")
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _enviar_painel(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        view = _DecorPanelBuilderView(self.author, settings)
        await interaction.response.send_message(view=view, ephemeral=True)

    async def _resetar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["gifs_decoracoes_log_channel"] = None
        settings["gifs_decoracoes_allowed_roles"] = []
        settings["gifs_decoracoes_panel"] = {"color": None, "sections": []}
        save_settings_to_disk()
        embed = build_gifs_decoracoes_embed(self.author, settings)
        await interaction.response.edit_message(embed=embed, view=GifsDecoracoesView(self.author))
        await interaction.followup.send("🔄 Tudo resetado!", ephemeral=True)


# ── Builder de painel ─────────────────────────────────────────────────────────

# ── Modal Separador ────────────────────────────────────────────────────────────

class _DecorSepConfigView(discord.ui.LayoutView):
    """
    Substitui temporariamente o builder para configurar um Separador.
    Usa selects reais no lugar de inputs de texto, mantendo tudo na mesma mensagem.
    """

    def __init__(self, parent):           # parent: _DecorPanelBuilderView
        super().__init__(timeout=120)
        self.parent   = parent
        self._visible = True
        self._spacing = "small"
        self._build_sep()

    def _build_sep(self):
        self.clear_items()

        # ── Título ─────────────────────────────────────────────────────────────
        self.add_item(discord.ui.Container(
            discord.ui.TextDisplay(
                "**Adicionar Separador**\n"
                "Escolha o tipo e o espaçamento e clique em **Enviar**."
            ),
        ))

        # ── Select: Tipo ───────────────────────────────────────────────────────
        tipo_sel = discord.ui.Select(
            placeholder="Tipo",
            options=[
                discord.SelectOption(
                    label="Com linha",
                    value="com",
                    description="Fica acima do texto",
                    default=True,
                ),
                discord.SelectOption(
                    label="Sem linha",
                    value="sem",
                    description="Apenas espaçamento, sem divisória",
                ),
            ],
        )
        tipo_sel.callback = self._on_tipo
        self.add_item(discord.ui.ActionRow(tipo_sel))

        # ── Select: Espaçamento ────────────────────────────────────────────────
        esp_sel = discord.ui.Select(
            placeholder="Espaçamento",
            options=[
                discord.SelectOption(label="Pequeno", value="small", default=True),
                discord.SelectOption(label="Grande",  value="large"),
            ],
        )
        esp_sel.callback = self._on_espaco
        self.add_item(discord.ui.ActionRow(esp_sel))

        # ── Botões ─────────────────────────────────────────────────────────────
        confirm = discord.ui.Button(label="Enviar",   style=discord.ButtonStyle.blurple)
        cancel  = discord.ui.Button(label="Cancelar", style=discord.ButtonStyle.secondary)
        confirm.callback = self._confirmar
        cancel.callback  = self._cancelar
        self.add_item(discord.ui.ActionRow(confirm, cancel))

    async def _on_tipo(self, interaction: discord.Interaction):
        self._visible = interaction.data["values"][0] == "com"
        await interaction.response.defer()

    async def _on_espaco(self, interaction: discord.Interaction):
        self._spacing = interaction.data["values"][0]
        await interaction.response.defer()

    async def _confirmar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel    = settings.setdefault("gifs_decoracoes_panel", {"color": None, "sections": []})
        panel["sections"].append({
            "type":    "separator",
            "visible": self._visible,
            "spacing": self._spacing,
        })
        save_settings_to_disk()
        self.parent.settings = settings
        self.parent._build()
        # Restaura o builder na mesma mensagem
        await interaction.response.edit_message(view=self.parent)

    async def _cancelar(self, interaction: discord.Interaction):
        # Apenas restaura o builder sem salvar nada
        await interaction.response.edit_message(view=self.parent)


# ── Editar item ────────────────────────────────────────────────────────────────

class _DecorItemEditView(discord.ui.LayoutView):
    """View de edição de uma seção já existente no painel."""

    def __init__(self, builder: "_DecorPanelBuilderView", idx: int, section: dict, settings: dict):
        super().__init__(timeout=300)
        self.builder  = builder
        self.idx      = idx
        self.section  = section
        self.settings = settings
        self._build()

    @staticmethod
    def _info_text(idx: int, sec: dict) -> str:
        tipo_label = {
            "text":      "texto",
            "gallery":   "galeria",
            "separator": "separador",
            "buttons":   "buttons",
        }.get(sec.get("type"), sec.get("type", "?"))

        if sec.get("type") == "text":
            resumo = (sec.get("content") or "")[:60] or "—"
        elif sec.get("type") == "gallery":
            resumo = f"{len(sec.get('images', []))} imagem(ns)"
        elif sec.get("type") == "separator":
            resumo = ("Com linha" if sec.get("visible", True) else "Sem linha") + \
                     " • " + ("Grande" if sec.get("spacing") == "large" else "Pequeno")
        elif sec.get("type") == "buttons":
            resumo = f"{len(sec.get('buttons', []))} botão(ões)"
        else:
            resumo = "—"

        return (
            f"**Editando item {idx + 1}**\n"
            f"**Tipo:** `{tipo_label}`\n"
            f"**Resumo:** {resumo}\n\n"
            "Use os botões abaixo para **editar** ou **apagar**."
        )

    def _build(self):
        self.clear_items()
        tipo  = self.section.get("type", "text")
        color = self.settings.get("embed_color", 0x5865F2)

        # ── Info como TextDisplay dentro de Container ─────────────────────────
        info_display = discord.ui.TextDisplay(self._info_text(self.idx, self.section))

        # Preview inline dos botões (tipo buttons)
        container_items: list = [info_display]
        if tipo == "buttons":
            style_map = {
                "primary":   discord.ButtonStyle.primary,
                "secondary": discord.ButtonStyle.secondary,
                "success":   discord.ButtonStyle.success,
                "danger":    discord.ButtonStyle.danger,
            }
            prev_btns = []
            for btn_data in self.section.get("buttons", []):
                style = style_map.get(btn_data.get("style", "secondary"), discord.ButtonStyle.secondary)
                prev_btns.append(discord.ui.Button(
                    label=btn_data.get("label", "Botão"), style=style, disabled=True
                ))
            if prev_btns:
                container_items.append(discord.ui.ActionRow(*prev_btns))

        self.add_item(discord.ui.Container(*container_items, accent_colour=color))

        # ── Botões de ação — emojis dinâmicos da guild ───────────────────────
        g = getattr(getattr(self.builder, "author", None), "guild", None)
        ei_edit  = _guild_emoji(g, "edit", "pencil", "wrench", "ferramenta", "config",
                                fallback="<:ferramentas_:1518271998613131274>")
        ei_emoji = _guild_emoji(g, "emoji", "smile", "star", "entret", "fun",
                                fallback="<:entretenimento_:1518271992191779038>")
        ei_del   = _guild_emoji(g, "alerta", "alert", "warn", "danger", "delete", "trash",
                                fallback="<a:alerta:1518271939460857968>")
        ei_back  = _guild_emoji(g, "back", "voltar", "left", "arrow", "return", "evol",
                                fallback="<:evolution_g:1518272004560654579>")

        editar_btn = discord.ui.Button(label="Editar",          style=discord.ButtonStyle.primary,   emoji=ei_edit)
        emoji_btn  = discord.ui.Button(label="Adicionar Emoji", style=discord.ButtonStyle.secondary, emoji=ei_emoji)
        apagar_btn = discord.ui.Button(label="Apagar",          style=discord.ButtonStyle.danger,    emoji=ei_del)
        voltar_btn = discord.ui.Button(label="Voltar",          style=discord.ButtonStyle.secondary, emoji=ei_back)
        editar_btn.callback = self._editar
        emoji_btn.callback  = self._add_emoji
        apagar_btn.callback = self._apagar
        voltar_btn.callback = self._voltar
        self.add_item(discord.ui.ActionRow(editar_btn, emoji_btn, apagar_btn, voltar_btn))

    async def interaction_check(self, interaction):
        return interaction.user.id == self.builder.author.id

    async def _editar(self, interaction: discord.Interaction):
        tipo = self.section.get("type")
        if tipo == "text":
            await interaction.response.send_modal(_DecorTextEditModal(self))
        elif tipo == "gallery":
            await interaction.response.send_modal(_DecorGalleryEditModal(self))
        elif tipo == "separator":
            await interaction.response.send_modal(_DecorSepEditModal(self))
        elif tipo == "buttons":
            await interaction.response.send_modal(_DecorBtnEditModal(self, 0))
        else:
            await interaction.response.send_message("Tipo não suportado para edição.", ephemeral=True)

    async def _add_emoji(self, interaction: discord.Interaction):
        tipo = self.section.get("type")
        n_btns = len(self.section.get("buttons", []))
        if tipo != "buttons" or n_btns == 0:
            await interaction.response.send_message(
                "❌ Apenas seções do tipo **buttons** suportam emoji.", ephemeral=True
            )
            return

        await interaction.response.send_message(
            f"Envie o **emoji** no chat para definir, ou envie `resetar` para remover.\n"
            f"Você também pode enviar **cancelar** para cancelar.\n"
            f"Este painel tem apenas **{n_btns} botão**, então basta enviar o emoji ou `resetar`.",
            ephemeral=True,
        )

        def check(m: discord.Message):
            return m.author.id == self.builder.author.id and m.channel.id == interaction.channel.id

        try:
            msg = await bot.wait_for("message", check=check, timeout=60)
        except asyncio.TimeoutError:
            await interaction.followup.send("⏰ Tempo esgotado.", ephemeral=True)
            return

        content = msg.content.strip()
        try:
            await msg.delete()
        except Exception:
            pass

        if content.lower() == "cancelar":
            await interaction.followup.send("Cancelado.", ephemeral=True)
            return

        settings = get_settings(interaction.guild.id)
        sec = settings["gifs_decoracoes_panel"]["sections"][self.idx]

        if content.lower() == "resetar":
            for b in sec.get("buttons", []):
                b["emoji"] = None
            save_settings_to_disk()
            await interaction.followup.send("🔄 Emoji(s) removido(s).", ephemeral=True)
        else:
            for b in sec.get("buttons", []):
                b["emoji"] = content
            save_settings_to_disk()
            await interaction.followup.send(f"{_e_success()} Emoji definido: {content}", ephemeral=True)

        self.section  = sec
        self.settings = settings
        self._build()
        await interaction.edit_original_response(view=self)

    async def _apagar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        sections = settings["gifs_decoracoes_panel"]["sections"]
        removed_idx = self.idx + 1
        if self.idx < len(sections):
            sections.pop(self.idx)
        save_settings_to_disk()
        self.builder.settings = settings
        self.builder._build()
        # Restaura o builder e confirma remoção via followup
        await interaction.response.edit_message(view=self.builder)
        await interaction.followup.send(f"🗑️ Seção {removed_idx} apagada.", ephemeral=True)

    async def _voltar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        self.builder.settings = settings
        self.builder._build()
        await interaction.response.edit_message(view=self.builder)


# ── Base para modais com componentes V2 (Label/FileUpload/RadioGroup) ──────────

class _ModalV2(discord.ui.Modal):
    """Modal com suporte a componentes V2 (FileUpload, RadioGroup).
    Injeta flags=32768 (IS_COMPONENTS_V2) no payload enviado ao Discord."""

    def to_dict(self) -> dict:
        d = super().to_dict()
        # Com flags=32768 o Discord exige que todos os componentes raiz sejam tipo (10,18).
        # Qualquer Label em _children indica que é um modal V2.
        if any(isinstance(c, discord.ui.Label) for c in self._children):
            d["flags"] = 32768  # MessageFlags.components_v2
            # Discord rejeita o campo 'label' em TextInput (tipo 4) quando dentro de Label (tipo 18)
            for comp in d.get("components", []):
                if comp.get("type") == 18 and isinstance(comp.get("component"), dict):
                    inner = comp["component"]
                    if inner.get("type") == 4:  # TextInput
                        inner.pop("label", None)
        return d

    async def on_error(self, interaction: discord.Interaction, error: Exception) -> None:
        import traceback
        traceback.print_exc()
        try:
            msg = f"❌ Erro no modal V2: `{type(error).__name__}: {error}`"
            if not interaction.response.is_done():
                await interaction.response.send_message(embed=_notif_embed(msg), ephemeral=True)
            else:
                await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)
        except Exception:
            pass


# ── Modais de edição de seções ─────────────────────────────────────────────────

class _DecorTextEditModal(_ModalV2):
    def __init__(self, parent: "_DecorItemEditView"):
        super().__init__(title="Editar Texto / Seção", timeout=300)
        self.parent = parent
        sec = parent.section

        self.text_lbl = discord.ui.Label(
            text="Texto (markdown)",
            description="Texto principal do painel",
            component=discord.ui.TextInput(
                style=discord.TextStyle.paragraph,
                default=sec.get("content", ""),
                required=True, max_length=2000,
            ),
        )
        self.thumb_upload_lbl = discord.ui.Label(
            text="Thumbnail (upload)",
            description='Opcional: envie 1 imagem para substituir (ou use "{resetar}")',
            component=discord.ui.FileUpload(required=False, min_values=0, max_values=1),
        )
        self.thumb_remove_lbl = discord.ui.Label(
            text="Remover thumbnail?",
            description='Digite "resetar" para remover (opcional)',
            component=discord.ui.TextInput(required=False, max_length=10),
        )
        self.btn_label_lbl = discord.ui.Label(
            text="Botão lateral (label)",
            description="Opcional: texto do botão lateral (Link)",
            component=discord.ui.TextInput(
                default=sec.get("btn_label") or "",
                required=False, max_length=80,
            ),
        )
        self.btn_url_lbl = discord.ui.Label(
            text="Botão lateral (URL)",
            description="Opcional: link do botão lateral",
            component=discord.ui.TextInput(
                default=sec.get("btn_url") or "",
                required=False, max_length=500,
            ),
        )
        for item in [self.text_lbl, self.thumb_upload_lbl, self.thumb_remove_lbl,
                     self.btn_label_lbl, self.btn_url_lbl]:
            self.add_item(item)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        sec = settings["gifs_decoracoes_panel"]["sections"][self.parent.idx]

        sec["content"] = self.text_lbl.component.value

        # Thumbnail — upload tem prioridade; "resetar" remove; senão mantém o atual
        thumbnail = sec.get("thumbnail")
        try:
            files = self.thumb_upload_lbl.component.values
            if files:
                thumbnail = files[0].url
        except Exception:
            pass
        try:
            if self.thumb_remove_lbl.component.value.strip().lower() == "resetar":
                thumbnail = None
        except Exception:
            pass
        sec["thumbnail"] = thumbnail

        sec["btn_label"] = self.btn_label_lbl.component.value.strip() or None
        sec["btn_url"]   = self.btn_url_lbl.component.value.strip() or None

        save_settings_to_disk()
        self.parent.section  = sec
        self.parent.settings = settings
        self.parent._build()
        await interaction.response.edit_message(view=self.parent)


class _DecorGalleryEditModal(_ModalV2):
    def __init__(self, parent: "_DecorItemEditView"):
        super().__init__(title="Editar Galeria", timeout=300)
        self.parent  = parent
        sec          = parent.section
        is_footer    = sec.get("position", "header") == "footer"

        self.upload_lbl = discord.ui.Label(
            text="Upload (opcional)",
            description="Envie para substituir as imagens (senão mantém).",
            component=discord.ui.FileUpload(required=False, min_values=0, max_values=10),
        )
        self.links_lbl = discord.ui.Label(
            text="Links de imagens (opcional)",
            description="Cole links de imagens (um por linha). Pode usar junto com upload.",
            component=discord.ui.TextInput(
                placeholder="https://cdn.discordapp.com/...",
                style=discord.TextStyle.paragraph,
                default="\n".join(sec.get("images", [])),
                required=False, max_length=2000,
            ),
        )
        self.pos_lbl = discord.ui.Label(
            text="Posição da imagem",
            description="Escolha onde a galeria ficará no painel",
            component=discord.ui.RadioGroup(
                required=True,
                options=[
                    discord.RadioGroupOption(
                        label="Topo (Header)", value="header",
                        description="Fica acima do texto", default=not is_footer,
                    ),
                    discord.RadioGroupOption(
                        label="Rodapé (Footer)", value="footer",
                        description="Fica acima dos botões", default=is_footer,
                    ),
                ],
            ),
        )
        for item in [self.upload_lbl, self.links_lbl, self.pos_lbl]:
            self.add_item(item)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        sec = settings["gifs_decoracoes_panel"]["sections"][self.parent.idx]

        # Imagens via upload
        images: list[str] = []
        try:
            uploaded = self.upload_lbl.component.values
            if uploaded:
                images = [att.url for att in uploaded]
        except Exception:
            pass

        # Imagens via links (acumulam com upload)
        try:
            raw_links = (self.links_lbl.component.value or "").strip()
            images += [l.strip() for l in raw_links.splitlines() if l.strip().startswith("http")]
        except Exception:
            pass

        images = images[:10] or list(sec.get("images", []))  # mantém existentes se nada enviado

        try:
            pos = self.pos_lbl.component.value or sec.get("position", "header")
        except Exception:
            pos = sec.get("position", "header")

        sec.update({"images": images, "position": pos})
        save_settings_to_disk()
        self.parent.section  = sec
        self.parent.settings = settings
        self.parent._build()
        await interaction.response.edit_message(view=self.parent)


