class _DecorBtnEditModal(_ModalV2):
    """Modal combinado: edita label + style de um botão em um único formulário."""

    def __init__(self, parent: "_DecorItemEditView", btn_idx: int = 0):
        super().__init__(title="Editar botão", timeout=120)
        self.parent  = parent
        self.btn_idx = btn_idx
        buttons      = parent.section.get("buttons", [])
        btn_data     = buttons[btn_idx] if btn_idx < len(buttons) else {}
        curr_style   = btn_data.get("style", "secondary")

        self.label_lbl = discord.ui.Label(
            text="Novo label (opcional)",
            description="Deixe vazio para manter o label atual",
            component=discord.ui.TextInput(
                placeholder=f"Atual: {btn_data.get('label', '')}",
                default="",
                required=False,
                max_length=80,
            ),
        )
        self.style_lbl = discord.ui.Label(
            text="Novo style (opcional)",
            description="Deixe vazio para manter o style atual",
            component=discord.ui.RadioGroup(
                required=False,
                options=[
                    discord.RadioGroupOption(label="Primary",   value="primary",   description="Azul (padrão)", default=(curr_style == "primary")),
                    discord.RadioGroupOption(label="Secondary", value="secondary", description="Cinza",          default=(curr_style == "secondary")),
                    discord.RadioGroupOption(label="Success",   value="success",   description="Verde",          default=(curr_style == "success")),
                    discord.RadioGroupOption(label="Danger",    value="danger",    description="Vermelho",       default=(curr_style == "danger")),
                ],
            ),
        )
        self.add_item(self.label_lbl)
        self.add_item(self.style_lbl)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        sec      = settings["gifs_decoracoes_panel"]["sections"][self.parent.idx]
        buttons  = sec.setdefault("buttons", [{}])
        while len(buttons) <= self.btn_idx:
            buttons.append({})
        btn = buttons[self.btn_idx]

        new_label = self.label_lbl.component.value.strip()
        if new_label:
            btn["label"] = new_label

        new_style = self.style_lbl.component.value
        if new_style:
            btn["style"] = new_style

        save_settings_to_disk()
        self.parent.section  = sec
        self.parent.settings = settings
        self.parent._build()
        await interaction.response.edit_message(view=self.parent)


def _guild_emoji(guild: discord.Guild | None, *keywords: str, fallback: str = "") -> discord.PartialEmoji | discord.Emoji | str:
    """
    Retorna o melhor emoji da guild que corresponda a uma das keywords.
    Prioriza emojis animados. Se não encontrar, usa o fallback.
    """
    if not guild or not guild.emojis:
        return discord.PartialEmoji.from_str(fallback) if fallback else "❓"
    kws = [k.lower() for k in keywords]
    # 1ª passagem: animados que correspondam
    for emoji in guild.emojis:
        if emoji.animated and any(k in emoji.name.lower() for k in kws):
            return emoji
    # 2ª passagem: estáticos que correspondam
    for emoji in guild.emojis:
        if any(k in emoji.name.lower() for k in kws):
            return emoji
    # Sem correspondência — fallback
    return discord.PartialEmoji.from_str(fallback) if fallback else guild.emojis[0]


class _DecorPanelBuilderView(discord.ui.LayoutView):
    def __init__(self, author: discord.Member, settings: dict):
        super().__init__(timeout=None)
        self.author   = author
        self.settings = settings
        self._build()

    def _preview_text(self) -> str:
        panel    = self.settings.get("gifs_decoracoes_panel", {})
        sections = panel.get("sections", [])
        n = len(sections)
        header = f"**Editor de Painel** • {n} seção(ões)"
        if not sections:
            return header + "\nConfigure as seções do painel e clique em **Enviar**."
        lines = [header]
        for sec in sections:
            if sec["type"] == "text":
                preview = (sec.get("content") or "")[:80]
                if preview:
                    lines.append(preview)
            elif sec["type"] == "separator":
                vis = sec.get("visible", True)
                lines.append("──────────" if vis else "  ")
            elif sec["type"] == "gallery":
                lines.append(f"🖼️ {len(sec.get('images', []))} imagem(ns)")
        return "\n".join(lines)

    def _build(self):
        self.clear_items()

        panel    = self.settings.get("gifs_decoracoes_panel", {})
        sections = panel.get("sections", [])
        color    = panel.get("color") or self.settings.get("embed_color", 0x5865F2)

        # ── Montar itens de preview das seções ────────────────────────────────
        preview_items: list = []
        for sec in sections:
            if sec["type"] == "text":
                txt       = discord.ui.TextDisplay(sec.get("content", ""))
                btn_label = sec.get("btn_label") or ""
                btn_url   = sec.get("btn_url") or ""
                thumb_url = sec.get("thumbnail") or ""
                if btn_label and btn_url:
                    link_btn = discord.ui.Button(
                        label=btn_label, style=discord.ButtonStyle.link, url=btn_url
                    )
                    preview_items.append(discord.ui.Section(txt, accessory=link_btn))
                elif thumb_url:
                    preview_items.append(
                        discord.ui.Section(txt, accessory=discord.ui.Thumbnail(thumb_url))
                    )
                else:
                    preview_items.append(txt)

            elif sec["type"] == "gallery":
                images = sec.get("images", [])
                pos    = sec.get("position", "header")
                if images:
                    gallery = discord.ui.MediaGallery(
                        *[discord.MediaGalleryItem(media=u) for u in images[:10]]
                    )
                    if pos == "footer":
                        preview_items.append(discord.ui.Separator(visible=False))
                        preview_items.append(gallery)
                    else:
                        preview_items.insert(0, gallery)

            elif sec["type"] == "separator":
                vis     = sec.get("visible", True)
                sp_str  = sec.get("spacing", "small")
                spacing = (
                    discord.SeparatorSpacing.large
                    if sp_str == "large"
                    else discord.SeparatorSpacing.small
                )
                preview_items.append(discord.ui.Separator(visible=vis, spacing=spacing))

        # ── Botão Decorar Perfil — desabilitado no builder (só prévia visual) ──
        decor_btn = discord.ui.Button(
            label="Decorar Perfil",
            style=discord.ButtonStyle.blurple,
            disabled=True,
        )

        # ── Montar Container com preview ──────────────────────────────────────
        n       = len(sections)
        header  = discord.ui.TextDisplay(f"## Editor de Painel • {n} seção(ões)")
        sep_top = discord.ui.Separator(visible=True)
        sep_bot = discord.ui.Separator(visible=True)
        action  = discord.ui.ActionRow(decor_btn)

        if not sections:
            container = discord.ui.Container(
                header, sep_top,
                discord.ui.TextDisplay("Configure as seções do painel e clique em **Enviar**."),
                sep_bot, action,
                accent_colour=color,
            )
        else:
            container = discord.ui.Container(
                header, sep_top,
                *preview_items,
                sep_bot, action,
                accent_colour=color,
            )
        self.add_item(container)

        # --- Emojis dinâmicos da guild ----------------------------------------
        g = getattr(self.author, "guild", None)
        ei_text  = _guild_emoji(g, "chat", "text", "write", "mensagem", "aparenc", "star",
                                fallback="<:aparncia_:1518271975317962895>")
        ei_gal   = _guild_emoji(g, "gif", "image", "photo", "galeria", "camera", "foto", "pic",
                                fallback="<:gifs:1518272035762081835>")
        ei_sep   = _guild_emoji(g, "line", "sep", "divid", "dash", "ferramenta", "config",
                                fallback="<:ferramentas_:1518271998613131274>")
        ei_reset = _guild_emoji(g, "alerta", "alert", "warn", "danger", "delete", "trash",
                                fallback="<a:alerta:1518271939460857968>")
        ei_edit  = _guild_emoji(g, "edit", "pencil", "wrench", "ferramenta", "config",
                                fallback="<:ferramentas_:1518271998613131274>")
        ei_save  = _guild_emoji(g, "online", "check", "ok", "save", "done", "confirm",
                                fallback="<a:online:1518271945550856295>")
        ei_send  = _guild_emoji(g, "send", "chat", "msg", "mensagem", "mail",
                                fallback="<:Mov_chat:1518271970008105031>")
        ei_color = _guild_emoji(g, "color", "cor", "paint", "aparenc", "palette",
                                fallback="<:aparncia_:1518271975317962895>")

        # --- ActionRow: Adicionar item ---
        add_select = discord.ui.Select(
            placeholder="Adicionar seção ao painel…",
            min_values=1, max_values=1,
            options=[
                discord.SelectOption(
                    label="Texto / Seção",
                    description="Texto com miniatura e botão lateral opcionais",
                    emoji=ei_text,
                    value="add_text",
                ),
                discord.SelectOption(
                    label="Galeria de Imagens",
                    description="Grade com até 10 imagens (links ou upload)",
                    emoji=ei_gal,
                    value="add_gallery",
                ),
                discord.SelectOption(
                    label="Separador",
                    description="Linha divisória ou espaçamento entre seções",
                    emoji=ei_sep,
                    value="add_sep",
                ),
                discord.SelectOption(
                    label="Resetar Painel",
                    description="Remove todas as seções configuradas",
                    emoji=ei_reset,
                    value="reset_all",
                ),
            ],
        )
        add_select.callback = self._on_add
        self.add_item(discord.ui.ActionRow(add_select))

        # --- ActionRow: Editar item ---
        sect_list  = self.settings.get("gifs_decoracoes_panel", {}).get("sections", [])
        _tipo_emoji = {"text": ei_text, "gallery": ei_gal, "separator": ei_sep}
        _tipo_nome  = {"text": "Texto", "gallery": "Galeria", "separator": "Separador"}
        edit_opts = []
        for i, sec in enumerate(sect_list):
            tipo_key = sec["type"]
            tipo     = _tipo_nome.get(tipo_key, tipo_key)
            emoji    = _tipo_emoji.get(tipo_key, ei_edit)
            preview  = (sec.get("content", "")[:50] or tipo)
            edit_opts.append(discord.SelectOption(
                label=f"{i + 1}.  {tipo}",
                description=preview,
                emoji=emoji,
                value=str(i),
            ))
        if not edit_opts:
            edit_opts = [discord.SelectOption(
                label="Nenhuma seção adicionada ainda",
                description="Use o menu acima para criar uma seção",
                emoji=ei_reset,
                value="_none",
            )]
        edit_select = discord.ui.Select(
            placeholder="Selecionar seção para editar…",
            min_values=1, max_values=1,
            options=edit_opts,
        )
        edit_select.callback = self._on_edit
        self.add_item(discord.ui.ActionRow(edit_select))

        # --- ActionRow: Cor / Salvar / Enviar ---
        cor_btn    = discord.ui.Button(label="Cor",    style=discord.ButtonStyle.secondary, emoji=ei_color)
        salvar_btn = discord.ui.Button(label="Salvar", style=discord.ButtonStyle.success,   emoji=ei_save)
        enviar_btn = discord.ui.Button(label="Enviar", style=discord.ButtonStyle.blurple,   emoji=ei_send)
        cor_btn.callback    = self._cor
        salvar_btn.callback = self._salvar
        enviar_btn.callback = self._enviar
        self.add_item(discord.ui.ActionRow(cor_btn, salvar_btn, enviar_btn))

    async def interaction_check(self, interaction):
        return interaction.user.id == self.author.id

    async def on_error(self, interaction: discord.Interaction, error: Exception, item) -> None:
        """Garante que qualquer falha de callback responda à interação."""
        try:
            if not interaction.response.is_done():
                await interaction.response.send_message(f"❌ Erro: `{error}`", ephemeral=True)
            else:
                await interaction.followup.send(f"❌ Erro: `{error}`", ephemeral=True)
        except Exception:
            pass

    async def _on_decorar_perfil(self, interaction: discord.Interaction):
        import time as _t
        uid   = interaction.user.id
        now_i = int(_t.time())

        settings = get_settings(interaction.guild.id)
        bot_name = bot.user.display_name if bot.user else "HypeBot"
        icon_url = bot.user.display_avatar.url if bot.user else None

        # Gera (ou reutiliza) token
        existing = _deco_links.get(uid)
        if existing and existing["exp"] > now_i:
            token       = existing["token"]
            remaining_m = max(1, (existing["exp"] - now_i) // 60)
        else:
            token, exp = _deco_make_token(interaction.user)
            _deco_links[uid] = {"token": token, "exp": exp}
            remaining_m = _DECO_TTL // 60

        site_url = f"https://hypebot-decoracoes.vercel.app?t={token}"

        embed = discord.Embed(
            description=(
                "Acesse o site para personalizar sua decoração manualmente.\n\n"
                f"-# Link válido por **{remaining_m} min**."
            ),
            color=settings.get("embed_color", 0x2B2D31),
        )
        embed.set_author(name=f"Decorações - {bot_name}", icon_url=icon_url)

        view = discord.ui.View(timeout=300)
        view.add_item(discord.ui.Button(
            label="Acessar Site",
            style=discord.ButtonStyle.link,
            url=site_url,
        ))
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _on_add(self, interaction: discord.Interaction):
        val = interaction.data["values"][0]
        settings = get_settings(interaction.guild.id)
        panel = settings.setdefault("gifs_decoracoes_panel", {"color": None, "sections": []})

        if val == "add_text":
            await interaction.response.send_modal(_DecorTextModal(self))
        elif val == "add_gallery":
            await interaction.response.send_modal(_DecorGalleryModal(self))
        elif val == "add_sep":
            # Substitui o builder pela view de configuração de separador (selects reais)
            await interaction.response.edit_message(view=_DecorSepConfigView(self))
        elif val == "reset_all":
            panel["sections"] = []
            save_settings_to_disk()
            self.settings = settings
            self._build()
            await interaction.response.edit_message(view=self)

    async def _on_edit(self, interaction: discord.Interaction):
        val = interaction.data["values"][0]
        if val == "_none":
            await interaction.response.send_message("Nenhuma seção para editar.", ephemeral=True)
            return
        idx = int(val)
        settings = get_settings(interaction.guild.id)
        sections = settings.get("gifs_decoracoes_panel", {}).get("sections", [])
        if idx >= len(sections):
            await interaction.response.send_message("Seção não encontrada.", ephemeral=True)
            return
        sec = sections[idx]
        edit_view = _DecorItemEditView(self, idx, sec, settings)
        # Edita a mensagem atual (builder) para mostrar o editor — "Voltar" restaura o builder
        await interaction.response.edit_message(view=edit_view)

    async def _cor(self, interaction: discord.Interaction):
        await interaction.response.send_modal(_DecorCorModal(self))

    async def _salvar(self, interaction: discord.Interaction):
        save_settings_to_disk()
        await interaction.response.send_message(f"{_e_success()} Painel salvo!", ephemeral=True)

    async def _enviar(self, interaction: discord.Interaction):
        # Usa self.settings para garantir que seções recém-adicionadas sejam incluídas
        panel    = self.settings.get("gifs_decoracoes_panel", {"color": None, "sections": []})
        sections = panel.get("sections", [])
        color    = panel.get("color") or self.settings.get("embed_color", 0x5865F2)

        if not sections:
            await interaction.response.send_message(
                "❌ Adicione pelo menos uma seção antes de enviar.", ephemeral=True
            )
            return

        view = _SentPanelView(sections, color)
        if not view.has_items:
            await interaction.response.send_message(
                "❌ Nenhum item válido para enviar.", ephemeral=True
            )
            return

        await interaction.response.send_message(view=view)


class _SentPanelView(discord.ui.LayoutView):
    """Painel final enviado ao canal com botão Decorar Perfil funcional."""

    def __init__(self, sections: list, color: int):
        super().__init__(timeout=None)
        self.has_items = False
        container_items: list = []

        for sec in sections:
            if sec["type"] == "text":
                txt       = discord.ui.TextDisplay(sec.get("content", ""))
                btn_label = sec.get("btn_label") or ""
                btn_url   = sec.get("btn_url") or ""
                thumb_url = sec.get("thumbnail") or ""
                if btn_label and btn_url:
                    link_btn = discord.ui.Button(
                        label=btn_label, style=discord.ButtonStyle.link, url=btn_url
                    )
                    container_items.append(discord.ui.Section(txt, accessory=link_btn))
                elif thumb_url:
                    container_items.append(
                        discord.ui.Section(txt, accessory=discord.ui.Thumbnail(thumb_url))
                    )
                else:
                    container_items.append(txt)

            elif sec["type"] == "gallery":
                images = sec.get("images", [])
                pos    = sec.get("position", "header")
                if images:
                    gallery = discord.ui.MediaGallery(
                        *[discord.MediaGalleryItem(media=u) for u in images[:10]]
                    )
                    if pos == "footer":
                        container_items.append(discord.ui.Separator(visible=False))
                        container_items.append(gallery)
                    else:
                        container_items.insert(0, gallery)

            elif sec["type"] == "separator":
                vis     = sec.get("visible", True)
                sp_str  = sec.get("spacing", "small")
                spacing = (
                    discord.SeparatorSpacing.large
                    if sp_str == "large"
                    else discord.SeparatorSpacing.small
                )
                container_items.append(discord.ui.Separator(visible=vis, spacing=spacing))

        if not container_items:
            return

        self.has_items = True

        # Botão Decorar Perfil — funcional para todos os usuários
        decor_btn = discord.ui.Button(
            label="Decorar Perfil",
            style=discord.ButtonStyle.blurple,
        )
        decor_btn.callback = self._on_decorar_perfil

        container_items.append(discord.ui.Separator(visible=True))
        container_items.append(discord.ui.ActionRow(decor_btn))

        self.add_item(discord.ui.Container(*container_items, accent_colour=color))

    async def _on_decorar_perfil(self, interaction: discord.Interaction):
        import time as _t
        uid   = interaction.user.id
        now_i = int(_t.time())

        settings = get_settings(interaction.guild.id)
        bot_name = bot.user.display_name if bot.user else "HypeBot"
        icon_url = bot.user.display_avatar.url if bot.user else None

        # Gera (ou reutiliza) token
        existing = _deco_links.get(uid)
        if existing and existing["exp"] > now_i:
            token       = existing["token"]
            remaining_m = max(1, (existing["exp"] - now_i) // 60)
        else:
            token, exp = _deco_make_token(interaction.user)
            _deco_links[uid] = {"token": token, "exp": exp}
            remaining_m = _DECO_TTL // 60

        site_url = f"https://hypebot-decoracoes.vercel.app?t={token}"

        embed = discord.Embed(
            description=(
                "Acesse o site para personalizar sua decoração manualmente.\n\n"
                f"-# Link válido por **{remaining_m} min**."
            ),
            color=settings.get("embed_color", 0x2B2D31),
        )
        embed.set_author(name=f"Decorações - {bot_name}", icon_url=icon_url)

        view = discord.ui.View(timeout=300)
        view.add_item(discord.ui.Button(
            label="Acessar Site",
            style=discord.ButtonStyle.link,
            url=site_url,
        ))
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

        # ── Log no canal configurado ──────────────────────────────────────────
        log_ch_id = settings.get("gifs_decoracoes_log_channel")
        if log_ch_id and interaction.guild:
            log_ch = interaction.guild.get_channel(log_ch_id)
            if log_ch:
                try:
                    user = interaction.user
                    log_embed = discord.Embed(
                        title="Sistema de decorações",
                        color=settings.get("embed_color", 0x2B2D31),
                    )
                    log_embed.add_field(
                        name="👤 Usuário que criou o link:",
                        value=f"Tag: `{user}`\nID: `{user.id}`",
                        inline=False,
                    )
                    log_embed.add_field(
                        name="# Observações:",
                        value="Link gerado com sucesso para criar decorações.",
                        inline=False,
                    )
                    log_embed.set_thumbnail(url=user.display_avatar.url)
                    log_embed.set_footer(
                        text=f"Powered by {bot_name}",
                        icon_url=icon_url,
                    )
                    log_embed.timestamp = discord.utils.utcnow()
                    await log_ch.send(embed=log_embed)
                except Exception:
                    pass


class _DecorTextModal(_ModalV2):
    def __init__(self, parent: "_DecorPanelBuilderView"):
        super().__init__(title="Adicionar Texto / Seção", timeout=300)
        self.parent = parent

        self.text_lbl = discord.ui.Label(
            text="Texto (markdown)",
            description="Texto principal do painel",
            component=discord.ui.TextInput(
                style=discord.TextStyle.paragraph,
                required=True,
                max_length=2000,
            ),
        )
        self.thumb_upload_lbl = discord.ui.Label(
            text="Thumbnail (upload)",
            description="Opcional: envie 1 imagem para ficar ao lado do texto",
            component=discord.ui.FileUpload(required=False, min_values=0, max_values=1),
        )
        self.btn_label_lbl = discord.ui.Label(
            text="Botão lateral (label)",
            description="Opcional: texto do botão lateral (Link)",
            component=discord.ui.TextInput(
                required=False,
                max_length=80,
            ),
        )
        self.btn_url_lbl = discord.ui.Label(
            text="Botão lateral (URL)",
            description="Opcional: link do botão lateral",
            component=discord.ui.TextInput(
                required=False,
                max_length=500,
            ),
        )
        for item in [self.text_lbl, self.thumb_upload_lbl, self.btn_label_lbl, self.btn_url_lbl]:
            self.add_item(item)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel = settings.setdefault("gifs_decoracoes_panel", {"color": None, "sections": []})

        # Thumbnail — upload tem prioridade sobre URL
        thumbnail = None
        try:
            files = self.thumb_upload_lbl.component.values
            if files:
                thumbnail = files[0].url
        except Exception:
            pass

        panel["sections"].append({
            "type":      "text",
            "content":   self.text_lbl.component.value,
            "thumbnail": thumbnail,
            "btn_label": self.btn_label_lbl.component.value.strip() or None,
            "btn_url":   self.btn_url_lbl.component.value.strip() or None,
        })
        save_settings_to_disk()
        self.parent.settings = settings
        self.parent._build()
        await interaction.response.edit_message(view=self.parent)


class _DecorGalleryModal(_ModalV2, title="Adicionar Galeria (até 10)"):
    upload_lbl = discord.ui.Label(
        text="Upload (opcional)",
        description="Envie até 10 imagens/gifs (PNG/JPG/GIF/WEBP).",
        component=discord.ui.FileUpload(required=False, min_values=0, max_values=10),
    )
    links_lbl = discord.ui.Label(
        text="Links de imagens (opcional)",
        description="Cole links de imagens (um por linha). Pode usar junto com upload.",
        component=discord.ui.TextInput(
            placeholder="https://exemplo.com/imagem1.png\nhttps://exemplo.com/imagem2.png",
            style=discord.TextStyle.paragraph,
            required=False,
            max_length=2000,
        ),
    )
    pos_lbl = discord.ui.Label(
        text="Posição da imagem",
        description="Escolha onde a galeria ficará no painel",
        component=discord.ui.RadioGroup(
            required=True,
            options=[
                discord.RadioGroupOption(
                    label="Topo (Header)",
                    value="header",
                    description="Fica acima do texto",
                    default=True,
                ),
                discord.RadioGroupOption(
                    label="Rodapé (Footer)",
                    value="footer",
                    description="Fica acima dos botões",
                ),
            ],
        ),
    )

    def __init__(self, parent: "_DecorPanelBuilderView"):
        super().__init__(timeout=300)
        self.parent = parent

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        panel = settings.setdefault("gifs_decoracoes_panel", {"color": None, "sections": []})

        # Imagens via upload
        images: list[str] = []
        try:
            images = [att.url for att in self.upload_lbl.component.values]
        except Exception:
            pass

        # Imagens via links
        try:
            raw_links = (self.links_lbl.component.value or "").strip()
            images += [l.strip() for l in raw_links.splitlines() if l.strip().startswith("http")]
        except Exception:
            pass

        images = images[:10]

        try:
            pos = self.pos_lbl.component.value or "header"
        except Exception:
            pos = "header"

        panel["sections"].append({
            "type":     "gallery",
            "images":   images,
            "position": pos,
        })
        save_settings_to_disk()
        self.parent.settings = settings
        self.parent._build()
        await interaction.response.edit_message(view=self.parent)

    async def on_error(self, interaction: discord.Interaction, error: Exception):
        try:
            await interaction.response.send_message(
                f"❌ Erro ao processar galeria: `{error}`", ephemeral=True
            )
        except Exception:
            pass


class _DecorCorModal(discord.ui.Modal):
    def __init__(self, parent: "_DecorPanelBuilderView"):
        super().__init__(title="Definir Cor do Painel", timeout=120)
        self.parent = parent
        self.cor_input = discord.ui.TextInput(
            label="Cor (hex, ex: #FF5733)",
            placeholder="#2B2D31",
            required=True,
            max_length=7,
        )
        self.add_item(self.cor_input)

    async def on_submit(self, interaction: discord.Interaction):
        raw = self.cor_input.value.strip().lstrip("#")
        try:
            color = int(raw, 16)
        except ValueError:
            await interaction.response.send_message("❌ Cor inválida. Use formato hex (ex: #FF5733).", ephemeral=True)
            return
        settings = get_settings(interaction.guild.id)
        settings.setdefault("gifs_decoracoes_panel", {"color": None, "sections": []})["color"] = color
        save_settings_to_disk()
        self.parent.settings = settings
        self.parent._build()
        await interaction.response.edit_message(view=self.parent)


# ── Auto Postador ─────────────────────────────────────────────────────────────
#
# Cada categoria tem:
#   gifs_autopostador_{cat}  → canal DESTINO (onde o bot posta)
#
# O bot busca imagens automaticamente: canal destino → A NATA → auto-descoberta.
# ─────────────────────────────────────────────────────────────────────────────

_AP_CATS = [
    ("masc_icons", "gifs_autopostador_masc_icons", "<:comunidade_:1518272016971595807> Icons Masculinos"),
    ("fem_icons",  "gifs_autopostador_fem_icons",  "<:comunidade_:1518272016971595807> Icons Femininos"),
    ("fem_gifs",   "gifs_autopostador_fem_gifs",   "<:gifs:1518272035762081835> GIFs Femininos"),
    ("masc_gifs",  "gifs_autopostador_masc_gifs",  "<:gifs:1518272035762081835> GIFs Masculinos"),
    ("banners",    "gifs_autopostador_banners",    "<:aparncia_:1518271975317962895> Banners"),
    ("animes",     "gifs_autopostador_animes",     "<:entretenimento_:1518271992191779038> Animes"),
]


def build_gifs_autopostador_embed(author: discord.Member, settings: dict) -> discord.Embed:
    icon_url = bot.user.display_avatar.url if bot.user else None
    enabled  = settings.get("gifs_autopostador_enabled", False)
    interval = settings.get("gifs_autopostador_interval", 30)
    guild    = author.guild

    status_icon = "<a:online:1518271945550856295>" if enabled else "<a:alerta:1518271939460857968>"
    status_txt  = "(Ativado)" if enabled else "(Desativado)"

    def _dest(key):
        cid = settings.get(key)
        if not cid: return "`Não definido`"
        ch = guild.get_channel(cid) if guild else None
        return ch.mention if ch else f"<#{cid}>"

    embed = discord.Embed(color=settings["embed_color"])
    embed.set_author(name="Postador automático - NATA®", icon_url=icon_url)
    if icon_url:
        embed.set_thumbnail(url=icon_url)

    # Campo: Informações
    embed.add_field(
        name="Informações:",
        value=(
            f"Estado: {status_icon} **{status_txt}**"
        ),
        inline=False,
    )

    # Campo: Canais de postagem
    lines = [
        ("Masc-Icons", "gifs_autopostador_masc_icons"),
        ("Fem-Icons",  "gifs_autopostador_fem_icons"),
        ("Fem-Gifs",   "gifs_autopostador_fem_gifs"),
        ("Masc-Gifs",  "gifs_autopostador_masc_gifs"),
        ("Banners",    "gifs_autopostador_banners"),
        ("Animes",     "gifs_autopostador_animes"),
    ]
    canais_str = "\n".join(
        f"{label}: {_dest(dest_k)}"
        for label, dest_k in lines
    )

    embed.add_field(
        name="Canais:",
        value=canais_str,
        inline=False,
    )

    # Campo: Observações
    embed.add_field(
        name="Observações:",
        value=(
            "Após ativo, o postador irá começar a **enviar icons ou gifs** nos "
            "canais setados, de acordo com o gênero."
        ),
        inline=False,
    )

    embed.set_footer(text=f"NATA® © • {author.name}", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


# ── Sub-painel de categoria (Destino + Fonte) ─────────────────────────────────

# ── Select simples por categoria ──────────────────────────────────────────────
# Usa Select comum (não ChannelSelect) preenchido com canais do guild ALVO do cliente.
# Isso garante que o dev veja os canais do servidor do cliente, não do servidor do admin.

def _get_target_guild_channels(fallback_guild=None) -> list[discord.TextChannel]:
    """Retorna os canais de texto do guild alvo (cliente), respeitando o override de dev.
    Se não houver override de dev, usa fallback_guild (guild do author/interaction).
    """
    guild_id = _dev_guild_ctx.get(0)
    if guild_id:
        guild = bot.get_guild(guild_id)
    else:
        # Modo cliente normal: usa o guild passado como fallback
        guild = fallback_guild
    if not guild:
        return []
    # Ordena: primeiro canais cujo nome contém palavras-chave do postador, depois os demais
    keywords = ("icon", "gif", "banner", "anime", "foto", "img", "nata", "male", "fem",
                "masc", "female", "post")
    channels = sorted(
        guild.text_channels,
        key=lambda c: (0 if any(k in c.name.lower() for k in keywords) else 1, c.name)
    )
    return channels[:25]


def _make_ap_cat_select(dest_key: str, cat_label: str):
    class _Sel(discord.ui.Select):
        _dest = dest_key
        _lbl  = cat_label

        def __init__(self_, channels: list[discord.TextChannel]):
            options = [
                discord.SelectOption(
                    label=f"#{ch.name}"[:100],
                    value=str(ch.id),
                    description=(ch.category.name[:100] if ch.category else None),
                )
                for ch in channels
            ] or [discord.SelectOption(label="Nenhum canal disponível", value="0")]
            super().__init__(
                placeholder=f"Selecione o canal de {cat_label}...",
                min_values=1, max_values=1,
                options=options,
            )

        async def callback(self_, interaction: discord.Interaction):
            channel_id_str = self_.values[0]
            if channel_id_str == "0":
                await interaction.response.send_message("❌ Nenhum canal disponível.", ephemeral=True)
                return
            channel_id = int(channel_id_str)
            # Recarrega antes de salvar para não sobrescrever mudanças paralelas
            ovr = _dev_guild_ctx.get(0)
            if ovr:
                _dev_load_client_settings(ovr, force=True)
            else:
                load_settings_from_disk()
            settings = get_settings(interaction.guild.id)
            settings[self_._dest] = channel_id
            save_settings_to_disk()
            embed = build_gifs_autopostador_embed(interaction.user, settings)
            author = getattr(self_.view, "author", interaction.user)
            await interaction.response.edit_message(embed=embed, view=GifsAutoPostadorView(author))
            icon_url = bot.user.display_avatar.url if bot.user else None
            conf = discord.Embed(
                description=f"{_e_success()} **{self_._lbl}**: <#{channel_id}>",
                color=0x57F287,
            )
            conf.set_footer(text=f"Auto Postador — NATA® © • {interaction.user.name}", icon_url=icon_url)
            await interaction.followup.send(embed=conf, ephemeral=True)
    return _Sel


class _APSimpleCatView(discord.ui.View):
    def __init__(self, author, SelectCls):
        super().__init__(timeout=120)
        self.author = author
        # Busca canais do guild ALVO (cliente) — em dev usa override, senão usa guild do author
        fallback = getattr(author, "guild", None)
        channels = _get_target_guild_channels(fallback_guild=fallback)
        self.add_item(SelectCls(channels))
        btn = discord.ui.Button(label="Voltar", style=discord.ButtonStyle.primary, row=1)
        btn.callback = self._voltar
        self.add_item(btn)

    async def interaction_check(self, interaction):
        return interaction.user.id == self.author.id

    async def _voltar(self, interaction: discord.Interaction):
        ovr = _dev_guild_ctx.get(0)
        if ovr:
            _dev_load_client_settings(ovr, force=True)
        else:
            load_settings_from_disk()
        settings = get_settings(interaction.guild.id)
        embed = build_gifs_autopostador_embed(interaction.user, settings)
        await interaction.response.edit_message(embed=embed, view=GifsAutoPostadorView(self.author))


_APMascIconsSel  = _make_ap_cat_select("gifs_autopostador_masc_icons", "Icons Masculinos")
_APFemIconsSel   = _make_ap_cat_select("gifs_autopostador_fem_icons",  "Icons Femininos")
_APFemGifsSel    = _make_ap_cat_select("gifs_autopostador_fem_gifs",   "GIFs Femininos")
_APMascGifsSel   = _make_ap_cat_select("gifs_autopostador_masc_gifs",  "GIFs Masculinos")
_APBannersSel    = _make_ap_cat_select("gifs_autopostador_banners",    "Banners")
_APAnimesSel     = _make_ap_cat_select("gifs_autopostador_animes",     "Animes")





class GifsAutoPostadorView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author and self.author.guild else 0)
        enabled  = settings.get("gifs_autopostador_enabled", False)
        tog_label = "Desativar" if enabled else "Ativar"
        tog_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            ("Voltar",             discord.ButtonStyle.primary,   self._back,           0),
            (tog_label,            tog_style,                     self._toggle,         0),
            ("Icons Masculinos",   discord.ButtonStyle.secondary, self._masc_icons,     0),
            ("Icons Femininos",    discord.ButtonStyle.secondary, self._fem_icons,      0),
            ("GIFS Femininos",     discord.ButtonStyle.secondary, self._fem_gifs,       0),
            ("GIFS Masculinos",    discord.ButtonStyle.secondary, self._masc_gifs,    1),
            ("Banners",            discord.ButtonStyle.secondary, self._banners,      1),
            ("Setar Animes",       discord.ButtonStyle.secondary, self._animes,       1),
            ("Resetar Tudo",       discord.ButtonStyle.danger,    self._resetar,      1),
        ]
        for label, style, cb, row in row0:
            btn = discord.ui.Button(label=label, style=style, row=row)
            btn.callback = cb
            self.add_item(btn)

    async def interaction_check(self, interaction):
        if interaction.user.id != self.author.id:
            await interaction.response.send_message(
                "Apenas quem abriu este painel pode usá-lo.", ephemeral=True
            )
            return False
        return True

    def _sync_reload(self, interaction: discord.Interaction) -> None:
        """Recarrega as settings mais recentes antes de qualquer ação no painel.
        Garante que o painel sempre opera sobre o estado atual, mesmo que o
        cliente tenha feito mudanças desde que o painel foi aberto."""
        ovr = _dev_guild_ctx.get(0)
        if ovr:
            # Modo dev: força releitura do arquivo do cliente
            _dev_load_client_settings(ovr, force=True)
        else:
            # Modo cliente: relê o arquivo local
            load_settings_from_disk()

    async def _back(self, interaction: discord.Interaction):
        self._sync_reload(interaction)
        settings = get_settings(interaction.guild.id)
        embed = build_gifs_embed(self.author, settings)
        await interaction.response.edit_message(embed=embed, view=GifsView(self.author))

    async def _toggle(self, interaction: discord.Interaction):
        self._sync_reload(interaction)
        settings = get_settings(interaction.guild.id)
        settings["gifs_autopostador_enabled"] = not settings.get("gifs_autopostador_enabled", False)
        save_settings_to_disk()
        embed = build_gifs_autopostador_embed(self.author, settings)
        await interaction.response.edit_message(embed=embed, view=GifsAutoPostadorView(self.author))

    async def _open_cat(self, interaction: discord.Interaction, SelectCls, label: str = ""):
        self._sync_reload(interaction)
        settings  = get_settings(interaction.guild.id)
        icon_url  = bot.user.display_avatar.url if bot.user else None
        embed = discord.Embed(
            description=f"Selecione o canal de texto para **{label}**.",
            color=settings.get("embed_color", 0x2B2D31),
        )
        embed.set_author(name="Postador automático - NATA®", icon_url=icon_url)
        if icon_url:
            embed.set_thumbnail(url=icon_url)
        embed.set_footer(text=f"NATA® © • {interaction.user.name}", icon_url=icon_url)
        embed.timestamp = datetime.now()
        await interaction.response.edit_message(embed=embed, view=_APSimpleCatView(self.author, SelectCls))

    async def _masc_icons(self, i): await self._open_cat(i, _APMascIconsSel,    "Icons Masculinos")
    async def _fem_icons(self,  i): await self._open_cat(i, _APFemIconsSel,     "Icons Femininos")
    async def _fem_gifs(self,   i): await self._open_cat(i, _APFemGifsSel,      "GIFs Femininos")
    async def _masc_gifs(self,  i): await self._open_cat(i, _APMascGifsSel,     "GIFs Masculinos")
    async def _banners(self,    i): await self._open_cat(i, _APBannersSel,      "Banners")
    async def _animes(self,     i): await self._open_cat(i, _APAnimesSel,       "Animes")


    async def _resetar(self, interaction: discord.Interaction):
        self._sync_reload(interaction)
        settings = get_settings(interaction.guild.id)
        for k in ("gifs_autopostador_enabled", "gifs_autopostador_masc_icons",
                  "gifs_autopostador_fem_icons", "gifs_autopostador_fem_gifs",
                  "gifs_autopostador_masc_gifs", "gifs_autopostador_banners",
                  "gifs_autopostador_animes"):
            settings[k] = False if k == "gifs_autopostador_enabled" else None
        settings["gifs_autopostador_last_posted"] = {}
        save_settings_to_disk()
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed = build_gifs_autopostador_embed(self.author, settings)
        await interaction.response.edit_message(embed=embed, view=GifsAutoPostadorView(self.author))
        conf = discord.Embed(description=f"{_e_success()} Auto Postador resetado com sucesso.", color=0x2ECC71)
        conf.set_footer(text=f"NATA® © • {interaction.user.name}", icon_url=icon_url)
        await interaction.followup.send(embed=conf, ephemeral=True)




# ── Gerenciar Postadores ──────────────────────────────────────────────────────

def build_gifs_postadores_embed(author: discord.Member, settings: dict) -> discord.Embed:
    icon_url = bot.user.display_avatar.url if bot.user else None
    enabled  = settings.get("gifs_postadores_enabled", False)
    status   = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else
        "<a:alerta:1518271939460857968> `(Desativado)`"
    )
    cats  = len(settings.get("gifs_postadores_categories", []))
    roles = len(settings.get("gifs_postadores_allowed_roles", []))

    embed = discord.Embed(color=settings["embed_color"])
    embed.set_author(name="Central de GIFs - NATA®", icon_url=icon_url)
    if icon_url:
        embed.set_thumbnail(url=icon_url)
    embed.add_field(
        name="<a:alerta:1518271939460857968>  Informações",
        value=(
            f"Status: {status}\n"
            f"Categorias: `{cats}`\n"
            f"Cargos: `{roles}`"
        ),
        inline=False,
    )
    embed.set_footer(
        text=f"Página: Gerenciamento de Postadores(a) • {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


# ── Configurar Sistema — embed principal ──────────────────────────────────────

def _build_config_sistema_embed(author: discord.Member, settings: dict) -> discord.Embed:
    icon_url = bot.user.display_avatar.url if bot.user else None
    guild    = author.guild

    log_id = settings.get("gifs_postadores_log_channel")
    cats   = settings.get("gifs_postadores_categories", [])
    roles  = settings.get("gifs_postadores_allowed_roles", [])

    log_val = (
        guild.get_channel(log_id).mention if log_id and guild and guild.get_channel(log_id)
        else f"<#{log_id}>" if log_id else "`Não definido.`"
    )

    embed = discord.Embed(color=settings["embed_color"])
    embed.set_author(name="Painel de Configuração — Postadores", icon_url=icon_url)
    if icon_url:
        embed.set_thumbnail(url=icon_url)
    embed.add_field(
        name="<a:alerta:1518271939460857968>  Informações",
        value=(
            f"Categorias: `{len(cats)}`\n"
            f"Cargos: `{len(roles)}`\n"
            f"Canal de Logs: {log_val}"
        ),
        inline=False,
    )
    embed.add_field(
        name="<:comunidade_:1518272016971595807>  Observações",
        value=(
            "Adicione os cargos que poderão postar GIFs,\n"
            "e as categorias que vai aplicar a permissão de postagem de cada canal."
        ),
        inline=False,
    )
    embed.set_footer(
        text=f"Pagina: Gerenciamento de Postadores(a) • {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


