# ── View principal: Configurar Sistema ───────────────────────────────────────

class _PostadoresConfigView(discord.ui.View):
    def __init__(self, author):
        super().__init__(timeout=300)
        self.author = author
        self._build()

    def _build(self):
        self.clear_items()
        row0 = [
            ("Voltar",             discord.ButtonStyle.primary,   self._voltar),
            ("Adicionar Categoria",discord.ButtonStyle.secondary, self._add_cat),
            ("Adicionar Cargo",    discord.ButtonStyle.secondary, self._add_cargo),
            ("Adicionar Canal Logs",discord.ButtonStyle.secondary,self._add_log),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0)
            btn.callback = cb
            self.add_item(btn)
        row1 = [
            ("Remover Categoria",    discord.ButtonStyle.danger, self._rem_cat),
            ("Remover Cargo",        discord.ButtonStyle.danger, self._rem_cargo),
            ("Resetar Pontos",       discord.ButtonStyle.danger, self._reset_pts),
            ("Resetar Configurações",discord.ButtonStyle.danger, self._reset_all),
        ]
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1)
            btn.callback = cb
            self.add_item(btn)

    async def interaction_check(self, interaction):
        if interaction.user.id != self.author.id:
            await interaction.response.send_message(
                "Apenas quem abriu este painel pode usá-lo.", ephemeral=True
            )
            return False
        return True

    async def _voltar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_gifs_postadores_embed(interaction.user, settings)
        await interaction.response.edit_message(embed=embed, view=GifsPostadoresView(self.author))

    async def _add_cat(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _postadores_select_embed(
            interaction.user, settings,
            "Adicionar Categoria — Postadores",
            "Selecione canais que deseja adicionar ou remover.",
        )
        await interaction.response.send_message(embed=embed, view=_PCatAddView(self.author), ephemeral=True)

    async def _rem_cat(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _postadores_select_embed(
            interaction.user, settings,
            "Remover Categoria — Postadores",
            "Selecione as categorias que deseja **remover** da lista.",
        )
        await interaction.response.send_message(embed=embed, view=_PCatRemoveView(self.author), ephemeral=True)

    async def _add_cargo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _postadores_select_embed(
            interaction.user, settings,
            "Adicionar Cargo — Postadores",
            "Selecione cargos que deseja adicionar ou remover.",
        )
        await interaction.response.send_message(embed=embed, view=_PCargoAddView(self.author), ephemeral=True)

    async def _rem_cargo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _postadores_select_embed(
            interaction.user, settings,
            "Remover Cargo — Postadores",
            "Selecione os cargos que deseja **remover** da lista de postadores.",
        )
        await interaction.response.send_message(embed=embed, view=_PCargoRemoveView(self.author), ephemeral=True)

    async def _add_log(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _postadores_select_embed(
            interaction.user, settings,
            "Adicionar Canal de Logs — Postadores",
            "Selecione o canal de logs dos postadores.",
        )
        await interaction.response.send_message(embed=embed, view=_PLogAddView(self.author), ephemeral=True)

    async def _reset_pts(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed = discord.Embed(
            description="🔄 Pontos resetados com sucesso.", color=0xFF4444
        )
        embed.set_footer(text=f"NATA® © • {interaction.user.name}", icon_url=icon_url)
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _reset_all(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["gifs_postadores_categories"]    = []
        settings["gifs_postadores_allowed_roles"] = []
        settings["gifs_postadores_log_channel"]   = None
        settings["gifs_postadores_channel"]       = None
        settings["gifs_postadores_enabled"]       = False
        save_settings_to_disk()
        embed = _build_config_sistema_embed(interaction.user, settings)
        await interaction.response.edit_message(embed=embed, view=_PostadoresConfigView(self.author))
        icon_url = bot.user.display_avatar.url if bot.user else None
        reset_embed = discord.Embed(description="🔄 Todas as configurações foram resetadas.", color=0xFF4444)
        reset_embed.set_footer(text=f"NATA® © • {interaction.user.name}", icon_url=icon_url)
        await interaction.followup.send(embed=reset_embed, ephemeral=True)


# ── Selects: Gerenciar Postadores (cargos) ────────────────────────────────────

class _PostadoresRoleSelect(discord.ui.RoleSelect):
    def __init__(self):
        super().__init__(placeholder="Selecione cargos postadores...", min_values=1, max_values=5)

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        existing = settings.get("gifs_postadores_allowed_roles", [])
        added, removed = [], []
        for r in self.values:
            if r.id in existing:
                existing.remove(r.id); removed.append(r.mention)
            else:
                existing.append(r.id); added.append(r.mention)
        settings["gifs_postadores_allowed_roles"] = existing
        save_settings_to_disk()
        embed = _build_gerenciar_roles_embed(interaction.user, settings)
        await interaction.response.edit_message(embed=embed, view=_PostadoresRolesView(interaction.user))
        partes = []
        if added:   partes.append(f"{_e_success()} Adicionados: {', '.join(added)}")
        if removed: partes.append(f"❌ Removidos: {', '.join(removed)}")
        await interaction.followup.send("\n".join(partes) or "Sem alterações.", ephemeral=True)


