class GifsPostadoresView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author and self.author.guild else 0)
        enabled  = settings.get("gifs_postadores_enabled", False)
        toggle_label = "Desativar" if enabled else "Ativar"
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            ("Voltar",                 discord.ButtonStyle.primary,   self._back),
            (toggle_label,             toggle_style,                  self._toggle),
            ("Configurar Sistema",     discord.ButtonStyle.secondary, self._config_sistema),
            ("Gerenciar Postadores",   discord.ButtonStyle.secondary, self._gerenciar),
            ("Listar Configurações",   discord.ButtonStyle.secondary, self._listar),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0)
            btn.callback = cb
            self.add_item(btn)

    async def interaction_check(self, interaction):
        if interaction.user.id != self.author.id:
            await interaction.response.send_message(
                "Apenas quem abriu este painel pode usá-lo.", ephemeral=True
            )
            return False
        return True

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_gifs_embed(self.author, settings)
        view = GifsView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["gifs_postadores_enabled"] = not settings.get("gifs_postadores_enabled", False)
        save_settings_to_disk()
        embed = build_gifs_postadores_embed(self.author, settings)
        await interaction.response.edit_message(embed=embed, view=GifsPostadoresView(self.author))

    async def _config_sistema(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _build_config_sistema_embed(interaction.user, settings)
        view  = _PostadoresConfigView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _gerenciar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _build_gerenciar_user_embed(interaction.user, settings)
        view  = _PostadoresRolesView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _listar(self, interaction: discord.Interaction):
        settings  = get_settings(interaction.guild.id)
        icon_url  = bot.user.display_avatar.url if bot.user else None
        guild     = interaction.guild
        enabled   = settings.get("gifs_postadores_enabled", False)

        ch_id  = settings.get("gifs_postadores_channel")
        log_id = settings.get("gifs_postadores_log_channel")
        cats   = settings.get("gifs_postadores_categories", [])
        roles  = settings.get("gifs_postadores_allowed_roles", [])

        def _ch(cid):
            if not cid: return "`Não definido`"
            ch = guild.get_channel(cid) if guild else None
            return ch.mention if ch else f"<#{cid}>"

        cats_lines  = "\n".join(
            (guild.get_channel(c).name if guild and guild.get_channel(c) else str(c))
            for c in cats
        ) or "`Nenhuma`"
        roles_lines = "\n".join(
            (guild.get_role(r).mention if guild and guild.get_role(r) else f"<@&{r}>")
            for r in roles
        ) or "`Nenhum`"

        status = "<a:online:1518271945550856295> `Ativado`" if enabled else "<a:alerta:1518271939460857968> `Desativado`"

        embed = discord.Embed(title="Listar Configurações — Postadores", color=settings["embed_color"])
        embed.set_author(name="Central de GIFs - NATA®", icon_url=icon_url)
        embed.add_field(name="Status",            value=status,           inline=True)
        embed.add_field(name="Canal de Postagem", value=_ch(ch_id),       inline=True)
        embed.add_field(name="Canal de Logs",     value=_ch(log_id),      inline=True)
        embed.add_field(name="Categorias",        value=cats_lines,       inline=False)
        embed.add_field(name="Cargos",            value=roles_lines,      inline=False)
        embed.set_footer(text=f"NATA® © • {self.author.name}", icon_url=icon_url)
        embed.timestamp = datetime.now()
        await interaction.response.send_message(embed=embed, ephemeral=True)


