class GifsView(discord.ui.View):
    def __init__(self, author: discord.Member | None = None):
        super().__init__(timeout=None)   # persistent — sobrevive a restarts
        self.author = author
        guild_id = author.guild.id if (author and author.guild) else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]
        self.add_item(GifsMenuSelect(placeholder=t["gifs_menu_placeholder"], lang=settings["language"]))

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        # Permite qualquer usuário autorizado (sem verificação de autor)
        # necessário para continuar funcionando após restarts do bot
        guild_id = interaction.guild.id if interaction.guild else 0
        settings = get_settings(guild_id)
        if not is_authorized(interaction.user, settings):
            lang = settings["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True


