class EntretenimentoMenuSelect(discord.ui.Select):
    def __init__(self, placeholder: str, lang: str = "pt-br"):
        t = TRANSLATIONS[lang]
        options = [
            discord.SelectOption(
                label=t[label_key],
                description=t[desc_key],
                emoji=_make_select_emoji(emoji),
                value=value,
            )
            for value, label_key, emoji, desc_key in ENTRETENIMENTO_MENU_OPTIONS
        ]
        super().__init__(placeholder=placeholder, min_values=1, max_values=1, options=options)

    async def callback(self, interaction: discord.Interaction):
        guild_id = interaction.guild.id if interaction.guild else 0
        settings = get_settings(guild_id)
        selected = self.values[0]

        if selected == "home_entretenimento":
            embed = build_main_embed(interaction.user, settings["language"])
            view = MenuView(interaction.user.id, lang=settings["language"])
            await interaction.response.edit_message(embed=embed, view=view)
            return

        if selected == "ent_calendario":
            embed = build_calendario_embed(interaction.user, settings)
            view = CalendarioView(interaction.user)
            await interaction.response.edit_message(embed=embed, view=view)
            return

        if selected == "ent_instagram":
            embed = build_instagram_embed(interaction.user, settings)
            view = InstagramView(interaction.user)
            await interaction.response.edit_message(embed=embed, view=view)
            return

        if selected == "ent_tellonym":
            embed = build_tellonym_embed(interaction.user, settings)
            view = TellonymView(interaction.user)
            await interaction.response.edit_message(embed=embed, view=view)
            return

        labels = {opt.value: opt.label for opt in self.options}
        await interaction.response.send_message(
            f"{TRANSLATIONS[settings['language']]['coming_soon']} (**{labels[selected]}**)",
            ephemeral=True,
        )


