def build_calendario_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["cal_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    enabled = settings.get("calendar_enabled", False)
    status_value = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else "<a:alerta:1518271939460857968> `(Desativado)`"
    )

    guild = author.guild
    nd = f"`{t['not_defined']}`"

    def _ch(key: str) -> str:
        cid = settings.get(key)
        if not cid or not guild:
            return nd
        ch = guild.get_channel(cid)
        return ch.mention if ch else nd

    cargo_id = settings.get("calendar_role")
    cargo = guild.get_role(cargo_id) if (guild and cargo_id) else None
    cargo_value = cargo.mention if cargo else nd

    msg = settings.get("calendar_message") or "🎉 Parabéns, {member}! 🎂 Que seu dia seja incrível! 🎁"

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"┃ **Status:** {status_value}\n"
            f"**{t['cal_canal_cal_label']}:** {_ch('calendar_calendar_channel')}\n"
            f"**{t['cal_canal_parabens_label']}:** {_ch('calendar_birthday_channel')}\n"
            f"**{t['cal_cargo_label']}:** {cargo_value}\n"
            f"**{t['cal_mensagem_label']}:**\n```{msg[:200]}```"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['advertencia_observations']}",
        value=(
            f"**{t['cal_cargo_label']}:** {t['cal_obs_cargo']}\n"
            f"**{t['cal_canal_parabens_label']}:** {t['cal_obs_canal']}"
        ),
        inline=False,
    )
    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class CalendarioCanaisModal(discord.ui.Modal):
    def __init__(self, parent_view: "CalendarioView", t: dict):
        super().__init__(title=t["cal_canais_modal_title"], timeout=300)
        self.parent_view = parent_view
        settings = get_settings(parent_view.author.guild.id)
        self.cal_inp = discord.ui.TextInput(
            label=t["cal_input_calendar_id"], required=True, max_length=30,
            default=str(settings.get("calendar_calendar_channel") or "") or None,
        )
        self.bday_inp = discord.ui.TextInput(
            label=t["cal_input_birthday_id"], required=True, max_length=30,
            default=str(settings.get("calendar_birthday_channel") or "") or None,
        )
        self.add_item(self.cal_inp)
        self.add_item(self.bday_inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]

        def _parse(s: str) -> int | None:
            s = s.strip().strip("<#>").strip("# ")
            if not s:
                return None
            try:
                return int(s)
            except ValueError:
                return None

        cal_id = _parse(self.cal_inp.value)
        bday_id = _parse(self.bday_inp.value)
        if not cal_id or not bday_id:
            await interaction.response.send_message(embed=_notif_embed(t["cal_invalid_channel_id"]), ephemeral=True)
            return
        settings["calendar_calendar_channel"] = cal_id
        settings["calendar_birthday_channel"] = bday_id
        embed = build_calendario_embed(self.parent_view.author, settings)
        view = CalendarioView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["cal_canais_updated"]), ephemeral=True)


class CalendarioView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=300)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("calendar_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_configurar_canais_cal"], discord.ButtonStyle.secondary, self._canais),
            (t["btn_configurar_cargo_cal"], discord.ButtonStyle.secondary, self._cargo),
            (t["btn_configurar_mensagem_cal"], discord.ButtonStyle.secondary, self._mensagem),
        ]
        row1 = [
            (t["btn_ver_aniversarios"], discord.ButtonStyle.primary, self._ver_aniv),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=None)
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_entretenimento_embed(self.author, settings)
        view = EntretenimentoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["calendar_enabled"] = not settings.get("calendar_enabled", False)
        embed = build_calendario_embed(self.author, settings)
        view = CalendarioView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["cal_activated"] if settings["calendar_enabled"] else t["cal_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = CalendarioCanaisModal(self, t)
        await interaction.response.send_modal(modal)

    async def _wait_for_chat(self, interaction: discord.Interaction, prompt: str) -> str | None:
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        await interaction.response.send_message(prompt, ephemeral=True)

        def check(m: discord.Message) -> bool:
            return m.author.id == self.author.id and m.channel.id == interaction.channel.id

        try:
            msg = await bot.wait_for("message", check=check, timeout=60)
        except asyncio.TimeoutError:
            await interaction.followup.send(embed=_notif_embed(t["cal_timed_out"]), ephemeral=True)
            return None

        content = msg.content.strip()
        try:
            await msg.delete()
        except (discord.Forbidden, discord.NotFound):
            pass

        if content.lower() in ("cancelar", "cancel"):
            await interaction.followup.send(embed=_notif_embed(t["cal_cancelled"]), ephemeral=True)
            return None
        return content

    async def _cargo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        content = await self._wait_for_chat(interaction, t["cal_prompt_cargo"])
        if content is None:
            return
        raw = content.strip().strip("<@&>")
        try:
            rid = int(raw)
        except ValueError:
            await interaction.followup.send(embed=_notif_embed(t["cal_invalid_role"]), ephemeral=True)
            return
        role = interaction.guild.get_role(rid) if interaction.guild else None
        if not role:
            await interaction.followup.send(embed=_notif_embed(t["cal_invalid_role"]), ephemeral=True)
            return
        settings["calendar_role"] = role.id
        embed = build_calendario_embed(self.author, settings)
        view = CalendarioView(self.author)
        try:
            await interaction.edit_original_response(embed=embed, view=view)
        except (discord.HTTPException, discord.NotFound):
            pass
        await interaction.followup.send(
            t["cal_cargo_set"].format(role=role.mention), ephemeral=True
        )

    async def _mensagem(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        content = await self._wait_for_chat(interaction, t["cal_prompt_mensagem"])
        if content is None:
            return
        settings["calendar_message"] = content[:1500]
        embed = build_calendario_embed(self.author, settings)
        view = CalendarioView(self.author)
        try:
            await interaction.edit_original_response(embed=embed, view=view)
        except (discord.HTTPException, discord.NotFound):
            pass
        await interaction.followup.send(embed=_notif_embed(t["cal_mensagem_set"]), ephemeral=True)

    async def _ver_aniv(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        birthdays = settings.get("calendar_birthdays", {})
        if not birthdays:
            embed = discord.Embed(
                title=f"📅 {t['cal_no_birthdays_title']}",
                description=t["cal_no_birthdays_desc"],
                color=settings["embed_color"],
            )
            await interaction.response.send_message(embed=embed, ephemeral=True)
            return
        lines = []
        for uid, date_str in list(birthdays.items())[:50]:
            lines.append(f"• <@{uid}> — `{date_str}`")
        embed = discord.Embed(
            title=t["cal_birthdays_title"],
            description="\n".join(lines)[:4000],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)


