def build_instagram_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["ig_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    enabled = settings.get("ig_enabled", False)
    status_value = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else "<a:alerta:1518271939460857968> `(Desativado)`"
    )

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=f"┃ **Status:** {status_value}",
        inline=False,
    )

    channels = settings.get("ig_channels", [])
    if channels and author.guild:
        mentions = []
        for entry in channels[:5]:
            ch = author.guild.get_channel(entry.get("post_channel_id") or 0)
            mentions.append(ch.mention if ch else f"<#{entry.get('post_channel_id')}>")
        chan_text = " ".join(mentions)
        if len(channels) > 5:
            chan_text += f" `+{len(channels) - 5}`"
    else:
        chan_text = f"`{t['ig_no_channels']}`"

    embed.add_field(
        name=f"**{t['ig_canais_configurados']}:**",
        value=chan_text,
        inline=False,
    )

    # Limpar Destaque global (yes if any channel has clear_highlight True)
    any_clear = any(c.get("clear_highlight") for c in channels)
    limpar_value = f"`{t['ig_clear_yes'] if any_clear else t['ig_clear_no']}`"
    msg_value = (
        f"`{t['ig_emojis_configurado']}`" if settings.get("ig_mensagem")
        else f"`{t['ig_msg_nao_config']}`"
    )
    canal_msg_id = settings.get("ig_canal_mensagem")
    if canal_msg_id and author.guild:
        ch = author.guild.get_channel(canal_msg_id)
        canal_msg_value = ch.mention if ch else f"<#{canal_msg_id}>"
    else:
        canal_msg_value = t["ig_canal_nao_config"]

    embed.add_field(
        name=f"**{t['ig_config_globais']}:**",
        value=(
            f"**{t['ig_limpar_destaque']}:** {limpar_value}\n"
            f"**{t['ig_emojis_botoes']}:** `{t['ig_emojis_configurado']}`\n"
            f"**{t['ig_msg_armazenada']}:** {msg_value}\n"
            f"**{t['ig_canal_msg']}:** {canal_msg_value}"
        ),
        inline=False,
    )

    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['advertencia_observations']}",
        value=f"{t['ig_obs_text']}\n\n> {t['ig_obs_quote']}",
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


