class IgConfigView(discord.ui.View):
    def __init__(self, parent_view: "InstagramView"):
        super().__init__(timeout=300)
        self.parent_view = parent_view
        self.draft: dict = {
            "post_channel_id": None,
            "highlight_channel_id": None,
            "role_id": None,
            "clear_highlight": False,
        }
        settings = get_settings(parent_view.author.guild.id)
        t = TRANSLATIONS[settings["language"]]
        self.add_item(IgConfigPostChannelSelect(self.draft, t))
        self.add_item(IgConfigDestChannelSelect(self.draft, t))
        self.add_item(IgConfigRoleSelect(self.draft, t))
        self.add_item(IgConfigClearSelect(self.draft, t))

        save_btn = discord.ui.Button(
            label=t["btn_salvar_botao"], style=discord.ButtonStyle.success,
            emoji="<a:online:1518271945550856295>", row=4,
        )
        save_btn.callback = self._save
        self.add_item(save_btn)
        cancel_btn = discord.ui.Button(
            label=t["btn_cancelar"], style=discord.ButtonStyle.danger, row=4,
        )
        cancel_btn.callback = self._cancel
        self.add_item(cancel_btn)

    async def _save(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if not self.draft.get("post_channel_id") or not self.draft.get("highlight_channel_id"):
            await interaction.response.send_message(embed=_notif_embed(t["panelv2_invalid_value"]), ephemeral=True)
            return
        settings.setdefault("ig_channels", []).append(self.draft.copy())
        # Update main panel
        embed = build_instagram_embed(self.parent_view.author, settings)
        new_view = InstagramView(self.parent_view.author)
        try:
            await interaction.response.edit_message(
                content=t["ig_channel_added"], embed=embed, view=None
            )
        except discord.HTTPException:
            await interaction.response.send_message(embed=_notif_embed(t["ig_channel_added"]), ephemeral=True)

    async def _cancel(self, interaction: discord.Interaction):
        try:
            await interaction.response.edit_message(content="Cancelado.", view=None, embed=None)
        except discord.HTTPException:
            await interaction.response.defer()


class IgDeleteSpecificSelect(discord.ui.Select):
    def __init__(self, parent_view: "InstagramView", t: dict, guild: discord.Guild):
        channels = get_settings(parent_view.author.guild.id).get("ig_channels", [])
        options = []
        for i, entry in enumerate(channels[:25]):
            cid = entry.get("post_channel_id")
            ch = guild.get_channel(cid) if (guild and cid) else None
            options.append(discord.SelectOption(
                label=(ch.name if ch else f"#{cid}")[:100], value=str(i),
            ))
        if not options:
            options = [discord.SelectOption(label="—", value="__none__")]
        super().__init__(placeholder=t["ig_delete_specific_placeholder"],
                         min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        if self.values[0] == "__none__":
            await interaction.response.defer()
            return
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        idx = int(self.values[0])
        channels = settings.get("ig_channels", [])
        if 0 <= idx < len(channels):
            channels.pop(idx)
        await interaction.response.send_message(embed=_notif_embed(t["ig_canal_deleted"]), ephemeral=True)


class IgDeleteSelect(discord.ui.Select):
    def __init__(self, parent_view: "InstagramView", t: dict):
        options = [
            discord.SelectOption(label=t["ig_delete_all"], description=t["ig_delete_all_desc"],
                                 value="all", emoji=_make_select_emoji("<a:alerta:1518271939460857968>")),
            discord.SelectOption(label=t["ig_delete_emojis"], description=t["ig_delete_emojis_desc"],
                                 value="emojis", emoji=_make_select_emoji("<:ferramentas_:1518271998613131274>")),
            discord.SelectOption(label=t["ig_delete_destaque"], description=t["ig_delete_destaque_desc"],
                                 value="destaque", emoji=_make_select_emoji("<:tickets:1518271952526250155>")),
            discord.SelectOption(label=t["ig_delete_specific"], description=t["ig_delete_specific_desc"],
                                 value="specific", emoji=_make_select_emoji("<:gifs:1518272035762081835>")),
        ]
        super().__init__(placeholder=t["ig_delete_placeholder"],
                         min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        v = self.values[0]
        if v == "all":
            settings["ig_channels"] = []
            await interaction.response.send_message(embed=_notif_embed(t["ig_canais_deleted"]), ephemeral=True)
        elif v == "emojis":
            settings["ig_emojis"] = {
                "destaque": "🏆", "curtir": "💗", "comentar": "💬",
                "ver_curtidas": "❤️", "ver_comentarios": "💭",
                "botao_instagram": "📷", "deletar": "🗑️",
            }
            await interaction.response.send_message(embed=_notif_embed(t["ig_emojis_reset_done"]), ephemeral=True)
        elif v == "destaque":
            for entry in settings.get("ig_channels", []):
                entry["clear_highlight"] = False
            settings["ig_last_highlight"] = {}
            await interaction.response.send_message(embed=_notif_embed(t["ig_destaque_reset_done"]), ephemeral=True)
        elif v == "specific":
            sub_view = _SingleSelectView(IgDeleteSpecificSelect(self.parent_view, t, interaction.guild))
            await interaction.response.send_message(
                t["ig_delete_specific_placeholder"], view=sub_view, ephemeral=True
            )


def build_ig_emojis_embed(settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["ig_emojis_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)
    embed.description = t["ig_emojis_subtitle"]
    emj = settings.get("ig_emojis", {})

    def _line(key: str, label_key: str) -> str:
        return f"**{t[label_key]}:** {emj.get(key, '?')}"

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ig_emojis_atuais']}",
        value=(
            f"{_line('destaque', 'ig_emoji_destaque')}\n"
            f"{_line('curtir', 'ig_emoji_curtir')}\n"
            f"{_line('comentar', 'ig_emoji_comentar')}\n"
            f"{_line('ver_curtidas', 'ig_emoji_ver_curtidas')}\n"
            f"{_line('ver_comentarios', 'ig_emoji_ver_comentarios')}\n"
            f"{_line('botao_instagram', 'ig_emoji_botao_ig')}\n"
            f"{_line('deletar', 'ig_emoji_deletar')}"
        ),
        inline=False,
    )
    embed.set_footer(text=_footer_name(settings=settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class IgEmojiModal(discord.ui.Modal):
    def __init__(self, parent_view: "IgEmojisView", key: str, t: dict):
        super().__init__(title=t["ig_emoji_modal_title"].format(name=t[f"ig_emoji_{key}"]), timeout=600)
        self.parent_view = parent_view
        self.key = key
        settings = get_settings(parent_view.author.guild.id)
        self.inp = discord.ui.TextInput(
            label=t["ig_emoji_input_label"],
            placeholder=t["ig_emoji_input_placeholder"],
            required=True, max_length=100,
            default=settings.get("ig_emojis", {}).get(key),
        )
        self.add_item(self.inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        emj = settings.setdefault("ig_emojis", {})
        emj[self.key] = self.inp.value.strip()
        embed = build_ig_emojis_embed(settings)
        new_view = IgEmojisView(self.parent_view.author, standalone=self.parent_view.standalone)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(
            t["ig_emoji_set"].format(name=t[f"ig_emoji_{self.key}"]), ephemeral=True
        )


class IgEmojisView(discord.ui.View):
    def __init__(self, author: discord.Member, standalone: bool = False):
        super().__init__(timeout=300)
        self.author = author
        self.standalone = standalone
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        if not self.standalone:
            back_btn = discord.ui.Button(
                label=t["back"], style=discord.ButtonStyle.primary,
                emoji=_button_emoji(discord.ButtonStyle.primary), row=0,
            )
            back_btn.callback = self._back
            self.add_item(back_btn)

        row0_items = [
            ("destaque", "ig_emoji_destaque", 0),
            ("curtir", "ig_emoji_curtir", 0),
            ("comentar", "ig_emoji_comentar", 0),
            ("ver_curtidas", "ig_emoji_ver_curtidas", 0),
        ]
        row1_items = [
            ("ver_comentarios", "ig_emoji_ver_comentarios", 1),
            ("botao_instagram", "ig_emoji_botao_ig", 1),
            ("deletar", "ig_emoji_deletar", 1),
        ]
        for key, lk, row in row0_items + row1_items:
            btn = discord.ui.Button(label=t[lk], style=discord.ButtonStyle.secondary, row=row)
            btn.callback = self._make_cb(key)
            self.add_item(btn)

        reset_btn = discord.ui.Button(
            label="Resetar Emojis", style=discord.ButtonStyle.danger,
            emoji="<a:alerta:1518271939460857968>", row=1,
        )
        reset_btn.callback = self._reset
        self.add_item(reset_btn)

    def _make_cb(self, key: str):
        async def cb(interaction: discord.Interaction):
            settings = get_settings(interaction.guild.id)
            t = TRANSLATIONS[settings["language"]]
            modal = IgEmojiModal(self, key, t)
            await interaction.response.send_modal(modal)
        return cb

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_instagram_embed(self.author, settings)
        view = InstagramView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["ig_emojis"] = {
            "destaque": "🏆", "curtir": "💗", "comentar": "💬",
            "ver_curtidas": "❤️", "ver_comentarios": "💭",
            "botao_instagram": "📷", "deletar": "🗑️",
        }
        embed = build_ig_emojis_embed(settings)
        new_view = IgEmojisView(self.author, standalone=self.standalone)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["ig_emojis_reset_done"]), ephemeral=True)


