class InstagramView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=300)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("ig_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_configurar_sistema"], discord.ButtonStyle.secondary, self._configurar_sistema),
            (t["btn_deletar_config"], discord.ButtonStyle.secondary, self._deletar),
        ]
        row1 = [
            (t["btn_configurar_emojis"], discord.ButtonStyle.secondary, self._cfg_emojis),
            (t["btn_configurar_msg"], discord.ButtonStyle.secondary, self._cfg_msg),
            (t["btn_resetar_destaque"], discord.ButtonStyle.danger, self._reset_destaque),
            (t["btn_resetar_tudo_simples_ig"], discord.ButtonStyle.danger, self._reset_all),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_entretenimento_embed(self.author, settings)
        view = EntretenimentoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["ig_enabled"] = not settings.get("ig_enabled", False)
        embed = build_instagram_embed(self.author, settings)
        view = InstagramView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["ig_activated"] if settings["ig_enabled"] else t["ig_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _configurar_sistema(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = IgConfigView(self)
        await interaction.response.send_message(embed=_notif_embed(t["ig_modal_title"]), view=view, ephemeral=True)

    async def _deletar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        embed = discord.Embed(
            title=t["ig_delete_title"], description=t["ig_delete_desc"],
            color=settings["embed_color"],
        )
        embed.set_footer(text=_footer_name(interaction.guild))
        view = _SingleSelectView(IgDeleteSelect(self, t))
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _cfg_emojis(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_ig_emojis_embed(settings)
        view = IgEmojisView(self.author, standalone=True)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _cfg_msg(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        embed = discord.Embed(
            description=t["ig_msg_panel_desc"], color=settings["embed_color"],
        )
        view = IgMsgPanelView(self)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _reset_destaque(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        for entry in settings.get("ig_channels", []):
            entry["clear_highlight"] = False
        settings["ig_last_highlight"] = {}
        embed = build_instagram_embed(self.author, settings)
        view = InstagramView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["ig_destaque_reset_done"]), ephemeral=True)

    async def _reset_all(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["ig_enabled"] = False
        settings["ig_channels"] = []
        settings["ig_emojis"] = {
            "destaque": "🏆", "curtir": "💗", "comentar": "💬",
            "ver_curtidas": "❤️", "ver_comentarios": "💭",
            "botao_instagram": "📷", "deletar": "🗑️",
        }
        settings["ig_mensagem"] = None
        settings["ig_canal_mensagem"] = None
        settings["ig_last_highlight"] = {}
        embed = build_instagram_embed(self.author, settings)
        view = InstagramView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["ig_reset_done"]), ephemeral=True)


