def build_tellonym_embed(author: discord.Member, settings: dict) -> discord.Embed:
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    guild = author.guild if hasattr(author, "guild") else None

    embed.set_author(name=f"Painel Tellonym — {_footer_name(guild, settings)}", icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    def _ch(cid):
        if not cid:
            return "`Não definido`"
        ch_obj = guild.get_channel(cid) if guild else None
        return ch_obj.mention if ch_obj else f"<#{cid}>"

    embed.add_field(
        name="<:entretenimento_:1518271992191779038>  Canais de Criação",
        value=(
            f"**Criação:** {_ch(settings.get('tellonym_creation_channel'))}\n"
            f"**Tellonym:** {_ch(settings.get('tellonym_channel'))}\n"
            f"**Logs:** {_ch(settings.get('tellonym_log_channel'))}\n"
            f"**Filtro:** {_ch(settings.get('tellonym_filter_channel'))}"
        ),
        inline=False,
    )

    roles   = settings.get("tellonym_allowed_roles", [])
    blocked = settings.get("tellonym_blocked_users", [])
    bar     = settings.get("tellonym_custom_bar")

    embed.add_field(
        name="<:seguranca:1518271987393232936>  Configurações Opcionais",
        value=(
            f"**Cargos Permitidos:** `{len(roles)} configurado(s)`\n"
            f"**Barrinha Personalizada:** `{'Barrinha Configurada!' if bar else 'Padrão'}`\n"
            f"**Usuários Bloqueados:** `{len(blocked)}`"
        ),
        inline=False,
    )

    embed.add_field(
        name="<:comunidade_:1518272016971595807>  Observações Gerais",
        value=(
            "Configurando o canal de filtro, os tellonyms serão enviados para "
            "aprovação antes de chegarem ao canal principal."
        ),
        inline=False,
    )

    embed.set_footer(text=f"Central de Configurações — {_footer_name(guild, settings)}", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


def build_tellonym_blocked_embed(author: discord.Member, settings: dict) -> discord.Embed:
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    guild = author.guild if hasattr(author, "guild") else None
    embed.set_author(name="Painel de Usuários Bloqueados", icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    blocked = settings.get("tellonym_blocked_users", [])
    if blocked:
        lines = []
        for uid in blocked[:20]:
            m = guild.get_member(uid) if guild else None
            lines.append(m.mention if m else f"`{uid}`")
        if len(blocked) > 20:
            lines.append(f"+{len(blocked) - 20} mais...")
        blocked_val = "  ".join(lines)
    else:
        blocked_val = "`Nenhum Usuário Bloqueado`"

    embed.add_field(name="👥  Usuários Bloqueados", value=blocked_val, inline=False)
    embed.add_field(
        name="<:comunidade_:1518272016971595807>  Observações",
        value="Os usuários listados acima estão bloqueados de usar o Tellonym.",
        inline=False,
    )
    embed.set_footer(text=f"Central de Configurações — {_footer_name(guild, settings)}", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


def _build_tellonym_message_embed(content: str, settings: dict) -> discord.Embed:
    bar = settings.get("tellonym_custom_bar") or "━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    embed = discord.Embed(
        description=f"{bar}\n{content[:1000]}\n{bar}",
        color=settings["embed_color"],
    )
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_footer(text="💬 Tellonym Anônimo", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


async def _tellonym_log(guild: discord.Guild, settings: dict, action: str, sender_id: int, content: str):
    log_ch_id = settings.get("tellonym_log_channel")
    if not log_ch_id:
        return
    log_ch = guild.get_channel(log_ch_id)
    if not log_ch:
        return
    try:
        sender = guild.get_member(sender_id)
        sender_str = sender.mention if sender else f"`{sender_id}`"
        embed = discord.Embed(
            color=settings["embed_color"],
            description=f"{action}\n**Remetente:** {sender_str} (`{sender_id}`)\n**Conteúdo:** {content[:500]}",
        )
        embed.set_footer(text="Tellonym — Log")
        embed.timestamp = datetime.now()
        await log_ch.send(embed=embed)
    except (discord.Forbidden, discord.HTTPException):
        pass


async def _process_tellonym_message(message: discord.Message, settings: dict):
    """Processa mensagem enviada no canal de criação do Tellonym."""
    # Usuário bloqueado
    if message.author.id in settings.get("tellonym_blocked_users", []):
        try:
            await message.delete()
            await message.author.send("❌ Você está bloqueado de usar o Tellonym neste servidor.")
        except Exception:
            pass
        return

    # Cargos permitidos (se configurado — vazio = todos podem)
    allowed_roles = settings.get("tellonym_allowed_roles", [])
    if allowed_roles:
        member_role_ids = {r.id for r in message.author.roles}
        if not member_role_ids.intersection(set(allowed_roles)):
            try:
                await message.delete()
                await message.author.send("❌ Você não tem permissão para usar o Tellonym neste servidor.")
            except Exception:
                pass
            return

    content = message.content.strip()
    if not content:
        try:
            await message.delete()
        except Exception:
            pass
        return

    # Deleta a mensagem original (preserva anonimato)
    try:
        await message.delete()
    except (discord.Forbidden, discord.HTTPException):
        pass

    guild = message.guild
    filter_ch_id = settings.get("tellonym_filter_channel")

    if filter_ch_id:
        filter_ch = guild.get_channel(filter_ch_id)
        if filter_ch:
            embed = discord.Embed(
                color=settings["embed_color"],
                description=f"📨 **Tellonym aguardando aprovação:**\n\n{content[:1000]}",
            )
            embed.set_footer(text="Use os botões abaixo para aprovar ou rejeitar.")
            embed.timestamp = datetime.now()
            view = TellonymFilterView(guild.id, message.author.id, content)
            await filter_ch.send(embed=embed, view=view)
            await _tellonym_log(guild, settings, "📨 Tellonym recebido (aguardando filtro)", message.author.id, content)
            return

    # Sem filtro: publica direto
    tell_ch_id = settings.get("tellonym_channel")
    if tell_ch_id:
        tell_ch = guild.get_channel(tell_ch_id)
        if tell_ch:
            embed = _build_tellonym_message_embed(content, settings)
            await tell_ch.send(embed=embed)

    await _tellonym_log(guild, settings, "📨 Tellonym publicado", message.author.id, content)


class TellonymFilterView(discord.ui.View):
    def __init__(self, guild_id: int, sender_id: int, content: str):
        super().__init__(timeout=86400)  # 24 horas
        self.guild_id  = guild_id
        self.sender_id = sender_id
        self.content   = content

        apv = discord.ui.Button(label="Aprovar", style=discord.ButtonStyle.success,
                                emoji=discord.PartialEmoji.from_str(EMOJI_CHECK))
        apv.callback = self._aprovar
        rej = discord.ui.Button(label="Rejeitar", style=discord.ButtonStyle.danger,
                                emoji=discord.PartialEmoji.from_str(EMOJI_DANGER))
        rej.callback = self._rejeitar
        self.add_item(apv)
        self.add_item(rej)

    async def _aprovar(self, interaction: discord.Interaction):
        settings = get_settings(self.guild_id)
        tell_ch_id = settings.get("tellonym_channel")
        if not tell_ch_id:
            await interaction.response.send_message("Canal Tellonym não configurado.", ephemeral=True)
            return
        tell_ch = interaction.guild.get_channel(tell_ch_id)
        if not tell_ch:
            await interaction.response.send_message("Canal Tellonym não encontrado.", ephemeral=True)
            return
        embed = _build_tellonym_message_embed(self.content, settings)
        await tell_ch.send(embed=embed)
        await _tellonym_log(interaction.guild, settings,
                            f"✅ Tellonym aprovado por {interaction.user.mention}",
                            self.sender_id, self.content)
        await interaction.response.edit_message(
            content=f"✅ Aprovado por {interaction.user.mention}", embed=None, view=None
        )

    async def _rejeitar(self, interaction: discord.Interaction):
        settings = get_settings(self.guild_id)
        await _tellonym_log(interaction.guild, settings,
                            f"❌ Tellonym rejeitado por {interaction.user.mention}",
                            self.sender_id, self.content)
        await interaction.response.edit_message(
            content=f"❌ Rejeitado por {interaction.user.mention}", embed=None, view=None
        )


def _build_tellonym_setup_embed(author: discord.Member, settings: dict) -> discord.Embed:
    guild = author.guild if hasattr(author, "guild") else None
    icon_url = bot.user.display_avatar.url if bot.user else None

    def _ch(cid):
        if not cid:
            return "`Não selecionado`"
        ch_obj = guild.get_channel(cid) if guild else None
        return ch_obj.mention if ch_obj else f"<#{cid}>"

    embed = discord.Embed(color=settings["embed_color"])
    embed.set_author(name=f"Painel Tellonym — {_footer_name(guild, settings)}", icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)
    embed.add_field(
        name="<:entretenimento_:1518271992191779038>  Configure os canais",
        value=(
            "Selecione cada canal usando os menus abaixo.\n"
            "As seleções são **salvas automaticamente**.\n\n"
            f"**Canal de Criação \\*:** {_ch(settings.get('tellonym_creation_channel'))}\n"
            f"**Canal do Tellonym \\*:** {_ch(settings.get('tellonym_channel'))}\n"
            f"**Canal do Filtro:** {_ch(settings.get('tellonym_filter_channel'))} *(opcional)*\n"
            f"**Canal de Logs \\*:** {_ch(settings.get('tellonym_log_channel'))}"
        ),
        inline=False,
    )
    embed.set_footer(text="\\* = obrigatório", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


