class TellonymChannelSetupView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=120)
        self.author = author
        self.add_item(_TellCriaSelect(author))
        self.add_item(_TellTellSelect(author))
        self.add_item(_TellFiltSelect(author))
        self.add_item(_TellLogSelect(author))

        clr_btn = discord.ui.Button(label="🗑️ Limpar Canal de Filtro", style=discord.ButtonStyle.secondary, row=4)
        clr_btn.callback = self._clear_filter
        self.add_item(clr_btn)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(TRANSLATIONS[lang]["only_author"], ephemeral=True)
            return False
        return True

    async def _clear_filter(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        settings["tellonym_filter_channel"] = None
        embed = _build_tellonym_setup_embed(self.author, settings)
        await interaction.response.edit_message(embed=embed)


class TellonymChannelsModal(discord.ui.Modal):
    def __init__(self, parent_view: "TellonymView"):
        super().__init__(title="Configure os canais do Tellonym", timeout=120)
        self.parent_view = parent_view
        settings = get_settings(parent_view.author.guild.id)
        guild = parent_view.author.guild

        def _ch_name(key: str) -> str | None:
            cid = settings.get(key)
            if not cid:
                return None
            ch = guild.get_channel(cid) if guild else None
            return f"#{ch.name}" if ch else str(cid)

        self.criar = discord.ui.TextInput(
            label="ADICIONE O CANAL PARA CRIAR TELLONYM *",
            placeholder="Coloque o ID do canal aqui",
            default=_ch_name("tellonym_creation_channel"),
            required=True, max_length=30,
        )
        self.tell = discord.ui.TextInput(
            label="ADICIONE O CANAL DO TELLONYM *",
            placeholder="Coloque o ID do canal aqui",
            default=_ch_name("tellonym_channel"),
            required=True, max_length=30,
        )
        self.filtro = discord.ui.TextInput(
            label="ADICIONE O CANAL DO FILTRO",
            placeholder="Não preencha caso queira o filtro desativado.",
            default=_ch_name("tellonym_filter_channel"),
            required=False, max_length=30,
        )
        self.log = discord.ui.TextInput(
            label="ADICIONE O CANAL DE LOGS *",
            placeholder="Coloque o ID do canal aqui",
            default=_ch_name("tellonym_log_channel"),
            required=True, max_length=30,
        )
        for item in (self.criar, self.tell, self.filtro, self.log):
            self.add_item(item)

    async def on_submit(self, interaction: discord.Interaction):
        guild = interaction.guild

        def _parse(s: str) -> int | None:
            s = s.strip().strip("<#>").lstrip("# ").strip()
            if not s:
                return None
            try:
                return int(s)
            except ValueError:
                pass
            ch = discord.utils.get(guild.text_channels, name=s.lstrip("#"))
            return ch.id if ch else None

        criar_id = _parse(self.criar.value)
        tell_id  = _parse(self.tell.value)
        filt_id  = _parse(self.filtro.value) if self.filtro.value.strip() else None
        log_id   = _parse(self.log.value)

        if not criar_id or not tell_id or not log_id:
            await interaction.response.send_message(
                "❌ Canal não encontrado. Use o ID numérico do canal (clique com o botão direito → Copiar ID).",
                ephemeral=True,
            )
            return

        settings = get_settings(guild.id)
        settings["tellonym_creation_channel"] = criar_id
        settings["tellonym_channel"]          = tell_id
        settings["tellonym_filter_channel"]   = filt_id
        settings["tellonym_log_channel"]      = log_id

        embed = build_tellonym_embed(self.parent_view.author, settings)
        await interaction.response.edit_message(embed=embed, view=TellonymView(self.parent_view.author))
        await interaction.followup.send("✅ Canais do Tellonym configurados!", ephemeral=True)


class TellonymBarModal(discord.ui.Modal):
    def __init__(self, parent_view: "TellonymView"):
        super().__init__(title="Barrinha Personalizada — Tellonym", timeout=120)
