    embed.add_field(
        name=f"ⓘ  {t['grupos_cargos_label']}",
        value=cargos_value,
        inline=True,
    )
    embed.add_field(
        name=f"ⓘ  {t['grupos_usuarios_label']}",
        value=usuarios_value,
        inline=True,
    )
    embed.add_field(
        name=f"👤  {t['advertencia_observations']}",
        value=t["editando_obs_text"],
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


