class EditarTipoSelect(discord.ui.Select):
    def __init__(self, parent_view: "EditandoCargosView", t: dict):
        options = [
            discord.SelectOption(
                label=t["editar_choice_cargo_label"],
                description=t["editar_choice_cargo_desc"],
                value="cargo",
            ),
            discord.SelectOption(
                label=t["editar_choice_usuario_label"],
                description=t["editar_choice_usuario_desc"],
                value="usuario",
            ),
        ]
        super().__init__(
            placeholder=t["editar_choice_placeholder"],
            min_values=1,
            max_values=1,
            options=options,
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        kind = self.values[0]
        guild = interaction.guild

        if kind == "cargo":
            grupos = settings.get("protecao_grupos_cargos", {})
            title = t["editar_grupo_cargo_title"]
            quote = t["editar_grupo_quote_cargo"]
            count_template = t["editar_grupo_count_cargo"]
        else:
            grupos = settings.get("protecao_grupos_usuarios", {})
            title = t["editar_grupo_usuario_title"]
            quote = t["editar_grupo_quote_usuario"]
            count_template = t["editar_grupo_count_usuario"]

        embed = discord.Embed(color=settings["embed_color"])
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed.set_author(name="NATA®", icon_url=icon_url)
        embed.description = (
            f"**{title}**\n"
            f"{t['editar_grupo_select_text']}\n\n"
            f">>> {quote}\n\n"
            f"{count_template.format(count=len(grupos))}"
        )
        embed.set_footer(
            text=f"{t['solicitado_por']} {self.parent_view.author.name}",
            icon_url=self.parent_view.author.display_avatar.url,
        )

        view = discord.ui.View(timeout=120)
        if not grupos:
            await interaction.response.send_message(
                embed=embed, ephemeral=True
            )
            await interaction.followup.send(
                t["editar_grupo_no_groups"], ephemeral=True
            )
            return

        options = []
        for ident_str in grupos:
            if kind == "cargo":
                try:
                    rid = int(ident_str)
                except ValueError:
                    continue
                role = guild.get_role(rid)
                label = role.name if role else f"Cargo {ident_str}"
            else:
                try:
                    uid = int(ident_str)
                except ValueError:
                    continue
                member = guild.get_member(uid)
                label = member.name if member else f"Usuário {ident_str}"
            options.append(discord.SelectOption(label=label[:100], value=ident_str))

        view.add_item(
            EditarGrupoEscolherSelect(
                self.parent_view, kind, options[:25],
                t["editar_grupo_select_placeholder"],
            )
        )
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)


class EditarGrupoEscolherSelect(discord.ui.Select):
    def __init__(
        self,
        parent_view: "EditandoCargosView",
        kind: str,
        options: list[discord.SelectOption],
        placeholder: str,
    ):
        super().__init__(
            placeholder=placeholder, min_values=1, max_values=1, options=options
        )
        self.parent_view = parent_view
        self.kind = kind

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        ident_str = self.values[0]

        if self.kind == "cargo":
            current_list = settings["protecao_grupos_cargos"].get(ident_str, [])
            modal = EditarGrupoCargoModal(self.parent_view, t, ident_str, current_list)
        else:
            current_list = settings["protecao_grupos_usuarios"].get(ident_str, [])
            modal = EditarGrupoUsuarioModal(self.parent_view, t, ident_str, current_list)

        await interaction.response.send_modal(modal)


class EditarGrupoCargoModal(discord.ui.Modal):
    def __init__(
        self,
        parent_view: "EditandoCargosView",
        t: dict,
        original_role_id: str,
        current_managed: list[int],
    ):
        super().__init__(title=t["editar_grupo_cargo_title"], timeout=600)
        self.parent_view = parent_view
        self.original_role_id = original_role_id

        default_values = [
            discord.SelectDefaultValue(id=rid, type=discord.SelectDefaultValueType.role)
            for rid in current_managed
        ]

