class DeletarGrupoSelect(discord.ui.Select):
    def __init__(self, parent_view: "EditandoCargosView", options: list[discord.SelectOption]):
        super().__init__(placeholder="Selecione...", min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        value = self.values[0]
        kind, key = value.split(":", 1)
        if kind == "c":
            settings["protecao_grupos_cargos"].pop(key, None)
        else:
            settings["protecao_grupos_usuarios"].pop(key, None)
        save_settings_to_disk()

        await interaction.response.send_message(embed=_notif_embed(t["grupo_deleted"]), ephemeral=True)
        try:
            embed = build_editando_cargos_embed(self.parent_view.author, settings)
            new_view = EditandoCargosView(self.parent_view.author)
            await interaction.message.edit(embed=embed, view=new_view)
        except (discord.HTTPException, AttributeError):
            pass


class EditandoCargosView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build_buttons()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_buttons(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        t = TRANSLATIONS[get_settings(guild_id)["language"]]
        self.clear_items()
        buttons = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (t["btn_adicionar_grupo_cargo"], discord.ButtonStyle.secondary, self._add_cargo),
            (t["btn_adicionar_grupo_usuario"], discord.ButtonStyle.secondary, self._add_usuario),
            (t["btn_editar_lista"], discord.ButtonStyle.secondary, self._editar_lista),
            (t["btn_deletar_grupo"], discord.ButtonStyle.danger, self._deletar_grupo),
        ]
        for label, style, cb in buttons:
            btn = discord.ui.Button(label=label, style=style, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_protecao_cargos_embed(self.author, settings)
        view = ProtecaoCargosView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _add_cargo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        await interaction.response.send_modal(GrupoCargoModal(self, t))

    async def _add_usuario(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        await interaction.response.send_modal(GrupoUsuarioModal(self, t))

    async def _editar_lista(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = discord.ui.View(timeout=120)
        view.add_item(EditarTipoSelect(self, t))

        embed = discord.Embed(
            color=settings["embed_color"],
            description=t["editar_tipo_prompt"],
        )
        icon_url = bot.user.display_avatar.url if bot.user else None
        embed.set_author(name="NATA®", icon_url=icon_url)
        embed.set_footer(
            text=f"{t['solicitado_por']} {self.author.name}",
            icon_url=self.author.display_avatar.url,
        )

        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _deletar_grupo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        guild = interaction.guild

        options: list[discord.SelectOption] = []
        for rid_str in settings.get("protecao_grupos_cargos", {}):
            try:
                rid = int(rid_str)
            except ValueError:
                continue
            role = guild.get_role(rid)
            label = f"Cargo: {role.name if role else f'<@&{rid}>'}"
            options.append(discord.SelectOption(label=label[:100], value=f"c:{rid_str}"))
        for uid_str in settings.get("protecao_grupos_usuarios", {}):
            try:
                uid = int(uid_str)
            except ValueError:
                continue
            member = guild.get_member(uid)
            label = f"Usuário: {member.name if member else uid_str}"
            options.append(discord.SelectOption(label=label[:100], value=f"u:{uid_str}"))

        if not options:
            await interaction.response.send_message(embed=_notif_embed(t["no_grupos_to_select"]), ephemeral=True)
            return

        view = discord.ui.View(timeout=120)
        view.add_item(DeletarGrupoSelect(self, options[:25]))
        embed = discord.Embed(
            description=t["select_grupo_to_delete"], color=settings["embed_color"]
        )
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)


def _build_lista_cargos_page(
    guild: discord.Guild, settings: dict, pages: list[tuple[str, list[int]]], idx: int
) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    key, managed_ids = pages[idx]

    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["lista_completa_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    try:
        rid = int(key)
        role = guild.get_role(rid)
        role_mention = role.mention if role else f"<@&{rid}>"
    except ValueError:
        role_mention = key

    embed.add_field(
        name=f"ⓘ  {t['grupo_por_cargo_section']}",
        value=role_mention,
        inline=False,
    )

    lines = []
    for i, mid in enumerate(managed_ids, start=1):
        m_role = guild.get_role(mid)
        m_mention = m_role.mention if m_role else f"<@&{mid}>"
        lines.append(f"`{i}.` {m_mention}")
    list_value = "\n".join(lines) or t["no_role_text"]

    embed.add_field(
        name=f"👤  {t['cargos_da_lista_total'].format(count=len(managed_ids))}",
        value=list_value[:1024],
        inline=False,
    )

    embed.set_footer(
        text=t["cargo_page_footer"].format(current=idx + 1, total=len(pages)),
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


class ListaCargosPaginatedView(discord.ui.View):
    def __init__(self, author: discord.Member, pages: list[tuple[str, list[int]]]):
        super().__init__(timeout=None)
        self.author = author
        self.pages = pages
        self.idx = 0
        self._build_buttons()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_buttons(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        t = TRANSLATIONS[get_settings(guild_id)["language"]]
        self.clear_items()

        prev_btn = discord.ui.Button(label=t["btn_anterior"], style=discord.ButtonStyle.secondary)
        next_btn = discord.ui.Button(label=t["btn_proximo"], style=discord.ButtonStyle.secondary)
        count_btn = discord.ui.Button(
            label=t["n_cargos_btn"].format(count=len(self.pages)),
            style=discord.ButtonStyle.success,
            disabled=True,
        )
        prev_btn.callback = self._prev
        next_btn.callback = self._next
        self.add_item(prev_btn)
        self.add_item(next_btn)
        self.add_item(count_btn)

    async def _prev(self, interaction: discord.Interaction):
        self.idx = (self.idx - 1) % len(self.pages)
        settings = get_settings(interaction.guild.id)
        embed = _build_lista_cargos_page(interaction.guild, settings, self.pages, self.idx)
        await interaction.response.edit_message(embed=embed, view=self)

    async def _next(self, interaction: discord.Interaction):
        self.idx = (self.idx + 1) % len(self.pages)
        settings = get_settings(interaction.guild.id)
        embed = _build_lista_cargos_page(interaction.guild, settings, self.pages, self.idx)
        await interaction.response.edit_message(embed=embed, view=self)


class ProtecaoRoleToggleSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "ProtecaoCargosView", placeholder: str, list_key: str):
        super().__init__(placeholder=placeholder, min_values=1, max_values=25)
        self.parent_view = parent_view
        self.list_key = list_key

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        target = settings[self.list_key]
        added, removed = _toggle_role_list(target, [r.id for r in self.values])
        save_settings_to_disk()

        await interaction.response.send_message(
            t["roles_toggled"].format(added=len(added), removed=len(removed)),
            ephemeral=True,
        )

        try:
            embed = build_protecao_cargos_embed(self.parent_view.author, settings)
            new_view = ProtecaoCargosView(self.parent_view.author)
            await interaction.message.edit(embed=embed, view=new_view)
        except (discord.HTTPException, AttributeError):
            pass


