def build_protecao_url_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["protecao_url_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    if settings.get("protecao_url_enabled"):
        status_value = "<a:online:1518271945550856295> `(Ativado)`"
    else:
        status_value = "<a:alerta:1518271939460857968> `(Desativado)`"

    token = settings.get("protecao_url_token")
    password = settings.get("protecao_url_password")
    if token and password:
        conta_value = "<a:online:1518271945550856295> `Configurada (oculta)`"
    else:
        conta_value = f"`{t['not_defined']}`"

    link = settings.get("protecao_url_link")
    if link:
        link_value = f"[`{link[:60] + ('...' if len(link) > 60 else '')}`]({link})"
    else:
        link_value = f"`{t['not_defined']}`"

    log_channel_id = settings.get("protecao_url_log_channel")
    if log_channel_id and author.guild:
        ch = author.guild.get_channel(log_channel_id)
        log_value = ch.mention if ch else f"<#{log_channel_id}>"
    else:
        log_value = f"`{t['not_defined_log']}`"

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['protecao_url_info_section']}",
        value=(
            f"┃ **{t['protecao_url_status_label']}:** {status_value}\n"
            f"<:urls:1518272078921339011> **{t['protecao_url_conta_label']}:** {conta_value}\n"
            f"<:urls:1518272078921339011> **{t['protecao_url_link_label']}:** {link_value}\n"
            f"<:mov_call:1518271964077232150> **{t['protecao_url_logs_label']}:** {log_value}"
        ),
        inline=False,
    )

    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['protecao_url_observations_title']}",
        value=t["protecao_url_observations_text"],
        inline=False,
    )

    embed.set_footer(
        text=f"NATA® • {t['solicitado_por']} {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


