class ProtecaoUrlView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build_buttons()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_buttons(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]
        self.clear_items()

        enabled = settings.get("protecao_url_enabled", False)
        activate_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        activate_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (activate_label, activate_style, self._toggle_activation),
            (t["btn_definir_conta"], discord.ButtonStyle.secondary, self._definir_conta),
            (t["btn_definir_link"], discord.ButtonStyle.secondary, self._definir_link),
        ]
        row1 = [
            (t["btn_definir_logs"], discord.ButtonStyle.secondary, self._definir_logs),
            (t["btn_reset_config"], discord.ButtonStyle.danger, self._reset_config),
        ]

        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_security_embed(self.author, settings)
        view = SecurityView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle_activation(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]

        if not settings.get("protecao_url_enabled"):
            if not (settings.get("protecao_url_token") and settings.get("protecao_url_password")):
                await interaction.response.send_message(
                    t["protecao_url_observations_text"], ephemeral=True
                )
                return
            if not settings.get("protecao_url_link"):
                await interaction.response.send_message(
                    f"`{t['protecao_url_link_label']}` — `{t['not_defined']}`",
                    ephemeral=True,
                )
                return

        settings["protecao_url_enabled"] = not settings.get("protecao_url_enabled", False)
        embed = build_protecao_url_embed(self.author, settings)
        new_view = ProtecaoUrlView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        msg = (
            t["protecao_url_activated"]
            if settings["protecao_url_enabled"]
            else t["protecao_url_deactivated"]
        )
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _definir_conta(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = ProtecaoUrlContaModal(self, t)
        await interaction.response.send_modal(modal)

    async def _definir_link(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = ProtecaoUrlLinkModal(self, t)
        await interaction.response.send_modal(modal)

    async def _definir_logs(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = ProtecaoUrlLogChannelView(self, t["protecao_url_select_log_placeholder"])
        await interaction.response.send_message(
            t["protecao_url_select_log_placeholder"], view=view, ephemeral=True
        )

    async def _reset_config(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["protecao_url_enabled"] = False
        settings["protecao_url_token"] = None
        settings["protecao_url_password"] = None
        settings["protecao_url_link"] = None
        settings["protecao_url_log_channel"] = None
        embed = build_protecao_url_embed(self.author, settings)
        new_view = ProtecaoUrlView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["protecao_url_reset_done"]), ephemeral=True)


def get_perm_label(perm_key: str) -> str:
    for key, label in PERMISSION_OPTIONS:
        if key == perm_key:
            return label
    return perm_key


def build_perm_manager_embed(
    author: discord.Member, settings: dict, current_perm_key: str
) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    perm = get_perm_data(settings, current_perm_key)
    perm_label = get_perm_label(current_perm_key)

    embed = discord.Embed(
        color=settings["embed_color"],
        description=t["perm_manager_description"],
    )

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["perm_manager_title"], icon_url=icon_url)

    embed.add_field(
        name="​",
        value=(
            f"┃ **{t['configurando_label']}:** `{perm_label}`\n"
            f"**{t['cargos_configurados_label']}**\n"
            f"`{len(perm['roles'])}` {t['count_role_unit_perm']}\n"
            f"**{t['usuarios_configurados_label']}**\n"
            f"`{len(perm['users'])}` {t['count_user_unit']}"
        ),
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class PermissionDropdown(discord.ui.Select):
    def __init__(self, parent_view: "PermManagerView", placeholder: str):
        options = [
            discord.SelectOption(
                label=label,
                value=key,
                description=f"Configurar permissões de {label}",
            )
            for key, label in PERMISSION_OPTIONS
        ]
        super().__init__(placeholder=placeholder, min_values=1, max_values=1, options=options, row=0)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        self.parent_view.current_perm_key = self.values[0]
        settings = get_settings(interaction.guild.id)
        embed = build_perm_manager_embed(
            self.parent_view.author, settings, self.parent_view.current_perm_key
        )
        new_view = PermManagerView(
            self.parent_view.author, self.parent_view.current_perm_key
        )
        await interaction.response.edit_message(embed=embed, view=new_view)


class PermAddRoleSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "PermManagerView", placeholder: str):
        super().__init__(placeholder=placeholder, min_values=1, max_values=25)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        perm = get_perm_data(settings, self.parent_view.current_perm_key)
        added = 0
        for role in self.values:
            if role.id not in perm["roles"]:
                perm["roles"].append(role.id)
                added += 1

        await interaction.response.send_message(
            t["perm_added_role"].format(
                perm=get_perm_label(self.parent_view.current_perm_key)
            ),
            ephemeral=True,
        )

        try:
            embed = build_perm_manager_embed(
                self.parent_view.author, settings, self.parent_view.current_perm_key
            )
            new_view = PermManagerView(
                self.parent_view.author, self.parent_view.current_perm_key
            )
            await interaction.message.edit(embed=embed, view=new_view)
        except (discord.HTTPException, AttributeError):
            pass


