class PermRemoveUserSelect(discord.ui.UserSelect):
    def __init__(self, parent_view: "PermManagerView", placeholder: str):
        super().__init__(placeholder=placeholder, min_values=1, max_values=25)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        perm = get_perm_data(settings, self.parent_view.current_perm_key)
        for user in self.values:
            if user.id in perm["users"]:
                perm["users"].remove(user.id)

        await interaction.response.send_message(
            t["perm_removed_user"].format(
                perm=get_perm_label(self.parent_view.current_perm_key)
            ),
            ephemeral=True,
        )

        try:
            embed = build_perm_manager_embed(
                self.parent_view.author, settings, self.parent_view.current_perm_key
            )
            new_view = PermManagerView(
                self.parent_view.author, self.parent_view.current_perm_key
            )
            await interaction.message.edit(embed=embed, view=new_view)
        except (discord.HTTPException, AttributeError):
            pass


class PermSelectActionView(discord.ui.View):
    def __init__(self, item: discord.ui.Item):
        super().__init__(timeout=120)
        self.add_item(item)


class PermManagerView(discord.ui.View):
    def __init__(self, author: discord.Member, current_perm_key: str = "banimentos_expulsoes"):
        super().__init__(timeout=None)
        self.author = author
        self.current_perm_key = current_perm_key
        self._build_components()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_components(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        t = TRANSLATIONS[get_settings(guild_id)["language"]]
        self.clear_items()

        self.add_item(PermissionDropdown(self, placeholder=t["select_permission_placeholder"]))

        row1 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (t["btn_listar"], discord.ButtonStyle.secondary, self._listar),
            (t["btn_listar_tudo"], discord.ButtonStyle.secondary, self._listar_tudo),
            (t["btn_adicionar_cargo"], discord.ButtonStyle.secondary, self._adicionar_cargo),
            (t["btn_adicionar_usuario"], discord.ButtonStyle.secondary, self._adicionar_usuario),
        ]
        row2 = [
            (t["btn_remover_usuario"], discord.ButtonStyle.danger, self._remover_usuario),
        ]

        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row2:
            btn = discord.ui.Button(label=label, style=style, row=2, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_security_embed(self.author, settings)
        view = SecurityView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _listar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        perm = get_perm_data(settings, self.current_perm_key)
        guild = interaction.guild

        if perm["roles"]:
            role_lines = []
            for rid in perm["roles"]:
                role = guild.get_role(rid)
                role_lines.append(f"• {role.mention if role else f'<@&{rid}>'} ( {rid} )")
            roles_text = "\n".join(role_lines)
        else:
            roles_text = t["perm_no_roles"]

        if perm["users"]:
            user_lines = []
            for uid in perm["users"]:
                user_lines.append(f"• <@{uid}> ( {uid} )")
            users_text = "\n".join(user_lines)
        else:
            users_text = t["perm_no_users"]

        embed = discord.Embed(
            title=t["perm_list_title"].format(perm=get_perm_label(self.current_perm_key)),
            color=settings["embed_color"],
            description=(
                f"**{t['cargos_configurados_label']}** ({len(perm['roles'])})\n"
                f"{roles_text}\n\n"
                f"**{t['usuarios_configurados_label']}** ({len(perm['users'])})\n"
                f"{users_text}"
            )[:4000],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _listar_tudo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        lines = []
        for key, label in PERMISSION_OPTIONS:
            perm = get_perm_data(settings, key)
            lines.append(f"**{label}** — `{len(perm['roles'])}` {t['count_role_unit_perm']}, `{len(perm['users'])}` {t['count_user_unit']}")
        embed = discord.Embed(
            title=t["perm_list_all_title"],
            description="\n".join(lines)[:4000],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _adicionar_cargo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = PermSelectActionView(PermAddRoleSelect(self, t["modal_roles_placeholder"]))
        await interaction.response.send_message(view=view, ephemeral=True)

    async def _adicionar_usuario(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = PermSelectActionView(PermAddUserSelect(self, t["select_users_placeholder"]))
        await interaction.response.send_message(view=view, ephemeral=True)

    async def _remover_usuario(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = PermSelectActionView(PermRemoveUserSelect(self, t["select_users_placeholder"]))
        await interaction.response.send_message(view=view, ephemeral=True)


def build_castigo_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]

    status_text = "(Ativado)" if settings["castigo_enabled"] else "(Desativado)"
    if settings["language"] == "en":
        status_text = "(Enabled)" if settings["castigo_enabled"] else "(Disabled)"

    block_value = (
        t["castigo_manual_block_on"]
        if settings["castigo_manual_block"]
        else t["castigo_manual_block_off"]
    )

    manual_roles = settings.get("castigo_manual_roles", [])
    if manual_roles and author.guild:
        manual_value = _format_roles_list(author.guild, manual_roles)
    else:
        manual_value = f"`{t['not_defined_short']}`"

    auto_roles = settings.get("castigo_auto_roles", [])
    auto_value = f"`{t['castigo_auto_roles_count'].format(count=len(auto_roles))}`"

    log_channel_id = settings.get("castigo_log_channel")
    if log_channel_id and author.guild:
        ch = author.guild.get_channel(log_channel_id)
        log_value = ch.mention if ch else f"`{t['not_defined_log']}`"
    else:
        log_value = f"`{t['not_defined_log']}`"

    embed = discord.Embed(
        title=t["castigo_panel_title"],
        color=settings["embed_color"],
    )
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_thumbnail(url=icon_url)

    embed.add_field(
        name=f"ⓘ  {t['info_section']}",
        value=(
            f"**{t['status']}:** `{status_text}`\n"
            f"**{t['castigo_manual_block_label']}:** `{block_value}`\n"
            f"**{t['castigo_manual_roles_label']}:** {manual_value}\n"
            f"**{t['castigo_auto_roles_label']}:** {auto_value}\n"
            f"**{t['advertencia_log_channel']}:** {log_value}"
        ),
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    return embed


def _parse_role_ids_from_text(text: str, guild: discord.Guild) -> list[int]:
    if not text:
        return []
    tokens = text.replace(",", " ").split()
    ids: list[int] = []
    for token in tokens:
        raw = token.strip().strip("<@&>")
        try:
            rid = int(raw)
        except ValueError:
            continue
        if guild.get_role(rid):
            ids.append(rid)
    return ids


def _toggle_role_list(target: list[int], ids: list[int]) -> tuple[list[int], list[int]]:
    added: list[int] = []
    removed: list[int] = []
    for rid in ids:
        if rid in target:
            target.remove(rid)
            removed.append(rid)
        else:
            target.append(rid)
            added.append(rid)
    return added, removed


class CastigoRolesModal(discord.ui.Modal):
    def __init__(self, parent_view: "CastigoView", t: dict):
        super().__init__(title=t["modal_role_selection_title"], timeout=600)
        self.parent_view = parent_view

        self.manuais_select = discord.ui.RoleSelect(
            placeholder=t["modal_roles_placeholder"],
            min_values=0,
            max_values=25,
        )
        self.automaticos_select = discord.ui.RoleSelect(
            placeholder=t["modal_roles_placeholder"],
            min_values=0,
            max_values=25,
        )

        self.add_item(discord.ui.Label(
            text=t["modal_manuais_label"],
            description=t["modal_manuais_description"],
            component=self.manuais_select,
        ))
        self.add_item(discord.ui.Label(
            text=t["modal_automaticos_label"],
            description=t["modal_automaticos_description"],
            component=self.automaticos_select,
        ))

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        guild = interaction.guild

        manuais_ids = [r.id for r in self.manuais_select.values]
        automaticos_ids = [r.id for r in self.automaticos_select.values]

        added_m, removed_m = _toggle_role_list(settings["castigo_manual_roles"], manuais_ids)
        added_a, removed_a = _toggle_role_list(settings["castigo_auto_roles"], automaticos_ids)

        def fmt_roles(ids):
            mentions = []
            for rid in ids:
                role = guild.get_role(rid)
                mentions.append(role.mention if role else f"<@&{rid}>")
            return " ".join(mentions)

        sections = []
        if added_m:
            sections.append(f"**{t['cargos_manuais_adicionados']}**\n{fmt_roles(added_m)}")
        if removed_m:
            sections.append(f"**{t['cargos_manuais_removidos']}**\n{fmt_roles(removed_m)}")
        if added_a:
            sections.append(f"**{t['cargos_automaticos_adicionados']}**\n{fmt_roles(added_a)}")
        if removed_a:
            sections.append(f"**{t['cargos_automaticos_removidos']}**\n{fmt_roles(removed_a)}")

        result_embed = discord.Embed(
            title=t["config_cargos_castigo_title"],
            description="\n\n".join(sections) if sections else t["nenhuma_alteracao"],
            color=settings["embed_color"],
        )
        result_embed.timestamp = datetime.now()

        panel_embed = build_castigo_embed(self.parent_view.author, settings)
        new_view = CastigoView(self.parent_view.author)
        await interaction.response.edit_message(embed=panel_embed, view=new_view)

        await interaction.followup.send(embed=result_embed, ephemeral=True)


