class CastigoView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build_buttons()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_buttons(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]
        self.clear_items()

        enabled = settings["castigo_enabled"]
        activate_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        activate_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        block_enabled = settings["castigo_manual_block"]
        block_label = t["btn_disable_block"] if block_enabled else t["btn_enable_block"]

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (activate_label, activate_style, self._toggle_activation),
            (block_label, discord.ButtonStyle.secondary, self._toggle_block),
            (t["btn_configurar_cargos"], discord.ButtonStyle.secondary, self._configurar_cargos),
            (t["btn_log_channel"], discord.ButtonStyle.secondary, self._define_logs),
        ]
        row1 = [
            (t["btn_listar_cargos"], discord.ButtonStyle.secondary, self._listar_cargos),
            (t["btn_como_configurar"], discord.ButtonStyle.secondary, self._como_configurar),
            (t["btn_resetar_tudo"], discord.ButtonStyle.danger, self._reset_all),
        ]

        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_security_embed(self.author, settings)
        view = SecurityView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle_activation(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["castigo_enabled"] = not settings["castigo_enabled"]
        embed = build_castigo_embed(self.author, settings)
        new_view = CastigoView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        msg = t["castigo_activated"] if settings["castigo_enabled"] else t["castigo_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _toggle_block(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["castigo_manual_block"] = not settings["castigo_manual_block"]
        embed = build_castigo_embed(self.author, settings)
        new_view = CastigoView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        msg = t["castigo_block_on_msg"] if settings["castigo_manual_block"] else t["castigo_block_off_msg"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _configurar_cargos(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = CastigoRolesModal(self, t)
        await interaction.response.send_modal(modal)

    async def _define_logs(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = CastigoLogChannelView(self, t["select_channels_placeholder"])
        embed = discord.Embed(
            description=t["select_channels_prompt"],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _listar_cargos(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        guild = interaction.guild
        manual_ids = settings.get("castigo_manual_roles", [])
        auto_ids = settings.get("castigo_auto_roles", [])

        def fmt_list(ids):
            if not ids:
                return t["no_role_text"]
            lines = []
            for rid in ids:
                role = guild.get_role(rid)
                mention = role.mention if role else f"<@&{rid}>"
                lines.append(f"• {mention} ( {rid} )")
            return "\n".join(lines)

        description = (
            f"**{t['castigo_manual_roles_label']} ({len(manual_ids)}):**\n"
            f"{fmt_list(manual_ids)}\n\n"
            f"**{t['castigo_auto_roles_label']} ({len(auto_ids)}):**\n"
            f"{fmt_list(auto_ids)}"
        )

        embed = discord.Embed(
            title=t["list_roles_title"],
            description=description[:4000],
            color=settings["embed_color"],
        )
        embed.set_footer(text=f"{guild.name} ©")
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _como_configurar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        embed = discord.Embed(
            title=t["castigo_how_title"],
            description=t["castigo_how_text"],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _reset_all(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["castigo_enabled"] = False
        settings["castigo_manual_block"] = False
        settings["castigo_manual_roles"] = []
        settings["castigo_auto_roles"] = []
        settings["castigo_log_channel"] = None
        embed = build_castigo_embed(self.author, settings)
        new_view = CastigoView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["config_reset"]), ephemeral=True)


class CmdBlockChannelToggleSelect(GuildChannelSelect):
    def __init__(self, parent_view: "CmdBlockView", placeholder: str):
        super().__init__(
            placeholder=placeholder,
            min_values=1,
            max_values=25,
            channel_types=[discord.ChannelType.text],
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        allowed = settings["cmd_block_allowed_channels"]

        added = 0
        removed = 0
        for ch in self.values:
            if ch.id in allowed:
                allowed.remove(ch.id)
                removed += 1
            else:
                allowed.append(ch.id)
                added += 1

        await interaction.response.send_message(
            t["channels_toggled"].format(added=added, removed=removed),
            ephemeral=True,
        )

        try:
            embed = build_cmd_block_embed(self.parent_view.author, settings)
            new_view = CmdBlockView(self.parent_view.author)
            await interaction.message.edit(embed=embed, view=new_view)
        except (discord.HTTPException, AttributeError):
            pass


