def build_limpeza_mensagem_embed(author: discord.Member, settings: dict) -> discord.Embed:
    if settings["limpeza_mensagem_enabled"]:
        status_value = "<a:online:1518271945550856295> `(Ativado)`"
    else:
        status_value = "<a:alerta:1518271939460857968> `(Desativado)`"

    voice_auto = settings.get("limpeza_voice_auto_all", False)
    if voice_auto:
        voice_status = "<a:online:1518271945550856295> `Todos os canais de voz`"
    else:
        voice_status = "<a:alerta:1518271939460857968> `Desativado`"

    text_channels = settings.get("limpeza_text_channels", [])
    text_count = len(text_channels)
    voice_delay = settings.get("limpeza_voice_delay_minutes", 1)
    text_delay = settings.get("limpeza_text_delay_minutes", 1)

    embed = discord.Embed(color=settings["embed_color"])

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name="Limpar Mensagem - NATA®", icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    embed.add_field(
        name="<:entretenimento_:1518271992191779038>  Informações",
        value=(
            f"**Status:** {status_value}\n"
            f"<:mov_call:1518271964077232150> **Canais de Voz:** {voice_status}\n"
            f"<:Mov_chat:1518271970008105031> **Chats Padrão Configurados:** `{text_count}`"
        ),
        inline=False,
    )

    embed.add_field(
        name="<:mov_call:1518271964077232150>  Tempos de Limpeza",
        value=(
            f"<:mov_call:1518271964077232150> **Canais de Voz:** `{voice_delay} minuto(s)`\n"
            f"<:Mov_chat:1518271970008105031> **Chats Padrão:** `{text_delay} minuto(s)`"
        ),
        inline=False,
    )

    embed.add_field(
        name="<:comunidade_:1518272016971595807>  Observações",
        value=(
            "<:mov_call:1518271964077232150> **Configurar Canais** → ativa limpeza em **todos** os canais de voz.\n"
            "<:Mov_chat:1518271970008105031> **Configurar Chat Padrão** → seleciona canais de texto.\n"
            "<:mov_call:1518271964077232150> **Tempo Voz** → tempo de limpeza dos canais de voz (1-60 min).\n"
            "<:Mov_chat:1518271970008105031> **Tempo Chat** → tempo de limpeza dos canais de texto (1-60 min)."
        ),
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    return embed


