class LimpezaVoiceDelayModal(discord.ui.Modal):
    def __init__(self, parent_view: "LimpezaMensagemView"):
        super().__init__(title="Tempo — Canais de Voz", timeout=120)
        self.parent_view = parent_view
        self.minutes_input = discord.ui.TextInput(
            label="Minutos (1-60)",
            placeholder="Ex: 5",
            required=True,
            max_length=2,
        )
        self.add_item(self.minutes_input)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        try:
            minutes = int(self.minutes_input.value.strip())
        except ValueError:
            await interaction.response.send_message("Número inválido.", ephemeral=True)
            return
        if minutes < 1 or minutes > 60:
            await interaction.response.send_message(
                "O tempo deve ser entre 1 e 60 minutos.", ephemeral=True
            )
            return

        settings["limpeza_voice_delay_minutes"] = minutes
        embed = build_limpeza_mensagem_embed(self.parent_view.author, settings)
        new_view = LimpezaMensagemView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(
            f"Tempo de limpeza dos **canais de voz** definido pra `{minutes}` minuto(s).",
            ephemeral=True,
        )


