class LimparAgoraSelect(GuildChannelSelect):
    def __init__(self, parent_view: "LimpezaMensagemView", placeholder: str, channel_types: list):
        super().__init__(
            placeholder=placeholder,
            min_values=1,
            max_values=1,
            channel_types=channel_types,
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        channel = self.values[0]
        actual_channel = interaction.guild.get_channel(channel.id)
        if actual_channel is None:
            await interaction.response.send_message("Canal não encontrado.", ephemeral=True)
            return

        await interaction.response.defer(ephemeral=True)
        deleted = 0
        try:
            if isinstance(actual_channel, (discord.TextChannel, discord.VoiceChannel)):
                deleted_msgs = await actual_channel.purge(limit=100)
                deleted = len(deleted_msgs)
        except (discord.Forbidden, discord.HTTPException) as e:
            await interaction.followup.send(
                f"Erro ao limpar: {e}", ephemeral=True
            )
            return

        await interaction.followup.send(
            f"**{deleted}** mensagem(ns) apagada(s) de {actual_channel.mention}.",
            ephemeral=True,
        )


