@bot.event
async def on_audit_log_entry_create(entry: discord.AuditLogEntry):
    """Reverte imediatamente alterações de cargos feitas por usuários na blacklist_cargos."""
    if entry.action != discord.AuditLogAction.member_role_update:
        return
    if not entry.user or not entry.target:
        return
    _bot_id = bot.user.id if bot.user else 0
    if entry.user.id == _bot_id:
        return  # ignora ações do próprio bot

    _guild = entry.guild
    _settings = get_settings(_guild.id)
    _bl = _settings.get("blacklist_cargos", [])
    if entry.user.id not in _bl:
        return

    # Usuário blacklistado alterou cargos de alguém — reverter
    _target = _guild.get_member(entry.target.id)
    if _target is None:
        try:
            _target = await _guild.fetch_member(entry.target.id)
        except Exception:
            return

    # after.roles = cargos adicionados; before.roles = cargos removidos
    _added_roles = getattr(getattr(entry.changes, "after", None), "roles", None) or []
    _removed_roles = getattr(getattr(entry.changes, "before", None), "roles", None) or []

    print(
        f"[bl_audit] blacklisted={entry.user.id} target={entry.target.id} "
        f"added={[r.id for r in _added_roles]} removed={[r.id for r in _removed_roles]}",
        flush=True,
    )

    _to_remove = [r for r in _added_roles if not r.is_default() and r.position < _guild.me.top_role.position]
    _to_restore = [r for r in _removed_roles if not r.is_default() and r.position < _guild.me.top_role.position]

    if _to_remove:
        try:
            await _target.remove_roles(*_to_remove, reason="Anti-Raid: blacklist de cargos — sem permissão para gerenciar cargos")
            print(f"[bl_audit] removidos {[r.id for r in _to_remove]} de {_target.id}", flush=True)
        except Exception as _e:
            print(f"[bl_audit] erro ao remover cargos: {_e}", flush=True)

    if _to_restore:
        try:
            await _target.add_roles(*_to_restore, reason="Anti-Raid: blacklist de cargos — restaurando cargos removidos")
            print(f"[bl_audit] restaurados {[r.id for r in _to_restore]} em {_target.id}", flush=True)
        except Exception as _e:
            print(f"[bl_audit] erro ao restaurar cargos: {_e}", flush=True)


