class CmdBlockView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build_buttons()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_buttons(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]
        self.clear_items()

        enabled = settings["cmd_block_enabled"]
        activate_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        activate_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (activate_label, activate_style, self._toggle_activation),
            (t["btn_configurar_canais"], discord.ButtonStyle.secondary, self._configurar_canais),
            (t["btn_log_channel"], discord.ButtonStyle.secondary, self._define_logs),
        ]
        row1 = [
            (t["btn_listar_canais"], discord.ButtonStyle.secondary, self._listar_canais),
            (t["btn_resetar"], discord.ButtonStyle.danger, self._reset_config),
        ]

        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _refresh(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_cmd_block_embed(self.author, settings)
        new_view = CmdBlockView(self.author)
        try:
            await interaction.edit_original_response(embed=embed, view=new_view)
        except discord.HTTPException:
            pass

    async def _wait_for_input(
        self, interaction: discord.Interaction, prompt: str
    ) -> str | None:
        guild_id = interaction.guild.id if interaction.guild else 0
        lang = get_settings(guild_id)["language"]
        t = TRANSLATIONS[lang]
        await interaction.response.send_message(
            f"{prompt}\n{t['cancel_hint']}", ephemeral=True
        )

        def check(m: discord.Message) -> bool:
            return (
                m.author.id == self.author.id
                and m.channel.id == interaction.channel.id
            )

        try:
            msg = await bot.wait_for("message", check=check, timeout=60)
        except asyncio.TimeoutError:
            await interaction.followup.send(embed=_notif_embed(t["timed_out"]), ephemeral=True)
            return None

        content = msg.content.strip()
        try:
            await msg.delete()
        except (discord.Forbidden, discord.NotFound):
            pass

        if content.lower() == t["cancel_keyword"]:
            await interaction.followup.send(
                t["operation_cancelled"], ephemeral=True
            )
            return None
        return content

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_security_embed(self.author, settings)
        view = SecurityView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle_activation(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["cmd_block_enabled"] = not settings["cmd_block_enabled"]
        embed = build_cmd_block_embed(self.author, settings)
        new_view = CmdBlockView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        msg = t["cmd_block_activated"] if settings["cmd_block_enabled"] else t["cmd_block_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _configurar_canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = ConfigurarCanaisView(self, t["select_channels_placeholder"])
        await interaction.response.send_message(
            t["select_channels_prompt"], view=view, ephemeral=True
        )

    async def _define_logs(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = CanalDeLogsView(self, t["select_channels_placeholder"])
        embed = discord.Embed(
            description=t["select_channels_prompt"],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _listar_canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        ids = settings.get("cmd_block_allowed_channels", [])
        guild = interaction.guild

        if not ids:
            description = (
                f"{t['no_channels_configured']}\n\n"
                f"{t['use_configurar_hint']}"
            )
        else:
            lines = []
            for cid in ids:
                ch = guild.get_channel(cid)
                lines.append(f"• {ch.mention if ch else f'<#{cid}>'} (`{cid}`)")
            description = "\n".join(lines)[:3500]

        embed = discord.Embed(
            title=t["list_channels_title"],
            description=description,
            color=settings["embed_color"],
        )
        embed.set_footer(text=t["use_configurar_footer"])
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _reset_config(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["cmd_block_enabled"] = False
        settings["cmd_block_allowed_channels"] = []
        settings["cmd_block_log_channel"] = None
        embed = build_cmd_block_embed(self.author, settings)
        new_view = CmdBlockView(self.author)
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["config_reset"]), ephemeral=True)


def build_blacklist_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["blacklist_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    embed.add_field(
        name=f"<:f1:1518271958024720555>  {t['administrator_label']}",
        value=f"<:bot_v3:1506343470242074785> {author.mention} ( `{author.id}` )",
        inline=False,
    )

    if settings["blacklist_enabled"]:
        status_value = "<a:online:1518271945550856295> `(Ativado)`"
    else:
        status_value = "<a:alerta:1518271939460857968> `(Desativado)`"

    log_channel_id = settings.get("blacklist_log_channel")
    if log_channel_id and author.guild:
        ch = author.guild.get_channel(log_channel_id)
        log_value = ch.mention if ch else f"`{t['not_defined_log']}`"
    else:
        log_value = f"`{t['not_defined_log']}`"

    embed.add_field(
        name=f"<:f1:1518271958024720555>  {t['info_section']}",
        value=(
            f"**{t['status']}:** {status_value}\n"
            f"**{t['advertencia_log_channel']}:** {log_value}"
        ),
        inline=False,
    )

    allowed_count = len(settings.get("blacklist_allowed_roles", []))
    action = settings.get("blacklist_action", "expulsar")
    action_display = t["expulsar_action"] if action == "expulsar" else t["banir_action"]

    embed.add_field(
        name=f"<:f1:1518271958024720555>  {t['protection']}",
        value=(
            f"**{t['blacklist_allowed_roles_label']}:** `{allowed_count} {t['backup_count_unit']}`\n"
            f"**{t['blacklist_action_label']}:** `{action_display}`"
        ),
        inline=False,
    )

    embed.add_field(
        name=f"<:f1:1518271958024720555>  {t['advertencia_observations']}",
        value=t["blacklist_observations_text"],
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


