        t = TRANSLATIONS[lang]
        content = await self._wait_for_input(interaction, t["send_warn_action"])
        if content is None:
            return
        action = content.lower()
        valid = {"nenhuma", "none", "kikar", "kick", "banir", "ban", "mutar", "mute"}
        if action not in valid:
            await interaction.followup.send(embed=_notif_embed(t["invalid_action"]), ephemeral=True)
