        t = TRANSLATIONS[settings["language"]]

        content = await self._wait_for_input(interaction, t["send_roles"])
        if content is None:
            return

        tokens = content.split()
        role_ids: list[int] = []
        for token in tokens[:3]:
            raw = token.strip("<@&>")
            try:
                rid = int(raw)
            except ValueError:
                continue
            role = interaction.guild.get_role(rid)
            if role:
                role_ids.append(role.id)

        if not role_ids:
            await interaction.followup.send(embed=_notif_embed(t["no_valid_role"]), ephemeral=True)
            return

        settings["warning_roles"] = role_ids
        await interaction.followup.send(embed=_notif_embed(t["roles_updated"]), ephemeral=True)
        await self._refresh_panel(interaction)

