def build_perm_embed(guild: discord.Guild, settings: dict) -> discord.Embed:
    lang = settings["language"]
    t = TRANSLATIONS[lang]
    owner = guild.owner
    members_count = len(settings.get("authorized_members", []))

    embed = discord.Embed(
        title=_apply_name(t["perm_panel_title"], settings),
        description=t["perm_description"],
        color=settings["embed_color"],
    )

    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_thumbnail(url=icon_url)

    owner_value = owner.mention if owner else "—"
    embed.add_field(
        name=f"{t['perm_info']}:",
        value=(
            f"**{t['perm_owner']}:** {owner_value}\n"
            f"**{t['perm_authorized']}:** `{members_count}`"
        ),
        inline=False,
    )

    embed.set_footer(text=t["perm_footer"], icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


async def resolve_member(guild: discord.Guild, raw: str) -> discord.Member | None:
    raw = raw.strip()
    if raw.startswith("<@") and raw.endswith(">"):
        raw = raw.strip("<@!>")
    try:
        user_id = int(raw)
    except ValueError:
        return None
    member = guild.get_member(user_id)
    if member is None:
        try:
            member = await guild.fetch_member(user_id)
        except (discord.NotFound, discord.HTTPException):
            return None
    return member


class PermView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build_buttons()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build_buttons(self):
        guild_id = self.author.guild.id if self.author.guild else 0
        t = TRANSLATIONS[get_settings(guild_id)["language"]]

        self.clear_items()

        buttons = [
            (t["btn_add_member"], discord.ButtonStyle.secondary, self._add_member),
            (t["btn_list_members"], discord.ButtonStyle.secondary, self._list_members),
            (t["btn_remove_member"], discord.ButtonStyle.danger, self._remove_member),
            (t["btn_close"], discord.ButtonStyle.danger, self._close),
        ]

        for label, style, cb in buttons:
            btn = discord.ui.Button(label=label, style=style, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _wait_for_member(
        self, interaction: discord.Interaction, prompt: str
    ) -> discord.Member | None:
        guild_id = interaction.guild.id if interaction.guild else 0
        lang = get_settings(guild_id)["language"]
        t = TRANSLATIONS[lang]

        await interaction.response.send_message(
            f"{prompt}\n{t['cancel_hint']}", ephemeral=True
        )

        def check(m: discord.Message) -> bool:
            return (
                m.author.id == self.author.id
                and m.channel.id == interaction.channel.id
            )

        try:
            msg = await bot.wait_for("message", check=check, timeout=60)
        except asyncio.TimeoutError:
            await interaction.followup.send(embed=_notif_embed(t["timed_out"]), ephemeral=True)
            return None

        content = msg.content.strip()
        try:
            await msg.delete()
        except (discord.Forbidden, discord.NotFound):
            pass

        if content.lower() == t["cancel_keyword"]:
            await interaction.followup.send(
                t["operation_cancelled"], ephemeral=True
            )
            return None

        member = await resolve_member(interaction.guild, content)
        if member is None:
            await interaction.followup.send(embed=_notif_embed(t["member_not_found"]), ephemeral=True)
            return None
        return member

    async def _refresh(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_perm_embed(interaction.guild, settings)
        try:
            await interaction.message.edit(embed=embed, view=self)
        except (discord.NotFound, discord.HTTPException):
            pass

    async def _add_member(self, interaction: discord.Interaction):
        guild_id = interaction.guild.id if interaction.guild else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]

        member = await self._wait_for_member(interaction, t["send_member_to_add"])
        if member is None:
            return

        if member.id in settings["authorized_members"]:
            await interaction.followup.send(embed=_notif_embed(t["member_already_in"]), ephemeral=True)
            return

        settings["authorized_members"].append(member.id)
        save_settings_to_disk()
        await interaction.followup.send(embed=_notif_embed(t["member_added"]), ephemeral=True)
        await self._refresh(interaction)

    async def _list_members(self, interaction: discord.Interaction):
        guild_id = interaction.guild.id if interaction.guild else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]
        ids = settings["authorized_members"]

        if not ids:
            await interaction.response.send_message(
                t["no_members"], ephemeral=True
            )
            return

        lines = []
        for uid in ids:
            member = interaction.guild.get_member(uid)
            lines.append(f"• {member.mention if member else f'<@{uid}>'} (`{uid}`)")

        embed = discord.Embed(
            title=t["members_list_title"],
            description="\n".join(lines),
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _remove_member(self, interaction: discord.Interaction):
        guild_id = interaction.guild.id if interaction.guild else 0
        settings = get_settings(guild_id)
        t = TRANSLATIONS[settings["language"]]

        member = await self._wait_for_member(
            interaction, t["send_member_to_remove"]
        )
        if member is None:
            return

        if member.id not in settings["authorized_members"]:
            await interaction.followup.send(embed=_notif_embed(t["member_not_in"]), ephemeral=True)
            return

        settings["authorized_members"].remove(member.id)
        save_settings_to_disk()
        await interaction.followup.send(embed=_notif_embed(t["member_removed"]), ephemeral=True)
        await self._refresh(interaction)

    async def _close(self, interaction: discord.Interaction):
        try:
            await interaction.message.delete()
        except (discord.Forbidden, discord.NotFound):
            await interaction.response.defer()


async def _backup_loop():
    await bot.wait_until_ready()
    while not bot.is_closed():
        try:
            for guild in bot.guilds:
                settings = get_settings(guild.id)
                if not settings.get("backup_enabled"):
                    continue
                interval = settings.get("backup_interval_hours", 1) * 3600
                last = settings.get("backup_last_timestamp")
                should_run = True
                if last:
                    try:
                        last_dt = datetime.fromisoformat(last)
                        if (datetime.now() - last_dt).total_seconds() < interval:
                            should_run = False
                    except Exception:
                        pass
                if not should_run:
                    continue
                settings["backup_data"] = take_guild_backup(guild)
                settings["backup_last_timestamp"] = datetime.now().isoformat()
                log_channel_id = settings.get("backup_log_channel")
                if log_channel_id:
                    channel = guild.get_channel(log_channel_id)
                    if channel:
                        try:
                            await channel.send(
                                f"📦 Backup automático realizado em "
                                f"`{datetime.now().strftime('%d/%m/%Y, %H:%M:%S')}` — "
                                f"`{len(settings['backup_data']['channels'])}` canais, "
                                f"`{len(settings['backup_data']['roles'])}` cargos."
                            )
                        except (discord.Forbidden, discord.HTTPException):
                            pass
        except Exception as e:
            print(f"[backup_loop] erro: {e}")
        await asyncio.sleep(300)


async def _settings_save_loop():
    await bot.wait_until_ready()
    while not bot.is_closed():
        await asyncio.sleep(30)
        save_settings_to_disk()


async def _calendar_loop():
    """Check daily for birthdays and send parabéns + assign role."""
    await bot.wait_until_ready()
    while not bot.is_closed():
        await asyncio.sleep(600)  # check every 10 minutes
        try:
            today_str = datetime.now().strftime("%d/%m")
            for guild in list(bot.guilds):
                settings = get_settings(guild.id)
                if not settings.get("calendar_enabled"):
                    continue
                last_check = settings.get("calendar_last_check")
                if last_check == today_str:
                    continue  # already processed today
                birthdays = settings.get("calendar_birthdays", {})
                if not birthdays:
                    settings["calendar_last_check"] = today_str
                    continue
                bday_ch_id = settings.get("calendar_birthday_channel")
                role_id = settings.get("calendar_role")
                msg_template = settings.get("calendar_message") or "🎉 Parabéns, {member}! 🎂"
                bday_ch = guild.get_channel(bday_ch_id) if bday_ch_id else None
                role = guild.get_role(role_id) if role_id else None
                for uid_str, date in birthdays.items():
                    if date == today_str:
                        try:
                            uid = int(uid_str)
                        except ValueError:
                            continue
                        member = guild.get_member(uid)
                        if not member:
                            continue
                        if bday_ch:
                            try:
                                msg = msg_template.format(member=member.mention)
                                await bday_ch.send(msg)
                            except (discord.Forbidden, discord.HTTPException):
                                pass
                        if role and role not in member.roles:
                            try:
                                await member.add_roles(role, reason="Aniversário (Calendário)")
                            except (discord.Forbidden, discord.HTTPException):
                                pass
                settings["calendar_last_check"] = today_str
        except Exception as e:
            print(f"[calendar_loop] erro: {e}")


async def _autopostador_loop():
    """Loop que posta automaticamente imagens nos canais configurados."""
    await bot.wait_until_ready()
    import time as _time
    import random as _random
    _dash_url_log = os.environ.get("BOT_DASHBOARD_URL", "http://localhost:8080")
    print(f"[autopostador] iniciado — dashboard URL: {_dash_url_log}", flush=True)
    _IMG_EXTS = (".jpg", ".jpeg", ".png", ".gif", ".webp")
    # Nomes de canal padrão para auto-descoberta (inclui padrões do servidor A NATA)
    _CAT_NAMES = {
        "masc_icons": ["male-icons",       "masc-icons",       "icons-masculinos",  "masc_icons",
                       "male_icons",       "icons-masc",       "icon-masculino",    "icons",
                       "icon",             "pfp-masc",         "pfp-male",          "icons-masc"],
        "fem_icons":  ["female-icons",     "fem-icons",        "icons-femininos",   "fem_icons",
                       "female_icons",     "icons-fem",        "icon-feminino",     "fem-icons",
                       "icons",            "icon",             "pfp-fem",           "pfp-female"],
        "fem_gifs":   ["female-gifs",      "fem-gifs",         "gifs-femininos",    "fem_gifs",
                       "female_gifs",      "gifs-fem",         "gifs",              "gif"],
        "masc_gifs":  ["male-gifs",        "masc-gifs",        "gifs-masculinos",   "masc_gifs",
                       "male_gifs",        "gifs-masc",        "gifs",              "gif"],
        "banners":    ["banners",          "banner",           "banners-icons",     "banner-icons",
                       "banner-masc",      "banner-fem"],
        "animes":     ["animes",           "anime",            "animes-icons",      "anime-icons",
                       "male-animes-icons","female-animes-icons","male-animes-gifs","female-animes-gifs",
                       "animes-masc",      "animes-fem"],
    }
    _AP_LOOP_CATS = [
        ("masc_icons", "gifs_autopostador_masc_icons"),
        ("fem_icons",  "gifs_autopostador_fem_icons"),
        ("fem_gifs",   "gifs_autopostador_fem_gifs"),
        ("masc_gifs",  "gifs_autopostador_masc_gifs"),
        ("banners",    "gifs_autopostador_banners"),
        ("animes",     "gifs_autopostador_animes"),
    ]

    async def _fetch_imgs(channel) -> list:
        """Retorna lista de (url, filename) de imagens no histórico do canal.
        Captura attachments E imagens de embeds (set_image / set_thumbnail)."""
        result = []
        seen: set = set()
        try:
            async for msg in channel.history(limit=300):
                # 1. Arquivos anexados diretamente
                for att in msg.attachments:
                    if att.filename.lower().endswith(_IMG_EXTS) and att.url not in seen:
                        result.append((att.url, att.filename))
                        seen.add(att.url)
                # 2. Imagens em embeds (postadas com set_image / set_thumbnail)
                for emb in msg.embeds:
                    for _img in (emb.image, emb.thumbnail):
                        if _img and _img.url and _img.url not in seen:
                            _u = _img.url
                            _f = _u.split("?")[0].split("/")[-1]
                            if not _f.lower().endswith(_IMG_EXTS):
                                _f += ".jpg"
                            result.append((_u, _f))
                            seen.add(_u)
                if len(result) >= 100:
                    break
        except Exception as _fe:
            print(f"[autopostador] _fetch_imgs #{channel.name}: {_fe}", flush=True)
        return result

    async def _fetch_imgs_http(channel_id: int, token: str) -> list:
        """Busca imagens via Discord HTTP API — não precisa estar no servidor.
        Captura attachments + imagens de embeds."""
        result = []
        seen: set = set()
        try:
            headers = {"Authorization": f"Bot {token}"}
            async with aiohttp.ClientSession(headers=headers) as sess:
                async with sess.get(
                    f"https://discord.com/api/v10/channels/{channel_id}/messages?limit=100",
                    timeout=aiohttp.ClientTimeout(total=15),
                ) as r:
                    if r.status == 200:
                        for msg in await r.json():
                            for att in msg.get("attachments", []):
                                fname = att.get("filename", "")
                                if fname.lower().endswith(_IMG_EXTS) and att["url"] not in seen:
                                    result.append((att["url"], fname))
                                    seen.add(att["url"])
                            for emb in msg.get("embeds", []):
                                for field in ("image", "thumbnail"):
                                    _ed = emb.get(field) or {}
                                    _eu = _ed.get("url", "") or _ed.get("proxy_url", "")
                                    if _eu and _eu not in seen:
                                        _ef = _eu.split("?")[0].split("/")[-1]
                                        if not _ef.lower().endswith(_IMG_EXTS):
                                            _ef += ".jpg"
                                        result.append((_eu, _ef))
                                        seen.add(_eu)
                            if len(result) >= 100:
                                break
        except Exception:
            pass
        return result

    async def _find_imgs_for_cat(cat_key: str, dest_ch) -> list:
        """Busca imagens: 1) Dashboard API  2) destino  3) A NATA gateway  4) auto-descoberta."""
        names = _CAT_NAMES.get(cat_key, [])
        _NATA_GUILD_ID = 1480530206505697404

        # 1. Dashboard API (Discord + Pinterest misturados)
        _dash_url = os.environ.get("BOT_DASHBOARD_URL", "http://localhost:8080")
        api_imgs = []
        try:
            async with aiohttp.ClientSession() as sess:
                async with sess.get(
                    f"{_dash_url}/api/v1/source-images/{cat_key}",
                    timeout=aiohttp.ClientTimeout(total=20),
                ) as r:
                    if r.status == 200:
                        data = await r.json()
                        if data.get("ok") and data.get("images"):
                            api_imgs = [(img["url"], img["filename"]) for img in data["images"]]
        except Exception as _de:
            print(f"[autopostador] dashboard API falhou ({cat_key}): {_de}", flush=True)

        # 2. Varre todos os servidores onde o bot está instalado buscando canais fonte.
        user_imgs = []
        url_set_u: set = set()
        for g in bot.guilds:
            for ch in g.text_channels:
                ch_name = ch.name.lower().lstrip("・•·﹒∙⋅.・ -")
                if ch_name in names and ch.id != dest_ch.id:
                    for url, fname in await _fetch_imgs(ch):
                        if url not in url_set_u:
                            url_set_u.add(url)
                            user_imgs.append((url, fname))

        # 3. Fallback: usa o próprio canal de DESTINO como fonte se nenhum outro canal foi encontrado
        dest_fallback = []
        if not user_imgs and not api_imgs:
            dest_fallback_raw = await _fetch_imgs(dest_ch)
            for u, f in dest_fallback_raw:
                if u not in set(x[0] for x in dest_fallback):
                    dest_fallback.append((u, f))
            if dest_fallback:
                print(f"[autopostador] usando canal destino como fonte ({cat_key}): {len(dest_fallback)} imgs", flush=True)

        # Combina Dashboard API + canais fonte + fallback destino, embaralha e retorna
        # Filtra imagens de canais para garantir que são arquivos de imagem reais
        import random as _rnd
        combined = []
        url_set_c: set = set()
        _IMG_EXTS_FILTER = (".jpg", ".jpeg", ".png", ".gif", ".webp")
        for u, f in api_imgs + user_imgs + dest_fallback:
            if u not in url_set_c:
                fname_lower = f.lower()
                if any(fname_lower.endswith(ext) for ext in _IMG_EXTS_FILTER):
                    url_set_c.add(u)
                    combined.append((u, f))
        _rnd.shuffle(combined)
        print(f"[autopostador] _find_imgs_for_cat({cat_key}): {len(combined)} imagens (api={len(api_imgs)}, canais={len(user_imgs)}, fallback={len(dest_fallback)})", flush=True)
        return combined

    while not bot.is_closed():
        await asyncio.sleep(60)   # verifica a cada 1 minuto
        try:
            now = _time.time()
            guilds_check = list(bot.guilds)
            for guild in guilds_check:
                try:
                    # Posta em qualquer guild onde o autopostador está ativado.
                    # BOT_GUILD_ID restringe comandos, mas o postador usa as próprias
                    # configurações de cada guild para decidir onde postar.
                    settings = get_settings(guild.id)
                    if not settings.get("gifs_autopostador_enabled"):
                        continue
                    print(f"[autopostador] postando em {guild.name} ({guild.id})", flush=True)
                    interval_sec = 2 * 60  # 2 minutos por categoria
                    last_posted  = settings.setdefault("gifs_autopostador_last_posted", {})
                    # Histórico de URLs já enviadas — evita repetição até esgotar o pool
                    sent_history = settings.setdefault("gifs_autopostador_sent", {})
                    changed      = False
                    for cat_key, dest_key in _AP_LOOP_CATS:
                        dest_id = settings.get(dest_key)
                        if not dest_id:
                            continue
                        info = last_posted.get(cat_key, {"ts": 0})
                        if now - info.get("ts", 0) < interval_sec:
                            continue
                        dest_ch = guild.get_channel(dest_id)
                        if not dest_ch:
                            print(f"[autopostador] canal {dest_id} não encontrado em {guild.name} ({cat_key})", flush=True)
                            continue

                        try:
                            imgs = await _find_imgs_for_cat(cat_key, dest_ch)
                            if not imgs:
                                print(f"[autopostador] sem imagens para {cat_key} em {guild.name}", flush=True)
                                continue
                            if not settings.get("gifs_autopostador_enabled"):
                                break
                            if settings.get(dest_key) != dest_id:
                                continue

                            _icon    = bot.user.display_avatar.url if bot.user else None
                            _botname = bot.user.name if bot.user else "NATA®"

                            # Histórico de enviados para esta categoria
                            _cat_sent: list = sent_history.get(cat_key, [])

                            # Chave de deduplicação: path completo sem query string
                            # (attachment_id do Discord é permanente; só o ?ex=... muda)
                            def _fname_key(url: str) -> str:
                                return url.split("?")[0]  # CDN path permanente e único por upload

                            _fresh = [(u, f) for u, f in imgs if _fname_key(u) not in _cat_sent]
                            # Se todo o pool já foi enviado → reseta histórico e usa tudo de novo
                            if not _fresh:
                                print(f"[autopostador] pool esgotado para {cat_key} — resetando histórico", flush=True)
                                _cat_sent = []
                                sent_history[cat_key] = []
                                _fresh = list(imgs)

                            async def _try_post_imgs(pool: list) -> str | None:
                                """Tenta até 8 imagens do pool. Retorna chave postada ou None."""
                                if not pool:
                                    return None
                                for _iu, _in in _random.sample(pool, min(8, len(pool))):
                                    _ext = _iu.split("?")[0].rsplit(".", 1)[-1].lower()
                                    if _ext not in ("jpg", "jpeg", "png", "gif", "webp"):
                                        _ext = "jpg"
                                    _fn = f"nata_post.{_ext}"
                                    try:
                                        async with aiohttp.ClientSession() as _s2:
                                            async with _s2.get(
                                                _iu,
                                                timeout=aiohttp.ClientTimeout(total=20),
                                                headers={"User-Agent": "Mozilla/5.0"},
                                            ) as _r2:
                                                if _r2.status != 200:
                                                    print(f"[autopostador] HTTP {_r2.status} ao baixar imagem", flush=True)
                                                    continue
                                                _d2 = await _r2.read()
                                                if len(_d2) < 5_000:
                                                    continue
                                        _f2   = discord.File(fp=io.BytesIO(_d2), filename=_fn)
                                        _s3 = await dest_ch.send(file=_f2)
                                        # Botão download — best-effort, não bloqueia o retorno
                                        try:
                                            _fu  = _s3.attachments[0].url if _s3.attachments else _iu
                                            _vw2 = discord.ui.View(timeout=None)
                                            _vw2.add_item(discord.ui.Button(
                                                label="Download",
                                                style=discord.ButtonStyle.link,
                                                url=_fu,
                                            ))
                                            await _s3.edit(view=_vw2)
                                        except Exception:
                                            pass
                                        return _fname_key(_iu)  # sucesso mesmo sem o botão
                                    except discord.Forbidden:
                                        print(f"[autopostador] sem permissão para postar em #{dest_ch.name}", flush=True)
                                        return None  # não adianta tentar outras imagens
                                    except Exception as _pe:
                                        print(f"[autopostador] erro ao postar ({cat_key}): {type(_pe).__name__}: {_pe}", flush=True)
                                return None

                            _posted_key = await _try_post_imgs(_fresh)

                            # Fallback: se todas as fontes falharam, tenta o canal de destino
                            if not _posted_key:
                                print(f"[autopostador] fontes falharam — tentando canal destino ({cat_key})", flush=True)
                                _fallback_imgs = await _fetch_imgs(dest_ch)
                                _fresh_fb = [(u, f) for u, f in _fallback_imgs if _fname_key(u) not in _cat_sent]
                                if not _fresh_fb:
                                    _fresh_fb = list(_fallback_imgs)
                                _posted_key = await _try_post_imgs(_fresh_fb)

                            _uploaded = _posted_key is not None

                            if _uploaded:
                                # Registra no histórico para não repetir
                                _cat_sent.append(_posted_key)
                                # Mantém histórico máximo de 500 entradas
                                if len(_cat_sent) > 500:
                                    _cat_sent = _cat_sent[-300:]
                                sent_history[cat_key] = _cat_sent
                                changed = True
                            else:
                                print(f"[autopostador] sem imagens válidas para {cat_key} em {guild.name}", flush=True)
                                continue

                            print(f"[autopostador] ✓ {cat_key} → #{dest_ch.name} em {guild.name}", flush=True)
                            last_posted[cat_key] = {"ts": now}
                            changed = True
                        except Exception as _ep:
                            print(f"[autopostador] erro {cat_key} em {guild.id}: {_ep}", flush=True)
                    if changed:
                        settings["gifs_autopostador_last_posted"] = last_posted
                        settings["gifs_autopostador_sent"]        = sent_history
                        save_settings_to_disk()
                except Exception as _eg:
                    print(f"[autopostador] erro guild {guild.id}: {_eg}", flush=True)
        except Exception as _e:
            print(f"[autopostador_loop] erro geral: {_e}", flush=True)


async def _auto_msg_loop():
    """Send auto messages at configured intervals."""
    await bot.wait_until_ready()
    while not bot.is_closed():
        await asyncio.sleep(30)
        try:
            now = datetime.now().timestamp()
            for guild in list(bot.guilds):
                settings = get_settings(guild.id)
                if not settings.get("auto_msg_enabled"):
                    continue
                lst = settings.get("auto_msg_list", [])
                for ent in lst:
                    try:
                        last = float(ent.get("last_sent") or 0)
                        interval = int(ent.get("interval_seconds") or 0)
                        if interval < 60:
                            continue
                        if now - last < interval:
                            continue
                        ch = guild.get_channel(ent.get("channel_id") or 0)
                        if not ch:
                            continue
                        if ent.get("mode") == "Embed":
                            embed = discord.Embed(
                                description=ent.get("message", ""),
                                color=settings["embed_color"],
                            )
                            await ch.send(embed=embed)
                        else:
                            await ch.send(ent.get("message", ""))
                        ent["last_sent"] = now
                    except (discord.Forbidden, discord.HTTPException):
                        continue
                    except Exception as e:
                        print(f"[auto_msg] erro: {e}")
        except Exception as e:
            print(f"[auto_msg_loop] erro geral: {e}")


@bot.event
async def on_ready():
    global _stream_prefix_current
    print(f"Bot online como {bot.user} (ID: {bot.user.id})")
    print(f"[DATA] embed_btn_data:   {_EMBED_BTN_DATA_FILE} (existe={os.path.exists(_EMBED_BTN_DATA_FILE)}, entradas={len(_embed_btn_data)})", flush=True)
    print(f"[DATA] embed_draft_data: {_EMBED_DRAFT_DATA_FILE} (existe={os.path.exists(_EMBED_DRAFT_DATA_FILE)}, entradas={len(_embed_draft_data)})", flush=True)
    print(f"[DATA] panelv2_data:     {_PANELV2_DATA_FILE} (existe={os.path.exists(_PANELV2_DATA_FILE)}, entradas={len(_panelv2_data)})", flush=True)
    # Restaura sessões de voz ativas (quem já está em call ao reiniciar o bot)
    _now_ts = datetime.now().timestamp()
    for _g in bot.guilds:
        for _vc in _g.voice_channels:
            for _m in _vc.members:
                if not _m.bot and _m.voice:
                    _vk = (_g.id, _m.id)
                    if _vk not in _voice_sessions:
                        _voice_sessions[_vk] = {
                            "join": _now_ts,
                            "mute_start": _now_ts if (_m.voice.self_mute or _m.voice.mute) else None,
                        }
    # on_ready dispara em reconexões — só inicia tasks uma vez (primeira conexão)
    if not getattr(bot, "_tasks_started", False):
        bot._tasks_started = True
        asyncio.create_task(_setup_success_emoji())
        asyncio.create_task(_setup_all_emojis())
        asyncio.create_task(_autopostador_loop())
        asyncio.create_task(_settings_watchdog_loop())
        _load_embed_drafts()
        # Auto-retoma dm_todos pendente
        try:
            _dt = _dm_todos_load()
            if _dt.get("message"):
                asyncio.create_task(_run_dm_todos(
                    _dt["message"],
                    _dt.get("notify_channel_id"),
                    set(_dt.get("sent_ids", [])),
                ))
        except Exception as _dte:
            print(f"[on_ready] auto-resume dm_todos: {_dte}")

        # Auto-retoma migrar_fotos pendente
        try:
            if os.path.exists(_MIGRAR_FOTOS_CKPT):
                import json as _mfjson
                with open(_MIGRAR_FOTOS_CKPT, "r", encoding="utf-8") as _mff:
                    _mfck = _mfjson.load(_mff)
                _mfsrc = _mfck.get("source")
                _mftgt = _mfck.get("target")
                _mfnch = _mfck.get("notify_channel_id")
                if _mfsrc and _mftgt:
                    asyncio.create_task(_run_migrar_fotos(_mfsrc, _mftgt, _mfnch or 0))
        except Exception as _mfe:
            print(f"[on_ready] auto-resume migrar_fotos: {_mfe}")

        # Auto-retoma migrações pendentes (checkpoint salvo em disco)
        try:
            for _mfname in os.listdir(_CLIENT_DIR):
                if _mfname.startswith("migration_") and _mfname.endswith(".json"):
                    try:
                        _mm = re.search(r"migration_(\d+)_(\d+)\.json", _mfname)
                        if _mm:
                            _msrc, _mtgt = int(_mm.group(1)), int(_mm.group(2))
                            _mmeta = _load_migration_ckpt(_msrc, _mtgt).get("_meta", {})
                            asyncio.create_task(_run_migration_task(_msrc, _mtgt, _mmeta.get("notify_channel_id")))
                    except Exception as _merr:
                        print(f"[on_ready] auto-resume migration item: {_merr}")
        except Exception as _le:
            print(f"[on_ready] auto-resume migration scan: {_le}")

    # Salva o nome de todos os servidores nas settings (para o dashboard)
    # Também atualiza bot_name e bot_tag com o tag completo do bot
    # get_settings() adiciona novas chaves via setdefault — salvar garante que fiquem no disco
    _disc = getattr(bot.user, "discriminator", "0") or "0"
    _bot_tag = f"{bot.user.name}#{_disc}"
    for _g in bot.guilds:
        try:
            _s = get_settings(_g.id)
            _s["guild_name"] = _g.name
            _s["bot_name"]   = _bot_tag
        except Exception:
            pass
    if bot.guilds:
        save_settings_to_disk()

    # Sincroniza bot_name com o dashboard ao iniciar (usa cid direto)
    if _BOT_CUSTOMER_ID:
        try:
            import aiohttp as _aio_r
            async with _aio_r.ClientSession() as _sess_r:
                await _sess_r.post(
                    f"{_DASHBOARD_URL}/api/admin/update-bot-name",
                    json={"cid": _BOT_CUSTOMER_ID, "bot_name": _bot_tag},
                    headers={"Authorization": f"Bearer {_DASHBOARD_SECRET}"},
                    timeout=_aio_r.ClientTimeout(total=10),
                )
        except Exception:
            pass

    # ── Registrar views persistentes ──────────────────────────────────────────
    for _view_cls, _view_name in [
        (_GifsConversorPublicSelect, "GifsConversorPublicSelect"),
        (lambda: MenuView(author_id=0),           "MenuView"),
        (GifsView,                                "GifsView"),
        (_FecharCanalView,                        "FecharCanalView"),
        (TicketThreadView,                        "TicketThreadView"),
    ]:
        try:
            bot.add_view(_view_cls())
        except Exception as _ve:
            print(f"[add_view] ERRO em {_view_name}: {_ve}", flush=True)

    # ── Restaurar painéis Dono de Call após reinício ───────────────────────────
    for _g in bot.guilds:
        _gs = get_settings(_g.id)
        for _cid_s, _mid in _gs.get("active_call_panels", {}).items():
            _call_panels[int(_cid_s)] = _mid
        for _cid_s, _oid in _gs.get("active_call_owners", {}).items():
            _call_owners[int(_cid_s)] = int(_oid)
        for _cid_s, _nm in _gs.get("active_call_orig_names", {}).items():
            _call_original_name[int(_cid_s)] = _nm
        for _cid_s, _lm in _gs.get("active_call_orig_limits", {}).items():
            _call_original_limit[int(_cid_s)] = int(_lm)
    # Registra views persistentes imediatamente (custom_ids determinísticos)
    for _cid in list(_call_panels.keys()):
        try:
            bot.add_view(DonoCallPanelView(_cid))
        except Exception as _ve:
            print(f"[add_view] DonoCallPanelView ch={_cid}: {_ve}", flush=True)
    asyncio.create_task(_restore_all_call_panels())

    # ── Reaplicar descrição salva ao Discord (persiste entre restarts) ───────
    if os.path.exists(DESC_SAVED_FILE):
        try:
            _saved_desc = open(DESC_SAVED_FILE, encoding="utf-8").read().strip()
            if _saved_desc and not os.path.exists(DESC_REQ_FILE):
                open(DESC_REQ_FILE, "w", encoding="utf-8").write(_saved_desc)
                print(f"[desc] reaplicando descrição salva no startup", flush=True)
        except Exception as _dse:
            print(f"[desc] erro ao ler descrição salva: {_dse}", flush=True)

    # ── Restaurar prefixo persistido ──────────────────────────────────────────
    # Prioridade: PREFIX_FILE (/data persistente) → bot_settings → "n!"
    _saved_prefix = "n!"

    # 1) PREFIX_FILE é atualizado sempre que o cliente muda o prefixo — fonte mais confiável
    if os.path.exists(PREFIX_FILE):
        try:
            _pf_val = open(PREFIX_FILE, "r", encoding="utf-8").read().strip()
            if _pf_val:
                _saved_prefix = _pf_val
        except Exception:
            pass

    # 2) Se PREFIX_FILE tem "n!" ou não existe, tenta bot_settings como fallback
    if _saved_prefix == "n!":
        if _BOT_GUILD_ID and _BOT_GUILD_ID in bot_settings:
            _p = bot_settings[_BOT_GUILD_ID].get("prefix", "n!")
            if _p and _p != "n!":
                _saved_prefix = _p
        elif bot.guilds:
            for _g in bot.guilds:
                if _g.id in bot_settings:
                    _p = bot_settings[_g.id].get("prefix", "n!")
                    if _p and _p != "n!":
                        _saved_prefix = _p
                        break

    # Salva no PREFIX_FILE para próximos restarts e sincroniza bot_settings
    try:
        with open(PREFIX_FILE, "w", encoding="utf-8") as _pf:
            _pf.write(_saved_prefix)
    except Exception:
        pass
    if _BOT_GUILD_ID and _BOT_GUILD_ID in bot_settings:
        bot_settings[_BOT_GUILD_ID]["prefix"] = _saved_prefix
    elif bot.guilds:
        for _g in bot.guilds:
            if _g.id in bot_settings:
                bot_settings[_g.id]["prefix"] = _saved_prefix
                break
    print(f"[prefix] restaurado: '{_saved_prefix}' de '{PREFIX_FILE}'", flush=True)

    _stream_prefix_current = _saved_prefix

    # ── Presence PRIMEIRO — antes de qualquer outro await que possa falhar ──────
    try:
        await bot.change_presence(
            status=discord.Status.online,
            activity=discord.Streaming(
                name=f"Prefixo: {_saved_prefix}",
                url="https://twitch.tv/hypebots",
            ),
        )
        print(f"[presence] OK streaming: Prefixo: {_saved_prefix}", flush=True)
    except Exception as e:
        print(f"[presence] ERRO: {e}", flush=True)
    if not _presence_task.is_running():
        _presence_task.start()
    if not _verif_pending_task.is_running():
        _verif_pending_task.start()
    if not _verif_auto_scan_task.is_running():
        _verif_auto_scan_task.start()

    # ── Bio / Descrição do perfil ─────────────────────────────────────────────
    _bio_text = "**Bot desenvolvido pela Hypebots**\nhttps://discord.gg/hypebot"
    try:
        import aiohttp as _aiohttp_bio
        _bio_headers = {
            "Authorization": f"Bot {bot.http.token}",
            "Content-Type": "application/json",
        }
        async with _aiohttp_bio.ClientSession() as _bio_session:
            # Tenta application description (visível no perfil do bot)
            async with _bio_session.patch(
                "https://discord.com/api/v10/applications/@me",
                headers=_bio_headers,
                json={"description": _bio_text},
            ) as _r1:
                _t1 = await _r1.text()
                print(f"[bio] /applications/@me -> {_r1.status}: {_t1[:200]}", flush=True)

            # Tenta também user bio (compatibilidade)
            async with _bio_session.patch(
                "https://discord.com/api/v10/users/@me",
                headers=_bio_headers,
                json={"bio": _bio_text},
            ) as _r2:
                _t2 = await _r2.text()
                print(f"[bio] /users/@me -> {_r2.status}: {_t2[:200]}", flush=True)
    except Exception as _e_bio:
        print(f"[bio] erro: {_e_bio}", flush=True)

    # ── Avatar / Banner padrão HYPE (aplicado se não houver arquivo customizado) ─
    if not getattr(bot, "_default_avatar_set", False):
        bot._default_avatar_set = True
        _code_dir = os.path.dirname(os.path.abspath(__file__))

        def _read_image(client_env_key: str, default_filename: str) -> bytes | None:
            """Lê o arquivo customizado do cliente; se não existir, usa o padrão HYPE."""
            # 1. Arquivo customizado do cliente
            client_path = os.environ.get(client_env_key, "")
            if client_path and os.path.exists(client_path):
                try:
                    data = open(client_path, "rb").read()
                    if data: return data
                except Exception:
                    pass
            # 2. Fallback: imagem padrão HYPE no diretório do código
            default_path = os.path.join(_code_dir, default_filename)
            if os.path.exists(default_path):
                try:
                    data = open(default_path, "rb").read()
                    if data: return data
                except Exception:
                    pass
            return None

        # Avatar — aplica o arquivo customizado do cliente OU o default_avatar.png
        _ab = _read_image("BOT_AVATAR_FILE", "default_avatar.png")
        _avatar_path = os.environ.get("BOT_AVATAR_FILE", "")
        # Determina o arquivo de referência para o hash (customizado > padrão)
        _hash_ref = (
            _avatar_path
            if (_avatar_path and os.path.exists(_avatar_path) and os.path.getsize(_avatar_path) > 0)
            else os.path.join(_code_dir, "default_avatar.png")
        )
        # Verifica se o avatar precisa ser atualizado via hash MD5
        _should_set_avatar = False
        if _ab:
            try:
                import hashlib as _hl
                _file_hash  = _hl.md5(_ab).hexdigest()
                _hash_file  = _hash_ref + ".md5"
                _saved_hash = open(_hash_file).read().strip() if os.path.exists(_hash_file) else ""
                # Troca apenas se o arquivo mudou OU se nunca foi aplicado (hash ausente)
                _should_set_avatar = (_file_hash != _saved_hash)
            except Exception:
                _should_set_avatar = True

        if _ab and _should_set_avatar:
            try:
                await bot.user.edit(avatar=_ab)
                print(f"[avatar] OK ({len(_ab)} bytes)", flush=True)
                await _update_app_icon(_ab, "image/png")
                # Salva hash para evitar re-aplicar no próximo restart
                try:
                    import hashlib as _hl2
                    open(_hash_ref + ".md5", "w").write(_hl2.md5(_ab).hexdigest())
                except Exception:
                    pass
            except discord.HTTPException as _e:
                print(f"[avatar] HTTPException código {_e.code}: {_e.text}", flush=True)
            except Exception as _e:
                print(f"[avatar] erro: {type(_e).__name__}: {_e}", flush=True)
        elif _ab:
            print("[avatar] avatar já está atualizado, pulando troca.", flush=True)
            # Garante que o ícone OAuth2 (tela de autorização) também está definido,
            # mesmo quando o avatar do bot não precisou ser trocado.
            await _update_app_icon(_ab, "image/png")
        else:
            print("[avatar] arquivo não encontrado.", flush=True)

        # Aguarda 2s entre edições para evitar rate limit
        await asyncio.sleep(2)

        # Banner — tenta com retry porque múltiplos bots no mesmo restart competem pelo rate limit
        _bb = _read_image("BOT_BANNER_FILE", "default_banner.png")
        if _bb:
            for _ba in range(3):
                try:
                    await bot.user.edit(banner=_bb)
                    print(f"[banner] OK ({len(_bb)} bytes)", flush=True)
                    break
                except discord.HTTPException as _e:
                    _is_rl = _e.code == 50035 and "too fast" in (_e.text or "").lower()
                    print(f"[banner] HTTPException código {_e.code} (tentativa {_ba+1}): {_e.text}", flush=True)
                    if _is_rl and _ba < 2:
                        await asyncio.sleep(90 * (_ba + 1))
                        continue
                    break
                except Exception as _e:
                    print(f"[banner] erro: {type(_e).__name__}: {_e}", flush=True)
                    break
        else:
            print("[banner] arquivo não encontrado", flush=True)

    if not getattr(bot, "_backup_task_started", False):
        bot.loop.create_task(_backup_loop())
        bot._backup_task_started = True
    if not getattr(bot, "_settings_save_task_started", False):
        bot.loop.create_task(_settings_save_loop())
        bot._settings_save_task_started = True
    if not getattr(bot, "_auto_msg_task_started", False):
        bot.loop.create_task(_auto_msg_loop())
        bot._auto_msg_task_started = True
    if not getattr(bot, "_calendar_task_started", False):
        bot.loop.create_task(_calendar_loop())
        bot._calendar_task_started = True
    if True:  # sempre sincroniza ao (re)conectar para garantir novos comandos
        import sys
        # 0. Remove /dev de todos os servidores via API (comando desativado definitivamente)
        for guild in bot.guilds:
            try:
                existing = await bot.tree.fetch_commands(guild=guild)
                for cmd in existing:
                    if cmd.name == "dev":
                        await bot.http.delete_guild_command(bot.application_id, guild.id, cmd.id)
                        print(f"[cleanup] /dev removido de '{guild.name}'", flush=True, file=sys.stderr)
            except Exception as e:
                print(f"[cleanup] erro ao remover /dev de '{guild.name}': {e}", flush=True, file=sys.stderr)
        # 1. Copia globais para cada servidor e sincroniza
        for guild in bot.guilds:
            try:
                bot.tree.copy_global_to(guild=guild)
                synced = await bot.tree.sync(guild=guild)
                print(f"[slash] {guild.name}: {len(synced)} cmds.", flush=True, file=sys.stderr)
            except Exception as e:
                print(f"[slash] ERRO {guild.name}: {e}", flush=True, file=sys.stderr)
        # Não limpa o global — necessário para on_guild_join funcionar em servidores novos
        bot._tree_synced = True


@bot.event
async def on_guild_join(guild: discord.Guild):
    """Sincroniza slash commands quando o bot entra em um servidor novo."""
    import sys
    try:
        bot.tree.copy_global_to(guild=guild)
        synced = await bot.tree.sync(guild=guild)
        print(f"[slash] novo servidor '{guild.name}': {len(synced)} cmds sincronizados.", flush=True, file=sys.stderr)
    except Exception as e:
        print(f"[slash] ERRO ao sincronizar '{guild.name}': {e}", flush=True, file=sys.stderr)


@bot.event
async def on_command_error(ctx: commands.Context, error: commands.CommandError):
    """Silently handle CommandNotFound + auto-delete trigger to keep chat clean."""
    if isinstance(error, commands.CommandNotFound):
        try:
            await ctx.message.delete(delay=2)
        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
            pass
        return
    if isinstance(error, commands.MissingRequiredArgument):
        try:
            await ctx.reply(
                f"<a:alerta:1518271939460857968> Argumento faltando: `{error.param.name}`",
                delete_after=8,
            )
        except (discord.Forbidden, discord.HTTPException):
            pass
        return
    if isinstance(error, commands.BadArgument):
        try:
            await ctx.reply(
                f"<a:alerta:1518271939460857968> Argumento inválido.",
                delete_after=8,
            )
        except (discord.Forbidden, discord.HTTPException):
            pass
        return
    if isinstance(error, commands.CheckFailure):
        try:
            await ctx.message.delete(delay=2)
        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
            pass
        return
    if isinstance(error, commands.CommandInvokeError):
        inner = error.original
        if isinstance(inner, discord.Forbidden):
            # Bot sem permissão para enviar mensagens no canal — tenta DM
            try:
                settings = get_settings(ctx.guild.id if ctx.guild else 0)
                prefix   = settings.get("prefix", "n!")
                await ctx.author.send(
                    f"⚠️ Não consigo responder em **{ctx.channel}** "
                    f"(`{ctx.guild.name if ctx.guild else ''}`) — sem permissão para enviar mensagens.\n"
                    f"Use `{prefix}{ctx.command.name}` em um canal onde tenho acesso."
                )
            except Exception:
                pass
            return
    # Outros erros: loga no console mas não polui o chat
    print(f"[on_command_error] {type(error).__name__}: {error}")


@bot.tree.error
async def on_app_command_error(interaction: discord.Interaction, error: discord.app_commands.AppCommandError) -> None:
    """Handler global para erros em slash commands — evita 'Esta interação falhou'."""
    import traceback
    traceback.print_exc()
    try:
        msg = f"❌ Erro interno: `{type(error).__name__}: {str(error)[:200]}`"
        if not interaction.response.is_done():
            await interaction.response.send_message(embed=_notif_embed(msg), ephemeral=True)
        else:
            await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)
    except Exception:
        pass


@bot.event
async def on_command_completion(ctx: commands.Context):
    """Anti-poluição: deleta a mensagem do usuário após N segundos de o comando rodar."""
    if ctx.guild is None or ctx.message is None:
        return
    settings = get_settings(ctx.guild.id)
    if not settings.get("anti_poluicao_enabled", True):
        return
    delay = int(settings.get("anti_poluicao_delay", 3) or 3)
    if delay < 1:
        return
    try:
        await ctx.message.delete(delay=delay)
    except (discord.Forbidden, discord.NotFound, discord.HTTPException):
        pass


async def _apply_action(action: str, member: discord.Member, message: discord.Message, reason: str):
    if action in ("apagar", "delete"):
        try:
            await message.delete()
        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
            pass
    elif action in ("kikar", "kick"):
        try:
            await message.delete()
        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
            pass
        try:
            await member.kick(reason=reason)
        except (discord.Forbidden, discord.HTTPException):
            pass
    elif action in ("banir", "ban"):
        try:
            await message.delete()
        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
            pass
        try:
            await member.ban(reason=reason, delete_message_days=0)
        except (discord.Forbidden, discord.HTTPException):
            pass
    elif action in ("mutar", "mute"):
        try:
            await member.timeout(timedelta(minutes=10), reason=reason)
        except (discord.Forbidden, discord.HTTPException):
            pass


# =============================================================================
# IA — Integração com API OpenAI-compatível
# =============================================================================

# =============================================================================
# Anti-Flood (anti-derrubar do bot)
# =============================================================================
# Rastreia tentativas de comando/mention por usuário em uma janela deslizante.
# Se exceder o limite, ignora o usuário por X segundos.
ANTI_FLOOD_HITS: dict[int, list[float]] = {}  # user_id -> [timestamp, ...]
ANTI_FLOOD_BLOCKED: dict[int, float] = {}  # user_id -> blocked_until_timestamp
ANTI_FLOOD_MAX = 10        # máx requests
ANTI_FLOOD_WINDOW = 5.0    # janela em segundos
ANTI_FLOOD_COOLDOWN = 30.0 # quanto tempo de bloqueio (segundos)


def _check_anti_flood(user_id: int) -> bool:
    """Returns True if user is blocked (should be ignored)."""
    now = datetime.now().timestamp()
    # Check if currently blocked
    blocked_until = ANTI_FLOOD_BLOCKED.get(user_id)
    if blocked_until and now < blocked_until:
        return True
    if blocked_until and now >= blocked_until:
        ANTI_FLOOD_BLOCKED.pop(user_id, None)

    # Add new hit
    hits = ANTI_FLOOD_HITS.setdefault(user_id, [])
    hits.append(now)
    # Drop old hits outside window
    cutoff = now - ANTI_FLOOD_WINDOW
    while hits and hits[0] < cutoff:
        hits.pop(0)
    # If too many in window, block
    if len(hits) >= ANTI_FLOOD_MAX:
        ANTI_FLOOD_BLOCKED[user_id] = now + ANTI_FLOOD_COOLDOWN
        hits.clear()
        return True
    return False


AI_HISTORY: dict[int, list[dict]] = {}  # {channel_id: [{role, content}, ...]}
AI_HISTORY_MAX = 20

def _get_ai_config() -> tuple[str | None, str, str]:
    """Returns (api_key, base_url, model)."""
    api_key = os.getenv("AI_API_KEY") or os.getenv("OPENAI_API_KEY")
    base = os.getenv("AI_API_BASE", "https://api.openai.com/v1").rstrip("/")
    model = os.getenv("AI_MODEL", "gpt-4o-mini")
    return api_key, base, model


async def _ai_complete(system_prompt: str, history: list[dict], user_msg: str) -> str | None:
    """Call OpenAI-compatible /chat/completions and return the assistant text."""
    api_key, base, model = _get_ai_config()
    if not api_key:
        return None
    messages = [{"role": "system", "content": system_prompt}]
    messages.extend(history)
    messages.append({"role": "user", "content": user_msg})
    payload = {
        "model": model,
        "messages": messages,
        "max_tokens": 800,
        "temperature": 0.7,
    }
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json",
    }
    url = f"{base}/chat/completions"
    try:
        async with aiohttp.ClientSession() as session:
            async with session.post(url, json=payload, headers=headers, timeout=30) as resp:
                if resp.status != 200:
                    text = await resp.text()
                    print(f"[AI] HTTP {resp.status}: {text[:200]}")
                    return None
                data = await resp.json()
                choices = data.get("choices") or []
                if not choices:
                    return None
                return choices[0].get("message", {}).get("content", "").strip() or None
    except (asyncio.TimeoutError, aiohttp.ClientError) as e:
        print(f"[AI] erro: {e}")
        return None


def _find_ia_panel_for_channel(settings: dict, channel: discord.abc.GuildChannel) -> dict | None:
    """Find a ticket panel where this channel matches (panel channel or thread parent)."""
    if channel is None:
        return None
    # Check direct match
    parent_id = getattr(channel, "parent_id", None) or 0
    own_id = getattr(channel, "id", 0)
    for panel in settings.get("ticket_panels", []):
        pid = panel.get("channel_id")
        if pid and (pid == own_id or pid == parent_id):
            cfg = settings.get("ticket_ia_configs", {}).get(str(panel["id"]))
            if cfg and cfg.get("enabled") and cfg.get("prompt"):
                return panel
    return None


def _build_ia_system_prompt(user_prompt: str, member: discord.Member | None) -> str:
    """Compose final system prompt with user-defined prompt + server/user context."""
    parts = [user_prompt.strip()]
    if member and member.guild:
        ctx = (
            f"\n\n[Contexto da conversa]\n"
            f"Servidor: {member.guild.name}\n"
            f"Usuário falando: {member.display_name} ({member.name})\n"
            f"Responda em **português brasileiro** a menos que o usuário fale outro idioma.\n"
            f"Seja direto, prestativo e use formatação Discord (negrito, listas) quando útil.\n"
            f"Não invente informações; se não souber, diga que vai chamar um moderador."
        )
        parts.append(ctx)
    return "".join(parts)


async def _process_ia_message(message: discord.Message) -> bool:
    """If IA is enabled for the channel's ticket panel, reply with AI. Return True if handled."""
    if message.guild is None or message.author.bot:
        return False
    if not message.content or message.content.startswith(("n!", "/")):
        return False
    settings = get_settings(message.guild.id)
    panel = _find_ia_panel_for_channel(settings, message.channel)
    if not panel:
        return False
    cfg = settings["ticket_ia_configs"][str(panel["id"])]
    user_prompt = cfg.get("prompt") or ""
    if not user_prompt:
        return False

    history = AI_HISTORY.setdefault(message.channel.id, [])
    # Count user messages already in history
    user_count = sum(1 for h in history if h.get("role") == "user")
    if user_count >= AI_HISTORY_MAX:
        return False  # cap reached for this ticket

    member = message.author if isinstance(message.author, discord.Member) else None
    system_prompt = _build_ia_system_prompt(user_prompt, member)

    # Typing indicator
    response = None
    try:
        async with message.channel.typing():
            response = await _ai_complete(system_prompt, history, message.content)
    except Exception as e:
        print(f"[AI] typing erro: {e}")

    if not response:
        try:
            await message.reply(
                "<a:alerta:1518271939460857968> IA não configurada (defina `AI_API_KEY` no `.env`) ou falha na resposta.",
                mention_author=False,
            )
        except (discord.Forbidden, discord.HTTPException):
            pass
        return True

    history.append({"role": "user", "content": message.content[:2000]})
    history.append({"role": "assistant", "content": response[:2000]})
    # Trim history to last 2*AI_HISTORY_MAX entries
    if len(history) > AI_HISTORY_MAX * 2:
        del history[: len(history) - AI_HISTORY_MAX * 2]

    # Reply as embed (cleaner look) with bot avatar/name as author
    try:
        chunk_size = 4000
        icon_url = bot.user.display_avatar.url if bot.user else None
        if len(response) <= chunk_size:
            embed = discord.Embed(
                description=response,
                color=settings["embed_color"],
            )
            embed.set_author(name="🤖 IA — NATA®", icon_url=icon_url)
            await message.reply(embed=embed, mention_author=False)
        else:
            for i in range(0, len(response), chunk_size):
                chunk = response[i:i + chunk_size]
                embed = discord.Embed(description=chunk, color=settings["embed_color"])
                if i == 0:
                    embed.set_author(name="🤖 IA — NATA®", icon_url=icon_url)
                await message.channel.send(embed=embed)
    except (discord.Forbidden, discord.HTTPException):
        # Fallback to plain text if embed fails
        try:
            await message.reply(response[:1900], mention_author=False)
        except (discord.Forbidden, discord.HTTPException):
            pass
    return True


async def _check_antspam(message: discord.Message, settings: dict) -> bool:
    if not settings.get("antspam_enabled"):
        return False
    window = settings.get("antspam_flood_time")
    threshold = settings.get("antspam_flood_value")
    if not window or not threshold:
        return False
    author = message.author
    if not isinstance(author, discord.Member):
        return False
    if author.guild_permissions.administrator:
        return False
    author_role_ids = {r.id for r in author.roles}
    if author_role_ids.intersection(settings.get("antspam_ignore_roles", [])):
        return False
    if message.channel.id in settings.get("antspam_ignore_channels", []):
        return False

    key = (message.guild.id, author.id)
    now = message.created_at.timestamp()

    history = antspam_history.setdefault(key, [])
    history.append(now)
    cutoff = now - window
    antspam_history[key] = [t for t in history if t >= cutoff]

    if len(antspam_history[key]) < threshold:
        return False

    antspam_history[key] = []
    action = settings["antspam_flood_action"]
    await _apply_action(action, author, message, "Anti Spam: limite de flood atingido.")

    log_channel_id = settings.get("antspam_log_channel")
    if log_channel_id:
        channel = message.guild.get_channel(log_channel_id)
        if channel:
            embed = discord.Embed(
                title=TRANSLATIONS[settings["language"]]["antspam_panel_title"],
                description=(
                    f"💬 **{author}** (`{author.id}`) — flood detectado "
                    f"({threshold} msgs em {window}s). Ação: `{action}`."
                ),
                color=settings["embed_color"],
            )
            embed.timestamp = datetime.now()
            try:
                await channel.send(embed=embed)
            except (discord.Forbidden, discord.HTTPException):
                pass
    return True


async def _schedule_cleanup_message(message: discord.Message, delay: int = 60):
    await asyncio.sleep(delay)
    try:
        await message.delete()
    except (discord.Forbidden, discord.NotFound, discord.HTTPException):
        pass


@bot.event
async def on_message(message: discord.Message):
    if message.author.bot or message.guild is None:
        await bot.process_commands(message)
        return

    # Anti-derrubar: se o usuário tá flooding o bot (comando OU mentions ao bot),
    # ignorar o restante (não processa comandos, IA, auto-resposta etc.)
    content_low = (message.content or "").lower()
    mentions_bot = bot.user and (bot.user in message.mentions or f"<@{bot.user.id}>" in message.content)
    is_bot_command = content_low.startswith("n!")
    if is_bot_command or mentions_bot:
        if _check_anti_flood(message.author.id):
            return  # ignora sem responder

    settings = get_settings(message.guild.id)

    # Auto-assume ticket: primeiro staff a mandar mensagem assume automaticamente
    if (
        isinstance(message.channel, discord.Thread)
        and isinstance(message.author, discord.Member)
        and _ticket_assumed.get(message.channel.id) is None
    ):
        _thr = message.channel
        _is_tkt = any(p.get("channel_id") == _thr.parent_id for p in settings.get("ticket_panels", []))
        if _is_tkt:
            _m = message.author
            _is_staff = _m.guild_permissions.administrator or message.guild.owner_id == _m.id
            if not _is_staff:
                for _p in settings.get("ticket_panels", []):
                    if _p.get("channel_id") == _thr.parent_id:
                        _rids: set[int] = set(_p.get("responsible_roles", []))
                        for _op in _p.get("menu_opcoes", []):
                            _rids |= set(_op.get("responsible_roles", []))
                        if _rids & {r.id for r in _m.roles}:
                            _is_staff = True
                            break
            if _is_staff:
                _ticket_assumed[_thr.id] = _m.id
                _ak_auto = (message.guild.id, _m.id)
                _ticket_assume_counts[_ak_auto] = _ticket_assume_counts.get(_ak_auto, 0) + 1
                _cnt_p = _ticket_assume_counts[_ak_auto]
                _cnt_t = settings.get("ticket_total_count", 0)
                import aiohttp as _ah_auto_msg
                try:
                    async with _ah_auto_msg.ClientSession() as _s_auto:
                        await _s_auto.post(
                            f"https://discord.com/api/v10/channels/{_thr.id}/messages",
                            json={
                                "flags": 32768,
                                "components": [{"type": 17, "accent_color": 0x2ecc71, "components": [{"type": 10, "content": f"<a:verificadoverde:1518272098290892810> Ticket assumido por: {_m.mention} ({_cnt_p}/{_cnt_t})"}]}],
                            },
                            headers={"Authorization": f"Bot {bot.http.token}", "Content-Type": "application/json"},
                        )
                except Exception as _ae:
                    print(f"[ticket_auto_assume] {_ae}", flush=True)

    # Verificação Instagram — auto-resposta quando foto é enviada no ticket
    if message.attachments and isinstance(message.channel, discord.Thread):
        _igv_parent = getattr(message.channel, 'parent_id', None)
        _igv_ch_id = settings.get("ig_verif_channel")
        if _igv_parent and _igv_ch_id and _igv_parent == _igv_ch_id:
            try:
                icon_url = bot.user.display_avatar.url if bot.user else None
                auto_emb = discord.Embed(
                    description="📸 Foto em analise pela equipe, pfv aguarde!!",
                    color=settings.get("embed_color", 0x2B2D31),
                )
                auto_emb.set_footer(text=_footer_name(message.guild, settings), icon_url=icon_url)
                await message.channel.send(embed=auto_emb)
            except Exception as _e:
                print(f"[ig_verif] erro auto-resposta foto: {_e}", flush=True)

    # Tellonym — captura mensagens no canal de criação e envia anonimamente
    _tell_cria_ch = settings.get("tellonym_creation_channel")
    if _tell_cria_ch and message.channel.id == _tell_cria_ch:
        await _process_tellonym_message(message, settings)
        return

    # Auto Reações (gatilhos por canal)
    if settings.get("auto_reacoes_enabled"):
        for ent in settings.get("auto_reacoes_list", []):
            try:
                if ent.get("channel_id") != message.channel.id:
                    continue
                trig = (ent.get("trigger") or "").lower()
                if not trig:
                    continue
                if trig in message.content.lower():
                    emoji_raw = (ent.get("emoji") or "").strip()
                    if not emoji_raw:
                        continue
                    try:
                        if emoji_raw.startswith("<") and emoji_raw.endswith(">"):
                            emoji = discord.PartialEmoji.from_str(emoji_raw)
                        else:
                            emoji = emoji_raw
                        await message.add_reaction(emoji)
                    except (discord.Forbidden, discord.HTTPException, discord.NotFound):
                        pass
            except Exception:
                pass

    # IA - Inteligência Artificial nos Tickets
    if await _process_ia_message(message):
        await bot.process_commands(message)
        return

    # Auto Resposta (responde com texto definido quando gatilho aparece em canais permitidos)
    if settings.get("auto_resp_enabled"):
        allowed = settings.get("auto_resp_channels", [])
        if not allowed or message.channel.id in allowed:
            content_low = message.content.lower()
            for entry in settings.get("auto_resp_messages", []):
                trig = (entry.get("trigger") or "").lower()
                if trig and trig in content_low:
                    try:
                        await message.channel.send(entry.get("response", ""))
                    except (discord.Forbidden, discord.HTTPException):
                        pass
                    break

    # Reações Personalizadas (por usuário, em canais permitidos)
    if settings.get("reacoes_user_enabled"):
        allowed = settings.get("reacoes_user_channels", [])
        if not allowed or message.channel.id in allowed:
            users = settings.get("reacoes_user_users", {})
            emojis = users.get(str(message.author.id), [])
            for emoji_raw in emojis[:5]:
                try:
                    if emoji_raw.startswith("<") and emoji_raw.endswith(">"):
                        emoji = discord.PartialEmoji.from_str(emoji_raw)
                    else:
                        emoji = emoji_raw
                    await message.add_reaction(emoji)
                except (discord.Forbidden, discord.HTTPException, discord.NotFound):
                    pass

    if settings.get("limpeza_mensagem_enabled"):
        delay_seconds = None

        if (
            settings.get("limpeza_voice_auto_all")
            and isinstance(message.channel, discord.VoiceChannel)
        ):
            delay_seconds = settings.get("limpeza_voice_delay_minutes", 1) * 60

        if delay_seconds is None:
            text_channels = settings.get("limpeza_text_channels", [])
            if text_channels and message.channel.id in text_channels:
                delay_seconds = settings.get("limpeza_text_delay_minutes", 1) * 60

        if delay_seconds is None:
            legacy_channels = settings.get("limpeza_mensagem_channels", [])
            if legacy_channels and message.channel.id in legacy_channels:
                delay_seconds = settings.get("limpeza_delay_minutes", 1) * 60

        if delay_seconds:
            bot.loop.create_task(_schedule_cleanup_message(message, delay_seconds))

    if settings.get("cmd_block_enabled"):
        prefix = settings.get("prefix", "n!")
        if message.content.startswith(prefix):
            is_admin = (
                isinstance(message.author, discord.Member)
                and message.author.guild_permissions.administrator
            )
            if not is_admin and message.channel.id not in settings.get("cmd_block_allowed_channels", []):
                log_channel_id = settings.get("cmd_block_log_channel")
                if log_channel_id:
                    log_channel = message.guild.get_channel(log_channel_id)
                    if log_channel:
                        try:
                            await log_channel.send(
                                f"⛔ Comando bloqueado de **{message.author}** em "
                                f"{message.channel.mention}: `{message.content[:200]}`"
                            )
                        except (discord.Forbidden, discord.HTTPException):
                            pass
                return

    if await _check_antspam(message, settings):
        return

    antlink_on = settings.get("antlink_enabled")
    antinvite_on = settings.get("antinvite_enabled")

    if not antlink_on and not antinvite_on:
        await bot.process_commands(message)
        return

    author = message.author
    if isinstance(author, discord.Member):
        if author.guild_permissions.administrator:
            await bot.process_commands(message)
            return
        author_role_ids = {r.id for r in author.roles}
        if author_role_ids.intersection(settings.get("antlink_protected_roles", [])):
            await bot.process_commands(message)
            return

    if message.channel.id in settings.get("antlink_allowed_channels", []):
        await bot.process_commands(message)
        return

    has_invite = bool(INVITE_REGEX.search(message.content))
    has_link = bool(LINK_REGEX.search(message.content))

    triggered = False
    if antinvite_on and has_invite:
        triggered = True
    elif antlink_on and has_link:
        triggered = True

    if not triggered:
        await bot.process_commands(message)
        return

    action = settings.get("antlink_action", "apagar")

    try:
        await message.delete()
    except (discord.Forbidden, discord.NotFound, discord.HTTPException):
        pass

    if action == "kikar" and isinstance(author, discord.Member):
        try:
            await author.kick(reason="Anti Link/Invite: envio de link bloqueado.")
        except (discord.Forbidden, discord.HTTPException):
            pass
    elif action == "banir" and isinstance(author, discord.Member):
        try:
            await author.ban(reason="Anti Link/Invite: envio de link bloqueado.", delete_message_days=0)
        except (discord.Forbidden, discord.HTTPException):
            pass


async def _log_kick(member: discord.Member, channel_id: int, title: str, description: str, color: int):
    if not channel_id:
        return
    channel = member.guild.get_channel(channel_id)
    if channel is None:
        return
    embed = discord.Embed(title=title, description=description, color=color)
    embed.timestamp = datetime.now()
    try:
        await channel.send(embed=embed)
    except (discord.Forbidden, discord.HTTPException):
        pass


@bot.event
async def on_member_update(before: discord.Member, after: discord.Member):
    added: set[int] = set()
    removed: set[int] = set()
    if before.roles == after.roles:
        if before is not after:
            return  # cargo não mudou (membro em cache)
        # Membro fora do cache — discord.py despacha o mesmo objeto para before e after.
        # Reconstruímos a mudança de cargo a partir do audit log.
        try:
            from datetime import timezone as _tz_mu
            await asyncio.sleep(0.3)
            async for entry in after.guild.audit_logs(
                limit=5, action=discord.AuditLogAction.member_role_update
            ):
                if not (entry.target and entry.target.id == after.id):
                    continue
                age = (datetime.now(_tz_mu.utc) - entry.created_at).total_seconds()
                if age > 20:
                    break
                _bl = getattr(entry.before, 'roles', [])
                _al = getattr(entry.after, 'roles', [])
                added = {r.id for r in _al} - {r.id for r in _bl}
                removed = {r.id for r in _bl} - {r.id for r in _al}
                break
        except Exception:
            return
        if not added and not removed:
            return
    else:
        before_ids = {r.id for r in before.roles}
        after_ids = {r.id for r in after.roles}
        added = after_ids - before_ids
        removed = before_ids - after_ids
        if not added and not removed:
            return

    # ── Blacklist de cargos permanente ────────────────────────────────────────
    if added:
        _bl_s = get_settings(after.guild.id)
        if after.id in _bl_s.get("blacklist_cargos", []):
            _removable_bl = [
                r for r in after.roles
                if r.id in added and not r.is_default()
                and r.position < after.guild.me.top_role.position
            ]
            if _removable_bl:
                try:
                    await after.remove_roles(*_removable_bl, reason="Anti-Raid: blacklist de cargos ativa")
                except Exception:
                    pass
            return

    settings = get_settings(after.guild.id)
    history = settings.setdefault("role_history", [])
    timestamp = datetime.now().strftime("%d/%m/%Y %H:%M")

    # ── Fast-path: cargos bloqueados são revertidos imediatamente sem esperar audit log ──
    _fast_handled: set[int] = set()
    if settings.get("protecao_cargos_enabled") and added:
        _bl_cfg_fast = settings.get("protecao_cargo_bloqueado", {})
        if _bl_cfg_fast:
            _fast_remove_roles: list[discord.Role] = []
            for _rid in list(added):
                if str(_rid) not in _bl_cfg_fast:
                    continue
                if _consume_bot_role_action(after.id, _rid, "add"):
                    # bot fez esta ação (ex: /groles) — não rebocar
                    _fast_handled.add(_rid)
                    continue
                _r = after.guild.get_role(_rid)
                if _r and _r.position < after.guild.me.top_role.position:
                    _fast_remove_roles.append(_r)
                _fast_handled.add(_rid)
            if _fast_remove_roles:
                try:
                    await after.remove_roles(
                        *_fast_remove_roles,
                        reason="Proteção de Cargos: cargo bloqueado",
                    )
                    print(
                        f"[protecao_fast] guild={after.guild.id} member={after.id} "
                        f"removidos={[r.id for r in _fast_remove_roles]}",
                        flush=True,
                    )
                except Exception as _fe:
                    print(f"[protecao_fast] erro ao remover: {_fe}", flush=True)
        added -= _fast_handled  # retira do added para o slow-path não reprocessar

    moderator_id = None
    moderator_name = "Sistema"
    moderator_obj = None
    await asyncio.sleep(0.3)  # reduzido de 2s — Discord regista audit log em <300ms
    try:
        from datetime import timezone as _tz
        async for entry in after.guild.audit_logs(limit=15, action=discord.AuditLogAction.member_role_update):
            if entry.target and entry.target.id == after.id:
                age = (datetime.now(_tz.utc) - entry.created_at).total_seconds()
                if age > 20:
                    break  # entrada muito antiga — ignorar para evitar falso-positivo
                if entry.user:
                    moderator_id = entry.user.id
                    moderator_name = entry.user.name
                    moderator_obj = entry.user
                break
    except (discord.Forbidden, discord.HTTPException) as e:
        print(f"[protecao_cargos] Falha ao ler audit log: {e}")

    print(
        f"[bl_check] member={after.id} mod={moderator_id} "
        f"added={added} removed={removed} "
        f"bl={settings.get('blacklist_cargos', [])}",
        flush=True,
    )

    # ── Bloqueio de moderador na blacklist de cargos ─────────────────────────
    if moderator_id and moderator_id != (bot.user.id if bot.user else 0):
        _bl_mod = settings.get("blacklist_cargos", [])
        if moderator_id in _bl_mod:
            if added:
                _bl_rev = [r for r in after.roles if r.id in added and not r.is_default() and r.position < after.guild.me.top_role.position]
                if _bl_rev:
                    try:
                        await after.remove_roles(*_bl_rev, reason="Anti-Raid: blacklist de cargos — sem permissão para gerenciar cargos")
                    except Exception:
                        pass
            if removed:
                _bl_rest = [discord.Object(id=rid) for rid in removed]
                if _bl_rest:
                    try:
                        await after.add_roles(*_bl_rest, reason="Anti-Raid: blacklist de cargos — restaurando cargos removidos")
                    except Exception:
                        pass
            return

    if settings.get("protecao_cargos_enabled"):
        is_bot_action = bot.user and moderator_obj and moderator_obj.id == bot.user.id

        moderator_member = None
        if moderator_obj:
            moderator_member = after.guild.get_member(moderator_obj.id)
            if moderator_member is None and isinstance(moderator_obj, discord.Member):
                moderator_member = moderator_obj
            if moderator_member is None:
                # Membro não está no cache (comum com outros bots) — busca do Discord
                try:
                    moderator_member = await after.guild.fetch_member(moderator_obj.id)
                except (discord.NotFound, discord.HTTPException):
                    pass

        has_acesso = False
        if moderator_member:
            acesso_role_ids = set(settings.get("protecao_cargos_acesso", []))
            mod_role_ids = {r.id for r in moderator_member.roles}
            has_acesso = bool(acesso_role_ids.intersection(mod_role_ids))

        clean_added: list[int] = []
        clean_removed: list[int] = []
        for rid in added:
            if _consume_bot_role_action(after.id, rid, "add"):
                continue
            clean_added.append(rid)
        for rid in removed:
            if _consume_bot_role_action(after.id, rid, "remove"):
                continue
            clean_removed.append(rid)

        whitelist = set(settings.get("protecao_cargos_whitelist", []))

        to_remove_added: list[int] = []
        to_restore_removed: list[int] = []
        wipe_all_roles = False

        blocked_roles_cfg = settings.get("protecao_cargo_bloqueado", {})
        mod_role_ids_for_blocked = {r.id for r in moderator_member.roles} if moderator_member else set()
        mod_is_admin = bool(moderator_member and moderator_member.guild_permissions.administrator)

        def _mod_can_manage(rid: int) -> bool:
            if is_bot_action:
                return True
            if str(rid) in blocked_roles_cfg:
                # Cargo bloqueado: apenas cargos de acesso específicos permitem,
                # mesmo administradores precisam ter o cargo de acesso configurado.
                access = set(blocked_roles_cfg[str(rid)])
                return bool(access and mod_role_ids_for_blocked.intersection(access))
            # Cargo não bloqueado: admin pode, ou quem tem acesso geral
            return mod_is_admin or has_acesso

        if not is_bot_action and (clean_added or clean_removed):
            for rid in clean_added:
                can = _mod_can_manage(rid)
                in_blocked = str(rid) in blocked_roles_cfg
                print(
                    f"[protecao_add] guild={after.guild.id} member={after.id} role={rid} "
                    f"mod={moderator_id} blocked={in_blocked} has_acesso={has_acesso} "
                    f"is_admin={mod_is_admin} mod_roles={list(mod_role_ids_for_blocked)[:5]} "
                    f"access_required={list(blocked_roles_cfg.get(str(rid), []))[:5]} "
                    f"allowed={can}",
                    flush=True,
                )
                if not can:
                    to_remove_added.append(rid)
            for rid in clean_removed:
                if rid not in whitelist and not _mod_can_manage(rid):
                    to_restore_removed.append(rid)

            non_whitelist_unauthorized = [rid for rid in to_remove_added if rid not in whitelist]
            if non_whitelist_unauthorized:
                now_ts = datetime.now().timestamp()
                key = (after.guild.id, after.id)
                hist = target_manual_add_history.setdefault(key, [])
                hist.extend([now_ts] * len(non_whitelist_unauthorized))
                hist[:] = [t for t in hist if now_ts - t <= 60]
                if len(hist) >= 3:
                    wipe_all_roles = True
                    hist.clear()

        print(
            f"[protecao_cargos] mod={moderator_obj} member={moderator_member} "
            f"has_acesso={has_acesso} is_bot_action={is_bot_action} "
            f"added={added} removed={removed} clean_added={clean_added} "
            f"clean_removed={clean_removed} reverting_add={to_remove_added} "
            f"reverting_remove={to_restore_removed} wipe_all={wipe_all_roles}"
        )

        if to_remove_added or to_restore_removed or wipe_all_roles:
            try:
                if to_remove_added:
                    roles_obj = [
                        after.guild.get_role(rid)
                        for rid in to_remove_added
                        if after.guild.get_role(rid)
                    ]
                    if roles_obj:
                        for rid in to_remove_added:
                            _register_bot_role_action(after.id, rid, "remove")
                        await after.remove_roles(
                            *roles_obj,
                            reason="Proteção de Cargos: modificação não autorizada revertida.",
                        )
                if to_restore_removed:
                    roles_obj = [
                        after.guild.get_role(rid)
                        for rid in to_restore_removed
                        if after.guild.get_role(rid)
                    ]
                    if roles_obj:
                        for rid in to_restore_removed:
                            _register_bot_role_action(after.id, rid, "add")
                        await after.add_roles(
                            *roles_obj,
                            reason="Proteção de Cargos: modificação não autorizada revertida.",
                        )

                if wipe_all_roles and moderator_member:
                    roles_to_strip = [
                        r for r in moderator_member.roles
                        if not r.is_default() and not r.managed
                        and r.id not in whitelist
                    ]
                    if roles_to_strip:
                        for r in roles_to_strip:
                            _register_bot_role_action(moderator_member.id, r.id, "remove")
                        await moderator_member.remove_roles(
                            *roles_to_strip,
                            reason="Proteção de Cargos: limite de tentativas atingido — cargos do moderador zerados.",
                        )
            except (discord.Forbidden, discord.HTTPException) as e:
                print(f"[protecao_cargos] Falha ao reverter cargos: {e}")

            # Punição do moderador não autorizado: remove cargos + DM + restaura em 30 min
            if moderator_member and not is_bot_action and not has_acesso:
                _pc_removable = [
                    r for r in moderator_member.roles
                    if not r.is_default() and r.position < after.guild.me.top_role.position
                ]
                _pc_role_ids = [r.id for r in _pc_removable]
                if _pc_removable and not wipe_all_roles:
                    try:
                        for _r in _pc_removable:
                            _register_bot_role_action(moderator_member.id, _r.id, "remove")
                        await moderator_member.remove_roles(*_pc_removable, reason="Proteção de Cargos: modificação não autorizada")
                    except Exception:
                        pass
                elif wipe_all_roles:
                    # wipe_all_roles já removeu — coleta os ids que foram removidos
                    _pc_role_ids = [r.id for r in moderator_member.roles if not r.is_default()] + _pc_role_ids
                    _pc_role_ids = list(set(_pc_role_ids))
                if _pc_role_ids:
                    _pc_key = (after.guild.id, moderator_member.id)
                    if _pc_key in _ANTRAID_PENDING_RESTORE:
                        _ANTRAID_PENDING_RESTORE[_pc_key].cancel()
                    _pc_task = asyncio.create_task(_antraid_restore_roles_task(after.guild.id, moderator_member.id, _pc_role_ids, 1800))
                    _ANTRAID_PENDING_RESTORE[_pc_key] = _pc_task
                    asyncio.create_task(_antraid_dm_punido(after.guild, moderator_member, "Proteção de Cargos"))

            log_channel_id = settings.get("protecao_cargos_log_channel")
            if log_channel_id:
                log_channel = after.guild.get_channel(log_channel_id)
                if log_channel:
                    role_names_added = ", ".join(
                        f"<@&{rid}>" for rid in to_remove_added
                    ) or "—"
                    role_names_removed = ", ".join(
                        f"<@&{rid}>" for rid in to_restore_removed
                    ) or "—"
                    if wipe_all_roles:
                        motivo = "🚨 **Limite de 3 tentativas atingido** — todos os cargos do **moderador** foram removidos"
                        description = (
                            f"**{moderator_obj.mention if moderator_obj else 'Alguém'}** "
                            f"excedeu o limite de modificações em {after.mention}. "
                            f"**Cargos do moderador zerados.**\n\n"
                            f"**Motivo:** {motivo}\n\n"
                            f"-# Use `n!groles` para gerenciar cargos."
                        )
                    else:
                        motivo = "❌ **Sem permissão** para setar cargos manualmente (use `n!groles`)"
                        description = (
                            f"**{moderator_obj.mention if moderator_obj else 'Alguém'}** tentou modificar cargos de "
                            f"{after.mention} manualmente. **Ação revertida.**\n\n"
                            f"**Motivo:** {motivo}\n"
                            f"**Cargos adicionados (revertidos):** {role_names_added}\n"
                            f"**Cargos removidos (restaurados):** {role_names_removed}\n\n"
                            f"-# Use `n!groles` para gerenciar cargos."
                        )
                    embed_log = discord.Embed(
                        title="⚠️ Proteção de Cargos",
                        description=description,
                        color=0xFF4040,
                    )
                    embed_log.timestamp = datetime.now()
                    try:
                        await log_channel.send(
                            embed=embed_log,
                            allowed_mentions=discord.AllowedMentions.none(),
                        )
                    except (discord.Forbidden, discord.HTTPException):
                        pass

        # Log de mudanças AUTORIZADAS (usuários com Cargos Acesso)
        # Bot não é logado aqui para evitar duplicata com o log de reversão
        elif has_acesso and not is_bot_action and (added or removed):
            _log_ch_id = settings.get("protecao_cargos_log_channel")
            if _log_ch_id:
                _log_ch = after.guild.get_channel(_log_ch_id)
                if _log_ch:
                    _added_txt   = ", ".join(f"<@&{r}>" for r in added)   or "—"
                    _removed_txt = ", ".join(f"<@&{r}>" for r in removed) or "—"
                    _actor = moderator_obj.mention if moderator_obj else "Desconhecido"
                    _emb = discord.Embed(
                        title="✅ Proteção de Cargos — Modificação Autorizada",
                        description=(
                            f"**{_actor}** modificou cargos de {after.mention}.\n\n"
                            f"**Adicionados:** {_added_txt}\n"
                            f"**Removidos:** {_removed_txt}"
                        ),
                        color=0x00CC44,
                    )
                    _emb.timestamp = datetime.now()
                    try:
                        await _log_ch.send(
                            embed=_emb,
                            allowed_mentions=discord.AllowedMentions.none(),
                        )
                    except (discord.Forbidden, discord.HTTPException):
                        pass

    for rid in added:
        role = after.guild.get_role(rid)
        if role is None:
            continue
        history.append({
            "timestamp": timestamp,
            "action": "add",
            "moderator_id": moderator_id,
            "moderator": moderator_name,
            "target_id": after.id,
            "target": after.name,
            "role_id": rid,
            "role": role.name,
        })
    for rid in removed:
        role = after.guild.get_role(rid)
        if role is None:
            continue
        history.append({
            "timestamp": timestamp,
            "action": "remove",
            "moderator_id": moderator_id,
            "moderator": moderator_name,
            "target_id": after.id,
            "target": after.name,
            "role_id": rid,
            "role": role.name,
        })

    if len(history) > 200:
        del history[:-200]

    # Auto Cargo Booster — when member starts boosting
    if (
        settings.get("auto_cargo_enabled")
        and not before.premium_since
        and after.premium_since
    ):
        for rid in settings.get("auto_cargo_booster_roles", []):
            role = after.guild.get_role(rid)
            if role and role not in after.roles:
                try:
                    _register_bot_role_action(after.id, rid, "add")
                    await after.add_roles(role, reason="Auto Cargo: novo booster.")
                except (discord.Forbidden, discord.HTTPException):
                    bot_role_actions.pop((after.id, rid, "add"), None)


@bot.event
async def on_member_remove(member: discord.Member):
    if member.bot:
        return
    settings = get_settings(member.guild.id)
    history = settings.setdefault("role_history", [])
    timestamp = datetime.now().strftime("%d/%m/%Y %H:%M")

    for role in member.roles:
        if role.is_default():
            continue
        history.append({
            "timestamp": timestamp,
            "action": "remove",
            "moderator_id": None,
            "moderator": "Sistema",
            "target_id": member.id,
            "target": member.name,
            "role_id": role.id,
            "role": role.name,
            "reason": "O Membro saiu do servidor",
        })

    if len(history) > 200:
        del history[:-200]

    # ── Anti-Raid: detecção de kick ───────────────────────────────────────────
    guild = member.guild
    if not settings.get("antraid_enabled"):
        return
    _prot_kick = settings.get("antraid_kick_massa", _antraid_prot_default())
    if not _prot_kick.get("enabled"):
        return
    await asyncio.sleep(0.8)
    try:
        _kick_resp_id: int | None = None
        import datetime as _kdt
        async for _kentry in guild.audit_logs(limit=3, action=discord.AuditLogAction.kick):
            _kdelta = (_kdt.datetime.now(_kdt.timezone.utc) - _kentry.created_at).total_seconds()
            if _kdelta < 5 and _kentry.target and _kentry.target.id == member.id:
                _kick_resp_id = _kentry.user.id if _kentry.user else None
                break
        if not _kick_resp_id or _kick_resp_id == guild.owner_id:
            return
        _kicker = guild.get_member(_kick_resp_id)
        if _kicker is None:
            try:
                _kicker = await guild.fetch_member(_kick_resp_id)
            except (discord.NotFound, discord.HTTPException):
                _kicker = None
        if not _kicker or _kicker.bot:
            return
        import time as _ktime
        _kwl = set(_prot_kick.get("whitelist", []))
        _kicker_roles = {r.id for r in _kicker.roles}
        _kick_in_wl = bool(_kwl & _kicker_roles) if _kwl else False
        if not _kick_in_wl:
            # Não whitelistado (ou sem whitelist) → remover cargos
            _kdb_key = (guild.id, _kick_resp_id, "kick_individual")
            _know = _ktime.monotonic()
            if _know - ANTRAID_DEBOUNCE.get(_kdb_key, 0.0) >= _ANTRAID_DEBOUNCE_TTL:
                ANTRAID_DEBOUNCE[_kdb_key] = _know
                await _antraid_apply(
                    guild, _kicker,
                    "remover_cargos",  # bloqueio individual: sempre remove cargos
                    "Anti-Raid: Kick não autorizado",
                    settings.get("antraid_log_channel"),
                    settings.get("embed_color", 0x2B2D31),
                    "Kick Não Autorizado",
                )
        elif _kick_in_wl and _antraid_check(guild.id, _kick_resp_id, "kick_massa", _prot_kick):
            # Whitelistado mas acima do threshold (kicks em massa)
            _kdb_key2 = (guild.id, _kick_resp_id, "kick_massa")
            _know2 = _ktime.monotonic()
            if _know2 - ANTRAID_DEBOUNCE.get(_kdb_key2, 0.0) >= _ANTRAID_DEBOUNCE_TTL:
                ANTRAID_DEBOUNCE[_kdb_key2] = _know2
                await _antraid_apply(
                    guild, _kicker,
                    _prot_kick.get("action", "remover_cargos"),
                    "Anti-Raid: Kicks em Massa",
                    settings.get("antraid_log_channel"),
                    settings.get("embed_color", 0x2B2D31),
                    ANTRAID_LABELS.get("kick_massa", "Kicks em Massa"),
                )
    except (discord.Forbidden, discord.HTTPException):
        pass


async def _dm_kicked_from_call(
    member: discord.Member,
    ch: discord.VoiceChannel,
    owner: discord.Member | None,
    locked: bool,
):
    """Envia DM ao membro desconectado automaticamente de uma call privada/trancada."""
    try:
        guild = ch.guild
        icon_url = guild.icon.url if guild.icon else None
        owner_val = owner.mention if owner else "—"

        if locked:
            restriction = "Call **trancada**"
        else:
            restriction = "**Modo Privado** ativo"

        embed = discord.Embed(
            description=(
                f"<:8118_xmark:1518272072839729182> **Acesso Negado**\n"
                f"<:mov_call:1518271964077232150> **Canal** › {ch.mention}\n"
                f"<a:alerta:1518271939460857968> **Restrição** › {restriction}\n"
                f"**Dono** › {owner_val}"
            ),
            color=0xE74C3C,
        )
        embed.set_author(name=f"{guild.name}  ·  Dono de Call", icon_url=icon_url)
        if icon_url:
            embed.set_thumbnail(url=icon_url)

        await member.send(embed=embed)
    except Exception:
        pass


@bot.event
async def on_voice_state_update(member: discord.Member, before: discord.VoiceState, after: discord.VoiceState):
    if member.guild is None:
        return
    settings = get_settings(member.guild.id)

    # Desmute Automático
    if settings.get("desmute_enabled"):
        desmute_ch_id = settings.get("desmute_channel")
        if (
            desmute_ch_id and after.channel and after.channel.id == desmute_ch_id
            and (before.channel is None or before.channel.id != desmute_ch_id)
            and after.mute
            and not member.bot
        ):
            allowed_roles = set(settings.get("desmute_roles", []))
            member_role_ids = {r.id for r in member.roles}
            if not allowed_roles or (allowed_roles & member_role_ids):
                try:
                    await member.edit(mute=False, reason="Desmute Automático")
                    log_id = settings.get("desmute_log_channel")
                    if log_id:
                        log_ch = member.guild.get_channel(log_id)
                        if log_ch:
                            t = TRANSLATIONS[settings["language"]]
                            try:
                                await log_ch.send(
                                    t["desmute_log_message"].format(
                                        member=member.mention, channel=after.channel.mention
                                    )
                                )
                            except (discord.Forbidden, discord.HTTPException):
                                pass
                except (discord.Forbidden, discord.HTTPException):
                    pass

    # ── Dono de Call ──────────────────────────────────────────────────────────
    if not member.bot:
        dc_monitored = set(settings.get("dono_call_channels", []))
        if dc_monitored:
            # Membro ENTROU num canal monitorado
            if after.channel and after.channel.id in dc_monitored and (before.channel is None or before.channel != after.channel):
                ch = after.channel
                _call_join_log.setdefault(ch.id, []).append((time.time(), member.id, member.display_name, "entrou"))
                _cur_owner = _call_owners.get(ch.id)
                if _cur_owner == member.id and ch.id in _call_owner_grace:
                    # Dono voltou dentro do grace period — cancela timer e atualiza painel
                    _call_owner_grace.pop(ch.id).cancel()
                    asyncio.create_task(_update_call_panel(ch, member))
                elif _cur_owner and _cur_owner != member.id:
                    _owner_member = ch.guild.get_member(_cur_owner)
                    # Membro autorizado individualmente pelo dono (via "Permitir Entrada") — nunca expulsar
                    _member_ow = ch.overwrites_for(member)
                    _autorizado = _member_ow.connect is True
                    if not _autorizado:
                        # Auto-kick se trancado nessa sessão
                        if ch.id in _call_locked:
                            _ow_ev = ch.overwrites_for(ch.guild.default_role)
                            if _ow_ev.connect is False:
                                try:
                                    await member.move_to(None, reason="Dono de Call — canal trancado, entrada não autorizada")
                                except Exception:
                                    pass
                                else:
                                    asyncio.create_task(_dm_kicked_from_call(member, ch, _owner_member, locked=True))
                        # Auto-kick modo privado (sem lock de permissões)
                        elif ch.id in _call_auto_kick:
                            try:
                                await member.move_to(None, reason="Dono de Call — modo privado ativo")
                            except Exception:
                                pass
                            else:
                                asyncio.create_task(_dm_kicked_from_call(member, ch, _owner_member, locked=False))
                elif not _cur_owner:
                    dc_allowed = set(settings.get("dono_call_allowed_roles", []))
                    member_roles = {r.id for r in member.roles}
                    if not dc_allowed or (dc_allowed & member_roles):
                        _call_owners[ch.id] = member.id
                        asyncio.create_task(_send_call_panel(ch, member))

            # Membro SAIU de um canal monitorado
            if before.channel and before.channel.id in dc_monitored and before.channel != after.channel:
                ch = before.channel
                # Anti-Mover: se a call está protegida (trancada ou modo privado) e o membro foi
                # movido para outro canal (não desconectou), reverte a movimentação.
                _anti_moved = False
                if (after.channel is not None
                        and (ch.id in _call_locked or ch.id in _call_auto_kick)
                        and ch.id in _call_owners):
                    try:
                        await member.move_to(ch, reason="Anti-Mover — call protegida")
                        _anti_moved = True
                    except Exception:
                        pass
                if not _anti_moved:
                    _call_join_log.setdefault(ch.id, []).append((time.time(), member.id, member.display_name, "saiu"))
                if not _anti_moved and ch.id in _call_owners:
                    # Remove override individual do membro que saiu (bot adicionou durante lock/permitir entrada)
                    _ow_saiu = ch.overwrites_for(member)
                    if _ow_saiu.connect is True or _ow_saiu.send_messages is True:
                        _ow_saiu.connect = None
                        _ow_saiu.send_messages = None
                        try:
                            if _ow_saiu.is_empty():
                                await ch.set_permissions(member, overwrite=None, reason="Dono de Call — membro saiu, limpa override")
                            else:
                                await ch.set_permissions(member, overwrite=_ow_saiu, reason="Dono de Call — membro saiu, limpa override")
                        except Exception:
                            pass
                    remaining = [m for m in ch.members if not m.bot]
                    if not remaining:
                        # Canal vazio — limpa
                        asyncio.create_task(_delete_call_panel(ch))
                        _call_owners.pop(ch.id, None)
                        _call_panels.pop(ch.id, None)
                    elif _call_owners.get(ch.id) == member.id:
                        # Dono saiu (qualquer motivo) — restaura permissões e transfere imediatamente
                        if ch.id in _call_owner_grace:
                            _call_owner_grace.pop(ch.id).cancel()
                        asyncio.create_task(_restore_call_permissions(ch))
                        dc_allowed = set(settings.get("dono_call_allowed_roles", []))
                        eligible = [m for m in remaining if not dc_allowed or ({r.id for r in m.roles} & dc_allowed)]
                        if eligible:
                            new_owner = eligible[0]
                            _call_owners[ch.id] = new_owner.id
                            settings.setdefault("active_call_owners", {})[str(ch.id)] = new_owner.id
                            save_settings_to_disk()
                            asyncio.create_task(_update_call_panel(ch, new_owner))
                        else:
                            asyncio.create_task(_delete_call_panel(ch))
                            _call_owners.pop(ch.id, None)
                            _call_panels.pop(ch.id, None)

    # ── Call Temporária ───────────────────────────────────────────────────────
    if not member.bot:
        ct_monitored = set(settings.get("call_temporaria_channels", []))
        if ct_monitored:
            # Membro ENTROU num canal monitorado
            if after.channel and after.channel.id in ct_monitored:
                ch = after.channel
                if ch.id not in _call_temp_owners:
                    _call_temp_owners[ch.id] = member.id
                    asyncio.create_task(_send_call_temp_panel(ch, member))

            # Membro SAIU de um canal monitorado
            if before.channel and before.channel.id in ct_monitored:
                ch = before.channel
                if ch.id in _call_temp_owners:
                    remaining = [m for m in ch.members if not m.bot]
                    if not remaining:
                        asyncio.create_task(_delete_call_temp_panel(ch))
                        _call_temp_owners.pop(ch.id, None)
                        _call_temp_panels.pop(ch.id, None)
                    elif _call_temp_owners.get(ch.id) == member.id:
                        new_owner = remaining[0]
                        _call_temp_owners[ch.id] = new_owner.id
                        asyncio.create_task(_update_call_temp_panel(ch, new_owner))

    # ── Voice Time Tracking ───────────────────────────────────────────────────
    if not member.bot:
        _vt_key  = (member.guild.id, member.id)
        _vt_now  = datetime.now().timestamp()
        _was_vc  = before.channel is not None
        _now_vc  = after.channel is not None
        _was_mut = before.self_mute or before.mute
        _now_mut = after.self_mute or after.mute

        if not _was_vc and _now_vc:
            _voice_sessions[_vt_key] = {"join": _vt_now, "mute_start": _vt_now if _now_mut else None}
        elif _was_vc and not _now_vc:
            _sess = _voice_sessions.pop(_vt_key, None)
            if _sess:
                _elapsed = _vt_now - _sess["join"]
                _vd = _get_user_vt(member.guild.id, member.id)
                _vt_rotate(_vd)
                _vd["total_seconds"]  = _vd.get("total_seconds", 0) + _elapsed
                _vd["week_seconds"]   = _vd.get("week_seconds",  0) + _elapsed
                if _sess.get("mute_start"):
                    _me = _vt_now - _sess["mute_start"]
                    _vd["muted_seconds"]      = _vd.get("muted_seconds",      0) + _me
                    _vd["week_muted_seconds"] = _vd.get("week_muted_seconds", 0) + _me
                _save_voice_time()
        elif _was_vc and _now_vc:
            _sess = _voice_sessions.get(_vt_key)
            if _sess:
                if not _was_mut and _now_mut:
                    _sess["mute_start"] = _vt_now
                elif _was_mut and not _now_mut and _sess.get("mute_start"):
                    _me = _vt_now - _sess["mute_start"]
                    _vd = _get_user_vt(member.guild.id, member.id)
                    _vt_rotate(_vd)
                    _vd["muted_seconds"]      = _vd.get("muted_seconds",      0) + _me
                    _vd["week_muted_seconds"] = _vd.get("week_muted_seconds", 0) + _me
                    _sess["mute_start"] = None
                    _save_voice_time()

    # ── Contador em Call ──────────────────────────────────────────────────────
    if before.channel != after.channel:
        asyncio.create_task(_update_contador_call(member.guild))


@bot.event
async def on_member_join(member: discord.Member):
    settings = get_settings(member.guild.id)
    t = TRANSLATIONS[settings["language"]]

    if settings.get("blacklist_enabled") and member.id in settings.get("blacklist_users", []):
        action = settings.get("blacklist_action", "expulsar")
        try:
            if action == "banir":
                await member.ban(reason="Blacklist: usuário banido automaticamente.", delete_message_days=0)
            else:
                await member.kick(reason="Blacklist: usuário expulso automaticamente.")
        except (discord.Forbidden, discord.HTTPException):
            return
        await _log_kick(
            member,
            settings.get("blacklist_log_channel"),
            t["blacklist_panel_title"],
            f"🚫 **{member}** (`{member.id}`) — bloqueado pela Blacklist (ação: `{action}`).",
            settings["embed_color"],
        )
        return

    if member.bot and settings.get("antbot_enabled"):
        whitelist = settings.get("antbot_whitelist", [])
        if member.id in whitelist:
            return
        # Verifica se quem adicionou o bot tem o cargo de acesso
        access_role_id = settings.get("antbot_access_role")
        if access_role_id:
            try:
                # Aguarda 1s para o audit log registrar a entrada
                await asyncio.sleep(1)
                async for entry in member.guild.audit_logs(
                    limit=5, action=discord.AuditLogAction.bot_add
                ):
                    if entry.target.id == member.id:
                        inviter = member.guild.get_member(entry.user.id)
                        if inviter is None:
                            try:
                                inviter = await member.guild.fetch_member(entry.user.id)
                            except Exception:
                                pass
                        if inviter and any(r.id == access_role_id for r in inviter.roles):
                            return  # Quem adicionou tem o cargo — bot liberado
                        break
            except Exception:
                pass
        # Bot não autorizado — kica
        try:
            await member.kick(reason="Anti Bot ativo: entrada de bot bloqueada.")
        except (discord.Forbidden, discord.HTTPException):
            return
        await _log_kick(
            member,
            settings.get("antbot_log_channel"),
            t["antbot_panel_title"],
            f"🤖 **{member}** (`{member.id}`) — kickado pelo Anti Bot.",
            settings["embed_color"],
        )
        return

    if not member.bot and settings.get("antfake_enabled"):
        min_days = settings.get("antfake_days")
        if not min_days:
            return
        age = datetime.now(member.created_at.tzinfo) - member.created_at
        if age.days >= min_days:
            return
        try:
            await member.kick(
                reason=f"Anti-Fake ativo: conta com {age.days} dias (mínimo {min_days})."
            )
        except (discord.Forbidden, discord.HTTPException):
            return
        await _log_kick(
            member,
            settings.get("antfake_log_channel"),
            t["antfake_panel_title"],
            f"👤 **{member}** (`{member.id}`) — kickado pelo Anti-Fake.\n"
            f"Conta criada há **{age.days}** dia(s) (mínimo: **{min_days}**).",
            settings["embed_color"],
        )
        return

    # Auto Cargo
    if settings.get("auto_cargo_enabled"):
        role_id = (
            settings.get("auto_cargo_bot_role")
            if member.bot else settings.get("auto_cargo_membro_role")
        )
        if role_id:
            role = member.guild.get_role(role_id)
            if role:
                try:
                    _register_bot_role_action(member.id, role_id, "add")
                    await member.add_roles(role, reason="Auto Cargo: entrada no servidor.")
                except (discord.Forbidden, discord.HTTPException):
                    bot_role_actions.pop((member.id, role_id, "add"), None)

    # Menção: marca o novo membro nos canais configurados
    if (
        settings.get("mencao_enabled")
        and not member.bot
    ):
        for cid in settings.get("mencao_channels", []):
            ch = member.guild.get_channel(cid)
            if not ch:
                continue
            try:
                sent = await ch.send(member.mention)
                # Apaga após 3 segundos pra não poluir o canal
                try:
                    await sent.delete(delay=3)
                except (discord.Forbidden, discord.NotFound, discord.HTTPException):
                    pass
            except (discord.Forbidden, discord.HTTPException):
                pass

    # Bem-Vindo
    if (
        settings.get("welcome_enabled")
        and settings.get("welcome_msg_entrar_enabled")
        and not member.bot
    ):
        template = settings.get("welcome_message")
        if template:
            formatted = _format_welcome_text(template, member)
            mode = settings.get("welcome_mode") or "Normal"
            delete_after = settings.get("welcome_delete_time") or None
            for cid in settings.get("welcome_channels", []):
                ch = member.guild.get_channel(cid)
                if not ch:
                    continue
                try:
                    if mode == "Embed":
                        emb = discord.Embed(description=formatted, color=settings["embed_color"])
                        emb.set_thumbnail(url=member.display_avatar.url)
                        emb.set_footer(text=member.guild.name)
                        sent = await ch.send(embed=emb)
                    else:
                        sent = await ch.send(formatted)
                    if delete_after:
                        try:
                            await sent.delete(delay=delete_after)
                        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
                            pass
                except (discord.Forbidden, discord.HTTPException):
                    pass

        # DM welcome
        if settings.get("welcome_msg_dm_enabled"):
            dm_draft = settings.get("welcome_dm_embed") or {}
            has_dm_content = (
                dm_draft.get("title") or dm_draft.get("description") or template
            )
            if has_dm_content:
                try:
                    if dm_draft.get("title") or dm_draft.get("description"):
                        dm_embed = _draft_to_embed(dm_draft, settings["embed_color"])
                        if dm_embed.description:
                            dm_embed.description = _format_welcome_text(dm_embed.description, member)
                        await member.send(embed=dm_embed)
                    elif template:
                        await member.send(_format_welcome_text(template, member))
                except (discord.Forbidden, discord.HTTPException):
                    pass



_MIGRAR_FOTOS_CKPT = os.path.join(_CLIENT_DIR, "migrar_fotos_checkpoint.json")
_migrar_fotos_running = False
_migrar_fotos_stop    = False   # sinaliza para a task parar no próximo ciclo


async def _run_migrar_fotos(source_guild_id: int, target_guild_id: int, notify_channel_id: int):
    global _migrar_fotos_running, _migrar_fotos_stop
    _migrar_fotos_running = True
    _migrar_fotos_stop    = False
    import json as _json, io, aiohttp

    IMAGE_EXTS = {".png", ".jpg", ".jpeg", ".gif", ".webp", ".mp4", ".mov", ".mkv"}

    # ── Checkpoint ─────────────────────────────────────────────────────────────
    ckpt: dict = {}
    if os.path.exists(_MIGRAR_FOTOS_CKPT):
        try:
            with open(_MIGRAR_FOTOS_CKPT, "r", encoding="utf-8") as _f:
                ckpt = _json.load(_f)
        except Exception:
            ckpt = {}

    if ckpt.get("source") != source_guild_id or ckpt.get("target") != target_guild_id:
        ckpt = {
            "source": source_guild_id, "target": target_guild_id,
            "notify_channel_id": notify_channel_id,
            "done_channels": [],
            "channel_last_msg": {},
            "total_sent": 0,
        }

    done_channels: set = set(int(x) for x in ckpt.get("done_channels", []))
    ch_last: dict      = {str(k): str(v) for k, v in ckpt.get("channel_last_msg", {}).items()}
    total_sent: int    = ckpt.get("total_sent", 0)

    def _save():
        ckpt["done_channels"]     = [int(x) for x in done_channels]
        ckpt["channel_last_msg"]  = ch_last
        ckpt["total_sent"]        = total_sent
        ckpt["notify_channel_id"] = notify_channel_id
        try:
            with open(_MIGRAR_FOTOS_CKPT, "w", encoding="utf-8") as _fw:
                _json.dump(ckpt, _fw)
        except Exception as _se:
            print(f"[migrar_fotos] erro ao salvar checkpoint: {_se}", flush=True)

    notify_ch = bot.get_channel(notify_channel_id)

    # Timeout generoso: 5 min por arquivo (servidores com imagens grandes)
    http_timeout = aiohttp.ClientTimeout(total=300)

    try:
        await bot.wait_until_ready()
        source_guild = bot.get_guild(source_guild_id)
        target_guild = bot.get_guild(target_guild_id)
        if not source_guild or not target_guild:
            if notify_ch:
                await notify_ch.send("❌ migrar_fotos: servidor não encontrado após reinício.")
            return

        tgt_by_name = {c.name.lower(): c for c in target_guild.text_channels}
        channels    = list(source_guild.text_channels)
        total_ch    = len(channels)
        ch_done_cnt = len(done_channels)

        print(f"[migrar_fotos] path checkpoint: {_MIGRAR_FOTOS_CKPT}", flush=True)
        print(f"[migrar_fotos] {total_ch} canais, {len(done_channels)} já prontos, {total_sent} já enviadas", flush=True)

        async with aiohttp.ClientSession(timeout=http_timeout) as session:
            for src_ch in channels:
                if _migrar_fotos_stop:
                    _save()
                    if notify_ch:
                        await notify_ch.send(f"⏹️ migrar_fotos parado. 📸 {total_sent} enviadas. Rode novamente para retomar.")
                    return
                if src_ch.id in done_channels:
                    continue

                tgt_ch = tgt_by_name.get(src_ch.name.lower())
                if tgt_ch is None:
                    print(f"[migrar_fotos] #{src_ch.name} sem canal equivalente — pulando", flush=True)
                    done_channels.add(src_ch.id)
                    ch_done_cnt += 1
                    _save()
                    continue

                last_id   = ch_last.get(str(src_ch.id))
                after_obj = discord.Object(id=int(last_id)) if last_id else None
                img_count = 0

                print(f"[migrar_fotos] #{src_ch.name} → #{tgt_ch.name} (after={last_id})", flush=True)

                try:
                    async for msg in src_ch.history(limit=None, oldest_first=True, after=after_obj):
                        atts = [
                            a for a in msg.attachments
                            if any(a.filename.lower().endswith(ext) for ext in IMAGE_EXTS)
                        ]

                        # Atualiza progresso mesmo para mensagens sem imagem
                        if not atts:
                            ch_last[str(src_ch.id)] = str(msg.id)
                            continue

                        # Baixa e reenvia cada arquivo individualmente
                        for att in atts:
                            data = None
                            for attempt in range(3):
                                try:
                                    async with session.get(att.url) as resp:
                                        if resp.status == 200:
                                            data = await resp.read()
                                    break
                                except Exception as _dl:
                                    print(f"[migrar_fotos] download falhou ({att.filename}) tentativa {attempt+1}: {_dl}", flush=True)
                                    await asyncio.sleep(3)

                            if not data:
                                continue

                            for attempt in range(4):
                                try:
                                    await tgt_ch.send(file=discord.File(fp=io.BytesIO(data), filename=att.filename))
                                    total_sent += 1
                                    img_count  += 1
                                    await asyncio.sleep(1.2)
                                    break
                                except discord.HTTPException as _he:
                                    if _he.status == 429:
                                        _wait = float(getattr(_he, "retry_after", 5) or 5) + 1
                                        print(f"[migrar_fotos] rate limit {_wait}s", flush=True)
                                        await asyncio.sleep(_wait)
                                    elif _he.status in (403, 50013):
                                        print(f"[migrar_fotos] sem permissão em #{tgt_ch.name}", flush=True)
                                        break
                                    else:
                                        print(f"[migrar_fotos] HTTP {_he.status} ao enviar {att.filename}", flush=True)
                                        await asyncio.sleep(3)
                                except Exception as _ue:
                                    print(f"[migrar_fotos] erro envio {att.filename}: {_ue}", flush=True)
                                    await asyncio.sleep(3)

                        ch_last[str(src_ch.id)] = str(msg.id)

                        # Salva checkpoint a cada arquivo enviado
                        if img_count % 5 == 0:
                            _save()

                except discord.Forbidden:
                    print(f"[migrar_fotos] sem leitura em #{src_ch.name}", flush=True)
                except Exception as _ce:
                    print(f"[migrar_fotos] erro canal #{src_ch.name}: {_ce}", flush=True)
                    _save()

                done_channels.add(src_ch.id)
                ch_last.pop(str(src_ch.id), None)
                ch_done_cnt += 1
                _save()
                print(f"[migrar_fotos] ✓ #{src_ch.name} | {ch_done_cnt}/{total_ch} canais | {total_sent} total", flush=True)

                if ch_done_cnt % 3 == 0 and notify_ch:
                    try:
                        await notify_ch.send(
                            f"⏳ migrar_fotos: **{ch_done_cnt}/{total_ch}** canais | 📸 {total_sent} enviadas"
                        )
                    except Exception:
                        pass

        if os.path.exists(_MIGRAR_FOTOS_CKPT):
            os.remove(_MIGRAR_FOTOS_CKPT)
        if notify_ch:
            await notify_ch.send(
                f"✅ **Migração concluída!**\n📸 **{total_sent}** imagens enviadas em {ch_done_cnt} canais."
            )
        print(f"[migrar_fotos] concluído — {total_sent} enviadas", flush=True)

    except Exception as _ge:
        print(f"[migrar_fotos] erro geral: {_ge}", flush=True)
        _save()
        if notify_ch:
            try:
                await notify_ch.send(
                    f"⚠️ migrar_fotos pausou: `{_ge}`\n"
                    f"📸 {total_sent} já enviadas. Rode o comando novamente para retomar."
                )
            except Exception:
                pass
    finally:
        _migrar_fotos_running = False


@bot.command(name="migrar_fotos", aliases=["migrarfotos", "copy_photos"])
async def migrar_fotos_cmd(ctx: commands.Context, arg1: str = None, arg2: str = None):
    """Copia todas as imagens de todos os canais do servidor de origem para o destino (com checkpoint)."""
    global _migrar_fotos_running
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    _perms = ctx.author.guild_permissions
    is_admin = _perms.administrator or _perms.manage_guild
    if not is_authorized(ctx.author, settings) and not is_admin:
        await ctx.reply("❌ Sem permissão.", delete_after=6)
        return

    # Sub-comando: reset — para a task e apaga checkpoint
    if arg1 == "reset":
        global _migrar_fotos_stop
        _migrar_fotos_stop = True
        if os.path.exists(_MIGRAR_FOTOS_CKPT):
            os.remove(_MIGRAR_FOTOS_CKPT)
        await ctx.reply("⏹️ Migração parada e checkpoint apagado. Bot liberado.")
        return

    # Sub-comando status (sem argumentos)
    if arg1 is None:
        if os.path.exists(_MIGRAR_FOTOS_CKPT):
            try:
                import json as _json
                with open(_MIGRAR_FOTOS_CKPT, "r", encoding="utf-8") as f:
                    ck = _json.load(f)
                status = "🔄 rodando" if _migrar_fotos_running else "⏸️ pausado (rode o comando para retomar)"
                await ctx.reply(
                    f"**migrar_fotos** — {status}\n"
                    f"Origem: `{ck.get('source')}` → Destino: `{ck.get('target')}`\n"
                    f"📸 {ck.get('total_sent', 0)} enviadas | "
                    f"✅ {len(ck.get('done_channels', []))} canais concluídos"
                )
            except Exception:
                await ctx.reply("❌ Use: `nata!migrar_fotos <ID_origem> <ID_destino>`")
        else:
            await ctx.reply("❌ Use: `nata!migrar_fotos <ID_origem> <ID_destino>`")
        return

    # Converte IDs
    try:
        source_guild_id = int(arg1)
    except ValueError:
        await ctx.reply("❌ ID de origem inválido.")
        return

    if arg2 is None:
        await ctx.reply("❌ Informe o ID do destino: `nata!migrar_fotos <ID_origem> <ID_destino>`")
        return
    try:
        target_guild_id = int(arg2)
    except ValueError:
        await ctx.reply("❌ ID de destino inválido.")
        return

    if _migrar_fotos_running:
        await ctx.reply("⚠️ Migração já está em andamento. Use `nata!migrar_fotos` sem argumentos para ver o progresso.")
        return

    source_guild = bot.get_guild(source_guild_id)
    if source_guild is None:
        await ctx.reply("❌ Servidor de origem não encontrado. O bot precisa estar lá.")
        return
    target_guild = bot.get_guild(target_guild_id)
    if target_guild is None:
        await ctx.reply("❌ Servidor de destino não encontrado. O bot precisa estar lá.")
        return

    import json as _json
    resuming = False
    if os.path.exists(_MIGRAR_FOTOS_CKPT):
        try:
            with open(_MIGRAR_FOTOS_CKPT, "r", encoding="utf-8") as f:
                ck = _json.load(f)
            if ck.get("source") == source_guild_id and ck.get("target") == target_guild_id:
                resuming = True
                # Atualiza canal de notificação
                ck["notify_channel_id"] = ctx.channel.id
                with open(_MIGRAR_FOTOS_CKPT, "w", encoding="utf-8") as fw:
                    _json.dump(ck, fw)
        except Exception:
            pass

    if not resuming:
        # Novo checkpoint
        with open(_MIGRAR_FOTOS_CKPT, "w", encoding="utf-8") as fw:
            _json.dump({
                "source": source_guild_id, "target": target_guild_id,
                "notify_channel_id": ctx.channel.id,
                "done_channels": [], "channel_last_msg": {},
                "total_sent": 0, "total_skip": 0,
            }, fw)

    if resuming:
        await ctx.reply("▶️ Retomando migração de onde parou... acompanhe aqui.")
    else:
        await ctx.reply(
            f"⏳ Iniciando migração de fotos de **{source_guild.name}** → **{target_guild.name}**.\n"
            "Vou atualizando a cada 5 canais. Use `nata!migrar_fotos reset` para cancelar e recomeçar do zero."
        )

    asyncio.create_task(_run_migrar_fotos(source_guild_id, target_guild_id, ctx.channel.id))


@bot.command(name="migrar_assets", aliases=["migrarassets", "copy_assets"])
async def migrar_assets_cmd(ctx: commands.Context, source_guild_id: int = None, target_guild_id: int = None):
    """Copia ícone e banner do servidor de origem para o destino."""
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    _perms = ctx.author.guild_permissions
    is_admin = _perms.administrator or _perms.manage_guild
    if not is_authorized(ctx.author, settings) and not is_admin:
        await ctx.reply("❌ Sem permissão.", delete_after=6)
        return
    if source_guild_id is None:
        await ctx.reply("❌ Use: `nata!migrar_assets <ID_origem>` ou `nata!migrar_assets <ID_origem> <ID_destino>`")
        return

    source_guild = bot.get_guild(source_guild_id)
    if source_guild is None:
        await ctx.reply("❌ Servidor de origem não encontrado. O bot precisa estar nos dois servidores.")
        return

    if target_guild_id:
        target_guild = bot.get_guild(target_guild_id)
        if target_guild is None:
            await ctx.reply("❌ Servidor de destino não encontrado.")
            return
    else:
        target_guild = ctx.guild

    msg = await ctx.reply("⏳ Copiando ícone e banner...")

    import aiohttp
    results: list[str] = []

    async with aiohttp.ClientSession() as session:
        # Ícone
        if source_guild.icon:
            try:
                async with session.get(str(source_guild.icon.url)) as resp:
                    icon_bytes = await resp.read()
                await target_guild.edit(icon=icon_bytes, reason=f"migrar_assets de {source_guild.name}")
                results.append("✅ Ícone copiado")
            except discord.Forbidden:
                results.append("❌ Ícone — sem permissão `Manage Server` no destino")
            except Exception as e:
                results.append(f"❌ Ícone — erro: {e}")
        else:
            results.append("⚠️ Servidor de origem não tem ícone")

        # Banner
        if source_guild.banner:
            try:
                async with session.get(str(source_guild.banner.url)) as resp:
                    banner_bytes = await resp.read()
                await target_guild.edit(banner=banner_bytes, reason=f"migrar_assets de {source_guild.name}")
                results.append("✅ Banner copiado")
            except discord.Forbidden:
                results.append("❌ Banner — sem permissão ou servidor sem boost suficiente")
            except Exception as e:
                results.append(f"❌ Banner — erro: {e}")
        else:
            results.append("⚠️ Servidor de origem não tem banner")

    await msg.edit(content="\n".join(results))


@bot.command(name="migrar_emojis", aliases=["migraremojis", "copy_emojis"])
async def migrar_emojis_cmd(ctx: commands.Context, source_guild_id: int = None, target_guild_id: int = None):
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    if not is_authorized(ctx.author, settings):
        await ctx.reply("❌ Sem permissão.", delete_after=6)
        return
    if source_guild_id is None:
        await ctx.reply("❌ Use: `natal!migrar_emojis <ID_origem>` ou `natal!migrar_emojis <ID_origem> <ID_destino>`")
        return

    source_guild = bot.get_guild(source_guild_id)
    if source_guild is None:
        await ctx.reply("❌ Servidor de origem não encontrado. O bot precisa estar nos dois servidores.")
        return

    if target_guild_id:
        target_guild = bot.get_guild(target_guild_id)
        if target_guild is None:
            await ctx.reply("❌ Servidor de destino não encontrado. O bot precisa estar lá também.")
            return
    else:
        target_guild = ctx.guild
    source_emojis = source_guild.emojis
    if not source_emojis:
        await ctx.reply("❌ O servidor de origem não tem emojis personalizados.")
        return

    existing_names = {e.name for e in target_guild.emojis}
    static_limit   = target_guild.emoji_limit
    animated_limit = target_guild.emoji_limit
    current_static   = sum(1 for e in target_guild.emojis if not e.animated)
    current_animated = sum(1 for e in target_guild.emojis if e.animated)

    msg = await ctx.reply(f"⏳ Migrando {len(source_emojis)} emoji(s)... aguarde.")

    ok: list[str] = []
    skipped: list[str] = []
    failed: list[str] = []

    import aiohttp
    async with aiohttp.ClientSession() as session:
        for emoji in source_emojis:
            if emoji.name in existing_names:
                skipped.append(f"`:{emoji.name}:` (já existe)")
                continue

            if emoji.animated:
                if current_animated >= animated_limit:
                    skipped.append(f"`:{emoji.name}:` (limite animados atingido)")
                    continue
            else:
                if current_static >= static_limit:
                    skipped.append(f"`:{emoji.name}:` (limite estáticos atingido)")
                    continue

            url = str(emoji.url)
            try:
                async with session.get(url) as resp:
                    if resp.status != 200:
                        failed.append(f"`:{emoji.name}:`")
                        continue
                    image_data = await resp.read()

                await target_guild.create_custom_emoji(
                    name=emoji.name,
                    image=image_data,
                    reason=f"Migração de emojis de {source_guild.name}",
                )
                ok.append(f"`:{emoji.name}:`")
                existing_names.add(emoji.name)
                if emoji.animated:
                    current_animated += 1
                else:
                    current_static += 1

            except discord.HTTPException as e:
                failed.append(f"`:{emoji.name}:` ({e.text[:40]})")
            except Exception:
                failed.append(f"`:{emoji.name}:`")

    lines = [f"✅ **Migração concluída de {source_guild.name} → {target_guild.name}**\n"]
    lines.append(f"✔️ Migrados: **{len(ok)}**")
    if skipped:
        lines.append(f"⏭️ Pulados: **{len(skipped)}** (já existiam ou limite atingido)")
    if failed:
        lines.append(f"❌ Falharam: **{len(failed)}**")
        for f_item in failed[:10]:
            lines.append(f"  • {f_item}")

    await msg.edit(content="\n".join(lines))


def _migration_ckpt_path(src_id: int, tgt_id: int) -> str:
    return os.path.join(_CLIENT_DIR, f"migration_{src_id}_{tgt_id}.json")

def _load_migration_ckpt(src_id: int, tgt_id: int) -> dict:
    try:
        with open(_migration_ckpt_path(src_id, tgt_id), encoding="utf-8") as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return {}

def _save_migration_ckpt(src_id: int, tgt_id: int, data: dict) -> None:
    try:
        with open(_migration_ckpt_path(src_id, tgt_id), "w", encoding="utf-8") as f:
            json.dump(data, f)
    except Exception:
        pass

def _msg_fp(message) -> str:
    """Fingerprint para deduplicação de mensagens."""
    parts = []
    c = (getattr(message, "content", None) or "").strip()
    if c:
        parts.append(c[:80])
    names = sorted(att.filename for att in getattr(message, "attachments", []))
    for emb in getattr(message, "embeds", []):
        url = None
        if getattr(emb, "image", None) and emb.image.url:
            url = emb.image.url
        elif getattr(emb, "thumbnail", None) and emb.thumbnail.url:
            url = emb.thumbnail.url
        if url:
            fname = url.split("?")[0].split("/")[-1]
            if fname:
                names.append(fname)
    parts.extend(names)
    return "|".join(parts)

async def _build_target_fps(channel: discord.TextChannel) -> set:
    fps = set()
    try:
        async for m in channel.history(limit=3000, oldest_first=False):
            fp = _msg_fp(m)
            if fp:
                fps.add(fp)
    except Exception:
        pass
    return fps

async def _delete_channel_duplicates(channel: discord.TextChannel) -> int:
    seen: dict[str, int] = {}
    to_delete: list[discord.Message] = []
    try:
        msgs: list[discord.Message] = []
        async for m in channel.history(limit=3000, oldest_first=True):
            msgs.append(m)
        for m in msgs:
            fp = _msg_fp(m)
            if not fp:
                continue
            if fp in seen:
                to_delete.append(m)
            else:
                seen[fp] = m.id
    except Exception:
        pass
    deleted = 0
    for m in to_delete:
        try:
            await m.delete()
            deleted += 1
            await asyncio.sleep(0.4)
        except Exception:
            pass
    return deleted


_active_migrations: set = set()  # (src_guild_id, tgt_guild_id)


async def _run_migration_task(src_guild_id: int, tgt_guild_id: int, notify_channel_id):
    """Migração em segundo plano — sobrevive a reinícios do bot via checkpoint."""
    key = (src_guild_id, tgt_guild_id)
    if key in _active_migrations:
        return
    _active_migrations.add(key)
    try:
        await bot.wait_until_ready()
        await asyncio.sleep(15)

        source_guild = bot.get_guild(src_guild_id)
        target_guild = bot.get_guild(tgt_guild_id)
        notify_chan = bot.get_channel(int(notify_channel_id)) if notify_channel_id else None

        if not source_guild or not target_guild:
            if notify_chan:
                try:
                    await notify_chan.send(f"❌ Migração **{src_guild_id} → {tgt_guild_id}** não pôde ser retomada: servidor(es) não encontrado(s).")
                except Exception:
                    pass
            try:
                os.remove(_migration_ckpt_path(src_guild_id, tgt_guild_id))
            except OSError:
                pass
            return

        source_channels = [c for c in source_guild.channels if isinstance(c, discord.TextChannel)]
        if not source_channels:
            return

        target_chan_by_name = {c.name: c for c in target_guild.channels if isinstance(c, discord.TextChannel)}
        target_cat_by_name  = {c.name: c for c in target_guild.categories}

        ckpt = _load_migration_ckpt(src_guild_id, tgt_guild_id)
        resumed = any(v for k, v in ckpt.items() if k != "_meta")

        status_msg = None
        if notify_chan:
            try:
                status_msg = await notify_chan.send(
                    f"{'🔄 Retomando' if resumed else '⏳ Iniciando'} migração de **{len(source_channels)}** canal(is) de "
                    f"**{source_guild.name}** → **{target_guild.name}**..."
                )
            except Exception:
                pass

        total_msgs        = 0
        total_channels_ok = 0
        total_skipped_ch  = 0
        errors: list[str] = []

        _http_timeout = aiohttp.ClientTimeout(total=30, connect=10)
        async with aiohttp.ClientSession(timeout=_http_timeout) as session:
            for chan_idx, source_chan in enumerate(source_channels, 1):
                chan_key = str(source_chan.id)

                if ckpt.get(chan_key) == "done":
                    total_channels_ok += 1
                    total_skipped_ch  += 1
                    continue

                target_chan = target_chan_by_name.get(source_chan.name)

                if target_chan is not None:
                    # Canal existe — pula só se já tiver conteúdo
                    has_content = False
                    try:
                        async for _ in target_chan.history(limit=1):
                            has_content = True
                            break
                    except Exception:
                        pass
                    if has_content:
                        ckpt[chan_key] = "done"
                        _save_migration_ckpt(src_guild_id, tgt_guild_id, ckpt)
                        total_channels_ok += 1
                        total_skipped_ch  += 1
                        continue
                    # Canal existe mas está vazio — garante permissão do bot e posta
                    bot_member = target_guild.get_member(bot.user.id)
                    if bot_member:
                        try:
                            await target_chan.set_permissions(
                                bot_member,
                                send_messages=True,
                                manage_webhooks=True,
                                attach_files=True,
                                embed_links=True,
                                read_messages=True,
                            )
                        except discord.HTTPException:
                            pass
                else:
                    # Cria o canal que está faltando
                    try:
                        cat = None
                        if source_chan.category:
                            cat = target_cat_by_name.get(source_chan.category.name)
                        bot_member = target_guild.get_member(bot.user.id)
                        overwrites = {}
                        if bot_member:
                            overwrites[bot_member] = discord.PermissionOverwrite(
                                send_messages=True,
                                manage_webhooks=True,
                                attach_files=True,
                                embed_links=True,
                                read_messages=True,
                            )
                        target_chan = await target_guild.create_text_channel(
                            name=source_chan.name,
                            category=cat,
                            topic=source_chan.topic or "",
                            overwrites=overwrites,
                            reason=f"Migração de canais de {source_guild.name}",
                        )
                        target_chan_by_name[source_chan.name] = target_chan
                    except discord.HTTPException as e:
                        errors.append(f"#{source_chan.name}: não consegui criar ({e.text[:50]})")
                        continue

                after_obj = None
                last_id = ckpt.get(chan_key)
                if last_id and last_id != "done":
                    after_obj = discord.Object(id=int(last_id))

                webhook = None
                try:
                    webhook = await target_chan.create_webhook(name="MigradorNATA")
                except discord.HTTPException:
                    pass

                chan_count = 0
                try:
                    async for message in source_chan.history(limit=None, oldest_first=True, after=after_obj):
                        has_embed_img = any(
                            (e.image and e.image.url) or (e.thumbnail and e.thumbnail.url)
                            for e in message.embeds
                        )
                        if not message.content and not message.attachments and not has_embed_img:
                            continue

                        files: list[discord.File] = []

                        for att in message.attachments[:10]:
                            try:
                                async with session.get(str(att.url)) as resp:
                                    if resp.status == 200:
                                        data = await resp.read()
                                        files.append(discord.File(io.BytesIO(data), filename=att.filename))
                            except Exception:
                                pass

                        for emb in message.embeds[:5]:
                            img_url = None
                            if emb.image and emb.image.url:
                                img_url = emb.image.url
                            elif emb.thumbnail and emb.thumbnail.url:
                                img_url = emb.thumbnail.url
                            if img_url and len(files) < 10:
                                try:
                                    async with session.get(str(img_url)) as resp:
                                        if resp.status == 200:
                                            data = await resp.read()
                                            fname = img_url.split("?")[0].split("/")[-1] or "image.png"
                                            if "." not in fname:
                                                fname += ".png"
                                            files.append(discord.File(io.BytesIO(data), filename=fname))
                                except Exception:
                                    pass

                        if not files and not message.content:
                            continue

                        content = (message.content or "")[:2000]

                        try:
                            if webhook:
                                await webhook.send(
                                    content=content or None,
                                    username=message.author.display_name[:80],
                                    avatar_url=str(message.author.display_avatar.url),
                                    files=files or discord.utils.MISSING,
                                    allowed_mentions=discord.AllowedMentions.none(),
                                )
                            else:
                                prefix = f"**{message.author.display_name}:** " if content else ""
                                await target_chan.send(
                                    content=f"{prefix}{content}" if content else None,
                                    files=files or discord.utils.MISSING,
                                    allowed_mentions=discord.AllowedMentions.none(),
                                )
                            chan_count += 1
                            total_msgs += 1

                            ckpt[chan_key] = str(message.id)
                            if total_msgs % 20 == 0:
                                _save_migration_ckpt(src_guild_id, tgt_guild_id, ckpt)

                            if total_msgs % 50 == 0 and status_msg:
                                try:
                                    await status_msg.edit(content=(
                                        f"⏳ [{chan_idx}/{len(source_channels)}] `#{source_chan.name}` "
                                        f"— {chan_count} msgs | Total: **{total_msgs}**"
                                    ))
                                except Exception:
                                    pass

                            await asyncio.sleep(0.75)

                        except discord.HTTPException:
                            pass
                        except Exception:
                            pass

                except discord.Forbidden:
                    errors.append(f"#{source_chan.name}: sem permissão para ler")
                except Exception as e:
                    errors.append(f"#{source_chan.name}: {str(e)[:60]}")
                finally:
                    if webhook:
                        try:
                            await webhook.delete()
                        except Exception:
                            pass

                ckpt[chan_key] = "done"
                _save_migration_ckpt(src_guild_id, tgt_guild_id, ckpt)
                total_channels_ok += 1

        try:
            os.remove(_migration_ckpt_path(src_guild_id, tgt_guild_id))
        except OSError:
            pass

        lines = [f"✅ **Migração concluída: {source_guild.name} → {target_guild.name}**\n"]
        lines.append(f"📨 Mensagens copiadas: **{total_msgs}**")
        lines.append(f"📁 Canais processados: **{total_channels_ok}/{len(source_channels)}**")
        if total_skipped_ch:
            lines.append(f"⏭️ Canais já migrados (pulados): **{total_skipped_ch}**")
        if errors:
            lines.append(f"\n⚠️ Erros ({len(errors)}):")
            for err in errors[:8]:
                lines.append(f"  • {err}")
        if status_msg:
            try:
                await status_msg.edit(content="\n".join(lines))
            except Exception:
                if notify_chan:
                    try:
                        await notify_chan.send("\n".join(lines))
                    except Exception:
                        pass
        elif notify_chan:
            try:
                await notify_chan.send("\n".join(lines))
            except Exception:
                pass

    finally:
        _active_migrations.discard(key)


@bot.command(name="migrar_canais", aliases=["migrarcanais", "copy_channels"])
async def migrar_canais_cmd(ctx: commands.Context, arg1: str = None, arg2: str = None, arg3: str = None):
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    is_admin = ctx.author.guild_permissions.administrator
    if not is_authorized(ctx.author, settings) and not is_admin:
        await ctx.reply("❌ Sem permissão.", delete_after=6)
        return

    # Sub-comando: natal!migrar_canais reset <src> <tgt>
    if arg1 == "reset":
        try:
            src = int(arg2) if arg2 else 0
            tgt = int(arg3) if arg3 else 0
            os.remove(_migration_ckpt_path(src, tgt))
            await ctx.reply("✅ Checkpoint removido. Rode o comando novamente para recomeçar do zero.")
        except (FileNotFoundError, ValueError):
            await ctx.reply("ℹ️ Nenhum checkpoint encontrado.")
        return

    # Sub-comando: natal!migrar_canais limpar <tgt_guild_id>
    if arg1 == "limpar":
        tgt_id = int(arg2) if arg2 and arg2.isdigit() else ctx.guild.id
        tgt_g = bot.get_guild(tgt_id)
        if not tgt_g:
            await ctx.reply("❌ Servidor de destino não encontrado.")
            return
        msg = await ctx.reply(f"🧹 Limpando duplicatas em **{tgt_g.name}**...")
        total_del = 0
        for ch in tgt_g.channels:
            if isinstance(ch, discord.TextChannel):
                total_del += await _delete_channel_duplicates(ch)
        await msg.edit(content=f"✅ Limpeza concluída — **{total_del}** mensagens duplicadas removidas em **{tgt_g.name}**.")
        return

    # Migração principal
    try:
        source_guild_id = int(arg1) if arg1 else None
        target_guild_id = int(arg2) if arg2 else None
    except ValueError:
        source_guild_id = None
        target_guild_id = None

    if source_guild_id is None:
        await ctx.reply(
            "❌ Use: `natal!migrar_canais <ID_origem> [ID_destino]`\n"
            "Outros usos:\n"
            "• `natal!migrar_canais reset <ID_origem> <ID_destino>` — recomeça do zero\n"
            "• `natal!migrar_canais limpar <ID_destino>` — remove duplicatas do destino"
        )
        return

    source_guild = bot.get_guild(source_guild_id)
    if source_guild is None:
        await ctx.reply("❌ Servidor de origem não encontrado. O bot precisa estar nos dois servidores.")
        return

    if target_guild_id:
        target_guild = bot.get_guild(target_guild_id)
        if target_guild is None:
            await ctx.reply("❌ Servidor de destino não encontrado. O bot precisa estar lá também.")
            return
    else:
        target_guild = ctx.guild

    source_channels = [c for c in source_guild.channels if isinstance(c, discord.TextChannel)]
    if not source_channels:
        await ctx.reply("❌ O servidor de origem não tem canais de texto.")
        return

    if (source_guild.id, target_guild.id) in _active_migrations:
        await ctx.reply("⚠️ Esta migração já está rodando em segundo plano.")
        return

    # Salva canal de notificação para auto-retomar se o bot reiniciar
    ckpt = _load_migration_ckpt(source_guild.id, target_guild.id)
    ckpt["_meta"] = {"notify_channel_id": ctx.channel.id}
    _save_migration_ckpt(source_guild.id, target_guild.id, ckpt)

    await ctx.reply(
        f"⏳ Migração de **{source_guild.name}** → **{target_guild.name}** iniciada em segundo plano.\n"
        "Continuará automaticamente mesmo se o bot reiniciar. Acompanhe o progresso neste canal."
    )
    asyncio.create_task(_run_migration_task(source_guild.id, target_guild.id, ctx.channel.id))


_DM_TODOS_CKPT    = os.path.join(_CLIENT_DIR, "dm_todos_pending.json")
_dm_todos_running = False


def _dm_todos_save(data: dict):
    try:
        with open(_DM_TODOS_CKPT, "w", encoding="utf-8") as f:
            json.dump(data, f)
    except Exception:
        pass


def _dm_todos_load() -> dict:
    try:
        with open(_DM_TODOS_CKPT, encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


async def _run_dm_todos(mensagem: str, notify_channel_id: int, sent_ids: set):
    global _dm_todos_running
    if _dm_todos_running:
        return
    _dm_todos_running = True
    try:
        await bot.wait_until_ready()
        await asyncio.sleep(5)

        notify_ch = bot.get_channel(notify_channel_id) if notify_channel_id else None

        # Coleta membros únicos e pula os já enviados
        seen: set[int] = set()
        membros: list[discord.Member] = []
        for guild in bot.guilds:
            for m in guild.members:
                if not m.bot and m.id not in seen:
                    seen.add(m.id)
                    if m.id not in sent_ids:
                        membros.append(m)

        total_restante = len(membros)
        ja_enviados    = len(sent_ids)
        total_geral    = total_restante + ja_enviados

        status_msg = None
        if notify_ch:
            try:
                prefixo = f"🔄 Retomando" if ja_enviados else "📨 Iniciando"
                status_msg = await notify_ch.send(
                    f"{prefixo} envio para **{total_geral}** membros "
                    f"({ja_enviados} já enviados, **{total_restante}** restantes)..."
                )
            except Exception:
                pass

        enviados = 0
        falhos   = 0
        for i, m in enumerate(membros, 1):
            try:
                await m.send(mensagem)
                enviados += 1
                sent_ids.add(m.id)
            except Exception:
                falhos += 1

            if i % 50 == 0:
                _dm_todos_save({"message": mensagem, "notify_channel_id": notify_channel_id, "sent_ids": list(sent_ids)})
                if status_msg:
                    try:
                        await status_msg.edit(content=(
                            f"📨 Progresso: **{ja_enviados + i}/{total_geral}** "
                            f"— ✅ {enviados} enviados | ❌ {falhos} falhos"
                        ))
                    except Exception:
                        pass

            await asyncio.sleep(1.5)

        # Concluído — remove checkpoint
        try:
            os.remove(_DM_TODOS_CKPT)
        except OSError:
            pass

        if status_msg:
            try:
                await status_msg.edit(content=(
                    f"✅ **Envio concluído!**\n"
                    f"📨 Enviados: **{ja_enviados + enviados}** | ❌ Falhos: **{falhos}**\n"
                    f"👥 Total: **{total_geral}** membros"
                ))
            except Exception:
                pass
    finally:
        _dm_todos_running = False


@bot.command(name="dm_todos", aliases=["dmtodos", "broadcast_dm"])
async def dm_todos_cmd(ctx: commands.Context, *, mensagem: str = None):
    """Envia uma mensagem na DM de todos os membros de todos os servidores."""
    settings = get_settings(ctx.guild.id) if ctx.guild else {}
    is_admin = ctx.author.guild_permissions.administrator if ctx.guild else False
    if not is_authorized(ctx.author, settings) and not is_admin:
        await ctx.reply("❌ Sem permissão.", delete_after=6)
        return
    if not mensagem:
        await ctx.reply("**Uso:** `n!dm_todos <mensagem>`", delete_after=10)
        return
    if _dm_todos_running:
        await ctx.reply("⚠️ Já existe um envio em andamento.", delete_after=8)
        return

    _dm_todos_save({"message": mensagem, "notify_channel_id": ctx.channel.id, "sent_ids": []})
    await ctx.reply(
        f"📨 Envio iniciado em segundo plano — **retoma automaticamente** se o bot reiniciar.\n"
        "Acompanhe o progresso aqui."
    )
    asyncio.create_task(_run_dm_todos(mensagem, ctx.channel.id, set()))


@bot.command(name="clonar_config", aliases=["clone_config", "clonarconfig"])
async def clonar_config_cmd(ctx: commands.Context, source_guild_id: int = None):
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    _perms = ctx.author.guild_permissions
    is_admin = _perms.administrator or _perms.manage_guild if ctx.guild else False
    if not is_authorized(ctx.author, settings) and not is_admin:
        await ctx.reply("❌ Sem permissão. Use `nata!perm` para se adicionar como autorizado.")
        return
    if source_guild_id is None:
        await ctx.reply("❌ Use: `nata!clonar_config <ID_do_servidor_origem>`")
        return

    source_guild = bot.get_guild(source_guild_id)
    target_guild = ctx.guild
    src = get_settings(source_guild_id)

    # Se não há nenhuma config salva E o bot não está no servidor, não tem nada pra copiar
    if source_guild is None and not src:
        await ctx.reply("❌ Servidor de origem não encontrado e nenhuma configuração salva para esse ID.")
        return

    if source_guild is None:
        # Bot não está mais no servidor de origem — faz cópia direta das settings salvas no disco
        # Canais/cargos são copiados como IDs brutos (o usuário precisará reconfigurar IDs diferentes)
        import copy
        tgt = get_settings(target_guild.id)
        _skip = {"guild_name", "guild_owner_id", "prefix", "backup_data",
                 "backup_last_timestamp", "ig_last_highlight", "warns_records",
                 "blacklist_users", "limite_ban_counts", "limite_ban_last_reset",
                 "gifs_autopostador_sent", "gifs_autopostador_last_posted",
                 "calendar_last_check"}
        for k, v in src.items():
            if k not in _skip:
                tgt[k] = copy.deepcopy(v)
        save_settings_to_disk()
        await ctx.reply(
            f"✅ Config copiada de **ID {source_guild_id}** → **{target_guild.name}**!\n"
            "⚠️ O bot não estava no servidor de origem — IDs de canais/cargos foram copiados brutos. "
            "Reconfigure canais e cargos pelo painel se o novo servidor tiver IDs diferentes."
        )
        return

    src_role_name  = {r.id: r.name for r in source_guild.roles}
    src_chan_name  = {c.id: c.name for c in source_guild.channels}
    tgt_role_by_name = {r.name: r.id for r in target_guild.roles}
    tgt_chan_by_name = {c.name: c.id for c in target_guild.channels}

    not_found: list[str] = []

    def mr(rid):
        if not rid:
            return None
        name = src_role_name.get(int(rid))
        if name is None:
            not_found.append(f"cargo ID:{rid}")
            return None
        new = tgt_role_by_name.get(name)
        if new is None:
            not_found.append(f"@{name}")
        return new

    def mc(cid):
        if not cid:
            return None
        name = src_chan_name.get(int(cid))
        if name is None:
            return None
        return tgt_chan_by_name.get(name)

    def mrl(lst):
        return [x for x in (mr(r) for r in lst) if x]

    def mcl(lst):
        return [x for x in (mc(c) for c in lst) if x]

    tgt = get_settings(target_guild.id)

    # Geral
    tgt["embed_color"] = src.get("embed_color", 0x2B2D31)
    tgt["language"]    = src.get("language", "pt")

    # Proteção de Cargos
    tgt["protecao_cargos_enabled"]    = src.get("protecao_cargos_enabled", False)
    tgt["protecao_cargos_whitelist"]  = mrl(src.get("protecao_cargos_whitelist", []))
    tgt["protecao_cargos_acesso"]     = mrl(src.get("protecao_cargos_acesso", []))
    tgt["protecao_cargos_log_channel"] = mc(src.get("protecao_cargos_log_channel"))
    tgt["protecao_grupos_cargos"] = {
        str(nr): mrl(managed)
        for rid_str, managed in src.get("protecao_grupos_cargos", {}).items()
        if (nr := mr(int(rid_str)))
    }
    tgt["protecao_grupos_usuarios"] = {
        uid: mrl(managed)
        for uid, managed in src.get("protecao_grupos_usuarios", {}).items()
    }
    tgt["protecao_cargo_bloqueado"] = {
        str(nr): mrl(access)
        for rid_str, access in src.get("protecao_cargo_bloqueado", {}).items()
        if (nr := mr(int(rid_str)))
    }

    # Anti-bot
    tgt["antbot_enabled"]     = src.get("antbot_enabled", False)
    tgt["antbot_log_channel"] = mc(src.get("antbot_log_channel"))
    tgt["antbot_access_role"] = mr(src.get("antbot_access_role"))
    tgt["antbot_whitelist"]   = src.get("antbot_whitelist", [])  # IDs de apps, não de cargos

    # Anti-ban
    tgt["antban_enabled"]       = src.get("antban_enabled", False)
    tgt["antban_log_channel"]   = mc(src.get("antban_log_channel"))
    tgt["antban_roles"]         = mrl(src.get("antban_roles", []))
    tgt["antban_allowed_roles"] = mrl(src.get("antban_allowed_roles", []))

    # Limite de ban
    tgt["limite_ban_enabled"]    = src.get("limite_ban_enabled", False)
    tgt["limite_ban_reset_days"] = src.get("limite_ban_reset_days")
    tgt["limite_ban_roles"] = {
        str(nr): limit
        for rid_str, limit in src.get("limite_ban_roles", {}).items()
        if (nr := mr(int(rid_str)))
    }

    # Anti-fake
    tgt["antfake_enabled"]     = src.get("antfake_enabled", False)
    tgt["antfake_days"]        = src.get("antfake_days")
    tgt["antfake_log_channel"] = mc(src.get("antfake_log_channel"))

    # Anti-link / anti-invite
    tgt["antlink_enabled"]          = src.get("antlink_enabled", False)
    tgt["antinvite_enabled"]        = src.get("antinvite_enabled", False)
    tgt["antlink_action"]           = src.get("antlink_action", "apagar")
