class _VerRankView(discord.ui.View):
    def __init__(self, guild_id: int):
        super().__init__(timeout=60)
        self.guild_id = guild_id

    @discord.ui.button(label="Ver Rank", style=discord.ButtonStyle.secondary)
    async def ver_rank(self, interaction: discord.Interaction, button: discord.ui.Button):
        settings  = get_settings(self.guild_id)
        icon_url  = bot.user.display_avatar.url if bot.user else None
        postagens = settings.get("gifs_postadores_postagens", {})

        # ordena pelo maior número de postagens
        ranking = sorted(postagens.items(), key=lambda x: x[1], reverse=True)[:10]

        embed = discord.Embed(color=settings["embed_color"])
        embed.set_author(name="A NATA - Ranking de Postadores", icon_url=icon_url)
        if icon_url:
            embed.set_thumbnail(url=icon_url)

        if not ranking:
            linhas = "`Nenhum postador registrado ainda.`"
        else:
            linhas = []
            guild = interaction.guild
            for i, (uid, pts) in enumerate(ranking, 1):
                membro = guild.get_member(int(uid)) if guild else None
                nome   = membro.display_name if membro else f"Usuário Desconhecido"
                linhas.append(f"• **#{i} - {nome}**\nPontos: `{pts}`")
            linhas = "\n".join(linhas)

        embed.add_field(name="TOP 10 POSTADORES:", value=linhas, inline=False)
        embed.timestamp = datetime.now()
        await interaction.response.send_message(embed=embed, ephemeral=True)


