@bot.command(name="castigo")
async def castigo_cmd(ctx: commands.Context, member: discord.Member = None, *, reason: str = None):
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    t = TRANSLATIONS[settings["language"]]

    is_admin = (
        isinstance(ctx.author, discord.Member)
        and ctx.author.guild_permissions.administrator
    )
    if not is_admin:
        await ctx.reply(t["not_authorized"], delete_after=8)
        return

    if not settings.get("castigo_enabled"):
        await ctx.reply("Sistema de Castigo está desativado.", delete_after=8)
        return

    if member is None:
        await ctx.reply("Uso: `n!castigo @membro motivo`", delete_after=8)
        return

    auto_roles = settings.get("castigo_auto_roles", [])
    if not auto_roles:
        await ctx.reply("Nenhum cargo de castigo configurado.", delete_after=8)
        return

    roles_to_add = []
    for rid in auto_roles:
        role = ctx.guild.get_role(rid)
        if role:
            roles_to_add.append(role)

    if not roles_to_add:
        await ctx.reply("Cargos de castigo não encontrados.", delete_after=8)
        return

    try:
        for r in roles_to_add:
            _register_bot_role_action(member.id, r.id, "add")
        await member.add_roles(*roles_to_add, reason=f"Castigo aplicado por {ctx.author}: {reason or 'sem motivo'}")
    except (discord.Forbidden, discord.HTTPException):
        await ctx.reply("Não consegui aplicar os cargos.", delete_after=8)
        return

    log_channel_id = settings.get("castigo_log_channel")
    if log_channel_id:
        log_channel = ctx.guild.get_channel(log_channel_id)
        if log_channel:
            log_embed = discord.Embed(
                title="🔒 Castigo Aplicado",
                color=settings["embed_color"],
            )
            log_embed.add_field(name="Alvo", value=f"{member.mention} (`{member.id}`)", inline=True)
            log_embed.add_field(name="Moderador", value=f"{ctx.author.mention} (`{ctx.author.id}`)", inline=True)
            log_embed.add_field(name="Motivo", value=reason or "Sem motivo informado.", inline=False)
            log_embed.timestamp = datetime.now()
            try:
                await log_channel.send(embed=log_embed)
            except (discord.Forbidden, discord.HTTPException):
                pass

    await ctx.reply(f"Castigo aplicado em {member.mention}!")


@bot.command(name="bl")
async def blacklist_cmd(ctx: commands.Context, action: str = None, target: str = None):
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    t = TRANSLATIONS[settings["language"]]

    is_admin = (
        isinstance(ctx.author, discord.Member)
        and ctx.author.guild_permissions.administrator
    )
    allowed_roles = settings.get("blacklist_allowed_roles", [])
    has_role = (
        isinstance(ctx.author, discord.Member)
        and any(r.id in allowed_roles for r in ctx.author.roles)
    )
    if not is_admin and not has_role:
        await ctx.reply(t["blacklist_not_allowed"], delete_after=8)
        return

    if action not in ("add", "rem", "remove") or target is None:
        await ctx.reply(t["blacklist_usage"], delete_after=8)
        return

    raw = target.strip("<@!>")
    try:
        user_id = int(raw)
    except ValueError:
        await ctx.reply(t["blacklist_usage"], delete_after=8)
        return

    users = settings.setdefault("blacklist_users", [])
    if action == "add":
        if user_id in users:
            await ctx.reply(t["already_in_blacklist"], delete_after=8)
            return
        users.append(user_id)
        await ctx.reply(t["user_added_blacklist"])
    else:
        if user_id not in users:
            await ctx.reply(t["not_in_blacklist"], delete_after=8)
            return
        users.remove(user_id)
        await ctx.reply(t["user_removed_blacklist"])


@bot.command(name="aviso")
async def aviso(ctx: commands.Context, member: discord.Member = None, *, reason: str = None):
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    t = TRANSLATIONS[settings["language"]]

    is_admin = (
        isinstance(ctx.author, discord.Member)
        and ctx.author.guild_permissions.administrator
    )
    mod_roles = settings.get("warns_moderator_roles", [])
    has_mod_role = (
        isinstance(ctx.author, discord.Member)
        and any(r.id in mod_roles for r in ctx.author.roles)
    )

    if not is_admin and not has_mod_role:
        await ctx.reply(t["warn_not_moderator"], delete_after=8)
        return

    if member is None:
        await ctx.reply(t["warn_member_not_found"], delete_after=8)
        return

    reason_text = reason or t["warn_no_reason"]
    records = settings.setdefault("warns_records", {})
    user_warns = records.setdefault(str(member.id), [])
    user_warns.append({
        "moderator_id": ctx.author.id,
        "reason": reason_text,
        "timestamp": datetime.now().isoformat(),
    })

    action = settings.get("warns_action", "nenhuma")
    action_applied = action if action != "nenhuma" else None
    if action_applied:
        await _apply_action(action, member, ctx.message, f"Aviso aplicado por {ctx.author}: {reason_text}")

    log_channel_id = settings.get("warns_log_channel")
    if log_channel_id:
        log_channel = ctx.guild.get_channel(log_channel_id)
        if log_channel:
            log_embed = discord.Embed(
                title=t["warn_log_title"],
                color=settings["embed_color"],
            )
            log_embed.add_field(name=t["warn_log_target"], value=f"{member.mention} (`{member.id}`)", inline=True)
            log_embed.add_field(name=t["warn_log_moderator"], value=f"{ctx.author.mention} (`{ctx.author.id}`)", inline=True)
            log_embed.add_field(name=t["warn_log_reason"], value=reason_text, inline=False)
            if action_applied:
                log_embed.add_field(name=t["warn_log_action"], value=f"`{action_applied}`", inline=True)
            log_embed.timestamp = datetime.now()
            try:
                await log_channel.send(embed=log_embed)
            except (discord.Forbidden, discord.HTTPException):
                pass

    await ctx.reply(t["warn_applied"].format(member=member.mention))


