def build_auto_cargo_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["auto_cargo_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    enabled = settings.get("auto_cargo_enabled", False)
    status_value = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else "<a:alerta:1518271939460857968> `(Desativado)`"
    )

    guild = author.guild
    nd = f"`{t['not_defined']}`"
    mem_id = settings.get("auto_cargo_membro_role")
    bot_id = settings.get("auto_cargo_bot_role")
    booster_ids = settings.get("auto_cargo_booster_roles", [])

    mem_role = guild.get_role(mem_id) if (guild and mem_id) else None
    bot_role = guild.get_role(bot_id) if (guild and bot_id) else None

    mem_value = mem_role.mention if mem_role else nd
    bot_value = bot_role.mention if bot_role else nd
    booster_value = _format_roles_list(guild, booster_ids) or nd

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"┃ **Status:** {status_value}\n"
            f"**{t['auto_cargo_cargo_membros']}:** {mem_value}\n"
            f"**{t['auto_cargo_cargo_bots']}:** {bot_value}\n"
            f"**{t['auto_cargo_cargo_boosters']}:** {booster_value}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['auto_cargo_obs_title']}:",
        value=t["auto_cargo_obs_text"],
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


