class _SingleSelectView(discord.ui.View):
    def __init__(self, item: discord.ui.Item):
        super().__init__(timeout=120)
        self.add_item(item)


class AutoCargoView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("auto_cargo_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_definir_cargo_membro"], discord.ButtonStyle.secondary, self._def_membro),
            (t["btn_definir_cargo_bot"], discord.ButtonStyle.secondary, self._def_bot),
            (t["btn_definir_cargo_booster"], discord.ButtonStyle.secondary, self._def_booster),
        ]
        row1 = [
            (t["btn_resetar_tudo_simples"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["auto_cargo_enabled"] = not settings.get("auto_cargo_enabled", False)
        embed = build_auto_cargo_embed(self.author, settings)
        view = AutoCargoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["auto_cargo_activated"] if settings["auto_cargo_enabled"] else t["auto_cargo_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _def_membro(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(AutoCargoMembroSelect(self, t["auto_cargo_select_membro"]))
        await interaction.response.send_message(embed=_notif_embed(t["auto_cargo_select_membro"]), view=view, ephemeral=True)

    async def _def_bot(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(AutoCargoBotSelect(self, t["auto_cargo_select_bot"]))
        await interaction.response.send_message(embed=_notif_embed(t["auto_cargo_select_bot"]), view=view, ephemeral=True)

    async def _def_booster(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(AutoCargoBoosterSelect(self, t["auto_cargo_select_booster"]))
        await interaction.response.send_message(embed=_notif_embed(t["auto_cargo_select_booster"]), view=view, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["auto_cargo_enabled"] = False
        settings["auto_cargo_membro_role"] = None
        settings["auto_cargo_bot_role"] = None
        settings["auto_cargo_booster_roles"] = []
        embed = build_auto_cargo_embed(self.author, settings)
        view = AutoCargoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["auto_cargo_reset_done"]), ephemeral=True)


