def build_reacoes_user_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["reacoes_user_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    enabled = settings.get("reacoes_user_enabled", False)
    status_value = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else "<a:alerta:1518271939460857968> `(Desativado)`"
    )

    users = settings.get("reacoes_user_users", {})
    channel_ids = settings.get("reacoes_user_channels", [])

    # Sample mentions for cleaner display (truncated if too many)
    if author.guild and channel_ids:
        mentions = []
        for cid in channel_ids[:5]:
            ch = author.guild.get_channel(cid)
            mentions.append(ch.mention if ch else f"<#{cid}>")
        channels_inline = " ".join(mentions)
        if len(channel_ids) > 5:
            channels_inline += f" `+{len(channel_ids) - 5}`"
    else:
        channels_inline = f"`{t['not_defined']}`"

    if users:
        user_lines = []
        for uid, emj in list(users.items())[:5]:
            emj_preview = " ".join(emj[:3]) or "—"
            user_lines.append(f"<@{uid}> {emj_preview}")
        users_inline = "\n".join(user_lines)
        if len(users) > 5:
            users_inline += f"\n`+{len(users) - 5} {t['reacoes_user_users_unit']}`"
    else:
        users_inline = f"`{t['not_defined']}`"

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"┃ **Status:** {status_value}\n"
            f"<:comunidade_:1518272016971595807> **{t['reacoes_user_usuarios']}:** "
            f"`{len(users)}` {t['reacoes_user_users_unit']}\n"
            f"<:Mov_chat:1518271970008105031> **{t['reacoes_user_canais']}:** "
            f"`{len(channel_ids)}` {t['reacoes_user_channels_unit']}"
        ),
        inline=False,
    )

    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['reacoes_user_usuarios']}",
        value=users_inline,
        inline=False,
    )

    embed.add_field(
        name=f"<:Mov_chat:1518271970008105031>  {t['reacoes_user_canais']}",
        value=channels_inline,
        inline=False,
    )

    embed.add_field(
        name=f"<:tickets:1518271952526250155>  {t['advertencia_observations']}",
        value=f"_{t['reacoes_user_obs']}_",
        inline=False,
    )

    embed.set_footer(
        text=f"NATA® ® • {t['solicitado_por']} {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


