class ReacoesUserView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("reacoes_user_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_gerenciar_canais"], discord.ButtonStyle.secondary, self._channels),
            (t["btn_gerenciar_usuarios"], discord.ButtonStyle.secondary, self._users),
            (t["btn_listar_configuracoes"], discord.ButtonStyle.secondary, self._list),
        ]
        row1 = [
            (t["btn_reset_config"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["reacoes_user_enabled"] = not settings.get("reacoes_user_enabled", False)
        embed = build_reacoes_user_embed(self.author, settings)
        view = ReacoesUserView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["reacoes_user_activated"] if settings["reacoes_user_enabled"] else t["reacoes_user_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _channels(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(ReacoesUserChannelsSelect(self, t["reacoes_user_channels_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["reacoes_user_channels_placeholder"]), view=view, ephemeral=True)

    async def _users(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        # Show instructions embed and wait for chat input
        embed = discord.Embed(
            title=t["reacoes_user_users_panel_title"],
            color=settings["embed_color"],
            description=(
                f"**{t['reacoes_user_add_instr_title']}**\n"
                f"{t['reacoes_user_add_instr_text']}\n\n"
                f"**{t['reacoes_user_remove_instr_title']}**\n"
                f"{t['reacoes_user_remove_instr_text']}\n\n"
                f"**{t['reacoes_user_examples_title']}**\n"
                f"{t['reacoes_user_examples_text']}\n\n"
                f"_{t['reacoes_user_wait_response']}_"
            ),
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

        def check(m: discord.Message) -> bool:
            return m.author.id == self.author.id and m.channel.id == interaction.channel.id

        try:
            msg = await bot.wait_for("message", check=check, timeout=30)
        except asyncio.TimeoutError:
            await interaction.followup.send(embed=_notif_embed(t["reacoes_user_response_timeout"]), ephemeral=True)
            return

        content = msg.content.strip()
        try:
            await msg.delete()
        except (discord.Forbidden, discord.NotFound):
            pass

        parts = content.split()
        if not parts:
            await interaction.followup.send(embed=_notif_embed(t["reacoes_user_response_invalid"]), ephemeral=True)
            return

        # Detect "remover @user"
        if parts[0].lower() in ("remover", "remove") and len(parts) >= 2:
            raw = parts[1].strip("<@!>")
            try:
                uid = int(raw)
            except ValueError:
                await interaction.followup.send(embed=_notif_embed(t["reacoes_user_response_user_not_found"]), ephemeral=True)
                return
            users = settings.setdefault("reacoes_user_users", {})
            users.pop(str(uid), None)
            embed2 = build_reacoes_user_embed(self.author, settings)
            try:
                await interaction.message.edit(embed=embed2, view=ReacoesUserView(self.author))
            except (discord.HTTPException, AttributeError):
                pass
            await interaction.followup.send(embed=_notif_embed(t["reacoes_user_response_removed"]), ephemeral=True)
            return

        # Add/edit pattern: @user emojis...
        raw = parts[0].strip("<@!>")
        try:
            uid = int(raw)
        except ValueError:
            await interaction.followup.send(embed=_notif_embed(t["reacoes_user_response_user_not_found"]), ephemeral=True)
            return
        emojis = parts[1:][:10]
        if not emojis:
            await interaction.followup.send(embed=_notif_embed(t["reacoes_user_response_invalid"]), ephemeral=True)
            return
        users = settings.setdefault("reacoes_user_users", {})
        users[str(uid)] = emojis
        embed2 = build_reacoes_user_embed(self.author, settings)
        try:
            await interaction.message.edit(embed=embed2, view=ReacoesUserView(self.author))
        except (discord.HTTPException, AttributeError):
            pass
        await interaction.followup.send(embed=_notif_embed(t["reacoes_user_response_added"]), ephemeral=True)

    async def _list(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        users = settings.get("reacoes_user_users", {})
        if not users:
            await interaction.response.send_message(f"`{t['auto_reacoes_nada']}`", ephemeral=True)
            return
        lines = [
            f"• <@{uid}> → {' '.join(emj)}" for uid, emj in list(users.items())[:30]
        ]
        embed = discord.Embed(
            title=t["reacoes_user_panel_title"],
            description="\n".join(lines)[:4000],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["reacoes_user_enabled"] = False
        settings["reacoes_user_channels"] = []
        settings["reacoes_user_users"] = {}
        embed = build_reacoes_user_embed(self.author, settings)
        view = ReacoesUserView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["reacoes_user_reset_done"]), ephemeral=True)


