def build_auto_msg_add_embed(author: discord.Member, settings: dict, draft: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["auto_msg_add_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    embed.add_field(
        name=f"<:tickets:1518271952526250155>  {t['administrator_label']}",
        value=f"{author.mention} ( `{author.id}` )",
        inline=False,
    )

    ch_id = draft.get("channel_id")
    if ch_id and author.guild:
        ch = author.guild.get_channel(ch_id)
        canal_value = ch.mention if ch else f"`{t['auto_msg_add_nenhum_canal']}`"
    else:
        canal_value = f"`{t['auto_msg_add_nenhum_canal']}`"

    mode_value = f"`{draft.get('mode') or t['auto_msg_modo_texto']}`"
    secs = draft.get("interval_seconds")
    tempo_value = f"`{_format_time_seconds(secs)}`" if secs else f"`{t['auto_msg_add_nenhum_tempo']}`"
    msg = draft.get("message")
    mensagem_preview = (
        f"```{msg[:200]}```" if msg else f"`{t['auto_msg_add_nada_configurado']}`"
    )

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"**{t['auto_msg_add_canal']}:** {canal_value}\n"
            f"**{t['auto_msg_add_modo']}:** {mode_value}\n"
            f"**{t['auto_msg_add_tempo']}:** {tempo_value}\n"
            f"**{t['auto_msg_add_mensagem']}:**\n{mensagem_preview}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['advertencia_observations']}",
        value=t["auto_msg_add_obs"],
        inline=False,
    )
    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class AutoMsgModeSelect(discord.ui.Select):
    def __init__(self, parent_view: "AutoMsgAddView", t: dict):
        options = [
            discord.SelectOption(label=t["auto_msg_modo_texto"], value="Texto",
                                 emoji=_make_select_emoji("<:Mov_chat:1518271970008105031>")),
            discord.SelectOption(label=t["auto_msg_modo_embed"], value="Embed",
                                 emoji=_make_select_emoji("<:tickets:1518271952526250155>")),
        ]
        super().__init__(placeholder="Texto/Embed", min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        self.parent_view.draft["mode"] = self.values[0]
        embed = build_auto_msg_add_embed(self.parent_view.author, settings, self.parent_view.draft)
        new_view = AutoMsgAddView(self.parent_view.author)
        new_view.draft = self.parent_view.draft
        await interaction.response.edit_message(embed=embed, view=new_view)
        await interaction.followup.send(
            t["auto_msg_modo_set"].format(mode=self.values[0]), ephemeral=True
        )


class AutoMsgAddView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self.draft = {"channel_id": None, "mode": None, "interval_seconds": None, "message": None}
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (t["btn_adicionar_canal"], discord.ButtonStyle.secondary, self._add_canal),
            (t["btn_selecionar_modo"], discord.ButtonStyle.secondary, self._sel_modo),
            (t["btn_adicionar_tempo"], discord.ButtonStyle.secondary, self._add_tempo),
            (t["btn_adicionar_mensagem"], discord.ButtonStyle.secondary, self._add_msg),
        ]
        row1 = [
            (t["btn_finalizar"], discord.ButtonStyle.success, self._finalize),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_auto_msg_embed(self.author, settings)
        view = AutoMsgView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _wait_for_chat(self, interaction: discord.Interaction, prompt: str) -> str | None:
        await interaction.response.send_message(prompt, ephemeral=True)

        def check(m: discord.Message) -> bool:
            return m.author.id == self.author.id and m.channel.id == interaction.channel.id

        try:
            msg = await bot.wait_for("message", check=check, timeout=60)
        except asyncio.TimeoutError:
            settings = get_settings(interaction.guild.id)
            t = TRANSLATIONS[settings["language"]]
            await interaction.followup.send(embed=_notif_embed(t["auto_msg_timed_out"]), ephemeral=True)
            return None

        content = msg.content.strip()
        try:
            await msg.delete()
        except (discord.Forbidden, discord.NotFound):
            pass

        if content.lower() in ("cancelar", "cancel"):
            settings = get_settings(interaction.guild.id)
            t = TRANSLATIONS[settings["language"]]
            await interaction.followup.send(embed=_notif_embed(t["auto_msg_cancelled"]), ephemeral=True)
            return None
        return content

    async def _refresh_main(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_auto_msg_add_embed(self.author, settings, self.draft)
        try:
            await interaction.edit_original_response(embed=embed, view=self)
        except (discord.HTTPException, discord.NotFound):
            pass

    async def _add_canal(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        content = await self._wait_for_chat(interaction, t["auto_msg_prompt_canal"])
        if content is None:
            return
        raw = content.strip("<#>").strip("# ")
        try:
            ch_id = int(raw)
        except ValueError:
            await interaction.followup.send(embed=_notif_embed(t["auto_msg_invalid_canal"]), ephemeral=True)
            return
        ch = interaction.guild.get_channel(ch_id)
        if not ch:
            await interaction.followup.send(embed=_notif_embed(t["auto_msg_invalid_canal"]), ephemeral=True)
            return
        self.draft["channel_id"] = ch.id
        await self._refresh_main(interaction)
        await interaction.followup.send(
            t["auto_msg_canal_set"].format(channel=ch.mention), ephemeral=True
        )

    async def _sel_modo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(AutoMsgModeSelect(self, t))
        await interaction.response.send_message("Texto/Embed:", view=view, ephemeral=True)

    async def _add_tempo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        content = await self._wait_for_chat(
            interaction, t["auto_msg_prompt_tempo"].format(user=self.author.mention)
        )
        if content is None:
            return
        secs = _parse_time_token(content)
        if not secs:
            await interaction.followup.send(embed=_notif_embed(t["auto_msg_invalid_tempo"]), ephemeral=True)
            return
        self.draft["interval_seconds"] = secs
        await self._refresh_main(interaction)
        await interaction.followup.send(
            t["auto_msg_tempo_set"].format(time=_format_time_seconds(secs)), ephemeral=True
        )

    async def _add_msg(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        content = await self._wait_for_chat(interaction, t["auto_msg_prompt_mensagem"])
        if content is None:
            return
        self.draft["message"] = content
        await self._refresh_main(interaction)
        await interaction.followup.send(embed=_notif_embed(t["auto_msg_mensagem_set"]), ephemeral=True)

    async def _finalize(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        d = self.draft
        if not all([d.get("channel_id"), d.get("mode"), d.get("interval_seconds"), d.get("message")]):
            await interaction.response.send_message(embed=_notif_embed(t["auto_msg_finalize_missing"]), ephemeral=True)
            return
        lst = settings.setdefault("auto_msg_list", [])
        if len(lst) >= 10:
            await interaction.response.send_message(embed=_notif_embed(t["auto_msg_limit_reached"]), ephemeral=True)
            return
        lst.append({
            "channel_id": d["channel_id"],
            "mode": d["mode"],
            "interval_seconds": d["interval_seconds"],
            "message": d["message"],
            "last_sent": 0,
        })
        embed = build_auto_msg_embed(self.author, settings)
        view = AutoMsgView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["auto_msg_finalized"]), ephemeral=True)


class AutoMsgView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("auto_msg_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_configurar_mensagens"], discord.ButtonStyle.secondary, self._configurar),
            (t["btn_listar_mensagens"], discord.ButtonStyle.secondary, self._listar),
            (t["btn_reset_config"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["auto_msg_enabled"] = not settings.get("auto_msg_enabled", False)
        embed = build_auto_msg_embed(self.author, settings)
        view = AutoMsgView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["auto_msg_activated"] if settings["auto_msg_enabled"] else t["auto_msg_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _configurar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        view = AutoMsgAddView(self.author)
        embed = build_auto_msg_add_embed(self.author, settings, view.draft)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _listar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        lst = settings.get("auto_msg_list", [])
        if not lst:
            await interaction.response.send_message(f"`{t['auto_msg_add_nada_configurado']}`", ephemeral=True)
            return
        lines = []
        for i, ent in enumerate(lst[:25], start=1):
            ch = interaction.guild.get_channel(ent["channel_id"]) if interaction.guild else None
            ch_text = ch.mention if ch else f"<#{ent['channel_id']}>"
            time_text = _format_time_seconds(ent["interval_seconds"])
            msg_text = ent["message"][:50].replace("\n", " ")
            lines.append(f"`{i}.` {ch_text} • `{ent['mode']}` • `{time_text}` • {msg_text}")
        embed = discord.Embed(
            title=t["auto_msg_list_title"],
            description="\n".join(lines)[:4000],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["auto_msg_enabled"] = False
        settings["auto_msg_list"] = []
        embed = build_auto_msg_embed(self.author, settings)
        view = AutoMsgView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["auto_msg_reset_done"]), ephemeral=True)


