class AutoRespRemoveChSelect(discord.ui.Select):
    def __init__(self, parent_view: "AutoRespView", t: dict, guild: discord.Guild):
        chans = get_settings(parent_view.author.guild.id).get("auto_resp_channels", [])
        options = []
        for cid in chans[:25]:
            ch = guild.get_channel(cid) if guild else None
            options.append(discord.SelectOption(
                label=(ch.name if ch else f"#{cid}")[:100], value=str(cid),
            ))
        if not options:
            options = [discord.SelectOption(label=t["auto_resp_nenhum"], value="__none__")]
        super().__init__(placeholder=t["auto_resp_remove_ch_placeholder"],
                         min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if self.values[0] == "__none__":
            await interaction.response.defer()
            return
        cid = int(self.values[0])
        chans = settings.get("auto_resp_channels", [])
        if cid in chans:
            chans.remove(cid)
        embed = build_auto_resp_embed(self.parent_view.author, settings)
        view = AutoRespView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["auto_resp_canais_updated"]), ephemeral=True)


class AutoRespRemoveMsgSelect(discord.ui.Select):
    def __init__(self, parent_view: "AutoRespView", t: dict):
        msgs = get_settings(parent_view.author.guild.id).get("auto_resp_messages", [])
        options = [
            discord.SelectOption(
                label=(m.get("trigger") or "?")[:100],
                description=(m.get("response") or "")[:100] or None,
                value=str(i),
            ) for i, m in enumerate(msgs[:25])
        ] or [discord.SelectOption(label=t["auto_resp_nada"], value="__none__")]
        super().__init__(placeholder=t["auto_resp_remove_msg_placeholder"],
                         min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if self.values[0] == "__none__":
            await interaction.response.defer()
            return
        idx = int(self.values[0])
        msgs = settings.get("auto_resp_messages", [])
        if 0 <= idx < len(msgs):
            msgs.pop(idx)
        embed = build_auto_resp_embed(self.parent_view.author, settings)
        view = AutoRespView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["auto_resp_removed"]), ephemeral=True)


def _build_auto_resp_list_embed(author: discord.Member, settings: dict, page: int) -> tuple[discord.Embed, int]:
    t = TRANSLATIONS[settings["language"]]
    msgs = settings.get("auto_resp_messages", [])
    chans = settings.get("auto_resp_channels", [])
    per_page = 5
    total_pages = max(1, (len(msgs) + per_page - 1) // per_page)
    page = max(1, min(page, total_pages))
    icon_url = bot.user.display_avatar.url if bot.user else None

    embed = discord.Embed(color=settings["embed_color"])
    embed.set_author(name=t["auto_resp_list_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    if author.guild and chans:
        mentions = []
        for cid in chans[:5]:
            ch = author.guild.get_channel(cid)
            mentions.append(ch.mention if ch else f"<#{cid}>")
        chan_text = " ".join(mentions)
        if len(chans) > 5:
            chan_text += f" `+{len(chans) - 5}`"
    else:
        chan_text = f"`{t['auto_resp_nenhum']}`"

    embed.description = (
        f"**{t['auto_resp_list_lista']}**\n"
        f"**{t['auto_resp_list_canais']}** {chan_text}\n\n"
    )
    if not msgs:
        embed.description += f"`{t['auto_resp_list_empty']}`"
    else:
        start = (page - 1) * per_page
        chunk = msgs[start:start + per_page]
        for i, m in enumerate(chunk, start=start + 1):
            embed.description += f"`{i}.` **{m.get('trigger','?')}** → {m.get('response','')[:120]}\n"

    embed.set_footer(text=f"NATA® ® • {t['page_label']} {page}/{total_pages}")
    return embed, total_pages


class AutoRespListView(discord.ui.View):
    def __init__(self, author: discord.Member, page: int = 1):
        super().__init__(timeout=None)
        self.author = author
        self.page = page
        settings = get_settings(author.guild.id if author.guild else 0)
        _, self.total_pages = _build_auto_resp_list_embed(author, settings, page)
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        prev_btn = discord.ui.Button(
            label=t["btn_anterior"], style=discord.ButtonStyle.secondary,
            disabled=(self.page <= 1),
        )
        prev_btn.callback = self._prev
        self.add_item(prev_btn)
        next_btn = discord.ui.Button(
            label=t["btn_proximo"], style=discord.ButtonStyle.secondary,
            disabled=(self.page >= self.total_pages),
        )
        next_btn.callback = self._next
        self.add_item(next_btn)
        close_btn = discord.ui.Button(
            label=t["btn_fechar"], style=discord.ButtonStyle.danger,
        )
        close_btn.callback = self._close
        self.add_item(close_btn)

    async def _prev(self, interaction: discord.Interaction):
        self.page = max(1, self.page - 1)
        settings = get_settings(interaction.guild.id)
        embed, _ = _build_auto_resp_list_embed(self.author, settings, self.page)
        new_view = AutoRespListView(self.author, self.page)
        await interaction.response.edit_message(embed=embed, view=new_view)

    async def _next(self, interaction: discord.Interaction):
        self.page = min(self.total_pages, self.page + 1)
        settings = get_settings(interaction.guild.id)
        embed, _ = _build_auto_resp_list_embed(self.author, settings, self.page)
        new_view = AutoRespListView(self.author, self.page)
        await interaction.response.edit_message(embed=embed, view=new_view)

    async def _close(self, interaction: discord.Interaction):
        try:
            await interaction.response.edit_message(content=None, embed=None, view=None)
        except discord.HTTPException:
            await interaction.response.defer()


class AutoRespView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("auto_resp_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_configurar_canais_auto"], discord.ButtonStyle.secondary, self._cfg_canais),
            (t["btn_adicionar_mensagem_auto"], discord.ButtonStyle.secondary, self._add_msg),
            (t["btn_listar_configuracoes"], discord.ButtonStyle.secondary, self._listar),
        ]
        row1 = [
            (t["btn_remover_canal"], discord.ButtonStyle.danger, self._rm_canal),
            (t["btn_remover_mensagem"], discord.ButtonStyle.danger, self._rm_msg),
            (t["btn_reset_config"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["auto_resp_enabled"] = not settings.get("auto_resp_enabled", False)
        embed = build_auto_resp_embed(self.author, settings)
        view = AutoRespView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["auto_resp_activated"] if settings["auto_resp_enabled"] else t["auto_resp_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _cfg_canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(AutoRespChannelsSelect(self, t["auto_resp_canais_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["auto_resp_canais_placeholder"]), view=view, ephemeral=True)

    async def _add_msg(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = AutoRespAddModal(self, t)
        await interaction.response.send_modal(modal)

    async def _listar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed, _ = _build_auto_resp_list_embed(self.author, settings, 1)
        view = AutoRespListView(self.author, 1)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _rm_canal(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(AutoRespRemoveChSelect(self, t, interaction.guild))
        await interaction.response.send_message(embed=_notif_embed(t["auto_resp_remove_ch_placeholder"]), view=view, ephemeral=True)

    async def _rm_msg(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(AutoRespRemoveMsgSelect(self, t))
        await interaction.response.send_message(embed=_notif_embed(t["auto_resp_remove_msg_placeholder"]), view=view, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["auto_resp_enabled"] = False
        settings["auto_resp_channels"] = []
        settings["auto_resp_messages"] = []
        embed = build_auto_resp_embed(self.author, settings)
        view = AutoRespView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["auto_resp_reset_done"]), ephemeral=True)


