def build_limite_call_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["call_limit_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    roles = settings.get("call_limit_roles", [])
    guild = author.guild
    if roles and guild:
        mentions = []
        for rid in roles:
            r = guild.get_role(rid)
            mentions.append(r.mention if r else f"<@&{rid}>")
        cargos_value = " ".join(mentions)
    else:
        cargos_value = f"`{t['not_defined']}`"

    embed.add_field(
        name=f"<:mov_call:1518271964077232150>  {t['ticket_config_info_section']}",
        value=(
            f"**{t['call_limit_cargos']}:** {cargos_value}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['advertencia_observations']}",
        value=t["call_limit_obs"],
        inline=False,
    )
    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class LimiteCallRoleSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "LimiteCallView", placeholder: str):
        super().__init__(placeholder=placeholder, min_values=0, max_values=25)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["call_limit_roles"] = [r.id for r in self.values]
