def build_dono_call_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["dono_call_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    chans = settings.get("dono_call_channels", [])
    canais_value = f"`{len(chans)} calls`" if chans else "`0 calls`"

    allowed_role_ids = settings.get("dono_call_allowed_roles", [])
    if allowed_role_ids and author.guild:
        roles_mention = " ".join(
            r.mention for rid in allowed_role_ids
            if (r := author.guild.get_role(rid))
        ) or "`—`"
    else:
        roles_mention = f"`{t.get('not_defined_short', 'Todos')}`"

    embed.add_field(
        name=f"<a:alerta:1518271939460857968>  {t['ticket_config_info_section']}",
        value=(
            f"<:mov_call:1518271964077232150> **{t['dono_call_canais_voz']}:** {canais_value}\n"
            f"<:comunidade_:1518272016971595807> **{t['dono_call_cargos_label']}:** {roles_mention}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:servidor_:1518271981189992638>  {t['advertencia_observations']}",
        value=t["dono_call_obs"],
        inline=False,
    )
    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class DonoCallRoleSelect(discord.ui.RoleSelect):
    """Seletor de cargos com acesso ao painel Dono de Call (toggle)."""

    def __init__(self, parent_view: "DonoCallView", placeholder: str):
        super().__init__(placeholder=placeholder, min_values=1, max_values=25)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        lst = settings.setdefault("dono_call_allowed_roles", [])
        for r in self.values:
            if r.id in lst:
                lst.remove(r.id)
            else:
                lst.append(r.id)
        save_settings_to_disk()
        embed = build_dono_call_embed(self.parent_view.author, settings)
        view = DonoCallView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        icon_url = bot.user.display_avatar.url if bot.user else None
        _fb = discord.Embed(
            description="<a:online:1518271945550856295> **Cargos do Dono de Call atualizados!**",
            color=0x57F287,
        )
        _fb.set_author(name=bot.user.display_name if bot.user else "NATA®", icon_url=icon_url)
        _fb.set_footer(text=_footer_name(interaction.guild, settings), icon_url=icon_url)
        _fb.timestamp = datetime.now()
        await interaction.followup.send(embed=_fb, ephemeral=True)


class DonoCallCategoryView(discord.ui.View):
    """Passo 1 — seleciona uma categoria para configurar seus canais de voz."""

    def __init__(self, author: discord.Member, guild: discord.Guild, parent_dono_view: "DonoCallView"):
        super().__init__(timeout=120)
        self.author = author
        self.guild = guild
        self.parent_dono_view = parent_dono_view
        self._build()

    def _build(self):
        self.clear_items()
        options: list[discord.SelectOption] = []
        for cat in self.guild.categories:
            voice_chs = [ch for ch in cat.channels if isinstance(ch, discord.VoiceChannel)]
            if voice_chs:
                n = len(voice_chs)
                options.append(discord.SelectOption(
                    label=cat.name[:100],
                    value=str(cat.id),
                    description=f"{n} canal{'is' if n != 1 else ''} de voz",
                    emoji="📁",
                ))
        uncategorized = [ch for ch in self.guild.channels if isinstance(ch, discord.VoiceChannel) and ch.category is None]
        if uncategorized:
            n = len(uncategorized)
            options.append(discord.SelectOption(
                label="Sem Categoria",
                value="__none_cat__",
                description=f"{n} canal{'is' if n != 1 else ''} de voz",
                emoji="📂",
            ))
        if options:
            cat_select = discord.ui.Select(
                placeholder="Selecione uma categoria...",
                min_values=1,
                max_values=1,
                options=options[:25],
                row=0,
            )
            cat_select.callback = self._on_category
            self.add_item(cat_select)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            await interaction.response.send_message("Apenas o autor pode interagir.", ephemeral=True)
            return False
        return True

    async def _on_category(self, interaction: discord.Interaction):
        selected_val = interaction.data["values"][0]
        settings = get_settings(interaction.guild.id)
        if selected_val == "__none_cat__":
            voice_channels = sorted(
                [ch for ch in interaction.guild.channels if isinstance(ch, discord.VoiceChannel) and ch.category is None],
                key=lambda c: c.position,
            )
            cat_name = "Sem Categoria"
        else:
            cat = interaction.guild.get_channel(int(selected_val))
            if not cat:
                await interaction.response.send_message("❌ Categoria não encontrada.", ephemeral=True)
                return
            voice_channels = sorted(
                [ch for ch in cat.channels if isinstance(ch, discord.VoiceChannel)],
                key=lambda c: c.position,
            )
            cat_name = cat.name

        if not voice_channels:
            await interaction.response.send_message("❌ Nenhum canal de voz nessa categoria.", ephemeral=True)
            return

        current_all: set[int] = set(settings.get("dono_call_channels", []))
        cat_ids = {vc.id for vc in voice_channels}
        # Toggle: se todos já estão, remove; senão adiciona todos
        if cat_ids.issubset(current_all):
            current_all -= cat_ids
            action = "removidos"
            color = 0xE74C3C
            emoji = "<:8118_xmark:1518272072839729182>"
        else:
            current_all |= cat_ids
            action = "adicionados"
            color = 0x2ECC71
            emoji = "<a:verificadoverde:1518272098290892810>"
        settings["dono_call_channels"] = list(current_all)
        save_settings_to_disk()

        embed = build_dono_call_embed(self.author, settings)
        view = DonoCallView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

        # Limpa imediatamente overrides stale nos canais adicionados
        if action == "adicionados":
            for _vc in voice_channels:
                asyncio.create_task(_clean_stale_call_overwrites(_vc))

        _ch_mentions = " ".join(vc.mention for vc in voice_channels) or "`—`"
        _upd_embed = discord.Embed(
            description=(
                f"{emoji} **Canais da categoria `{cat_name}` {action}!**\n"
                f"<:mov_call:1518271964077232150> {_ch_mentions}"
            ),
            color=color,
        )
        await interaction.followup.send(embed=_upd_embed, ephemeral=True)


class DonoCallCategoryChannelsView(discord.ui.View):
    """Passo 2 — seleciona canais de voz individuais dentro de uma categoria."""

    def __init__(
        self,
        author: discord.Member,
        guild: discord.Guild,
        voice_channels: list,
        currently_selected: set,
        cat_name: str,
        parent_dono_view: "DonoCallView",
    ):
        super().__init__(timeout=120)
        self.author = author
        self.guild = guild
        self.voice_channels = voice_channels
        self.currently_selected = set(currently_selected)
        self.cat_name = cat_name
        self.parent_dono_view = parent_dono_view
        self._build()

    def _build(self):
        self.clear_items()
        options: list[discord.SelectOption] = []
        for ch in self.voice_channels[:25]:
            options.append(discord.SelectOption(
                label=ch.name[:100],
                value=str(ch.id),
                emoji="🔊",
                default=ch.id in self.currently_selected,
            ))
        if options:
            ch_select = discord.ui.Select(
                placeholder=f"Canais em {self.cat_name[:50]}...",
                min_values=0,
                max_values=len(options),
                options=options,
                row=0,
            )
            ch_select.callback = self._on_channels
            self.add_item(ch_select)
        btn_back = discord.ui.Button(
            label="Voltar",
            emoji=discord.PartialEmoji.from_str(EMOJI_BACK),
            style=discord.ButtonStyle.primary,
            row=1,
        )
        btn_back.callback = self._back
        self.add_item(btn_back)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            await interaction.response.send_message("Apenas o autor pode interagir.", ephemeral=True)
            return False
        return True

    async def _on_channels(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        current_all: set[int] = set(settings.get("dono_call_channels", []))
        cat_ids = {ch.id for ch in self.voice_channels}
        current_all -= cat_ids
        for val in interaction.data["values"]:
            current_all.add(int(val))
        settings["dono_call_channels"] = list(current_all)
        save_settings_to_disk()
        # Volta ao seletor de categorias para o usuário poder configurar mais
        view = DonoCallCategoryView(self.author, interaction.guild, self.parent_dono_view)
        color = settings.get("embed_color", 0x2B2D31)
        embed = discord.Embed(
            description="<:mov_call:1518271964077232150> Selecione uma categoria para configurar os canais:",
            color=color,
        )
        await interaction.response.edit_message(embed=embed, view=view)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        view = DonoCallCategoryView(self.author, interaction.guild, self.parent_dono_view)
        color = settings.get("embed_color", 0x2B2D31)
        embed = discord.Embed(
            description="<:mov_call:1518271964077232150> Selecione uma categoria para configurar os canais:",
            color=color,
        )
        await interaction.response.edit_message(embed=embed, view=view)


