class DonoCallStatusSelect(discord.ui.Select):
    def __init__(self, channel_id: int, t: dict):
        self.channel_id = channel_id
        self._t = t
        options = [
            discord.SelectOption(label=t["dono_call_status_abrir"], value="abrir"),
            discord.SelectOption(label=t["dono_call_status_fechar"], value="fechar"),
        ]
        super().__init__(placeholder=t["dono_call_btn_status"], options=options, min_values=1, max_values=1)

    async def callback(self, interaction: discord.Interaction):
        t = self._t
        ch = interaction.guild.get_channel(self.channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.response.send_message(embed=_notif_embed(t["dono_call_status_error"]), ephemeral=True)
            return
        everyone = interaction.guild.default_role
        try:
            overw = ch.overwrites_for(everyone)
            if self.values[0] == "fechar":
                overw.connect = False
            else:
                overw.connect = None
            await ch.set_permissions(everyone, overwrite=overw, reason="Dono de Call — alterar status")
        except (discord.Forbidden, discord.HTTPException):
            await interaction.response.send_message(embed=_notif_embed(t["dono_call_status_error"]), ephemeral=True)
            return
        settings = get_settings(interaction.guild.id)
        owner_id = _call_owners.get(self.channel_id)
        owner = interaction.guild.get_member(owner_id) if owner_id else interaction.user
        embed = _build_call_panel_embed(ch, owner or interaction.user, settings)
        msg_id = _call_panels.get(self.channel_id)
        if msg_id:
            try:
                msg = await ch.fetch_message(msg_id)
                view = DonoCallPanelView(self.channel_id)
                await msg.edit(embed=embed, view=view)
            except Exception:
                pass
        await interaction.response.send_message(embed=_notif_embed(t["dono_call_status_ok"]), ephemeral=True)


class _DonoCallExpulsarSelect(discord.ui.Select):
    def __init__(self, channel_id: int, members: list, t: dict):
        self._channel_id = channel_id
        self._t = t
        options = [
            discord.SelectOption(
                label=m.display_name[:25],
                value=str(m.id),
                description=f"@{m.name}"[:50],
                emoji=discord.PartialEmoji(name="bot", id=1518326704735649983),
            )
            for m in members[:25]
        ]
        super().__init__(
            placeholder=t["dono_call_expulsar_placeholder"],
            options=options,
            min_values=1,
            max_values=1,
        )

    async def callback(self, interaction: discord.Interaction):
        t = self._t
        ch = interaction.guild.get_channel(self._channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.response.send_message(embed=_notif_embed(t["dono_call_expulsar_error"]), ephemeral=True)
            return
        member_id = int(self.values[0])
        member = interaction.guild.get_member(member_id)
        if not member or member not in ch.members:
            await interaction.response.send_message(embed=_notif_embed(t["dono_call_expulsar_not_in_call"]), ephemeral=True)
            return
        try:
            await member.move_to(None, reason="Dono de Call — expulso pelo dono")
        except (discord.Forbidden, discord.HTTPException):
            await interaction.response.send_message(embed=_notif_embed(t["dono_call_expulsar_error"]), ephemeral=True)
            return
        await interaction.response.send_message(
            t["dono_call_expulsar_ok"].format(name=member.display_name),
            ephemeral=True,
        )


class _DonoCallNomeModal(discord.ui.Modal, title="Alterar Nome da Call"):
    novo_nome = discord.ui.TextInput(
        label="Novo nome",
        placeholder="Digite o nome...",
        min_length=1,
        max_length=100,
    )

    def __init__(self, channel_id: int):
        super().__init__()
        self.channel_id = channel_id

    async def on_submit(self, interaction: discord.Interaction):
        ch = interaction.guild.get_channel(self.channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.response.send_message(
                embed=discord.Embed(description="<a:alerta:1518271939460857968> **Canal não encontrado.**", color=0xE74C3C),
                ephemeral=True,
            )
            return
        novo_nome = self.novo_nome.value.strip()[:100]
        try:
            await ch.edit(name=novo_nome, reason="Dono de Call — alterar nome")
        except Exception:
            await interaction.response.send_message(
                embed=discord.Embed(description="<a:alerta:1518271939460857968> **Não foi possível renomear o canal.**", color=0xE74C3C),
                ephemeral=True,
            )
            return
        settings = get_settings(interaction.guild.id)
        owner_id = _call_owners.get(self.channel_id)
        owner = interaction.guild.get_member(owner_id) if owner_id else interaction.user
        panel_embed = _build_call_panel_embed(ch, owner or interaction.user, settings)
        msg_id = _call_panels.get(self.channel_id)
        if msg_id:
            try:
                panel_msg = await ch.fetch_message(msg_id)
                await panel_msg.edit(embed=panel_embed, view=DonoCallPanelView(self.channel_id))
            except Exception:
                pass
        await interaction.response.send_message(
            embed=discord.Embed(
                description=f"<a:verificadoverde:1518272098290892810> **Nome alterado para** `{novo_nome}`",
                color=0x2ECC71,
            ),
            ephemeral=True,
        )


class _DonoCallLimiteModal(discord.ui.Modal, title="Alterar Limite da Call"):
    limite = discord.ui.TextInput(
        label="Limite (0 = sem limite)",
        placeholder="Ex: 5",
        min_length=1,
        max_length=2,
    )

    def __init__(self, channel_id: int):
        super().__init__()
        self.channel_id = channel_id

    async def on_submit(self, interaction: discord.Interaction):
        ch = interaction.guild.get_channel(self.channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.response.send_message(
                embed=discord.Embed(description="<a:alerta:1518271939460857968> **Canal não encontrado.**", color=0xE74C3C),
                ephemeral=True,
            )
            return
        raw = self.limite.value.strip()
        try:
            n = int(raw)
            if not (0 <= n <= 99):
                raise ValueError
        except ValueError:
            await interaction.response.send_message(
                embed=discord.Embed(description="<a:alerta:1518271939460857968> **Valor inválido.** Digite um número entre 0 e 99.", color=0xE74C3C),
                ephemeral=True,
            )
            return
        try:
            await ch.edit(user_limit=n, reason="Dono de Call — alterar limite")
        except Exception:
            await interaction.response.send_message(
                embed=discord.Embed(description="<a:alerta:1518271939460857968> **Não foi possível alterar o limite.**", color=0xE74C3C),
                ephemeral=True,
            )
            return
        settings = get_settings(interaction.guild.id)
        owner_id = _call_owners.get(self.channel_id)
        owner = interaction.guild.get_member(owner_id) if owner_id else interaction.user
        panel_embed = _build_call_panel_embed(ch, owner or interaction.user, settings)
        msg_id = _call_panels.get(self.channel_id)
        if msg_id:
            try:
                panel_msg = await ch.fetch_message(msg_id)
                await panel_msg.edit(embed=panel_embed, view=DonoCallPanelView(self.channel_id))
            except Exception:
                pass
        limite_str = f"**{n}** usuários" if n else "**∞** livre"
        await interaction.response.send_message(
            embed=discord.Embed(
                description=f"<a:verificadoverde:1518272098290892810> **Limite alterado para** {limite_str}",
                color=0x2ECC71,
            ),
            ephemeral=True,
        )


class DonoCallPanelView(discord.ui.View):
    """View enviada no canal de voz com os controles do dono."""

    def __init__(self, channel_id: int, force_locked: bool | None = None):
        super().__init__(timeout=None)
        self.channel_id = channel_id
        self._force_locked = force_locked
        self._build()

    def _build(self):
        self.clear_items()
        ch = bot.get_channel(self.channel_id)
        is_locked = False
        if self._force_locked is not None:
            is_locked = self._force_locked
        elif isinstance(ch, discord.VoiceChannel):
            everyone = ch.guild.default_role
            overw = ch.overwrites_for(everyone)
            is_locked = overw.connect is False

        cid = self.channel_id

        btn_nome = discord.ui.Button(
            label="Alterar Nome",
            style=discord.ButtonStyle.secondary,
            custom_id=f"dc_nome_{cid}",
            row=0,
        )
        btn_nome.callback = self._btn_nome
        self.add_item(btn_nome)

        btn_limite = discord.ui.Button(
            label="Alterar Limite",
            style=discord.ButtonStyle.secondary,
            custom_id=f"dc_limite_{cid}",
            row=0,
        )
        btn_limite.callback = self._btn_limite
        self.add_item(btn_limite)

        btn_status = discord.ui.Button(
            label="Abrir Call" if is_locked else "Trancar Call",
            style=discord.ButtonStyle.secondary,
            custom_id=f"dc_status_{cid}",
            row=1,
        )
        btn_status.callback = self._btn_status
        self.add_item(btn_status)

        btn_expulsar = discord.ui.Button(
            label="Expulsar da Call",
            style=discord.ButtonStyle.secondary,
            custom_id=f"dc_expulsar_{cid}",
            row=1,
        )
        btn_expulsar.callback = self._btn_expulsar
        self.add_item(btn_expulsar)

        is_auto_kick = cid in _call_auto_kick
        btn_privado = discord.ui.Button(
            label="Desativar Privado" if is_auto_kick else "Modo Privado",
            style=discord.ButtonStyle.danger if is_auto_kick else discord.ButtonStyle.secondary,
            custom_id=f"dc_privado_{cid}",
            row=2,
        )
        btn_privado.callback = self._btn_privado
        self.add_item(btn_privado)

        btn_permitir = discord.ui.Button(
            label="Permitir Entrada",
            style=discord.ButtonStyle.secondary,
            custom_id=f"dc_permitir_{cid}",
            row=2,
        )
        btn_permitir.callback = self._btn_permitir
        self.add_item(btn_permitir)

        btn_registro = discord.ui.Button(
            label="Registro de Call",
            style=discord.ButtonStyle.secondary,
            custom_id=f"dc_registro_{cid}",
            emoji="📋",
            row=3,
        )
        btn_registro.callback = self._btn_registro
        self.add_item(btn_registro)


    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        owner_id = _call_owners.get(self.channel_id)
        if not owner_id and interaction.guild:
            _gs = get_settings(interaction.guild.id)
            _raw = _gs.get("active_call_owners", {}).get(str(self.channel_id))
            if _raw:
                owner_id = int(_raw)
                _call_owners[self.channel_id] = owner_id
        if interaction.user.id != owner_id:
            _err_embed = discord.Embed(
                description="<a:alerta:1518271939460857968> **Apenas o dono da call pode usar isso.**",
                color=0xE74C3C,
            )
            await interaction.response.send_message(embed=_err_embed, ephemeral=True)
            return False
        return True

    async def _btn_nome(self, interaction: discord.Interaction):
        await interaction.response.send_modal(_DonoCallNomeModal(self.channel_id))

    async def _btn_limite(self, interaction: discord.Interaction):
        await interaction.response.send_modal(_DonoCallLimiteModal(self.channel_id))

    async def _btn_status(self, interaction: discord.Interaction):
        await interaction.response.defer(ephemeral=True)
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        ch = interaction.guild.get_channel(self.channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.followup.send(embed=_notif_embed(t["dono_call_status_error"]), ephemeral=True)
            return
        everyone = interaction.guild.default_role
        overw = ch.overwrites_for(everyone)
        is_locked = overw.connect is False
        new_is_locked = not is_locked

        owner_id = _call_owners.get(self.channel_id)
        if not owner_id:
            _gs = get_settings(interaction.guild.id)
            _raw = _gs.get("active_call_owners", {}).get(str(self.channel_id))
            if _raw:
                owner_id = int(_raw)
                _call_owners[self.channel_id] = owner_id
        owner = interaction.guild.get_member(owner_id) if owner_id else interaction.user

        try:
            if new_is_locked:
                # Salva o connect original do @everyone ANTES de trancar
                # para restaurar exatamente quando abrir (evita herdar deny da categoria)
                _call_pre_lock_connect[self.channel_id] = ch.overwrites_for(everyone).connect
                # Constrói TODOS os overwrites de uma vez e aplica em UMA única chamada de API.
                # Múltiplas chamadas sequenciais causavam race condition onde o @everyone connect=False
                # chegava ao Discord antes dos overrides individuais, desconectando membros presentes.
                new_overwrites = {t: discord.PermissionOverwrite.from_pair(*ow.pair())
                                  for t, ow in ch.overwrites.items()}
                ow_ev = new_overwrites.setdefault(everyone, discord.PermissionOverwrite())
                ow_ev.connect = False
                ow_ev.send_messages = True
                for m in ch.members:
                    if not m.bot:
                        ow_m = new_overwrites.setdefault(m, discord.PermissionOverwrite())
                        ow_m.connect = True
                        ow_m.send_messages = True
                await ch.edit(overwrites=new_overwrites, reason="Dono de Call — trancar")
                _call_locked.add(self.channel_id)
            else:
                # Restaura connect ao valor pré-lock (None = herda da categoria; evita deixar override stale)
                _pre_connect = _call_pre_lock_connect.pop(self.channel_id, None)
                _call_locked.discard(self.channel_id)
                _ow_open = ch.overwrites_for(everyone)
                _ow_open.connect = _pre_connect
                _ow_open.send_messages = None
                if _ow_open.is_empty():
                    await ch.set_permissions(everyone, overwrite=None, reason="Dono de Call — abrir")
                else:
                    await ch.set_permissions(everyone, overwrite=_ow_open, reason="Dono de Call — abrir")
        except (discord.Forbidden, discord.HTTPException) as _perm_err:
            print(f"[btn_status] erro de permissão ch={self.channel_id}: {_perm_err}", flush=True)
            await interaction.followup.send(embed=_notif_embed(t["dono_call_status_error"]), ephemeral=True)
            return

        embed = _build_call_panel_embed(ch, owner or interaction.user, settings, force_locked=new_is_locked)
        new_view = DonoCallPanelView(self.channel_id, force_locked=new_is_locked)
        try:
            msg_id = _call_panels.get(self.channel_id)
            if not msg_id:
                _gs = get_settings(interaction.guild.id)
                _raw = _gs.get("active_call_panels", {}).get(str(self.channel_id))
                if _raw:
                    msg_id = _raw
                    _call_panels[self.channel_id] = msg_id
            if msg_id:
                msg = await ch.fetch_message(msg_id)
                await msg.edit(embed=embed, view=new_view)
        except Exception as _e:
            print(f"[btn_status] falha ao editar painel ch={self.channel_id}: {_e}", flush=True)
        if new_is_locked:
            _fb_embed = discord.Embed(
                title="<a:alerta:1518271939460857968>  Call Trancada",
                description=(
                    f"**Canal** › {ch.mention}\n\n"
                    f"O canal foi **trancado** com sucesso.\n"
                    f"Membros presentes **permanecem** na call.\n"
                    f"Novas entradas estão **bloqueadas**."
                ),
                color=0xE74C3C,
            )
        else:
            _fb_embed = discord.Embed(
                title="<a:online:1518271945550856295>  Call Aberta",
                description=(
                    f"**Canal** › {ch.mention}\n\n"
                    f"O canal está **aberto** para todos.\n"
                    f"Qualquer membro pode entrar livremente."
                ),
                color=0x2ECC71,
            )
        await interaction.followup.send(embed=_fb_embed, ephemeral=True)

