def build_call_temp_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["call_temp_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    chans = settings.get("call_temporaria_channels", [])
    canais_value = f"`{len(chans)} calls`" if chans else "`0 calls`"

    embed.add_field(
        name=f"<:mov_call:1518271964077232150>  {t['ticket_config_info_section']}",
        value=f"**{t['call_temp_canais_voz']}:** {canais_value}",
        inline=False,
    )
    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['advertencia_observations']}",
        value=t["call_temp_obs"],
        inline=False,
    )
    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class CallTempChannelSelect(GuildChannelSelect):
    def __init__(self, parent_view: "CallTempView", placeholder: str):
        super().__init__(
            placeholder=placeholder, min_values=1, max_values=25,
            channel_types=[discord.ChannelType.voice],
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["call_temporaria_channels"] = [c.id for c in self.values]
        save_settings_to_disk()
        embed = build_call_temp_embed(self.parent_view.author, settings)
        view = CallTempView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["call_temp_channels_updated"]), ephemeral=True)


class CallTempView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        btn_back = discord.ui.Button(label=t["back"], style=discord.ButtonStyle.primary, row=0)
        btn_back.callback = self._back
        self.add_item(btn_back)

        btn_canais = discord.ui.Button(
            label=t["call_temp_canais_voz"],
            style=discord.ButtonStyle.secondary,
            emoji="<:mov_call:1518271964077232150>",
            row=0,
        )
        btn_canais.callback = self._configurar_canais
        self.add_item(btn_canais)

        btn_reset = discord.ui.Button(
            label=t["btn_resetar_tudo"],
            style=discord.ButtonStyle.danger,
            emoji=_button_emoji(discord.ButtonStyle.danger),
            row=0,
        )
        btn_reset.callback = self._reset
        self.add_item(btn_reset)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _configurar_canais(self, interaction: discord.Interaction):
        try:
            settings = get_settings(interaction.guild.id)
            t = TRANSLATIONS[settings["language"]]
            view = _SingleSelectView(CallTempChannelSelect(self, t["call_temp_canais_voz"]))
            await interaction.response.send_message(
                embed=discord.Embed(description="Selecione os canais de voz a monitorar:", color=get_settings(interaction.guild.id).get("embed_color", 0x2B2D31)),
                view=view,
                ephemeral=True,
            )
        except Exception as e:
            msg = f"❌ Erro ao abrir seletor: `{type(e).__name__}: {str(e)[:150]}`"
            if not interaction.response.is_done():
                await interaction.response.send_message(embed=_notif_embed(msg), ephemeral=True)
            else:
                await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["call_temporaria_channels"] = []
        save_settings_to_disk()
        embed = build_call_temp_embed(self.author, settings)
        view = CallTempView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["call_temp_reset_done"]), ephemeral=True)


# ── Modais do painel de usuário ───────────────────────────────────────────────

class CallTempNomeModal(discord.ui.Modal):
    def __init__(self, channel_id: int, t: dict):
        super().__init__(title=t["call_temp_nome_title"])
        self.channel_id = channel_id
        self._t = t
        self.nome = discord.ui.TextInput(
            label=t["call_temp_nome_label"],
            placeholder=t["call_temp_nome_placeholder"],
            max_length=100,
        )
        self.add_item(self.nome)

    async def on_submit(self, interaction: discord.Interaction):
        t = self._t
        ch = interaction.guild.get_channel(self.channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_nome_error"]), ephemeral=True)
            return
        try:
            await ch.edit(name=self.nome.value.strip())
        except (discord.Forbidden, discord.HTTPException):
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_nome_error"]), ephemeral=True)
            return
        settings = get_settings(interaction.guild.id)
        owner_id = _call_temp_owners.get(ch.id)
        owner = interaction.guild.get_member(owner_id) if owner_id else interaction.user
        await _refresh_call_temp_panel(ch, owner or interaction.user, settings)
        await interaction.response.send_message(embed=_notif_embed(t["call_temp_nome_ok"]), ephemeral=True)


class CallTempLimiteModal(discord.ui.Modal):
    def __init__(self, channel_id: int, t: dict):
        super().__init__(title=t["call_temp_limite_title"])
        self.channel_id = channel_id
        self._t = t
        self.limite = discord.ui.TextInput(
            label=t["call_temp_limite_label"],
            placeholder=t["call_temp_limite_placeholder"],
            max_length=2,
        )
        self.add_item(self.limite)

    async def on_submit(self, interaction: discord.Interaction):
        t = self._t
        try:
            n = int(self.limite.value.strip())
            if not (0 <= n <= 99):
                raise ValueError
        except ValueError:
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_limite_invalid"]), ephemeral=True)
            return
        ch = interaction.guild.get_channel(self.channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_limite_error"]), ephemeral=True)
            return
        try:
            await ch.edit(user_limit=n)
        except (discord.Forbidden, discord.HTTPException):
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_limite_error"]), ephemeral=True)
            return
        settings = get_settings(interaction.guild.id)
        owner_id = _call_temp_owners.get(ch.id)
        owner = interaction.guild.get_member(owner_id) if owner_id else interaction.user
        await _refresh_call_temp_panel(ch, owner or interaction.user, settings)
        await interaction.response.send_message(embed=_notif_embed(t["call_temp_limite_ok"]), ephemeral=True)


# ── Painel V2 enviado no canal de voz ────────────────────────────────────────

class CallTempStatusSelect(discord.ui.Select):
    def __init__(self, channel_id: int, t: dict):
        self.channel_id = channel_id
        self._t = t
        options = [
            discord.SelectOption(label=t["call_temp_status_abrir"], value="abrir"),
            discord.SelectOption(label=t["call_temp_status_fechar"], value="fechar"),
        ]
        super().__init__(
            placeholder=t["call_temp_opt_status"],
            options=options,
            min_values=1,
            max_values=1,
        )

    async def callback(self, interaction: discord.Interaction):
        t = self._t
        ch = interaction.guild.get_channel(self.channel_id)
        if not isinstance(ch, discord.VoiceChannel):
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_status_error"]), ephemeral=True)
            return
        everyone = interaction.guild.default_role
        try:
            overw = ch.overwrites_for(everyone)
            overw.connect = False if self.values[0] == "fechar" else None
            await ch.set_permissions(everyone, overwrite=overw, reason="Call Temporária — alterar status")
        except (discord.Forbidden, discord.HTTPException):
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_status_error"]), ephemeral=True)
            return
        settings = get_settings(interaction.guild.id)
        owner_id = _call_temp_owners.get(ch.id)
        owner = interaction.guild.get_member(owner_id) if owner_id else interaction.user
        await _refresh_call_temp_panel(ch, owner or interaction.user, settings)
        await interaction.response.send_message(embed=_notif_embed(t["call_temp_status_ok"]), ephemeral=True)


class CallTempPanelView(discord.ui.LayoutView):
    """Painel V2 enviado no chat do canal de voz."""

    def __init__(self, channel_id: int, owner: discord.Member, settings: dict):
        super().__init__(timeout=None)
        self.channel_id = channel_id
        self._owner_id = owner.id
        self._build(channel_id, owner, settings)

    def _build(self, channel_id: int, owner: discord.Member, settings: dict):
        t = TRANSLATIONS[settings["language"]]
        color = settings.get("embed_color", 0x5865F2)

        ch = owner.guild.get_channel(channel_id) if owner.guild else None
        ch_name = ch.name if ch else "call"
        everyone = owner.guild.default_role if owner.guild else None
        if ch and everyone:
            overw = ch.overwrites_for(everyone)
            is_locked = overw.connect is False
        else:
            is_locked = False
        status_icon = "🔴" if is_locked else "🟢"
        limite = ch.user_limit if ch else 0
        limite_str = f"{limite}" if limite else "∞"

        container = discord.ui.Container(accent_colour=color)

        txt = discord.ui.TextDisplay(
            f"### <:mov_call:1518271964077232150> {ch_name}\n"
            f"{owner.mention} {t['call_temp_panel_header']}\n"
            f"-# {t['call_temp_panel_subtext']}\n\n"
            f"**Status:** {status_icon}  **Limite:** `{limite_str}`"
        )
        thumb = discord.ui.Thumbnail(owner.display_avatar.url)
        section = discord.ui.Section(txt, accessory=thumb)
        container.add_item(section)
        container.add_item(discord.ui.Separator())

        sel_row = discord.ui.ActionRow()
        sel = discord.ui.Select(
            placeholder=t["call_temp_select_placeholder"],
            options=[
                discord.SelectOption(
                    label=t["call_temp_opt_nome"],
                    value="nome",
                    description=t["call_temp_opt_nome_desc"],
                    emoji="✏️",
                ),
                discord.SelectOption(
                    label=t["call_temp_opt_limite"],
                    value="limite",
                    description=t["call_temp_opt_limite_desc"],
                    emoji="👥",
                ),
                discord.SelectOption(
                    label=t["call_temp_opt_status"],
                    value="status",
                    description=t["call_temp_opt_status_desc"],
                    emoji="🔒",
                ),
            ],
        )
        sel.callback = self._on_select
        sel_row.add_item(sel)
        container.add_item(sel_row)

        self.add_item(container)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        owner_id = _call_temp_owners.get(self.channel_id)
        if interaction.user.id != owner_id:
            settings = get_settings(interaction.guild.id) if interaction.guild else {}
            t = TRANSLATIONS.get(settings.get("language", "pt-br"), TRANSLATIONS["pt-br"])
            await interaction.response.send_message(embed=_notif_embed(t["call_temp_only_owner"]), ephemeral=True)
            return False
        return True

    async def _on_select(self, interaction: discord.Interaction):
        val = interaction.data["values"][0]
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if val == "nome":
            await interaction.response.send_modal(CallTempNomeModal(self.channel_id, t))
        elif val == "limite":
            await interaction.response.send_modal(CallTempLimiteModal(self.channel_id, t))
        elif val == "status":
            view = _SingleSelectView(CallTempStatusSelect(self.channel_id, t))
            await interaction.response.send_message(
                t["call_temp_status_ask"], view=view, ephemeral=True
            )


# ── Funções auxiliares de painel Call Temporária ──────────────────────────────

async def _send_call_temp_panel(ch: discord.VoiceChannel, owner: discord.Member):
    try:
        settings = get_settings(ch.guild.id)
        view = CallTempPanelView(ch.id, owner, settings)
        msg = await ch.send(view=view)
        _call_temp_panels[ch.id] = msg.id
    except Exception as e:
        print(f"[call_temp] erro ao enviar painel em #{ch.name} ({ch.id}): {type(e).__name__}: {e}")


async def _delete_call_temp_panel(ch: discord.VoiceChannel):
    msg_id = _call_temp_panels.get(ch.id)
    if msg_id:
        try:
            msg = await ch.fetch_message(msg_id)
            await msg.delete()
        except Exception:
            pass


async def _refresh_call_temp_panel(ch: discord.VoiceChannel, owner: discord.Member, settings: dict):
    """Edita a mensagem do painel para refletir mudanças no canal."""
    msg_id = _call_temp_panels.get(ch.id)
    if not msg_id:
        return
    try:
        msg = await ch.fetch_message(msg_id)
        view = CallTempPanelView(ch.id, owner, settings)
        await msg.edit(view=view)
    except Exception:
        pass


async def _update_call_temp_panel(ch: discord.VoiceChannel, new_owner: discord.Member):
    settings = get_settings(ch.guild.id)
    await _refresh_call_temp_panel(ch, new_owner, settings)


