def build_bate_ponto_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["bp_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    guild = author.guild
    nd = f"`{t['not_defined']}`"
    cargos_ponto = settings.get("bate_ponto_cargos", [])
    cargos_acesso = settings.get("bate_ponto_cargos_acesso", [])
    canal_id = settings.get("bate_ponto_canal")
    tempo = settings.get("bate_ponto_tempo_pausa", 15)
    usar_topico = settings.get("bate_ponto_usar_topico", False)

    if canal_id and guild:
        ch = guild.get_channel(canal_id)
        canal_value = ch.mention if ch else f"<#{canal_id}>"
    else:
        canal_value = nd

    cargos_acesso_value = _format_roles_list(guild, cargos_acesso) or nd

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"**{t['bp_cargos_ponto']}:** `{len(cargos_ponto)}`\n"
            f"**{t['bp_cargos_acesso']}:** {cargos_acesso_value}\n"
            f"**{t['bp_canal_label']}:** {canal_value}\n"
            f"**{t['bp_tempo_pausa_label']}:** `{tempo} {t['bp_tempo_pausa_unit']}`\n"
            f"**{t['bp_topico_ativo']}:** `{t['ticket_sim'] if usar_topico else t['ticket_nao']}`"
        ),
        inline=False,
    )

    def _log_value(key: str) -> str:
        cid = settings.get(key)
        if not cid or not guild:
            return nd
        ch = guild.get_channel(cid)
        return ch.mention if ch else f"<#{cid}>"

    embed.add_field(
        name=f"<:ferramentas_:1518271998613131274>  {t['bp_logs_section']}",
        value=(
            f"**{t['bp_log_inicio_fim']}:** {_log_value('bate_ponto_log_inicio_fim')}\n"
            f"**{t['bp_log_pausas']}:** {_log_value('bate_ponto_log_pausas')}\n"
            f"**{t['bp_log_cancelados']}:** {_log_value('bate_ponto_log_cancelados')}"
        ),
        inline=False,
    )

    embed.add_field(
        name=f"<:comunidade_:1518272016971595807>  {t['advertencia_observations']}",
        value=f"{t['bp_obs']}\n[{t['bp_obs_link_text']}]({t['bp_obs_link_url']})",
        inline=False,
    )

    embed.set_footer(text=_footer_name(author.guild, settings), icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class BatePontoCanaisModal(discord.ui.Modal):
    def __init__(self, parent_view: "BatePontoView", t: dict):
        super().__init__(title=t["bp_canais_modal_title"], timeout=300)
        self.parent_view = parent_view
        settings = get_settings(parent_view.author.guild.id)

        def _cur(key: str) -> str | None:
            v = settings.get(key)
            return str(v) if v else None

        self.main_inp = discord.ui.TextInput(
            label=t["bp_input_canal_main"], required=True, max_length=30,
            default=_cur("bate_ponto_canal"),
        )
        self.inicio_inp = discord.ui.TextInput(
            label=t["bp_input_log_inicio_fim"], required=False, max_length=30,
            default=_cur("bate_ponto_log_inicio_fim"),
        )
        self.pausas_inp = discord.ui.TextInput(
            label=t["bp_input_log_pausas"], required=False, max_length=30,
            default=_cur("bate_ponto_log_pausas"),
        )
        self.cancel_inp = discord.ui.TextInput(
            label=t["bp_input_log_cancelados"], required=False, max_length=30,
            default=_cur("bate_ponto_log_cancelados"),
        )
        self.add_item(self.main_inp)
        self.add_item(self.inicio_inp)
        self.add_item(self.pausas_inp)
        self.add_item(self.cancel_inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]

        def _parse(s: str) -> int | None:
            s = s.strip().strip("<#>").strip("# ")
            if not s:
                return None
            try:
                return int(s)
            except ValueError:
                return None

        main_id = _parse(self.main_inp.value)
        if main_id is None:
            await interaction.response.send_message(embed=_notif_embed(t["auto_msg_invalid_canal"]), ephemeral=True)
            return
        settings["bate_ponto_canal"] = main_id
        settings["bate_ponto_log_inicio_fim"] = _parse(self.inicio_inp.value)
        settings["bate_ponto_log_pausas"] = _parse(self.pausas_inp.value)
        settings["bate_ponto_log_cancelados"] = _parse(self.cancel_inp.value)

        embed = build_bate_ponto_embed(self.parent_view.author, settings)
        view = BatePontoView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["bp_canais_updated"]), ephemeral=True)


class BatePontoTempoModal(discord.ui.Modal):
    def __init__(self, parent_view: "BatePontoView", t: dict):
        super().__init__(title=t["bp_tempo_modal_title"], timeout=600)
        self.parent_view = parent_view
        settings = get_settings(parent_view.author.guild.id)
        self.inp = discord.ui.TextInput(
            label=t["bp_input_tempo_label"],
            placeholder=t["bp_input_tempo_placeholder"],
            required=True, max_length=4,
            default=str(settings.get("bate_ponto_tempo_pausa") or 15),
        )
        self.add_item(self.inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        try:
            mins = int(self.inp.value.strip())
            if mins < 1 or mins > 240:
                raise ValueError
        except ValueError:
            await interaction.response.send_message(embed=_notif_embed(t["bp_invalid_tempo"]), ephemeral=True)
            return
        settings["bate_ponto_tempo_pausa"] = mins
        embed = build_bate_ponto_embed(self.parent_view.author, settings)
        view = BatePontoView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(t["bp_tempo_set"].format(value=mins), ephemeral=True)


