def _build_bp_cargos_ponto_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    role_ids = settings.get("bate_ponto_cargos", [])
    if role_ids and author.guild:
        lines = []
        for rid in role_ids:
            r = author.guild.get_role(rid)
            lines.append(f"• {r.mention if r else f'<@&{rid}>'}")
        value = "\n".join(lines)
    else:
        value = f"`{t['bp_gp_nenhum']}`"
    embed.title = t["bp_gp_panel_title"]
    embed.description = value
    embed.set_footer(text=f"{t['bp_gp_footer']}", icon_url=icon_url)
    embed.timestamp = datetime.now()
    return embed


class BatePontoCargosPontoAddSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "BatePontoCargosPontoManageView", placeholder: str):
        super().__init__(placeholder=placeholder, min_values=1, max_values=25)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        target = settings.setdefault("bate_ponto_cargos", [])
        added = 0
        for r in self.values:
            if r.id not in target:
                target.append(r.id)
                added += 1
        new_embed = _build_bp_cargos_ponto_embed(self.parent_view.author, settings)
        new_view = BatePontoCargosPontoManageView(self.parent_view.author)
        await interaction.response.edit_message(embed=new_embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["bp_gp_role_added"]), ephemeral=True)


class BatePontoCargosPontoRemoveSelect(discord.ui.Select):
    def __init__(self, parent_view: "BatePontoCargosPontoManageView", t: dict, guild: discord.Guild):
        cargos = get_settings(parent_view.author.guild.id).get("bate_ponto_cargos", [])
        options = []
        for rid in cargos[:25]:
            role = guild.get_role(rid) if guild else None
            options.append(discord.SelectOption(
                label=(role.name if role else f"@{rid}")[:100],
                value=str(rid),
            ))
        if not options:
            options = [discord.SelectOption(label=t["bp_gp_remove_none"], value="__none__")]
        super().__init__(placeholder=t["bp_gp_remove_placeholder"],
                         min_values=1, max_values=1, options=options)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if self.values[0] == "__none__":
            await interaction.response.defer()
            return
        rid = int(self.values[0])
        cargos = settings.get("bate_ponto_cargos", [])
        if rid in cargos:
            cargos.remove(rid)
        new_embed = _build_bp_cargos_ponto_embed(self.parent_view.author, settings)
        new_view = BatePontoCargosPontoManageView(self.parent_view.author)
        await interaction.response.edit_message(embed=new_embed, view=new_view)
        await interaction.followup.send(embed=_notif_embed(t["bp_gp_role_removed"]), ephemeral=True)


class BatePontoCargosPontoManageView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=300)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        add_btn = discord.ui.Button(
            label=t["btn_adicionar_simples"], style=discord.ButtonStyle.success,
            emoji="<a:online:1518271945550856295>",
        )
        add_btn.callback = self._adicionar
        self.add_item(add_btn)

        rm_btn = discord.ui.Button(
            label=t["btn_remover_simples"], style=discord.ButtonStyle.danger,
            emoji="<a:alerta:1518271939460857968>",
        )
        rm_btn.callback = self._remover
        self.add_item(rm_btn)

    async def _adicionar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(BatePontoCargosPontoAddSelect(self, t["bp_gp_add_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["bp_gp_add_placeholder"]), view=view, ephemeral=True)

    async def _remover(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(BatePontoCargosPontoRemoveSelect(self, t, interaction.guild))
        await interaction.response.send_message(embed=_notif_embed(t["bp_gp_remove_placeholder"]), view=view, ephemeral=True)


class BatePontoView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (t["btn_definir_canais_bp"], discord.ButtonStyle.secondary, self._canais),
            (t["btn_listar_cargos_bp"], discord.ButtonStyle.secondary, self._listar),
            (t["btn_tempo_pausa_bp"], discord.ButtonStyle.secondary, self._tempo),
            (t["btn_configurar_embed_bp"], discord.ButtonStyle.primary, self._cfg_embed),
        ]
        row1 = [
            (t["btn_usar_topico_canal"], discord.ButtonStyle.secondary, self._toggle_topico),
            (t["btn_cargos_acesso_bp"], discord.ButtonStyle.secondary, self._cargos_acesso),
            (t["btn_gerenciar_pontos_bp"], discord.ButtonStyle.success, self._gerenciar_pontos),
            (t["btn_resetar_tudo"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            emoji = _button_emoji(style) if (style != discord.ButtonStyle.primary or label == t["back"]) else None
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=emoji)
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _canais(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = BatePontoCanaisModal(self, t)
        await interaction.response.send_modal(modal)

    async def _listar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        roles = settings.get("bate_ponto_cargos", [])
        if not roles:
            await interaction.response.send_message(embed=_notif_embed(t["bp_no_cargos"]), ephemeral=True)
            return
        lines = []
        for rid in roles:
            r = interaction.guild.get_role(rid) if interaction.guild else None
            lines.append(f"• {r.mention if r else f'<@&{rid}>'}")
        embed = discord.Embed(
            title=t["bp_listar_title"],
            description="\n".join(lines)[:4000],
            color=settings["embed_color"],
        )
        await interaction.response.send_message(embed=embed, ephemeral=True)

    async def _tempo(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        modal = BatePontoTempoModal(self, t)
        await interaction.response.send_modal(modal)

    async def _cfg_embed(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        draft = settings.setdefault("bate_ponto_embed", _empty_embed_draft())
        if not draft.get("buttons") and not isinstance(draft.get("buttons"), list):
            draft["buttons"] = []
        # Find a target channel for the embed builder (use bate_ponto_canal or current)
        target = None
        if interaction.guild and settings.get("bate_ponto_canal"):
            target = interaction.guild.get_channel(settings["bate_ponto_canal"])
        if not isinstance(target, discord.TextChannel):
            target = interaction.channel if isinstance(interaction.channel, discord.TextChannel) else None
        if target is None:
            await interaction.response.send_message("Canal não encontrado. Defina o Canal principal primeiro.", ephemeral=True)
            return
        view = EmbedBuilderView(self.author, target, draft=draft)
        await interaction.response.send_message(view.header_text(), view=view, ephemeral=True)

    async def _toggle_topico(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["bate_ponto_usar_topico"] = not settings.get("bate_ponto_usar_topico", False)
        embed = build_bate_ponto_embed(self.author, settings)
        view = BatePontoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(
            t["bp_topico_changed"].format(
                value=t["ticket_sim"] if settings["bate_ponto_usar_topico"] else t["ticket_nao"]
            ),
            ephemeral=True,
        )

    async def _cargos_acesso(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(BatePontoCargosAcessoSelect(self, t["bp_cargos_resp_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["bp_cargos_resp_placeholder"]), view=view, ephemeral=True)

    async def _gerenciar_pontos(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = _build_bp_cargos_ponto_embed(self.author, settings)
        view = BatePontoCargosPontoManageView(self.author)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["bate_ponto_cargos"] = []
        settings["bate_ponto_cargos_acesso"] = []
        settings["bate_ponto_canal"] = None
        settings["bate_ponto_tempo_pausa"] = 15
        settings["bate_ponto_usar_topico"] = False
        settings["bate_ponto_log_inicio_fim"] = None
        settings["bate_ponto_log_pausas"] = None
        settings["bate_ponto_log_cancelados"] = None
        settings["bate_ponto_embed"] = {
            "title": None, "description": None, "color": None,
            "thumbnail": None, "image": None,
        }
        embed = build_bate_ponto_embed(self.author, settings)
        view = BatePontoView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["bp_reset_done"]), ephemeral=True)


