def build_desmute_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    embed = discord.Embed(color=settings["embed_color"])
    icon_url = bot.user.display_avatar.url if bot.user else None
    embed.set_author(name=t["desmute_panel_title"], icon_url=icon_url)
    embed.set_thumbnail(url=icon_url)

    enabled = settings.get("desmute_enabled", False)
    status_value = (
        "<a:online:1518271945550856295> `(Ativado)`"
        if enabled else "<a:alerta:1518271939460857968> `(Desativado)`"
    )

    guild = author.guild
    nd = f"`{t['not_defined']}`"
    unknown = f"`{t['ticket_unknown_channel']}`"

    def _channel_value(cid: int | None) -> str:
        if not cid:
            return nd
        if not guild:
            return nd
        ch = guild.get_channel(cid)
        return ch.mention if ch else unknown

    canal_value = _channel_value(settings.get("desmute_channel"))
    log_value = _channel_value(settings.get("desmute_log_channel"))

    roles = settings.get("desmute_roles", [])
    cargos_value = _format_roles_list(guild, roles) or nd

    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['ticket_config_info_section']}",
        value=(
            f"┃ **Status:** {status_value}\n"
            f"<:mov_call:1518271964077232150> **{t['desmute_canal_label']}:** {canal_value}\n"
            f"<:ferramentas_:1518271998613131274> **{t['desmute_canal_logs_label']}:** {log_value}\n"
            f"<:comunidade_:1518272016971595807> **{t['desmute_cargos_label']}:** {cargos_value}"
        ),
        inline=False,
    )
    embed.add_field(
        name=f"<:seguranca:1518271987393232936>  {t['desmute_como_funciona']}",
        value=t["desmute_como_funciona_text"],
        inline=False,
    )
    embed.set_footer(
        text=f"NATA® ® • {t['solicitado_por']} {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


