class DesmuteCargosSelect(discord.ui.RoleSelect):
    def __init__(self, parent_view: "DesmuteView", placeholder: str):
        super().__init__(placeholder=placeholder, min_values=1, max_values=25)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["desmute_roles"] = [r.id for r in self.values]
        embed = build_desmute_embed(self.parent_view.author, settings)
        view = DesmuteView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["desmute_cargos_updated"]), ephemeral=True)


class DesmuteView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("desmute_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_canal_desmute"], discord.ButtonStyle.secondary, self._canal),
            (t["btn_canal_logs"], discord.ButtonStyle.secondary, self._logs),
            (t["btn_definir_cargos_desmute"], discord.ButtonStyle.secondary, self._cargos),
        ]
        row1 = [
            (t["btn_reset_config"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)
        for label, style, cb in row1:
            btn = discord.ui.Button(label=label, style=style, row=1, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["desmute_enabled"] = not settings.get("desmute_enabled", False)
        embed = build_desmute_embed(self.author, settings)
        view = DesmuteView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["desmute_activated"] if settings["desmute_enabled"] else t["desmute_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)

    async def _canal(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(DesmuteCanalSelect(self, t["desmute_select_canal_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["desmute_select_canal_placeholder"]), view=view, ephemeral=True)

    async def _logs(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(DesmuteLogSelect(self, t["desmute_select_log_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["desmute_select_log_placeholder"]), view=view, ephemeral=True)

    async def _cargos(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(DesmuteCargosSelect(self, t["desmute_select_cargos_placeholder"]))
        await interaction.response.send_message(embed=_notif_embed(t["desmute_select_cargos_placeholder"]), view=view, ephemeral=True)

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["desmute_enabled"] = False
        settings["desmute_channel"] = None
        settings["desmute_log_channel"] = None
        settings["desmute_roles"] = []
        embed = build_desmute_embed(self.author, settings)
        view = DesmuteView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["desmute_reset_done"]), ephemeral=True)


# =============================================================================
# Contador em Call
# =============================================================================

async def _update_contador_call(guild: discord.Guild):
    settings = get_settings(guild.id)
    if not settings.get("contador_call_enabled"):
        return
    channel_id = settings.get("contador_call_channel")
    if not channel_id:
        return
    ch = guild.get_channel(channel_id)
    if ch is None:
        return
    total = sum(
        len([m for m in vc.members if not m.bot])
        for vc in guild.channels
        if isinstance(vc, discord.VoiceChannel)
    )
    template = settings.get("contador_call_message", "users in call: {contador}")
    new_name = template.format(contador=total)
    try:
        await ch.edit(name=new_name)
    except Exception:
        pass


def build_contador_call_embed(author: discord.Member, settings: dict) -> discord.Embed:
    t = TRANSLATIONS[settings["language"]]
    guild = author.guild
    color = settings.get("embed_color", 0x2B2D31)
    icon_url = bot.user.display_avatar.url if bot.user else None

    enabled = settings.get("contador_call_enabled", False)
    status_value = ("<a:on_:1518272007624802375> Ativado" if enabled
                    else "<a:off_:1518272060870778910> Desativado")

    channel_id = settings.get("contador_call_channel")
    nd = "<:erro:1518271951914606593> Não definido"
    if channel_id and guild:
        ch = guild.get_channel(channel_id)
        canal_value = ch.mention if ch else nd
    else:
        canal_value = nd

    msg_template = settings.get("contador_call_message", "users in call: {contador}")

    embed = discord.Embed(title=t["contador_call_panel_title"], color=color)
    embed.add_field(
        name=f"<:ferramentas_:1518271998613131274>  {t['contador_call_funcoes']}",
        value=t["contador_call_funcoes_text"],
        inline=False,
    )
    embed.add_field(
        name=f"<:entretenimento_:1518271992191779038>  {t['contador_call_info']}",
        value=(
            f"┃ **{t['contador_call_estado_label']}:** {status_value}\n"
            f"<:mov_call:1518271964077232150> **{t['contador_call_canal_label']}:** {canal_value}\n"
            f"<:comunidade_:1518272016971595807> **{t['contador_call_mensagem_label']}:** `{discord.utils.escape_markdown(msg_template)}`"
        ),
        inline=False,
    )
    embed.set_footer(
        text=f"NATA® • {t['solicitado_por']} {author.name}",
        icon_url=icon_url,
    )
    embed.timestamp = datetime.now()
    return embed


class ContadorCallCanalSelect(GuildChannelSelect):
    def __init__(self, parent_view: "ContadorCallView", placeholder: str):
        super().__init__(
            placeholder=placeholder, min_values=1, max_values=1,
            channel_types=[discord.ChannelType.voice],
        )
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        ch = self.values[0]
        settings["contador_call_channel"] = ch.id
        embed = build_contador_call_embed(self.parent_view.author, settings)
        view = ContadorCallView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(
            embed=_notif_embed(t["contador_call_canal_set"].format(channel=ch.mention)),
            ephemeral=True,
        )


class ContadorCallMensagemModal(discord.ui.Modal):
    def __init__(self, parent_view: "ContadorCallView"):
        settings = get_settings(parent_view.author.guild.id if parent_view.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        super().__init__(title=t["contador_call_mensagem_modal_title"])
        self.parent_view = parent_view
        self.msg_input = discord.ui.TextInput(
            label=t["contador_call_mensagem_label_input"],
            placeholder="users in call: {contador}",
            default=settings.get("contador_call_message", "users in call: {contador}"),
            max_length=100,
            required=True,
        )
        self.add_item(self.msg_input)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        value = self.msg_input.value.strip()
        if "{contador}" not in value:
            await interaction.response.send_message(
                embed=_notif_embed(t["contador_call_mensagem_invalid"]), ephemeral=True
            )
            return
        settings["contador_call_message"] = value
        embed = build_contador_call_embed(self.parent_view.author, settings)
        view = ContadorCallView(self.parent_view.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(
            embed=_notif_embed(t["contador_call_mensagem_set"]), ephemeral=True
        )


class ContadorCallView(discord.ui.View):
    def __init__(self, author: discord.Member):
        super().__init__(timeout=None)
        self.author = author
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        enabled = settings.get("contador_call_enabled", False)
        toggle_label = t["btn_deactivate"] if enabled else t["btn_activate"]
        toggle_style = discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success

        row0 = [
            (t["back"], discord.ButtonStyle.primary, self._back),
            (toggle_label, toggle_style, self._toggle),
            (t["btn_contador_call_canal"], discord.ButtonStyle.secondary, self._canal),
            (t["btn_contador_call_mensagem"], discord.ButtonStyle.secondary, self._mensagem),
            (t["btn_contador_call_reset"], discord.ButtonStyle.danger, self._reset),
        ]
        for label, style, cb in row0:
            btn = discord.ui.Button(label=label, style=style, row=0, emoji=_button_emoji(style))
            btn.callback = cb
            self.add_item(btn)

    async def _back(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        embed = build_servidor_embed(self.author, settings)
        view = ServidorView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)

    async def _toggle(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["contador_call_enabled"] = not settings.get("contador_call_enabled", False)
        embed = build_contador_call_embed(self.author, settings)
        view = ContadorCallView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        msg = t["contador_call_activated"] if settings["contador_call_enabled"] else t["contador_call_deactivated"]
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)
        if interaction.guild:
            asyncio.create_task(_update_contador_call(interaction.guild))

    async def _canal(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        view = _SingleSelectView(ContadorCallCanalSelect(self, t["contador_call_select_canal"]))
        await interaction.response.send_message(
            embed=_notif_embed(t["contador_call_select_canal"]), view=view, ephemeral=True
        )

    async def _mensagem(self, interaction: discord.Interaction):
        await interaction.response.send_modal(ContadorCallMensagemModal(self))

    async def _reset(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        settings["contador_call_enabled"] = False
        settings["contador_call_channel"] = None
        settings["contador_call_message"] = "users in call: {contador}"
        embed = build_contador_call_embed(self.author, settings)
        view = ContadorCallView(self.author)
        await interaction.response.edit_message(embed=embed, view=view)
        await interaction.followup.send(embed=_notif_embed(t["contador_call_reset_done"]), ephemeral=True)


# =============================================================================
# Components V2 — Panel Builder (Preview do Painel V2)
# =============================================================================

def _empty_panel_v2() -> dict:
    return {"color": None, "title": "", "description": "", "blocks": []}


def _extract_panel_from_v2_message(msg: discord.Message) -> dict | None:
    """Reconstrói dados de painel V2 a partir de msg.components (para painéis sem dados salvos)."""
    try:
        blocks: list[dict] = []
        color: int | None = None

        for comp in msg.components:
            cname = type(comp).__name__

            # ── Container ─────────────────────────────────────────────────────
            if cname == "Container":
                ac = getattr(comp, "accent_color", None)
                if color is None and ac is not None:
                    color = ac.value if hasattr(ac, "value") else int(ac)
                for child in (getattr(comp, "children", None) or []):
                    _extract_v2_child(child, blocks)

            # ── Separador no nível raiz ────────────────────────────────────────
            elif cname == "SeparatorComponent":
                _append_separator(comp, blocks)

            # ActionRow (botões) — ignorar para fins de extração

        return {"color": color, "blocks": blocks} if (color is not None or blocks) else None
    except Exception:
        return None


def _extract_v2_child(child, blocks: list) -> None:
    """Extrai um componente filho de um Container e adiciona ao lista de blocos."""
    cname = type(child).__name__

    if cname == "TextDisplay":
        text = getattr(child, "content", "") or ""
        blocks.append({"type": "text", "text": text})

    elif cname == "SectionComponent":
        text = ""
        for sc in (getattr(child, "children", None) or []):
            if type(sc).__name__ == "TextDisplay":
                text = getattr(sc, "content", "") or ""
                break
        block: dict = {"type": "text", "text": text}
        acc = getattr(child, "accessory", None)
        if acc:
            aname = type(acc).__name__
            if aname == "ThumbnailComponent":
                media = getattr(acc, "media", None)
                url = getattr(media, "url", None) if media else None
                if url:
                    block["thumbnail"] = url
            elif aname == "Button":
                block["button_label"] = getattr(acc, "label", "") or ""
                block["button_url"] = getattr(acc, "url", "") or ""
        blocks.append(block)

    elif cname == "SeparatorComponent":
        _append_separator(child, blocks)

    elif cname in ("MediaGallery", "MediaGalleryComponent"):
        images = []
        for item in (getattr(child, "children", None) or []):
            media = getattr(item, "media", None)
            url = getattr(media, "url", None) if media else None
            if url:
                images.append(url)
        if images:
            blocks.append({"type": "gallery", "images": images})


def _append_separator(sep, blocks: list) -> None:
    visible = getattr(sep, "visible", True)
    spacing = getattr(sep, "spacing", None)
    blocks.append({
        "type": "separator",
        "style": "Com linha" if visible else "Sem linha",
        "spacing": "Grande" if spacing == discord.SeparatorSpacing.large else "Pequeno",
    })


def build_panel_v2_embed(panel: dict, settings: dict) -> discord.Embed:
    """Renderiza o embed do painel V2 como preview — título/thumbnail/imagem, igual à nata.
    Os blocos de texto são componentes V2 separados e não aparecem na descrição do embed."""
    t = TRANSLATIONS[settings["language"]]
    color = panel.get("color")
    if not isinstance(color, int):
        color = settings["embed_color"]

    title    = (panel.get("title") or "").strip() or None
    raw_desc = (panel.get("description") or "").strip()

    blocks = panel.get("blocks") or []
    thumbnail_url = None
    gallery_image = None

    for b in blocks:
        btype = b.get("type")
        if btype == "text":
            # Thumbnail do bloco de texto → thumbnail da embed
            thumb = b.get("thumbnail")
            if thumb and not thumbnail_url:
                thumbnail_url = thumb
        elif btype == "gallery":
            imgs = b.get("images") or []
            if imgs and not gallery_image:
                gallery_image = imgs[0]
        # Separators — componentes V2 separados, não aparecem no embed

    embed = discord.Embed(title=title, color=color)

    if raw_desc:
        embed.description = raw_desc
    elif not blocks:
        embed.description = t["panelv2_empty"]
    else:
        # Preview: mostra o conteúdo real dos blocos sem labels de debug
        preview_parts = []
        for b in blocks:
            btype = b.get("type")
            if btype == "text":
                txt = (b.get("text") or "").strip()
                if txt:
                    preview_parts.append(txt)
            elif btype == "separator":
                preview_parts.append("─────────────────")
        if preview_parts:
            embed.description = "\n\n".join(preview_parts)

    if thumbnail_url:
        try:
            embed.set_thumbnail(url=thumbnail_url)
        except Exception:
            pass
    if gallery_image:
        try:
            embed.set_image(url=gallery_image)
        except Exception:
            pass

    return embed


def _build_v2_panel_items(blocks: list, color: int, _inner_action_row=None) -> list:
    """Converte blocos do painel em itens de LayoutView.

    Todo o conteúdo fica em UM único Container.
    Separadores ficam DENTRO do Container como linha divisória interna
    (junto com o embed), não como elementos raiz entre containers.
    """

    def _seg_to_items(seg: list) -> list:
        """Converte um segmento (entre separadores) em lista de items sem Container."""
        items: list = []
        topo_done: set = set()
        # Galerias posicionadas no topo do segmento
        for i, b in enumerate(seg):
            if b.get("type") == "gallery" and b.get("position", "Topo") != "Rodape":
                images = b.get("images") or []
                if images:
                    items.insert(len(topo_done), discord.ui.MediaGallery(
                        *[discord.MediaGalleryItem(media=u) for u in images[:10]]
                    ))
                    topo_done.add(i)
        # Resto dos blocos em ordem
        for i, b in enumerate(seg):
            if i in topo_done:
                continue
            btype = b.get("type")
            if btype == "text":
                txt  = b.get("text") or ""
                th   = (b.get("thumbnail") or "").strip()
                bl   = (b.get("button_label") or "").strip()
                bu   = (b.get("button_url") or "").strip()
                td   = discord.ui.TextDisplay(txt)
                if bl and bu:
                    items.append(discord.ui.Section(td, accessory=discord.ui.Button(
                        label=bl, style=discord.ButtonStyle.link, url=bu)))
                elif th:
                    items.append(discord.ui.Section(td, accessory=discord.ui.Thumbnail(th)))
                else:
                    items.append(td)
            elif btype == "gallery":
                images = b.get("images") or []
                if images:
                    items.append(discord.ui.Separator(visible=False))
                    items.append(discord.ui.MediaGallery(
                        *[discord.MediaGalleryItem(media=u) for u in images[:10]]
                    ))
        return items

    all_items: list = []
    current_seg: list = []

    for b in blocks:
        if b.get("type") == "separator":
            # Adiciona os itens do segmento atual ao container único
            all_items.extend(_seg_to_items(current_seg))
            current_seg = []
            # Separador DENTRO do Container (linha divisória interna)
            style_v     = b.get("style", "Com linha")
            spacing_str = b.get("spacing", "Pequeno")
            all_items.append(discord.ui.Separator(
                visible=(style_v == "Com linha"),
                spacing=(
                    discord.SeparatorSpacing.large
                    if spacing_str == "Grande"
                    else discord.SeparatorSpacing.small
                ),
            ))
        else:
            current_seg.append(b)

    # Último segmento
    all_items.extend(_seg_to_items(current_seg))

    if not all_items:
        return []

    # Tudo em um único Container — separadores ficam "junto com o embed"
    if _inner_action_row is not None:
        all_items.append(_inner_action_row)
    return [discord.ui.Container(*all_items, accent_colour=color)]


def build_panel_v2_layout(
    panel: dict,
    settings: dict,
    ticket_panel: dict | None = None,
    _inner_action_row=None,
) -> discord.ui.LayoutView:
    """Constrói um LayoutView V2 com componentes nativos.

    Separadores ficam no NÍVEL RAIZ do LayoutView (linha nativa entre Containers).
    *ticket_panel*: dict completo do painel de ticket (contém id, menu_opcoes, menus_selecao).
    """
    color = panel.get("color")
    if not isinstance(color, int):
        color = settings.get("embed_color", 0x2B2D31)

    blocks = panel.get("blocks") or []
    layout = discord.ui.LayoutView(timeout=None)

    # Monta ActionRow do select menu do ticket para inserir DENTRO do container
    _ticket_select_row = None
    if ticket_panel and ticket_panel.get("menus_selecao") and ticket_panel.get("menu_opcoes"):
        opcoes   = ticket_panel.get("menu_opcoes", [])
        panel_id = str(ticket_panel.get("id", ""))
        tp_opts  = []
        for i, op in enumerate(opcoes[:25]):
            tp_opts.append(discord.SelectOption(
                label=(op.get("label") or "Opção")[:100],
                description=((op.get("description") or "")[:100]) or None,
                emoji=_ticket_menu_emoji(op, i),
                value=op.get("id", op.get("label", "opcao")),
            ))
        if tp_opts:
            ticket_select = discord.ui.Select(
                placeholder="Selecione uma opção...",
                options=tp_opts,
                custom_id=f"ticket_panel_menu_{panel_id}",
            )
            _ticket_select_row = discord.ui.ActionRow(ticket_select)

    # _inner_action_row explícito tem prioridade; caso contrário usa o do ticket
    inner = _inner_action_row or _ticket_select_row

    panel_items = _build_v2_panel_items(blocks, color, _inner_action_row=inner)
    if not panel_items:
        layout.add_item(discord.ui.Container(
            discord.ui.TextDisplay("*Painel sem conteúdo.*"),
            accent_colour=color,
        ))
    else:
        for item in panel_items:
            layout.add_item(item)

    return layout


class PanelV2TextModal(_ModalV2):
    def __init__(self, parent_view: "PanelV2BuilderView", t: dict, edit_idx: int | None = None):
        super().__init__(title=t["panelv2_modal_text_title"], timeout=300)
        self.parent_view = parent_view
        self.edit_idx = edit_idx
        existing = (parent_view.panel["blocks"][edit_idx] if edit_idx is not None else {}) or {}
        self._existing = existing
        # Todos os componentes embrulhados em Label (tipo 18) — obrigatório com flags=32768.
        # Py-cord envolve TextInput em ActionRow (tipo 1) quando adicionado diretamente,
        # mas tipo 1 é rejeitado pelo Discord em modais V2. Label (tipo 18) é aceito.
        _text = discord.ui.TextInput(
            label=t["panelv2_input_text_label"],
            placeholder=t["panelv2_input_text_placeholder"],
            required=True, max_length=2000, style=discord.TextStyle.paragraph,
            default=existing.get("text"),
        )
        self.text_inp = _text
        _fu = discord.ui.FileUpload(required=False, min_values=0, max_values=1)
        self.thumb_upload = _fu
        _btn_label = discord.ui.TextInput(
            label=t["panelv2_input_btn_label"],
            placeholder=t["panelv2_input_btn_label_placeholder"],
            required=False, max_length=80,
            default=existing.get("button_label"),
        )
        self.btn_label_inp = _btn_label
        _btn_url = discord.ui.TextInput(
            label=t["panelv2_input_btn_url_label"],
            placeholder=t["panelv2_input_btn_url_placeholder"],
            required=False, max_length=500,
            default=existing.get("button_url"),
        )
        self.btn_url_inp = _btn_url
        self.add_item(discord.ui.Label(text=t["panelv2_input_text_label"],        description=t["panelv2_input_text_placeholder"],        component=_text))
        self.add_item(discord.ui.Label(text="Thumbnail (upload)",                 description="Opcional: envie 1 imagem para ficar ao lado do texto", component=_fu))
        self.add_item(discord.ui.Label(text=t["panelv2_input_btn_label"],         description=t["panelv2_input_btn_label_placeholder"],    component=_btn_label))
        self.add_item(discord.ui.Label(text=t["panelv2_input_btn_url_label"],     description=t["panelv2_input_btn_url_placeholder"],      component=_btn_url))

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if self.thumb_upload.values:
            thumb = self.thumb_upload.values[0].url
        else:
            thumb = self._existing.get("thumbnail")
        block = {
            "type": "text",
            "text": self.text_inp.value.strip(),
            "thumbnail": thumb or None,
            "button_label": (self.btn_label_inp.value or "").strip() or None,
            "button_url": (self.btn_url_inp.value or "").strip() or None,
        }
        blocks = self.parent_view.panel.setdefault("blocks", [])
        if self.edit_idx is not None and 0 <= self.edit_idx < len(blocks):
            blocks[self.edit_idx] = block
            msg = t["panelv2_block_updated"]
        else:
            blocks.append(block)
            msg = t["panelv2_block_added"]
        new_view = self.parent_view._rebuild()
        await interaction.response.edit_message(view=new_view)
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)


class PanelV2GalleryModal(_ModalV2):
    def __init__(self, parent_view: "PanelV2BuilderView", t: dict, edit_idx: int | None = None):
        super().__init__(title=t["panelv2_modal_gallery_title"], timeout=300)
        self.parent_view = parent_view
        self.edit_idx = edit_idx
        existing = (parent_view.panel["blocks"][edit_idx] if edit_idx is not None else {}) or {}
        self._existing = existing
        cur_pos = existing.get("position", "Topo")
        # Todos os componentes embrulhados em Label (tipo 18) — obrigatório com flags=32768
        _fu = discord.ui.FileUpload(required=False, min_values=0, max_values=10)
        self.files_upload = _fu
        _links = discord.ui.TextInput(
            label=t["panelv2_input_gallery_links_label"],
            placeholder=t["panelv2_input_gallery_links_placeholder"],
            required=False, max_length=2000, style=discord.TextStyle.paragraph,
            default="\n".join(existing.get("images", []) or []) or None,
        )
        self.links_inp = _links
        _pos_rg = discord.ui.RadioGroup(
            required=True,
            options=[
                discord.RadioGroupOption(label="Topo (Header)",   value="Topo",   description="Fica acima do texto",   default=(cur_pos == "Topo")),
                discord.RadioGroupOption(label="Rodapé (Footer)", value="Rodape", description="Fica acima dos botões", default=(cur_pos == "Rodape")),
            ],
        )
        self.pos_radio = _pos_rg
        self.add_item(discord.ui.Label(text="Upload (opcional)",     description="Envie até 10 imagens/gifs (PNG/JPG/GIF/WEBP).",  component=_fu))
        self.add_item(discord.ui.Label(text=t["panelv2_input_gallery_links_label"], description=t["panelv2_input_gallery_links_placeholder"], component=_links))
        self.add_item(discord.ui.Label(text="Posição da imagem",     description="Escolha onde a galeria ficará no painel",        component=_pos_rg))

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        uploaded = [a.url for a in (self.files_upload.values or [])]
        typed    = [l.strip() for l in (self.links_inp.value or "").splitlines() if l.strip()]
        links    = (uploaded + typed)[:10] or self._existing.get("images", [])
        block = {
            "type": "gallery",
            "images": links,
            "position": self.pos_radio.value or "Topo",
        }
        blocks = self.parent_view.panel.setdefault("blocks", [])
        if self.edit_idx is not None and 0 <= self.edit_idx < len(blocks):
            blocks[self.edit_idx] = block
            msg = t["panelv2_block_updated"]
        else:
            blocks.append(block)
            msg = t["panelv2_block_added"]
        new_view = self.parent_view._rebuild()
        await interaction.response.edit_message(view=new_view)
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)


class PanelV2SeparatorModal(_ModalV2):
    def __init__(self, parent_view: "PanelV2BuilderView", t: dict, edit_idx: int | None = None):
        super().__init__(title=t["panelv2_modal_separator_title"], timeout=300)
        self.parent_view = parent_view
        self.edit_idx = edit_idx
        existing = (parent_view.panel["blocks"][edit_idx] if edit_idx is not None else {}) or {}
        cur_style   = existing.get("style",   "Com linha")
        cur_spacing = existing.get("spacing", "Pequeno")

        # ── Seletor de posição (apenas ao adicionar novo, com ≤9 blocos existentes) ──
        blocks = parent_view.panel.get("blocks", [])
        self.pos_radio: "discord.ui.RadioGroup | None" = None
        if edit_idx is None and 1 <= len(blocks) <= 9:
            pos_options = [
                discord.RadioGroupOption(
                    label="Ao final (padrão)",
                    value="-1",
                    description="Após todos os blocos existentes",
                    default=True,
                )
            ]
            for i, b in enumerate(blocks[:9]):
                btype = b.get("type", "")
                if btype == "text":
                    desc = (b.get("text") or "texto")[:40] or None
                elif btype == "gallery":
                    desc = f"Galeria ({len(b.get('images', []))} img)"
                else:
                    desc = "Separador"
                pos_options.append(discord.RadioGroupOption(
                    label=f"Após bloco {i + 1}",
                    value=str(i),
                    description=desc,
                ))
            _pos_rg = discord.ui.RadioGroup(required=True, options=pos_options)
            self.pos_radio = _pos_rg
            self.add_item(discord.ui.Label(
                text="Posição",
                description="Onde inserir a linha divisória no painel",
                component=_pos_rg,
            ))

        # ── Tipo (Com/Sem linha) ──────────────────────────────────────────────────
        _tipo_rg = discord.ui.RadioGroup(
            required=True,
            options=[
                discord.RadioGroupOption(label="Com linha", value="Com linha", description="Mostra uma linha divisória", default=(cur_style == "Com linha")),
                discord.RadioGroupOption(label="Sem linha", value="Sem linha", description="Apenas espaçamento",         default=(cur_style == "Sem linha")),
            ],
        )
        self.tipo_radio = _tipo_rg
        self.add_item(discord.ui.Label(
            text="Tipo",
            description="Escolha se terá linha divisória visível",
            component=_tipo_rg,
        ))

        # ── Espaçamento ───────────────────────────────────────────────────────────
        _spacing_rg = discord.ui.RadioGroup(
            required=True,
            options=[
                discord.RadioGroupOption(label="Pequeno", value="Pequeno", description="Espaçamento menor", default=(cur_spacing == "Pequeno")),
                discord.RadioGroupOption(label="Grande",  value="Grande",  description="Espaçamento maior", default=(cur_spacing == "Grande")),
            ],
        )
        self.spacing_radio = _spacing_rg
        self.add_item(discord.ui.Label(
            text="Espaçamento",
            description="Define o tamanho do espaçamento vertical",
            component=_spacing_rg,
        ))

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        style   = self.tipo_radio.value    or "Com linha"
        spacing = self.spacing_radio.value or "Pequeno"
        block = {"type": "separator", "style": style, "spacing": spacing}
        blocks = self.parent_view.panel.setdefault("blocks", [])
        if self.edit_idx is not None and 0 <= self.edit_idx < len(blocks):
            blocks[self.edit_idx] = block
            msg = t["panelv2_block_updated"]
        else:
            # Determina a posição de inserção
            pos_val = (self.pos_radio.value if self.pos_radio else None) or "-1"
            if pos_val == "-1":
                blocks.append(block)
            else:
                try:
                    insert_after = int(pos_val)   # índice do bloco APÓS o qual inserir
                    blocks.insert(insert_after + 1, block)
                except (ValueError, TypeError):
                    blocks.append(block)
            msg = t["panelv2_block_added"]
        new_view = self.parent_view._rebuild()
        await interaction.response.edit_message(view=new_view)
        await interaction.followup.send(embed=_notif_embed(msg), ephemeral=True)


class PanelV2ColorModal(discord.ui.Modal):
    def __init__(self, parent_view: "PanelV2BuilderView", t: dict):
        super().__init__(title=t["panelv2_modal_color_title"], timeout=600)
        self.parent_view = parent_view
        current = parent_view.panel.get("color")
        default_hex = f"#{current:06X}" if isinstance(current, int) else None
        self.inp = discord.ui.TextInput(
            label=t["panelv2_input_color_label"],
            placeholder="#5865F2",
            required=True, max_length=10,
            default=default_hex,
        )
        self.add_item(self.inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        raw = self.inp.value.strip().lstrip("#")
        try:
            color = int(raw, 16)
            if color < 0 or color > 0xFFFFFF:
                raise ValueError
        except ValueError:
            await interaction.response.send_message(embed=_notif_embed(t["panelv2_invalid_value"]), ephemeral=True)
            return
        self.parent_view.panel["color"] = color
        await self.parent_view._refresh(interaction)
        await interaction.followup.send(embed=_notif_embed(t["panelv2_color_set"]), ephemeral=True)


