class PanelV2AddSelect(discord.ui.Select):
    def __init__(self, parent_view: "PanelV2BuilderView", t: dict):
        options = [
            discord.SelectOption(label=t["panelv2_add_text_label"], description=t["panelv2_add_text_desc"],
                                 value="text", emoji=_make_select_emoji("<:tickets:1518271952526250155>")),
            discord.SelectOption(label=t["panelv2_add_gallery_label"], description=t["panelv2_add_gallery_desc"],
                                 value="gallery", emoji=_make_select_emoji("<:gifs:1518272035762081835>")),
            discord.SelectOption(label=t["panelv2_add_separator_label"], description=t["panelv2_add_separator_desc"],
                                 value="separator", emoji=_make_select_emoji("<:ferramentas_:1518271998613131274>")),
            discord.SelectOption(label=t["panelv2_add_reset_label"], description=t["panelv2_add_reset_desc"],
                                 value="reset", emoji=_make_select_emoji("<a:alerta:1518271939460857968>")),
        ]
        super().__init__(placeholder=t["panelv2_add_placeholder"], min_values=1, max_values=1, options=options, row=0)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        v = self.values[0]
        if v == "text":
            await interaction.response.send_modal(PanelV2TextModal(self.parent_view, t))
        elif v == "gallery":
            await interaction.response.send_modal(PanelV2GalleryModal(self.parent_view, t))
        elif v == "separator":
            await interaction.response.send_modal(PanelV2SeparatorModal(self.parent_view, t))
        elif v == "reset":
            # Limpa in-place para preservar a referência ao dict das settings
            self.parent_view.panel.clear()
            self.parent_view.panel.update(_empty_panel_v2())
            new_view = self.parent_view._rebuild()
            await interaction.response.edit_message(view=new_view)
            await interaction.followup.send(embed=_notif_embed(t["panelv2_reset_done"]), ephemeral=True)


class PanelV2EditSelect(discord.ui.Select):
    def __init__(self, parent_view: "PanelV2BuilderView", t: dict):
        blocks = parent_view.panel.get("blocks", [])
        if blocks:
            options = []
            for i, b in enumerate(blocks[:25]):
                t_block = b.get("type")
                if t_block == "text":
                    label = f"{i+1}. Texto: " + (b.get("text") or "")[:50]
                    emoji = "<:tickets:1518271952526250155>"
                elif t_block == "gallery":
                    label = f"{i+1}. Galeria ({len(b.get('images', []))} img)"
                    emoji = "<:gifs:1518272035762081835>"
                else:
                    label = f"{i+1}. Separador ({b.get('style', '?')})"
                    emoji = "<:ferramentas_:1518271998613131274>"
                options.append(discord.SelectOption(
                    label=label[:100], value=str(i),
                    emoji=_make_select_emoji(emoji),
                    description=f"Clique para editar/remover",
                ))
            super().__init__(placeholder=t["panelv2_edit_placeholder"],
                             min_values=1, max_values=1, options=options, row=1)
            self.disabled = False
        else:
            super().__init__(placeholder=t["panelv2_edit_empty_placeholder"],
                             min_values=1, max_values=1,
                             options=[discord.SelectOption(label="—", value="__none__")],
                             row=1, disabled=True)
        self.parent_view = parent_view

    async def callback(self, interaction: discord.Interaction):
        v = self.values[0]
        if v == "__none__":
            await interaction.response.defer()
            return
        idx = int(v)
        block = self.parent_view.panel["blocks"][idx]
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        btype = block.get("type")
        if btype == "text":
            await interaction.response.send_modal(PanelV2TextModal(self.parent_view, t, idx))
        elif btype == "gallery":
            await interaction.response.send_modal(PanelV2GalleryModal(self.parent_view, t, idx))
        elif btype == "separator":
            await interaction.response.send_modal(PanelV2SeparatorModal(self.parent_view, t, idx))


