class PanelV2BuilderView(discord.ui.LayoutView):
    def __init__(self, author: discord.Member, panel: dict | None = None,
                 edit_message_id: int | None = None, edit_channel=None):
        super().__init__(timeout=None)
        self.author = author
        self.panel = panel or _empty_panel_v2()
        self.edit_message_id = edit_message_id
        self.edit_channel    = edit_channel
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        color = self.panel.get("color")
        if not isinstance(color, int):
            color = settings.get("embed_color", 0x5865F2)

        blocks = self.panel.get("blocks") or []
        n = len(blocks)

        # ── Header do editor ──────────────────────────────────────────────────
        header_container = discord.ui.Container(
            discord.ui.TextDisplay(f"**Editor de Painel V2** • {n} bloco(s)"),
            accent_colour=color,
        )
        self.add_item(header_container)

        # ── Preview: Containers + Separadores nativos entre eles ─────────────
        if not blocks:
            self.add_item(discord.ui.Container(
                discord.ui.TextDisplay(t["panelv2_empty"]),
                accent_colour=color,
            ))
        else:
            for item in _build_v2_panel_items(blocks, color):
                self.add_item(item)

        # ── ActionRow: Adicionar item ──────────────────────────────────────────
        adder = PanelV2AddSelect(self, t)
        self.add_item(discord.ui.ActionRow(adder))

        # ── ActionRow: Editar / remover bloco ─────────────────────────────────
        editor = PanelV2EditSelect(self, t)
        self.add_item(discord.ui.ActionRow(editor))

        # ── ActionRow: Cor / Salvar / Enviar ──────────────────────────────────
        cor_btn = discord.ui.Button(label=t["panelv2_btn_cor"], style=discord.ButtonStyle.secondary)
        cor_btn.callback = self._cor
        salvar_btn = discord.ui.Button(
            label=t["panelv2_btn_salvar"], style=discord.ButtonStyle.success,
            emoji="<a:online:1518271945550856295>",
        )
        salvar_btn.callback = self._salvar
        if self.edit_message_id:
            enviar_btn = discord.ui.Button(
                label="Atualizar Painel", style=discord.ButtonStyle.primary,
                emoji="✏️",
            )
            enviar_btn.callback = self._atualizar
        else:
            enviar_btn = discord.ui.Button(
                label=t["btn_enviar"], style=discord.ButtonStyle.primary,
            )
            enviar_btn.callback = self._enviar
        self.add_item(discord.ui.ActionRow(cor_btn, salvar_btn, enviar_btn))

    def _rebuild(self) -> "PanelV2BuilderView":
        """Recria a view do mesmo tipo. Subclasses sobrescrevem para preservar ticket ref."""
        return PanelV2BuilderView(self.author, self.panel,
                                  edit_message_id=self.edit_message_id,
                                  edit_channel=self.edit_channel)

    async def _refresh(self, interaction: discord.Interaction):
        new_view = self._rebuild()
        try:
            await interaction.edit_original_response(view=new_view)
        except (discord.HTTPException, discord.NotFound):
            pass

    async def _cor(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        await interaction.response.send_modal(PanelV2ColorModal(self, t))

    async def _salvar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        saved_layout = discord.ui.LayoutView(timeout=None)
        saved_layout.add_item(discord.ui.Container(
            discord.ui.TextDisplay(f"<a:online:1518271945550856295> {t['panelv2_saved']}"),
            accent_colour=settings.get("embed_color", 0x5865F2),
        ))
        try:
            await interaction.response.edit_message(view=saved_layout)
        except discord.HTTPException:
            await interaction.response.defer()

    async def _enviar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if not self.panel.get("blocks"):
            await interaction.response.send_message(embed=_notif_embed(t["panelv2_send_empty"]), ephemeral=True)
            return
        view = PanelV2EnviarView(self, t["panelv2_enviar_placeholder"], guild=interaction.guild)
        await interaction.response.send_message(embed=_notif_embed(t["panelv2_enviar_prompt"]), view=view, ephemeral=True)

    async def _atualizar(self, interaction: discord.Interaction):
        """Edita a mensagem V2 original em vez de enviar para um canal novo."""
        settings = get_settings(interaction.guild.id)
        if not self.panel.get("blocks"):
            await interaction.response.send_message(
                "❌ Adicione pelo menos um bloco antes de atualizar.", ephemeral=True
            )
            return
        if not self.edit_message_id or not self.edit_channel:
            await interaction.response.send_message(
                "❌ Mensagem original não encontrada.", ephemeral=True
            )
            return
        layout = build_panel_v2_layout(self.panel, settings)
        try:
            msg = await self.edit_channel.fetch_message(self.edit_message_id)
            await msg.edit(view=layout)
        except Exception as e:
            await interaction.response.send_message(f"❌ Erro ao atualizar: {e}", ephemeral=True)
            return
        # Persiste o panel dict atualizado
        _panelv2_data[self.edit_message_id] = self.panel
        _save_panelv2_data()
        await interaction.response.send_message("✅ Painel atualizado!", ephemeral=True)


