class IgVerifPanelV2BuilderView(PanelV2BuilderView):
    """PanelV2Builder para o embed público de Verificação Instagram."""

    def __init__(self, author: discord.Member, panel: dict | None = None):
        settings = get_settings(author.guild.id if author.guild else 0)
        if panel is None:
            panel = settings.setdefault("ig_verif_panel_v2", _empty_panel_v2())
        super().__init__(author, panel)

    def _rebuild(self) -> "IgVerifPanelV2BuilderView":
        return IgVerifPanelV2BuilderView(self.author, self.panel)

    async def _enviar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        if not self.panel.get("blocks"):
            await interaction.response.send_message(
                "<a:alerta:1518271939460857968> Adicione pelo menos um bloco antes de enviar.",
                ephemeral=True,
            )
            return
        ch_id = settings.get("ig_verif_channel")
        ch    = interaction.guild.get_channel(ch_id) if ch_id else None
        if not isinstance(ch, discord.TextChannel):
            await interaction.response.send_message(
                "<a:alerta:1518271939460857968> Configure o canal da verificação primeiro (Definir Canais no painel).",
                ephemeral=True,
            )
            return
        verif_btn = discord.ui.Button(
            label="verificar",
            style=discord.ButtonStyle.secondary,
            custom_id="ig_verif_check",
        )
        layout = build_panel_v2_layout(
            self.panel, settings,
            _inner_action_row=discord.ui.ActionRow(verif_btn),
        )
        try:
            await ch.send(view=layout)
        except Exception as e:
            await interaction.response.send_message(f"<a:alerta:1518271939460857968> Erro: {e}", ephemeral=True)
            return
        settings["ig_verif_panel_v2"] = self.panel
        save_settings_to_disk()
        await interaction.response.send_message(
            f"<a:online:1518271945550856295> Embed enviado para {ch.mention}!", ephemeral=True,
        )


@bot.command(name="painelv2")
async def painelv2_cmd(ctx: commands.Context, *args: str):
    if ctx.guild is None:
        return

    # n!painelv2 editar <id>
    if args and args[0].lower() in ("editar", "edit") and len(args) >= 2:
        try:
            mid = int(args[1])
        except ValueError:
            await ctx.reply("❌ ID inválido. Use: `n!painelv2 editar <id_da_mensagem>`", delete_after=8)
            return

        panel = _panelv2_data.get(mid)
        if not panel:
            # Tenta buscar nos canais como fallback
            await ctx.reply(
                "❌ Painel não encontrado.\n"
                "Só é possível editar painéis enviados **após** o deploy desta atualização.\n"
                "Para painéis antigos, recrie com `n!painelv2`.",
                delete_after=15,
            )
            return

        view = PanelV2BuilderView(ctx.author, panel=dict(panel))
        try:
            await ctx.message.delete()
        except (discord.Forbidden, discord.NotFound):
            pass
        await ctx.send(view=view)
        return

    # n!painelv2 — novo painel em branco
    view = PanelV2BuilderView(ctx.author)
    await ctx.send(view=view)


