def _vt_week_start() -> str:
    today = datetime.now().date()
    return (today - timedelta(days=today.weekday())).isoformat()

def _vt_week_range(iso: str) -> str:
    try:
        d = date.fromisoformat(iso)
        return f"{d.strftime('%d/%m')} - {(d + timedelta(days=6)).strftime('%d/%m')}"
    except Exception:
        return iso

def _load_voice_time() -> None:
    global _voice_time
    try:
        if os.path.exists(_VOICE_TIME_FILE):
            with open(_VOICE_TIME_FILE, "r", encoding="utf-8") as _f:
                raw = json.load(_f)
                _voice_time = {int(g): {int(u): v for u, v in ud.items()} for g, ud in raw.items()}
    except Exception:
        _voice_time = {}

