def _get_user_vt(gid: int, uid: int) -> dict:
    ud = _voice_time.setdefault(gid, {})
    if uid not in ud:
        ud[uid] = {
            "total_seconds": 0, "muted_seconds": 0,
            "week_seconds": 0, "week_muted_seconds": 0,
            "last_week_seconds": 0, "last_week_muted_seconds": 0,
            "week_start": _vt_week_start(), "last_week_start": "",
        }
    return ud[uid]

def _vt_rotate(data: dict) -> None:
    ws = _vt_week_start()
    if data.get("week_start") != ws:
        data["last_week_seconds"]       = data.get("week_seconds", 0)
        data["last_week_muted_seconds"] = data.get("week_muted_seconds", 0)
        data["last_week_start"]         = data.get("week_start", ws)
        data["week_seconds"]            = 0
        data["week_muted_seconds"]      = 0
        data["week_start"]              = ws

def _fmt_vt(s: float) -> str:
    s = int(s)
    if s <= 0:
        return "0s"
    p: list[str] = []
    if s >= 3600: p.append(f"{s // 3600}h"); s %= 3600
    if s >= 60:   p.append(f"{s // 60}m");   s %= 60
    if s:         p.append(f"{s}s")
    return " ".join(p)

_TEMPO_FONT_PATH: str | None = None  # cached path para fonte TTF (NotoSans Bold)
_TEMPO_FONT_CACHE: dict[int, object] = {}  # size -> ImageFont object

async def _ensure_tempo_font() -> str | None:
    global _TEMPO_FONT_PATH
    if _TEMPO_FONT_PATH and os.path.exists(_TEMPO_FONT_PATH):
        return _TEMPO_FONT_PATH
    # 1. Tenta fontes do sistema
    for _p in [
        "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
        "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf",
        "/usr/share/fonts/truetype/freefont/FreeSansBold.ttf",
        "/usr/share/fonts/truetype/noto/NotoSans-Bold.ttf",
        "/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf",
    ]:
        if os.path.exists(_p):
            _TEMPO_FONT_PATH = _p
            return _p
    # 2. Baixa NotoSans Bold (unicode completo) ou Roboto Bold como fallback
    try:
        import aiohttp as _ah
        _dest = "/tmp/hypebot_notosans_bold.ttf"
        for _url in [
            "https://github.com/googlefonts/noto-fonts/raw/main/hinted/ttf/NotoSans/NotoSans-Bold.ttf",
            "https://github.com/google/fonts/raw/main/apache/roboto/static/Roboto-Bold.ttf",
        ]:
            try:
                async with _ah.ClientSession() as _s:
                    async with _s.get(_url, timeout=_ah.ClientTimeout(total=20)) as _r:
                        if _r.status == 200:
                            with open(_dest, "wb") as _f:
                                _f.write(await _r.read())
                            _TEMPO_FONT_PATH = _dest
                            print(f"[tempo] Fonte baixada: {_url}", flush=True)
                            return _dest
            except Exception:
                continue
    except Exception as _e:
        print(f"[WARN] _ensure_tempo_font: {_e}", flush=True)
    return None


async def _gen_tempo_card(
    target: discord.abc.User,
    guild: discord.Guild | None,
    total_sec: float,
    week_sec: float, week_mut: float, week_range: str,
    lw_sec: float,  lw_mut: float,  lw_range: str,
) -> io.BytesIO | None:
    try:
        from PIL import Image, ImageDraw, ImageFont
        import aiohttp as _ah
    except ImportError:
        return None
    try:
        font_path = await _ensure_tempo_font()
        W, H = 1380, 730
        img  = Image.new("RGB", (W, H), (0, 0, 0))
        draw = ImageDraw.Draw(img)

        # ── Fonts ────────────────────────────────────────────────────────────
        def _font(size: int):
            if font_path:
                try:
                    return ImageFont.truetype(font_path, size)
                except Exception:
                    pass
            try:
                return ImageFont.load_default(size=size)
            except TypeError:
                return ImageFont.load_default()

        f_xl  = _font(52)
        f_lg  = _font(58)
        f_md  = _font(26)
        f_sm  = _font(21)
        f_xs  = _font(18)
        f_cmp = _font(20)

        # ── Colors ───────────────────────────────────────────────────────────
        WHITE     = (255, 255, 255)
        GRAY      = (150, 150, 160)
        ACCENT    = (148, 75,  232)
        DARK_CARD = (20,  20,  28)
        RED_CARD  = (38,  8,   8)
        RED       = (220, 60,  60)
        GREEN     = (72,  200, 110)
        BORD_DK   = (60,  60,  90)
        BORD_RD   = (180, 50,  50)

        # ── Gradient background ───────────────────────────────────────────────
        for _gy in range(H):
            _gf = _gy / H
            _gr = int(7  + 9  * _gf)
            _gg = int(7  + 9  * _gf)
            _gb = int(12 + 14 * _gf)
            draw.line([(0, _gy), (W, _gy)], fill=(_gr, _gg, _gb))

        # ── Top accent stripe ─────────────────────────────────────────────────
        draw.rectangle([0, 0, W, 6], fill=ACCENT)

        # ── Download avatar ──────────────────────────────────────────────────
        async with _ah.ClientSession() as sess:
            async with sess.get(str(target.display_avatar.replace(size=256).url)) as r:
                av_bytes = await r.read()
            icon_bytes = None
            if guild and guild.icon:
                async with sess.get(str(guild.icon.replace(size=128).url)) as r:
                    icon_bytes = await r.read()

        av_size = 190
        av_raw  = Image.open(io.BytesIO(av_bytes)).convert("RGBA").resize((av_size, av_size), Image.LANCZOS)
        av_mask = Image.new("L", (av_size, av_size), 0)
        ImageDraw.Draw(av_mask).ellipse([0, 0, av_size, av_size], fill=255)
        av_raw.putalpha(av_mask)
        # Purple border on avatar
        border = av_size + 10
        bimg   = Image.new("RGBA", (border, border), (*ACCENT, 255))
        bm     = Image.new("L",    (border, border), 0)
        ImageDraw.Draw(bm).ellipse([0, 0, border, border], fill=255)
        bimg.putalpha(bm)
        img.paste(bimg.convert("RGB"), (45, 45), bm)
        img.paste(av_raw, (50, 50), av_mask)

        if icon_bytes:
            ic_size = 110
            ic = Image.open(io.BytesIO(icon_bytes)).convert("RGBA").resize((ic_size, ic_size), Image.LANCZOS)
            ic_mask = Image.new("L", (ic_size, ic_size), 0)
            ImageDraw.Draw(ic_mask).ellipse([0, 0, ic_size, ic_size], fill=255)
            ic.putalpha(ic_mask)
            img.paste(ic, (W - 150, 55), ic_mask)

        # ── Header text ──────────────────────────────────────────────────────
        _max_name_w = W - 270 - 180
        _display_name = target.display_name
        while len(_display_name) > 1:
            try:
                _tw = draw.textlength(_display_name, font=f_xl)
            except Exception:
                break
            if _tw <= _max_name_w:
                break
            _display_name = _display_name[:-1]
        if _display_name != target.display_name:
            _display_name = _display_name.rstrip() + "…"
        draw.text((270, 75),  _display_name, font=f_xl, fill=WHITE)
        draw.text((270, 145), f"Tempo total de voz: {_fmt_vt(total_sec)}", font=f_xs, fill=GRAY)

        # ── Separator ────────────────────────────────────────────────────────
        draw.rectangle([0, 248, W, 250], fill=(50, 40, 75))

        # ── Clock icon helper ─────────────────────────────────────────────────
        def _clock(cx: int, cy: int, r: int, c):
            draw.ellipse([cx-r, cy-r, cx+r, cy+r], outline=c, width=4)
            draw.line([cx, cy, cx, cy - r + 8],  fill=c, width=4)
            draw.line([cx, cy, cx + r - 10, cy], fill=c, width=4)
            draw.ellipse([cx-4, cy-4, cx+4, cy+4], fill=c)

        # ── Muted-mic icon helper ─────────────────────────────────────────────
        def _muted_mic(cx: int, cy: int, sz: int, c):
            mw = sz // 4
            draw.rounded_rectangle([cx - mw, cy - sz//3, cx + mw, cy + sz//8], radius=mw, outline=c, width=3)
            for ang_start, ang_end in [(0, 180)]:
                draw.arc([cx - sz//3, cy - sz//8, cx + sz//3, cy + sz//2], ang_start, ang_end, fill=c, width=3)
            draw.line([cx, cy + sz//2, cx, cy + sz//2 + sz//6], fill=c, width=3)
            draw.line([cx - sz//4, cy + sz//2 + sz//6, cx + sz//4, cy + sz//2 + sz//6], fill=c, width=3)
            draw.line([cx - sz//2 + 4, cy - sz//2 + 4, cx + sz//2 - 4, cy + sz//2 - 4], fill=c, width=5)

        # ── Comparison badge (esta semana vs passada) ─────────────────────────
        _cmp_text  = ""
        _cmp_color = GRAY
        if lw_sec > 0:
            _diff = (week_sec - lw_sec) / lw_sec * 100
            if _diff >= 1:
                _cmp_text  = f"▲ {_diff:.0f}% vs semana passada"
                _cmp_color = GREEN
            elif _diff <= -1:
                _cmp_text  = f"▼ {abs(_diff):.0f}% vs semana passada"
                _cmp_color = RED
            else:
                _cmp_text  = "≈ igual à semana passada"
                _cmp_color = GRAY

        # ── Column helper ─────────────────────────────────────────────────────
        COL_W = W // 2 - 50

        def _column(ox: int, title: str, date_s: str, t_sec: float, t_mut: float, show_cmp: bool = False):
            draw.text((ox, 265), title,         font=f_md, fill=WHITE)
            draw.text((ox, 298), f"({date_s})", font=f_xs, fill=GRAY)
            if show_cmp and _cmp_text:
                draw.text((ox, 323), _cmp_text, font=f_cmp, fill=_cmp_color)

            y1 = 358
            draw.rounded_rectangle([ox, y1, ox + COL_W, y1 + 148], radius=16, fill=DARK_CARD, outline=BORD_DK, width=2)
            _clock(ox + 65, y1 + 74, 30, WHITE)
            draw.text((ox + 115, y1 + 20), _fmt_vt(t_sec),          font=f_lg, fill=WHITE)
            draw.text((ox + 115, y1 + 98), "Tempo total da semana.", font=f_sm, fill=GRAY)

            y2 = y1 + 163
            draw.rounded_rectangle([ox, y2, ox + COL_W, y2 + 148], radius=16, fill=RED_CARD, outline=BORD_RD, width=2)
            _muted_mic(ox + 65, y2 + 74, 54, RED)
            draw.text((ox + 115, y2 + 20), _fmt_vt(t_mut),              font=f_lg, fill=RED)
            draw.text((ox + 115, y2 + 98), "Tempo que passou mutado.", font=f_sm, fill=GRAY)

        _column(30,          "TEMPO DA SEMANA",         week_range, week_sec, week_mut, show_cmp=True)
        _column(W // 2 + 20, "TEMPO DA SEMANA PASSADA", lw_range,   lw_sec,  lw_mut)

        # ── Vertical divider ──────────────────────────────────────────────────
        draw.rectangle([W // 2 - 5, 258, W // 2 - 3, H - 20], fill=(45, 35, 70))

        out = io.BytesIO()
        img.save(out, format="PNG")
        out.seek(0)
        return out
    except Exception as _e:
        print(f"[WARN] _gen_tempo_card: {_e}", flush=True)
        return None

_load_voice_time()

# ── Draft auto-save (persiste rascunho no disco para sobreviver a restarts) ────
_EMBED_DRAFTS_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), "embed_drafts.json")
_embed_auto_drafts: dict[str, dict] = {}

def _load_embed_drafts() -> None:
    global _embed_auto_drafts
    try:
        if os.path.exists(_EMBED_DRAFTS_FILE):
            with open(_EMBED_DRAFTS_FILE, "r", encoding="utf-8") as f:
                _embed_auto_drafts = json.load(f)
    except Exception:
        _embed_auto_drafts = {}

def _save_embed_draft(guild_id: int, user_id: int, draft: dict) -> None:
    serializable = {k: v for k, v in draft.items() if not isinstance(v, (bytes, bytearray))}
    key = f"{guild_id}:{user_id}"
    _embed_auto_drafts[key] = {"draft": serializable, "ts": time.time()}
    try:
        with open(_EMBED_DRAFTS_FILE, "w", encoding="utf-8") as f:
            json.dump(_embed_auto_drafts, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

def _get_embed_draft(guild_id: int, user_id: int) -> dict | None:
    key = f"{guild_id}:{user_id}"
    entry = _embed_auto_drafts.get(key)
    if not entry:
        return None
    if time.time() - entry.get("ts", 0) > 86400:  # expira após 24h
        _pop_embed_draft(guild_id, user_id)
        return None
    draft = entry.get("draft") or {}
    if not (draft.get("title") or draft.get("description")
            or draft.get("sep_blocks") or draft.get("buttons")):
        return None
    return draft

def _pop_embed_draft(guild_id: int, user_id: int) -> None:
    key = f"{guild_id}:{user_id}"
    if key in _embed_auto_drafts:
        del _embed_auto_drafts[key]
        try:
            with open(_EMBED_DRAFTS_FILE, "w", encoding="utf-8") as f:
                json.dump(_embed_auto_drafts, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

EMBED_BTN_COLOR_MAP = {
    "primary": discord.ButtonStyle.primary,
    "secondary": discord.ButtonStyle.secondary,
    "success": discord.ButtonStyle.success,
    "danger": discord.ButtonStyle.danger,
    "link": discord.ButtonStyle.link,
}


def _empty_embed_draft() -> dict:
    return {
        "title": None,
        "description": None,
        "color": None,
        "thumbnail": None,
        "image": None,
        "footer_text": None,
        "footer_icon": None,
        "author_name": None,
        "author_icon": None,
        "author_url": None,
        "buttons": [],
        "sep_blocks": [],  # [{divider: bool, spacing: "small"|"large"}]
    }


def _draft_to_embed(draft: dict, default_color: int) -> discord.Embed:
    color = draft.get("color")
    if not isinstance(color, int):
        color = default_color
    embed = discord.Embed(
        title=draft.get("title") or None,
        description=draft.get("description") or None,
        color=color,
    )
    if draft.get("thumbnail"):
        try:
            embed.set_thumbnail(url=draft["thumbnail"])
        except Exception:
            pass
    if draft.get("image"):
        try:
            embed.set_image(url=draft["image"])
        except Exception:
            pass
    if draft.get("footer_text") or draft.get("footer_icon"):
        embed.set_footer(
            text=draft.get("footer_text") or "",
            icon_url=draft.get("footer_icon") or None,
        )
    if draft.get("author_name") or draft.get("author_icon") or draft.get("author_url"):
        embed.set_author(
            name=draft.get("author_name") or "",
            icon_url=draft.get("author_icon") or None,
            url=draft.get("author_url") or None,
        )
    return embed


def _draft_view_from_buttons(draft: dict) -> discord.ui.View | None:
    btns = draft.get("buttons", [])
    if not btns:
        return None
    v = discord.ui.View(timeout=None)
    for i, b in enumerate(btns[:25]):
        style = EMBED_BTN_COLOR_MAP.get(b.get("color", "secondary"), discord.ButtonStyle.secondary)
        emoji = None
        emoji_raw = b.get("emoji")
        if emoji_raw:
            try:
                if emoji_raw.startswith("<") and emoji_raw.endswith(">"):
                    emoji = discord.PartialEmoji.from_str(emoji_raw)
                else:
                    emoji = emoji_raw
            except Exception:
                emoji = None
        if b.get("type") == "link" and b.get("response"):
            btn = discord.ui.Button(
                style=discord.ButtonStyle.link, label=b.get("text", "Link"),
                url=b["response"], emoji=emoji, row=i // 5,
            )
        elif b.get("type") == "verif_check":
            btn = discord.ui.Button(
                style=discord.ButtonStyle.success, label=b.get("text", "Verificar"),
                emoji=emoji or "✅", row=i // 5, custom_id="verif_check",
            )
        elif b.get("type") == "ig_verif_check":
            btn = discord.ui.Button(
                style=discord.ButtonStyle.secondary, label=b.get("text", "verificar"),
                emoji=None, row=i // 5, custom_id="ig_verif_check",
            )
        else:
            btn = discord.ui.Button(
                style=style, label=b.get("text", "Botão"),
                emoji=emoji, row=i // 5, custom_id=f"embed_btn_{i}",
            )
        v.add_item(btn)
    return v


