class EmbedTextModal(discord.ui.Modal):
    def __init__(self, parent_view: "EmbedBuilderView", t: dict, field: str):
        titles = {
            "title": t["embed_modal_title_text"],
            "description": t["embed_modal_desc_text"],
            "color": t["embed_modal_color_text"],
            "thumbnail": t["embed_modal_thumb_text"],
            "image": t["embed_modal_image_text"],
        }
        super().__init__(title=titles[field], timeout=300)
        self.parent_view = parent_view
        self.field = field
        labels_placeholders = {
            "title": (t["embed_input_title_label"], None, 256, discord.TextStyle.short),
            "description": (t["embed_input_desc_label"], None, 4000, discord.TextStyle.paragraph),
            "color": (t["embed_input_color_label"], "#5865F2", 10, discord.TextStyle.short),
            "thumbnail": (t["embed_input_url_label"], "https://...", 500, discord.TextStyle.short),
            "image": (t["embed_input_url_label"], "https://...", 500, discord.TextStyle.short),
        }
        label, placeholder, mx, style = labels_placeholders[field]
        current = parent_view.draft.get(
            "color" if field == "color" else field
        )
        if field == "color" and isinstance(current, int):
            default = f"#{current:06X}"
        else:
            default = current
        self.inp = discord.ui.TextInput(
            label=label, placeholder=placeholder, required=False,
            max_length=mx, style=style, default=default or None,
        )
        self.add_item(self.inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        val = self.inp.value.strip() or None
        if self.field == "color" and val:
            raw = val.lstrip("#")
            try:
                self.parent_view.draft["color"] = int(raw, 16)
            except ValueError:
                await interaction.response.send_message(embed=_notif_embed(t["ticket_embed_invalid_color"]), ephemeral=True)
                return
        else:
            self.parent_view.draft[self.field] = val
        await self.parent_view._refresh(interaction)
        await interaction.followup.send(embed=_notif_embed(t["embed_set_ok"]), ephemeral=True)


