class EmbedSepModal(discord.ui.Modal, title="Adicionar Separador"):
    """Modal nativo do Discord — idêntico ao da nata."""

    tipo = discord.ui.Label(
        text="Tipo *",
        description="Escolha se terá linha divisória",
        component=discord.ui.Select(options=[
            discord.SelectOption(label="Com linha", value="com", description="Mostra uma linha divisória"),
            discord.SelectOption(label="Sem linha", value="sem", description="Apenas espaçamento"),
        ]),
    )

    espacamento = discord.ui.Label(
        text="Espaçamento *",
        description="Define o tamanho do espaçamento",
        component=discord.ui.Select(options=[
            discord.SelectOption(label="Pequeno", value="small", description="Espaçamento menor"),
            discord.SelectOption(label="Grande",  value="large", description="Espaçamento maior"),
        ]),
    )

    def __init__(self, parent_view: "EmbedBuilderView"):
        super().__init__()
        self.parent_view = parent_view

    async def on_submit(self, interaction: discord.Interaction):
        tipo_val = self.tipo.component.values[0]     if self.tipo.component.values     else "com"
        esp_val  = self.espacamento.component.values[0] if self.espacamento.component.values else "small"

        self.parent_view.draft.setdefault("sep_blocks", []).append({
            "divider": tipo_val == "com",
            "spacing": esp_val,
        })
        await interaction.response.send_message(
            f"{EMOJI_CHECK} Separador adicionado!", ephemeral=True
        )
        await self.parent_view.update_main()


