class EmbedSubSelect(discord.ui.Select):
    """Sub-selector for actions within a section."""
    def __init__(self, parent_view: "EmbedBuilderView", section: str, t: dict):
        if section == "embed":
            placeholder = t["embed_builder_select_sub_embed"]
            options = [
                discord.SelectOption(label=t["embed_action_title"], value="title",
                                     emoji=_make_select_emoji("<:tickets:1518271952526250155>")),
                discord.SelectOption(label=t["embed_action_description"], value="description",
                                     emoji=_make_select_emoji("<:Mov_chat:1518271970008105031>")),
                discord.SelectOption(label=t["embed_action_color"], value="color",
                                     emoji=_make_select_emoji("<:aparncia_:1518271975317962895>")),
                discord.SelectOption(label=t["embed_action_back"], value="__back__",
                                     emoji=_make_select_emoji(EMOJI_BACK)),
            ]
        elif section == "images":
            placeholder = t["embed_builder_select_sub_images"]
            options = [
                discord.SelectOption(label=t["embed_action_thumbnail"], value="thumbnail",
                                     emoji=_make_select_emoji("<:gifs:1518272035762081835>")),
                discord.SelectOption(label=t["embed_action_image"], value="image",
                                     emoji=_make_select_emoji("<:gifs:1518272035762081835>")),
                discord.SelectOption(label=t["embed_action_back"], value="__back__",
                                     emoji=_make_select_emoji(EMOJI_BACK)),
            ]
        else:  # extras
            placeholder = t["embed_builder_select_sub_extras"]
            options = [
                discord.SelectOption(label=t["embed_action_footer"], value="footer",
                                     emoji=_make_select_emoji("<:ferramentas_:1518271998613131274>")),
                discord.SelectOption(label=t["embed_action_author"], value="author",
                                     emoji=_make_select_emoji("<:comunidade_:1518272016971595807>")),
                discord.SelectOption(label=t["embed_action_back"], value="__back__",
                                     emoji=_make_select_emoji(EMOJI_BACK)),
            ]
        super().__init__(placeholder=placeholder, options=options, min_values=1, max_values=1, row=0)
        self.parent_view = parent_view
        self.section = section

    async def callback(self, interaction: discord.Interaction):
        action = self.values[0]
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if action == "__back__":
            self.parent_view.section = None
            await self.parent_view._rebuild(interaction)
            return

        # Para tudo, usa chat-based input (sem modal)
        prompts = {
            "title": (t["embed_title_prompt"], t["embed_title_set"]),
            "description": (t["embed_desc_prompt"], t["embed_desc_set"]),
            "color": (t["embed_color_prompt"], t["embed_color_set_ok"]),
            "thumbnail": (t["embed_thumb_prompt"], t["embed_image_set"]),
            "image": (t["embed_image_prompt"], t["embed_image_set"]),
            "footer": (t["embed_footer_prompt"], t["embed_footer_set"]),
            "author": (t["embed_author_prompt"], t["embed_author_set"]),
        }
        if action not in prompts:
            await interaction.response.defer()
            return

        prompt, success_msg = prompts[action]
        await interaction.response.send_message(
            f"{prompt}\n_{t['embed_image_cancel_hint']}_", ephemeral=True
        )

        author_id = interaction.user.id
        channel_id = interaction.channel.id

        def check(m: discord.Message) -> bool:
            return m.author.id == author_id and m.channel.id == channel_id

        try:
            msg = await bot.wait_for("message", check=check, timeout=180)
        except asyncio.TimeoutError:
            await interaction.followup.send(embed=_notif_embed(t["welcome_timed_out"]), ephemeral=True)
            return

        content = (msg.content or "").strip()

        # Deleta a mensagem ephemeral de instrução
        try:
            await interaction.delete_original_response()
        except Exception:
            pass

        # Cancel?
        if content.lower() in ("cancelar", "cancel"):
            try:
                await msg.delete()
            except Exception:
                pass
            await interaction.followup.send(embed=_notif_embed(t["embed_cancelled"]), ephemeral=True)
            return

        if action in ("thumbnail", "image"):
            url = None
            att_bytes: bytes | None = None
            att_ext   = "png"
            # Prioridade 1: anexo de imagem → baixa os bytes imediatamente
            for att in msg.attachments:
                is_img = (
                    (att.content_type and att.content_type.startswith("image/"))
                    or (att.filename or "").lower().endswith((".png", ".jpg", ".jpeg", ".gif", ".webp"))
                )
                if is_img:
                    url = att.url
                    _ext_raw = (att.filename or "img").rsplit(".", 1)[-1].lower()
                    att_ext  = _ext_raw if _ext_raw in ("jpg", "jpeg", "png", "gif", "webp") else "png"
                    try:
                        att_bytes = await att.read()
                    except Exception:
                        att_bytes = None
                    # proxy_url salvo separadamente para uso no preview (não expira)
                    self.parent_view.draft[f"_{action}_proxy"] = att.proxy_url or att.url
                    break
            # Prioridade 2: URL no texto
            if not url and content.startswith(("http://", "https://")):
                url = content
            if not url:
                try:
                    await msg.delete()
                except (discord.Forbidden, discord.NotFound):
                    pass
                await interaction.followup.send(embed=_notif_embed(t["embed_image_invalid"]), ephemeral=True)
                return

            # Salva bytes no draft para usar no envio final (garante que não expire)
            self.parent_view.draft[action] = url
            if att_bytes:
                self.parent_view.draft[f"_{action}_bytes"] = att_bytes
                self.parent_view.draft[f"_{action}_ext"]   = att_ext
            print(f"[Embed] {action} setado ({len(att_bytes) if att_bytes else 0}b): {url[:200]}")

            # Atualiza preview ANTES de deletar (URL ainda válida)
            await self.parent_view.update_main()
            try:
                await msg.delete()
            except Exception:
                pass
            await interaction.followup.send(success_msg, ephemeral=True)
            return

        if action == "color":
            raw = content.lstrip("#")
            try:
                self.parent_view.draft["color"] = int(raw, 16)
            except ValueError:
                try:
                    await msg.delete()
                except Exception:
                    pass
                await interaction.followup.send(embed=_notif_embed(t["embed_invalid_color_hex"]), ephemeral=True)
                return
            try:
                await msg.delete()
            except Exception:
                pass
            print(f"[Embed] color setado para: {self.parent_view.draft.get('color')}")
            await self.parent_view.update_main()
            await interaction.followup.send(success_msg, ephemeral=True)
            return

        # title, description, footer, author — texto puro
        max_lens = {
            "title": 256, "description": 4000,
            "footer": 2048, "author": 256,
        }
        max_len = max_lens.get(action, 2000)
        text = content[:max_len]
        if action == "footer":
            self.parent_view.draft["footer_text"] = text or None
        elif action == "author":
            self.parent_view.draft["author_name"] = text or None
        else:
            # action is "title" or "description"
            self.parent_view.draft[action] = text or None

        try:
            await msg.delete()
        except Exception:
            pass
        # Log para debug
        print(f"[Embed] {action} setado para: {repr(self.parent_view.draft.get('footer_text' if action == 'footer' else 'author_name' if action == 'author' else action))[:80]}")
        await self.parent_view.update_main()
        await interaction.followup.send(success_msg, ephemeral=True)


# Botões da Embed (gerenciar e criar) ----------------------------------------

class EmbedButtonsView(discord.ui.View):
    def __init__(self, parent_view: "EmbedBuilderView"):
        super().__init__(timeout=None)
        self.parent_view = parent_view
        self._build()

    def _build(self):
        self.clear_items()
        settings = get_settings(self.parent_view.author.guild.id)
        t = TRANSLATIONS[settings["language"]]

        btns = self.parent_view.draft.get("buttons", [])
        max_reached = len(btns) >= 15

        # Existing buttons as editable (with pencil)
        for i, b in enumerate(btns):
            style = EMBED_BTN_COLOR_MAP.get(b.get("color", "secondary"), discord.ButtonStyle.secondary)
            if style == discord.ButtonStyle.link:
                style = discord.ButtonStyle.secondary
            emoji_raw = b.get("emoji") or None
            emoji = "<:f1:1518271958024720555>"
            if emoji_raw:
                try:
                    emoji = discord.PartialEmoji.from_str(emoji_raw) if emoji_raw.startswith("<") else emoji_raw
                except Exception:
                    emoji = "<:f1:1518271958024720555>"
            btn = discord.ui.Button(
                label=b.get("text") or f"Botão {i+1}",
                style=style, emoji=emoji, row=i // 5,
            )
            btn.callback = self._make_edit_callback(i)
            self.add_item(btn)

        # Adicionar Botão fica na mesma linha do último botão existente
        add_row = len(btns) // 5
        back_row = add_row + 1

        add_btn = discord.ui.Button(
            label=t["btn_adicionar_botao"],
            style=discord.ButtonStyle.success,
            emoji="<a:online:1518271945550856295>",
            disabled=max_reached,
            row=add_row,
        )
        add_btn.callback = self._add
        self.add_item(add_btn)

        back_btn = discord.ui.Button(
            label=t["back"], style=discord.ButtonStyle.secondary,
            emoji=_button_emoji(discord.ButtonStyle.primary),
            row=back_row,
        )
        back_btn.callback = self._back
        self.add_item(back_btn)

    def _build_embed(self) -> discord.Embed:
        settings = get_settings(self.parent_view.author.guild.id)
        t = TRANSLATIONS[settings["language"]]
        btns = self.parent_view.draft.get("buttons", [])
        embed = discord.Embed(
            title=t["embed_buttons_panel_title"],
            color=settings["embed_color"],
            description=(
                f"{t['embed_buttons_count'].format(count=len(btns))}\n\n"
                f"**{t['embed_buttons_how_title']}**\n"
                f"{t['embed_buttons_how_text']}\n\n"
                f"{t['embed_buttons_final_note']}\n\n"
                f"_{t['embed_buttons_use_hint']}_"
            ),
        )
        return embed

    def _make_edit_callback(self, idx: int):
        async def cb(interaction: discord.Interaction):
            view = EmbedNewButtonView(self.parent_view, idx)
            embed = view._build_embed()
            await interaction.response.edit_message(content=None, embed=embed, view=view, attachments=[])
        return cb

    async def _add(self, interaction: discord.Interaction):
        view = EmbedNewButtonView(self.parent_view, None)
        embed = view._build_embed()
        await interaction.response.edit_message(content=None, embed=embed, view=view, attachments=[])

    async def _back(self, interaction: discord.Interaction):
        self.parent_view.section = None
        await self.parent_view._rebuild(interaction)


class EmbedNewButtonModal(discord.ui.Modal):
    def __init__(self, parent_view: "EmbedNewButtonView", field: str, t: dict):
        is_link = parent_view.draft_btn.get("type") == "link" and field == "response"
        titles = {
            "text": t["embed_btn_modal_text"],
            "type": t["embed_btn_modal_type"],
            "color": t["embed_btn_modal_color"],
            "emoji": t["embed_btn_modal_emoji"],
            "response": "URL do Botão de Link" if is_link else t["embed_btn_modal_response"],
        }
        super().__init__(title=titles[field], timeout=300)
        self.parent_view = parent_view
        self.field = field
        labels = {
            "text": (t["embed_btn_input_text_label"], 80),
            "type": (t["embed_btn_input_type_label"], 20),
            "color": (t["embed_btn_input_color_label"], 20),
            "emoji": (t["embed_btn_input_emoji_label"], 100),
            "response": ("URL (ex: https://discord.gg/...)" if is_link else t["embed_btn_input_response_label"], 2000),
        }
        label, mx = labels[field]
        style = discord.TextStyle.paragraph if (field == "response" and not is_link) else discord.TextStyle.short
        current = parent_view.draft_btn.get(field) or None
        self.inp = discord.ui.TextInput(
            label=label, required=True, max_length=mx, style=style,
            default=current,
            placeholder="https://discord.gg/seuservidor" if is_link else None,
        )
        self.add_item(self.inp)

    async def on_submit(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        val = self.inp.value.strip()
        if self.field == "type":
            v = val.lower()
            if v not in ("link", "action", "role", "embed"):
                await interaction.response.send_message(embed=_notif_embed(t["embed_btn_invalid_type"]), ephemeral=True)
                return
            self.parent_view.draft_btn["type"] = v
        elif self.field == "color":
            v = val.lower()
            if v not in EMBED_BTN_COLOR_MAP:
                await interaction.response.send_message(embed=_notif_embed(t["embed_btn_invalid_color"]), ephemeral=True)
                return
            self.parent_view.draft_btn["color"] = v
        elif self.field == "text":
            self.parent_view.draft_btn["text"] = val[:80]
        elif self.field == "emoji":
            self.parent_view.draft_btn["emoji"] = None if val.lower() == "remover" else val
        else:
            self.parent_view.draft_btn[self.field] = val
        self.parent_view._build()
        embed = self.parent_view._build_embed()
        await interaction.response.edit_message(embed=embed, view=self.parent_view, attachments=[])


class EmbedNewButtonView(discord.ui.View):
    def __init__(self, parent_view: "EmbedBuilderView", edit_idx: int | None):
        super().__init__(timeout=None)
        self.parent_view = parent_view
        self.edit_idx = edit_idx
        if edit_idx is not None:
            existing = parent_view.draft["buttons"][edit_idx].copy()
            self.draft_btn = existing
        else:
            self.draft_btn = {"text": None, "type": None, "color": None, "emoji": None, "response": None}
        self._build()

    def _build(self):
        self.clear_items()
        settings = get_settings(self.parent_view.author.guild.id)
        t = TRANSLATIONS[settings["language"]]
        is_link = self.draft_btn.get("type") == "link"

        # Texto do Botão
        btn_text = discord.ui.Button(label=t["btn_definir_texto_botao"], style=discord.ButtonStyle.secondary, row=0)
        btn_text.callback = self._make_field_cb("text")
        self.add_item(btn_text)

        # Tipo
        btn_type = discord.ui.Button(label=t["btn_definir_tipo"], style=discord.ButtonStyle.secondary, row=0)
        btn_type.callback = self._make_field_cb("type")
        self.add_item(btn_type)

        # Cor — desabilitado e renomeado se for link
        btn_color = discord.ui.Button(
            label="Cor (automática)" if is_link else t["btn_definir_cor"],
            style=discord.ButtonStyle.secondary,
            disabled=is_link,
            row=0,
        )
        if not is_link:
            btn_color.callback = self._make_field_cb("color")
        self.add_item(btn_color)

        # Emoji — desabilitado e renomeado se for link
        btn_emoji = discord.ui.Button(
            label="Emoji (indisponível)" if is_link else t["btn_definir_emoji_botao"],
            style=discord.ButtonStyle.secondary,
            disabled=is_link,
            row=0,
        )
        if not is_link:
            btn_emoji.callback = self._make_field_cb("emoji")
        self.add_item(btn_emoji)

        # Resposta vira URL se for link
        btn_resp = discord.ui.Button(
            label="URL" if is_link else t["btn_definir_resposta"],
            style=discord.ButtonStyle.secondary,
            row=1,
        )
        btn_resp.callback = self._make_field_cb("response")
        self.add_item(btn_resp)

        vis_btn = discord.ui.Button(label=t["btn_visualizar"], style=discord.ButtonStyle.primary, row=1)
        vis_btn.callback = self._visualize
        self.add_item(vis_btn)

        fin_btn = discord.ui.Button(
            label=t["btn_finalizar_botao"], style=discord.ButtonStyle.success,
            emoji="<a:online:1518271945550856295>", row=2,
        )
        fin_btn.callback = self._finalize
        self.add_item(fin_btn)

        cancel_btn = discord.ui.Button(
            label=t["btn_cancelar"], style=discord.ButtonStyle.danger,
            emoji="<a:alerta:1518271939460857968>", row=2,
        )
        cancel_btn.callback = self._cancel
        self.add_item(cancel_btn)

    def _make_field_cb(self, field: str):
        async def cb(interaction: discord.Interaction):
            settings = get_settings(interaction.guild.id)
            t = TRANSLATIONS[settings["language"]]

            # ── Tipo: embed dedicada com botões clicáveis ─────────────────────
            if field == "type":
                embed = discord.Embed(
                    title="Tipo do Botão",
                    description="Selecione o tipo de botão que deseja criar:",
                    color=settings["embed_color"],
                )
                embed.add_field(name="Texto",  value="Exibe uma mensagem\nquando clicado", inline=True)
                embed.add_field(name="Embed",  value="Exibe uma embed quando\nclicado",    inline=True)
                embed.add_field(name="Link",   value="Redireciona para um site\nexterno",  inline=True)

                type_view = discord.ui.View(timeout=120)
                for lbl, val in [("Texto", "action"), ("Embed", "embed"), ("Link", "link")]:
                    btn = discord.ui.Button(label=lbl, style=discord.ButtonStyle.secondary)
                    async def type_cb(intr: discord.Interaction, v=val, lv=lbl):
                        self.draft_btn["type"] = v
                        if v == "link":
                            self.draft_btn["color"] = "link"
                            self.draft_btn["emoji"] = None
                            self._build()
                            upd = self._build_embed()
                            await intr.response.edit_message(embed=upd, view=self)
                            await intr.followup.send(
                                f"{EMOJI_CHECK} Tipo **link** selecionado! Cor definida automaticamente como **link** e emoji removido (botões de link não suportam emojis)",
                                ephemeral=True,
                            )
                        else:
                            self._build()
                            upd = self._build_embed()
                            await intr.response.edit_message(embed=upd, view=self)
                            await intr.followup.send(f"{EMOJI_CHECK} Tipo definido: **{lv}**", ephemeral=True)
                    btn.callback = type_cb
                    type_view.add_item(btn)

                await interaction.response.edit_message(embed=embed, view=type_view)
                return

            # ── Cor: embed dedicada com botões coloridos ──────────────────────
            if field == "color":
                embed = discord.Embed(
                    title="Cor do Botão",
                    description="Selecione a cor do botão:",
                    color=settings["embed_color"],
                )
                embed.add_field(name="🔵 Primário",   value="Azul - Para ações\nprincipais",        inline=True)
                embed.add_field(name="⚫ Secundário", value="Cinza - Para ações\nsecundárias",       inline=True)
                embed.add_field(name="🟢 Sucesso",    value="Verde - Para\nconfirmações",            inline=True)
                embed.add_field(name="🔴 Perigo",     value="Vermelho - Para ações\nde alerta",      inline=True)
                embed.add_field(name="🔗 Link",       value="Cor padrão do Discord",                 inline=True)

                color_view = discord.ui.View(timeout=120)
                color_opts = [
                    ("Primário",   "primary",   discord.ButtonStyle.primary),
                    ("Secundário", "secondary", discord.ButtonStyle.secondary),
                    ("Sucesso",    "success",   discord.ButtonStyle.success),
                    ("Perigo",     "danger",    discord.ButtonStyle.danger),
                    ("Link (tipo link apenas)", "link", discord.ButtonStyle.secondary),
                ]
                for lbl, val, style in color_opts:
                    btn = discord.ui.Button(label=lbl, style=style)
                    async def color_cb(intr: discord.Interaction, v=val, lv=lbl):
                        self.draft_btn["color"] = v
                        upd = self._build_embed()
                        await intr.response.edit_message(embed=upd, view=self)
                        await intr.followup.send(f"{EMOJI_CHECK} Cor definida: **{lv}**", ephemeral=True)
                    btn.callback = color_cb
                    color_view.add_item(btn)

                await interaction.response.edit_message(embed=embed, view=color_view)
                return

            # ── Validação: resposta exige tipo definido ───────────────────────
            if field == "response" and not self.draft_btn.get("type"):
                err = discord.Embed(
                    description="Defina o tipo do botão primeiro!",
                    color=discord.Color.red(),
                )
                await interaction.response.send_message(embed=err, ephemeral=True)
                return

            # ── Text, Emoji, Resposta/URL: prompt ephemeral no chat ──────────
            is_link = self.draft_btn.get("type") == "link"
            prompts = {
                "text": (
                    f"**Texto do Botão**\n"
                    f"Envie o texto que aparecerá no botão (máximo 80 caracteres):\n\n"
                    f"**Exemplos:**\n• `Suporte`\n• `Regras do Servidor`\n• `Website`"
                ),
                "emoji": (
                    f"**Emoji do Botão**\n"
                    f"Envie o emoji que aparecerá no botão ou digite **remover** para remover o emoji atual"
                ),
                "response": (
                    f"**URL do Botão de Link**\n"
                    f"Envie a URL completa para onde o botão deve redirecionar:\n\n"
                    f"**Exemplos:**\n• `https://discord.gg/seuservidor`\n• `https://meusite.com`\n• `https://github.com/meuusuario`\n\n"
                    f"**Importante:** A URL deve começar com `http://` ou `https://`"
                ) if is_link else (
                    f"**Conteúdo da Embed**\n"
                    f"Envie o texto que aparecerá na embed quando o botão for clicado:\n\n"
                    f"**Exemplo:**\n"
                    f"```\U0001f517 **Links Úteis**\n• Website: https://hypebot\n• Discord: https://discord.gg/hypebot```"
                ),
            }
            prompt_text = prompts.get(field, f"**{field}**\nEnvie o valor:") + "\n\n_Para cancelar, envie `cancelar`_"
            await interaction.response.send_message(prompt_text, ephemeral=True)

            author_id = interaction.user.id
            channel_id = interaction.channel.id

            def check(m: discord.Message) -> bool:
                return m.author.id == author_id and m.channel.id == channel_id

            try:
                msg = await bot.wait_for("message", check=check, timeout=180)
            except asyncio.TimeoutError:
                await interaction.followup.send(f"{EMOJI_DANGER} Tempo esgotado.", ephemeral=True)
                return

            val = (msg.content or "").strip()
            try:
                await msg.delete()
            except Exception:
                pass
            try:
                await interaction.delete_original_response()
            except Exception:
                pass

            if val.lower() in ("cancelar", "cancel"):
                await interaction.followup.send(f"{EMOJI_DANGER} Cancelado.", ephemeral=True)
                return

            if field == "emoji" and val.lower() == "remover":
                self.draft_btn["emoji"] = None
            elif field == "text":
                self.draft_btn["text"] = val[:80]
            else:
                self.draft_btn[field] = val

            self._build()
            embed = self._build_embed()
            try:
                await interaction.message.edit(embed=embed, view=self)
            except Exception:
                pass
            await interaction.followup.send(f"{EMOJI_CHECK} Configurado!", ephemeral=True)

        return cb

    def _build_embed(self) -> discord.Embed:
        settings = get_settings(self.parent_view.author.guild.id)
        t = TRANSLATIONS[settings["language"]]
        lang = settings["language"]
        d = self.draft_btn
        nd = t["not_defined"].rstrip(".")  # "Não definido" sem ponto

        # Traduções de cor e tipo para PT-BR
        _cor_map_pt = {"primary": "primário", "secondary": "secundário", "success": "sucesso",
                       "danger": "perigo", "link": "link"}
        _tipo_map_pt = {"action": "texto", "embed": "embed", "link": "link", "role": "cargo"}
        _cor_map_en = {"primary": "primary", "secondary": "secondary", "success": "success",
                       "danger": "danger", "link": "link"}
        _tipo_map_en = {"action": "action", "embed": "embed", "link": "link", "role": "role"}
        cor_map  = _cor_map_pt  if lang == "pt-br" else _cor_map_en
        tipo_map = _tipo_map_pt if lang == "pt-br" else _tipo_map_en

        header = "Configuração atual:" if lang == "pt-br" else "Current configuration:"

        embed = discord.Embed(
            title=t["embed_btn_new_title"],
            color=settings["embed_color"],
            description=f"**{header}**",
        )
        # 3 colunas inline: Texto do Botão | Tipo | Cor
        embed.add_field(
            name=t["embed_btn_text"],
            value=d.get("text") or nd,
            inline=True,
        )
        embed.add_field(
            name=t["embed_btn_type"],
            value=tipo_map.get(d.get("type") or "", d.get("type") or nd),
            inline=True,
        )
        embed.add_field(
            name=t["embed_btn_color"],
            value=cor_map.get(d.get("color") or "", d.get("color") or nd),
            inline=True,
        )
        # Linha cheia: Emoji
        embed.add_field(
            name=t["embed_btn_emoji"],
            value=d.get("emoji") or nd,
            inline=False,
        )
        # Linha cheia: Resposta/URL
        resp = d.get("response") or nd
        embed.add_field(
            name=t["embed_btn_response"],
            value=resp[:200],
            inline=False,
        )
        embed.set_footer(text=t["embed_btn_finalize_hint"])
        return embed

    async def _visualize(self, interaction: discord.Interaction):
        d = self.draft_btn
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if not d.get("text") or not d.get("type") or not d.get("color"):
            err_embed = discord.Embed(
                description=t["embed_btn_visualize_required"],
                color=discord.Color.red(),
            )
            await interaction.response.send_message(embed=err_embed, ephemeral=True)
            return
        style = EMBED_BTN_COLOR_MAP.get(d.get("color") or "secondary", discord.ButtonStyle.secondary)
        emoji_raw = d.get("emoji") or None  # garante que string vazia vira None
        emoji = None
        if emoji_raw:
            try:
                if emoji_raw.startswith("<"):
                    emoji = discord.PartialEmoji.from_str(emoji_raw)
                else:
                    emoji = emoji_raw
            except Exception:
                emoji = None

        preview_embed = discord.Embed(
            title="Visualização do Botão",
            color=settings["embed_color"],
            description=(
                f"**Como ficará:**\n"
                f"• **Texto:** {d.get('text') or 'Não definido'}\n"
                f"• **Tipo:** {d.get('type') or 'Não definido'}\n"
                f"• **Cor:** {d.get('color') or 'Não definido'}\n"
                f"• **Emoji:** {emoji_raw if emoji_raw else 'Nenhum'}\n"
                f"• **Resposta:**\n{d.get('response') or 'Não definida'}"
            ),
        )

        v = discord.ui.View()
        is_link_type = style == discord.ButtonStyle.link
        url = d.get("response") if is_link_type else None
        if is_link_type and not url:
            url = "https://discord.gg/hypebot"
        v.add_item(discord.ui.Button(
            style=discord.ButtonStyle.link if is_link_type else style,
            label=d.get("text") or "?",
            emoji=emoji,
            url=url,
            disabled=not is_link_type,
        ))
        await interaction.response.send_message(embed=preview_embed, view=v, ephemeral=True)

    async def _finalize(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if not self.draft_btn.get("text"):
            await interaction.response.send_message(embed=_notif_embed(t["embed_btn_text_required"]), ephemeral=True)
            return
        btns = self.parent_view.draft.setdefault("buttons", [])
        if self.edit_idx is not None and 0 <= self.edit_idx < len(btns):
            btns[self.edit_idx] = self.draft_btn
        else:
            if len(btns) >= 15:
                btns[14] = self.draft_btn
            else:
                btns.append(self.draft_btn)
        view = EmbedButtonsView(self.parent_view)
        embed = view._build_embed()
        await interaction.response.edit_message(content=None, embed=embed, view=view, attachments=[])
        await interaction.followup.send(embed=_notif_embed(t["embed_btn_finalized"]), ephemeral=True)

    async def _cancel(self, interaction: discord.Interaction):
        view = EmbedButtonsView(self.parent_view)
        embed = view._build_embed()
        await interaction.response.edit_message(content=None, embed=embed, view=view, attachments=[])


# Main Embed Builder View ----------------------------------------------------

class EmbedBuilderView(discord.ui.View):
    def __init__(self, author: discord.Member, target_channel: discord.TextChannel,
                 draft: dict | None = None, edit_message_id: int | None = None):
        super().__init__(timeout=None)  # 1 hora
        self.author = author
        self.target_channel = target_channel
        self.draft = draft or _empty_embed_draft()
        self.edit_message_id = edit_message_id
        self.section: str | None = None  # None = show top-level select
        self.main_message: discord.Message | None = None
        self._build()

    def header_embed(self) -> discord.Embed:
        """Embed wrapper for the header text (dark color = invisible bar)."""
        embed = discord.Embed(
            description=self.header_text(),
            color=0x2B2D31,  # Discord dark theme — invisible left bar
        )
        return embed

    def preview_embed(self) -> discord.Embed | None:
        """Return preview embed if draft has at least title/description, else None."""
        if not (self.draft.get("title") or self.draft.get("description")
                or self.draft.get("thumbnail") or self.draft.get("image")
                or self.draft.get("footer_text") or self.draft.get("author_name")):
            return None
        # Cor invisível pra ficar igual ao Nata (sem barra lateral colorida no preview)
        default_color = self.draft.get("color") or 0x2B2D31
        return _draft_to_embed(self.draft, default_color)

    def _build_embeds_from_draft(self, draft: dict) -> list[discord.Embed]:
        """Constrói embeds a partir de um draft customizado (pode ter attachment://)."""
        color = draft.get("color") if isinstance(draft.get("color"), int) else 0x2B2D31
        desc_parts = [self.header_text()]
        if draft.get("description"):
            desc_parts.append("")
            desc_parts.append(draft["description"])
        embed = discord.Embed(
            title=draft.get("title") or None,
            description="\n".join(desc_parts),
            color=color,
        )
        if draft.get("thumbnail"):
            try: embed.set_thumbnail(url=draft["thumbnail"])
            except Exception: pass
        if draft.get("image"):
            try: embed.set_image(url=draft["image"])
            except Exception: pass
        if draft.get("footer_text") or draft.get("footer_icon"):
            embed.set_footer(text=draft.get("footer_text") or "", icon_url=draft.get("footer_icon") or None)
        if draft.get("author_name") or draft.get("author_icon") or draft.get("author_url"):
            embed.set_author(name=draft.get("author_name") or "", icon_url=draft.get("author_icon") or None, url=draft.get("author_url") or None)
        return [embed]

    def _get_preview_files(self) -> tuple[list[discord.File], dict[str, str]]:
        """Constrói discord.File a partir dos bytes armazenados para re-upload no preview.
        Retorna (files, attach_urls) onde attach_urls mapeia 'thumbnail'/'image' → 'attachment://fname'.
        """
        files: list[discord.File] = []
        attach_urls: dict[str, str] = {}
        for field in ("thumbnail", "image"):
            b = self.draft.get(f"_{field}_bytes")
            ext = self.draft.get(f"_{field}_ext", "png")
            if b:
                fname = f"emb_{field}.{ext}"
                files.append(discord.File(io.BytesIO(b), filename=fname))
                attach_urls[field] = f"attachment://{fname}"
        return files, attach_urls

    def build_embeds(self, attach_urls: dict[str, str] | None = None) -> list[discord.Embed]:
        """Retorna UM embed combinando header do editor + preview do draft (tudo junto).
        attach_urls: quando fornecido, usa attachment:// para thumbnail/image.
        """
        _au = attach_urls or {}
        settings = get_settings(self.author.guild.id if self.author.guild else 0)

        header = self.header_text()
        extra: list[str] = []
        if self.draft.get("sep_blocks"):
            n = len(self.draft["sep_blocks"])
            extra.append(f"-# ↳ {n} separador(es) nativo(s)")
        if not _au:
            has_thumb = bool(self.draft.get("_thumbnail_bytes") or self.draft.get("thumbnail"))
            has_img   = bool(self.draft.get("_image_bytes")     or self.draft.get("image"))
            if has_thumb or has_img:
                parts = []
                if has_thumb: parts.append("Thumbnail: ✓")
                if has_img:   parts.append("Imagem: ✓")
                extra.append(f"-# 🖼️  {' · '.join(parts)}")

        has_content = bool(
            self.draft.get("title") or self.draft.get("description") or
            self.draft.get("author_name") or self.draft.get("footer_text") or
            self.draft.get("thumbnail") or self.draft.get("image") or
            self.draft.get("_thumbnail_bytes") or self.draft.get("_image_bytes")
        )
        if not has_content:
            desc = header + ("\n" + "\n".join(extra) if extra else "")
            _e = discord.Embed(description=desc, color=0x2B2D31)
            _icon = bot.user.display_avatar.url if bot.user else None
            _g = self.author.guild if self.author.guild else None
            _s = get_settings(_g.id if _g else 0)
            _e.set_author(name=bot.user.display_name if bot.user else "NATA®", icon_url=_icon)
            _e.set_footer(text=_footer_name(_g, _s) if _g else "NATA®", icon_url=_icon)
            _e.timestamp = datetime.now()
            return [_e]

        _draft_preview = dict(self.draft)
        for _field in ("thumbnail", "image"):
            if _au.get(_field):
                _draft_preview[_field] = _au[_field]

        embed = _draft_to_embed(_draft_preview, settings["embed_color"])
        desc_parts = [header]
        if extra:
            desc_parts.extend(extra)
        if embed.description:
            desc_parts.append("")
            desc_parts.append(embed.description)
        embed.description = "\n".join(desc_parts)
        return [embed]

    async def update_main(self):
        """Atualiza a mensagem principal do builder.

        Quando há bytes de imagem: apaga a mensagem antiga e reenvia com channel.send() +
        attachment:// (única forma de mostrar imagens dentro do embed sem duplicar).
        Para atualizações sem imagem (cor, título, etc.): edita a mensagem existente.
        """
        if not self.main_message:
            return
        if self.author.guild:
            _save_embed_draft(self.author.guild.id, self.author.id, self.draft)
        sep_blocks = self.draft.get("sep_blocks", [])
        files, attach_urls = self._get_preview_files()

        channel = self.main_message.channel

        if files:
            # Apaga mensagem antiga e reenvia — attachment:// só funciona em channel.send()
            try:
                await self.main_message.delete()
            except Exception:
                pass
            try:
                if sep_blocks:
                    layout = self._build_preview_layout(attach_urls=attach_urls)
                    self.main_message = await channel.send(view=layout, files=files)
                else:
                    self.main_message = await channel.send(
                        embeds=self.build_embeds(attach_urls=attach_urls),
                        view=self, files=files)
                if self.author.guild:
                    _save_embed_draft(self.author.guild.id, self.author.id, self.draft)
            except Exception as _e:
                print(f"[EmbedBuilder] update_main resend erro: {type(_e).__name__}: {_e}", flush=True)
        else:
            # Sem arquivos — edita normalmente (texto, cor, título, separador)
            try:
                if sep_blocks:
                    layout = self._build_preview_layout()
                    await self.main_message.edit(
                        content=None, embeds=[], view=layout, attachments=[])
                else:
                    await self.main_message.edit(
                        content=None, embeds=self.build_embeds(), view=self, attachments=[])
            except discord.HTTPException as _e:
                print(f"[EmbedBuilder] update_main HTTPException {_e.code}: {_e.text[:100]}", flush=True)
            except discord.NotFound:
                print("[EmbedBuilder] update_main: mensagem não encontrada", flush=True)
            except Exception as _e:
                print(f"[EmbedBuilder] update_main erro: {type(_e).__name__}: {_e}", flush=True)

    def _build_preview_only_layout(self, vis_urls: dict[str, str] | None = None) -> discord.ui.LayoutView:
        """LayoutView read-only para o Visualizar — conteúdo completo com imagens."""
        _vu = vis_urls or {}
        sep_blocks = self.draft.get("sep_blocks", [])
        thumb_url = _vu.get("thumbnail") or ""
        img_url   = _vu.get("image") or ""

        layout = discord.ui.LayoutView(timeout=60)
        preview_items: list = []

        top: list[str] = []
        if self.draft.get("author_name"):
            top.append(f"**{self.draft['author_name']}**")
        if self.draft.get("title"):
            top.append(f"# {self.draft['title']}")

        if top:
            top_txt = discord.ui.TextDisplay("\n".join(top))
            if thumb_url:
                preview_items.append(discord.ui.Section(
                    top_txt, accessory=discord.ui.Thumbnail(media=thumb_url)))
            else:
                preview_items.append(top_txt)
        elif thumb_url:
            preview_items.append(discord.ui.Section(
                discord.ui.TextDisplay("​"),
                accessory=discord.ui.Thumbnail(media=thumb_url)))

        for sep in sep_blocks:
            spacing = (discord.SeparatorSpacing.large if sep.get("spacing") == "large"
                       else discord.SeparatorSpacing.small)
            preview_items.append(discord.ui.Separator(
                visible=sep.get("divider", True), spacing=spacing))

        if self.draft.get("description"):
            preview_items.append(discord.ui.TextDisplay(self.draft["description"]))

        if img_url:
            try:
                preview_items.append(discord.ui.MediaGallery(
                    discord.MediaGalleryItem(media=img_url)))
            except Exception:
                pass

        if preview_items:
            layout.add_item(discord.ui.Container(*preview_items))

        return layout

    def _build_preview_layout(self, attach_urls: dict[str, str] | None = None) -> discord.ui.LayoutView:
        """LayoutView para o preview do builder quando há separadores nativos."""
        _au = attach_urls or {}
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        sep_blocks = self.draft.get("sep_blocks", [])
        thumb_url = _au.get("thumbnail") or ""
        img_url   = _au.get("image") or ""

        layout = discord.ui.LayoutView(timeout=self.timeout)

        header = discord.ui.TextDisplay(self.header_text())
        top: list[str] = []
        if self.draft.get("author_name"):
            top.append(f"**{self.draft['author_name']}**")
        if self.draft.get("title"):
            top.append(f"# {self.draft['title']}")

        content_items: list = [header]
        if top:
            top_txt = discord.ui.TextDisplay("\n".join(top))
            if thumb_url:
                content_items.append(discord.ui.Section(
                    top_txt, accessory=discord.ui.Thumbnail(media=thumb_url)))
            else:
                content_items.append(top_txt)
        elif thumb_url:
            content_items[0] = discord.ui.Section(
                discord.ui.TextDisplay(self.header_text()),
                accessory=discord.ui.Thumbnail(media=thumb_url))

        for sep in sep_blocks:
            spacing = (discord.SeparatorSpacing.large if sep.get("spacing") == "large"
                       else discord.SeparatorSpacing.small)
            content_items.append(discord.ui.Separator(
                visible=sep.get("divider", True), spacing=spacing))

        if self.draft.get("description"):
            content_items.append(discord.ui.TextDisplay(self.draft["description"]))

        if not _au:
            # Sem arquivos: indicadores de texto
            has_thumb = bool(self.draft.get("_thumbnail_bytes") or self.draft.get("thumbnail"))
            has_img   = bool(self.draft.get("_image_bytes")     or self.draft.get("image"))
            if has_thumb or has_img:
                parts = []
                if has_thumb: parts.append("Thumbnail: ✓")
                if has_img:   parts.append("Imagem: ✓")
                content_items.append(discord.ui.TextDisplay(f"-# 🖼️  {' · '.join(parts)}"))

        # Imagem dentro do Container (como set_image num embed normal)
        if img_url:
            try:
                content_items.append(discord.ui.MediaGallery(
                    discord.MediaGalleryItem(media=img_url)))
            except Exception:
                pass

        layout.add_item(discord.ui.Container(*content_items))

        select = EmbedSectionSelect(self, t) if self.section is None else EmbedSubSelect(self, self.section, t)
        layout.add_item(discord.ui.ActionRow(select))

        _send_label = "Salvar Alterações" if self.edit_message_id else t["btn_enviar_embed"]
        send_btn   = discord.ui.Button(label=_send_label, style=discord.ButtonStyle.success)
        vis_btn    = discord.ui.Button(label=t["btn_visualizar"],   style=discord.ButtonStyle.secondary)
        cancel_btn = discord.ui.Button(label=t["btn_cancelar"],     style=discord.ButtonStyle.danger)
        send_btn.callback   = self._do_send
        vis_btn.callback    = self._visualize
        cancel_btn.callback = self._cancel
        layout.add_item(discord.ui.ActionRow(send_btn, vis_btn, cancel_btn))

        return layout

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            guild_id = interaction.guild.id if interaction.guild else 0
            lang = get_settings(guild_id)["language"]
            await interaction.response.send_message(
                TRANSLATIONS[lang]["only_author"], ephemeral=True
            )
            return False
        return True

    def _build(self):
        self.clear_items()
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]

        if self.section is None:
            self.add_item(EmbedSectionSelect(self, t))
        else:
            self.add_item(EmbedSubSelect(self, self.section, t))

        send_label = "Salvar Alterações" if self.edit_message_id else t["btn_enviar_embed"]
        send_btn = discord.ui.Button(
            label=send_label, style=discord.ButtonStyle.success, row=1,
        )
        send_btn.callback = self._do_send
        self.add_item(send_btn)

        vis_btn = discord.ui.Button(
            label=t["btn_visualizar"], style=discord.ButtonStyle.secondary, row=1,
        )
        vis_btn.callback = self._visualize
        self.add_item(vis_btn)

        cancel_btn = discord.ui.Button(
            label=t["btn_cancelar"], style=discord.ButtonStyle.danger, row=1,
        )
        cancel_btn.callback = self._cancel
        self.add_item(cancel_btn)

    def header_text(self) -> str:
        settings = get_settings(self.author.guild.id if self.author.guild else 0)
        t = TRANSLATIONS[settings["language"]]
        ch = getattr(self.target_channel, "mention", str(self.target_channel))
        if self.edit_message_id:
            return t["embed_builder_header_edit"].format(channel=ch)
        return t["embed_builder_header_new"].format(channel=ch)

    async def _rebuild(self, interaction: discord.Interaction):
        self._build()
        files, attach_urls = self._get_preview_files()
        if self.draft.get("sep_blocks"):
            layout = self._build_preview_layout(attach_urls=attach_urls)
            await interaction.response.edit_message(
                content=None, embeds=[], view=layout,
                attachments=files if files else [])
        else:
            await interaction.response.edit_message(
                content=None,
                embeds=self.build_embeds(attach_urls=attach_urls),
                view=self,
                attachments=files if files else [])

    async def _visualize(self, interaction: discord.Interaction):
        """Mostra preview completo com imagens reais (ephemeral).
        Usa attachment:// + channel.send — funciona corretamente ao contrário de message.edit.
        """
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        sep_blocks = self.draft.get("sep_blocks", [])

        # Constrói arquivos de imagem para o preview (attachment:// funciona em send)
        _vis_files: list[discord.File] = []
        _vis_urls: dict[str, str] = {}
        for _field in ("thumbnail", "image"):
            _b = self.draft.get(f"_{_field}_bytes")
            _e = self.draft.get(f"_{_field}_ext", "png")
            if _b:
                _fname = f"vis_{_field}.{_e}"
                _vis_files.append(discord.File(io.BytesIO(_b), filename=_fname))
                _vis_urls[_field] = f"attachment://{_fname}"
            elif self.draft.get(_field):
                _vis_urls[_field] = self.draft[_field]

        try:
            if sep_blocks:
                # LayoutView com thumbnail + MediaGallery usando attachment://
                preview = self._build_preview_only_layout(vis_urls=_vis_urls)
                kw: dict = dict(content=t["embed_visualize_only"], view=preview, ephemeral=True)
                if _vis_files:
                    kw["files"] = _vis_files
                await interaction.response.send_message(**kw)
            else:
                # Embed tradicional com attachment:// para thumbnail e image
                _draft_vis = dict(self.draft)
                for _field, _url in _vis_urls.items():
                    _draft_vis[_field] = _url
                embed = _draft_to_embed(_draft_vis, settings["embed_color"])
                view = _draft_view_from_buttons(self.draft)
                kw = dict(content=t["embed_visualize_only"], embed=embed, view=view, ephemeral=True)
                if _vis_files:
                    kw["files"] = _vis_files
                await interaction.response.send_message(**kw)
        except discord.HTTPException:
            await interaction.response.send_message(embed=_notif_embed(t["embed_empty_warning"]), ephemeral=True)

    async def _do_send(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        sep_blocks = self.draft.get("sep_blocks", [])
        has_text = bool(self.draft.get("title") or self.draft.get("description") or
                        self.draft.get("author_name") or self.draft.get("footer_text"))
        if not has_text and not sep_blocks:
            await interaction.response.send_message(embed=_notif_embed(t["embed_empty_warning"]), ephemeral=True)
            return
        # Separador nativo exige texto para ser visível
        if sep_blocks and not has_text:
            await interaction.response.send_message(
                "⚠️ Adicione um **título** ou **descrição** antes de enviar com separador.\n"
                "-# O separador nativo do Discord só é visível quando há texto acima ou abaixo.",
                ephemeral=True,
            )
            return

        sent_message: discord.Message | None = None

        if sep_blocks:
            # ── Mensagem com Components V2 + separador nativo ──
            # Prepara arquivos de imagem (mesma lógica do path não-sep)
            _send_files: list[discord.File] = []
            _thumb_url: str | None = None
            _img_url: str | None = None
            for _field in ("thumbnail", "image"):
                _b = self.draft.get(f"_{_field}_bytes")
                _e = self.draft.get(f"_{_field}_ext", "png")
                if _b:
                    _fname = f"embed_{_field}.{_e}"
                    _send_files.append(discord.File(io.BytesIO(_b), filename=_fname))
                    _resolved = f"attachment://{_fname}"
                else:
                    _resolved = self.draft.get(_field) or None
                if _field == "thumbnail":
                    _thumb_url = _resolved
                else:
                    _img_url = _resolved

            container_items: list = []

            # Bloco 1: autor + título (com thumbnail como accessory se disponível)
            top_parts: list[str] = []
            if self.draft.get("author_name"):
                top_parts.append(f"**{self.draft['author_name']}**")
            if self.draft.get("title"):
                top_parts.append(f"# {self.draft['title']}")
            if top_parts:
                top_txt = discord.ui.TextDisplay("\n".join(top_parts))
                if _thumb_url:
                    container_items.append(discord.ui.Section(
                        top_txt, accessory=discord.ui.Thumbnail(media=_thumb_url)))
                else:
                    container_items.append(top_txt)
            elif _thumb_url:
                container_items.append(discord.ui.Section(
                    discord.ui.TextDisplay("​"),
                    accessory=discord.ui.Thumbnail(media=_thumb_url)))

            # Separadores + conteúdo abaixo de cada um
            for i, sep in enumerate(sep_blocks):
                spacing = (discord.SeparatorSpacing.large
                           if sep.get("spacing") == "large"
                           else discord.SeparatorSpacing.small)
                container_items.append(discord.ui.Separator(
                    visible=sep.get("divider", True),
                    spacing=spacing,
                ))

            # Bloco 2: descrição (abaixo do separador)
            if self.draft.get("description"):
                container_items.append(discord.ui.TextDisplay(self.draft["description"]))

            if self.draft.get("footer_text"):
                container_items.append(discord.ui.TextDisplay(f"-# {self.draft['footer_text']}"))

            # Imagem principal como MediaGallery (dentro do container)
            if _img_url:
                try:
                    container_items.append(discord.ui.MediaGallery(
                        discord.MediaGalleryItem(media=_img_url)))
                except Exception:
                    pass

            # Garante que o Container nunca fique vazio
            if not container_items:
                container_items.append(discord.ui.TextDisplay("​"))

            layout = discord.ui.LayoutView(timeout=None)
            layout.add_item(discord.ui.Container(*container_items))

            btns = self.draft.get("buttons", [])
            if btns:
                ar = discord.ui.ActionRow()
                for i, b in enumerate(btns[:5]):
                    style = EMBED_BTN_COLOR_MAP.get(b.get("color", "secondary"), discord.ButtonStyle.secondary)
                    emoji_raw = b.get("emoji")
                    emoji = None
                    if emoji_raw:
                        try:
                            emoji = (discord.PartialEmoji.from_str(emoji_raw)
                                     if emoji_raw.startswith("<") else emoji_raw)
                        except Exception:
                            pass
                    if b.get("type") == "link" and b.get("response"):
                        ar.add_item(discord.ui.Button(
                            style=discord.ButtonStyle.link,
                            label=b.get("text", "Link"),
                            url=b["response"], emoji=emoji,
                        ))
                    elif b.get("type") == "verif_check":
                        ar.add_item(discord.ui.Button(
                            style=discord.ButtonStyle.success,
                            label=b.get("text", "Verificar"),
                            emoji=emoji or "✅", custom_id="verif_check",
                        ))
                    elif b.get("type") == "ig_verif_check":
                        ar.add_item(discord.ui.Button(
                            style=discord.ButtonStyle.secondary,
                            label=b.get("text", "verificar"),
                            emoji=None, custom_id="ig_verif_check",
                        ))
                    else:
                        ar.add_item(discord.ui.Button(
                            style=style, label=b.get("text", "Botão"),
                            emoji=emoji, custom_id=f"embed_btn_{i}",
                        ))
                layout.add_item(ar)

            print(f"[EmbedBuilder] sep send: files={len(_send_files)}, thumb={bool(_thumb_url)}, img={bool(_img_url)}, edit={bool(self.edit_message_id)}", flush=True)
            try:
                if self.edit_message_id:
                    _orig = await self.target_channel.fetch_message(self.edit_message_id)
                    if _send_files:
                        await _orig.edit(view=layout, attachments=_send_files)
                    else:
                        await _orig.edit(view=layout)
                    sent_message = _orig
                    print(f"[EmbedBuilder] separador editado OK: {sent_message.id}", flush=True)
                elif _send_files:
                    sent_message = await self.target_channel.send(view=layout, files=_send_files)
                    print(f"[EmbedBuilder] separador enviado OK: {sent_message.id}", flush=True)
                else:
                    sent_message = await self.target_channel.send(view=layout)
                    print(f"[EmbedBuilder] separador enviado OK: {sent_message.id}", flush=True)
            except Exception as e:
                print(f"[EmbedBuilder] ERRO ao enviar/editar separador: {type(e).__name__}: {e}", flush=True)
                await interaction.response.send_message(
                    t["embed_send_failed"].format(err=str(e)[:200]), ephemeral=True
                )
                return

        else:
            # ── Embed tradicional ──
            _send_files: list[discord.File] = []
            _draft_send = dict(self.draft)
            for _field in ("thumbnail", "image"):
                _b = self.draft.get(f"_{_field}_bytes")
                _e = self.draft.get(f"_{_field}_ext", "png")
                if _b:
                    _fname = f"embed_{_field}.{_e}"
                    _send_files.append(discord.File(io.BytesIO(_b), filename=_fname))
                    _draft_send[_field] = f"attachment://{_fname}"

            embed = _draft_to_embed(_draft_send, settings["embed_color"])
            buttons_view = _draft_view_from_buttons(self.draft)
            print(f"[EmbedBuilder] send: files={len(_send_files)}, "
                  f"thumb={bool(_draft_send.get('thumbnail'))}, "
                  f"img={bool(_draft_send.get('image'))}, "
                  f"thumb_url={str(_draft_send.get('thumbnail',''))[:60]}", flush=True)
            try:
                if self.edit_message_id:
                    msg = await self.target_channel.fetch_message(self.edit_message_id)
                    if _send_files:
                        await msg.edit(embed=embed, view=buttons_view or discord.utils.MISSING,
                                       attachments=_send_files)
                    else:
                        await msg.edit(embed=embed, view=buttons_view or discord.utils.MISSING)
                    sent_message = msg
                else:
                    if _send_files:
                        sent_message = await self.target_channel.send(
                            files=_send_files, embed=embed, view=buttons_view)
                    else:
                        sent_message = await self.target_channel.send(embed=embed, view=buttons_view)
                print(f"[EmbedBuilder] enviado OK: {sent_message.id if sent_message else 'None'}", flush=True)
            except Exception as e:
                print(f"[EmbedBuilder] ERRO no envio: {type(e).__name__}: {e}", flush=True)
                await interaction.response.send_message(
                    t["embed_send_failed"].format(err=str(e)[:200]), ephemeral=True
                )
                return

        # Salva dados dos botões para o handler de clique
        if sent_message and self.draft.get("buttons"):
            _embed_btn_data[sent_message.id] = self.draft["buttons"]
            _save_embed_btn_data()

        # Salva draft completo para restaurar no n!embed editar
        if sent_message:
            _embed_draft_data[sent_message.id] = {k: v for k, v in self.draft.items() if not k.startswith("_")}
            _save_embed_draft_data()

        # Apaga a mensagem principal do builder (limpa o canal)
        try:
            if self.main_message:
                await self.main_message.delete()
        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
            pass

        # Limpa rascunho salvo após envio bem-sucedido
        if self.author.guild:
            _pop_embed_draft(self.author.guild.id, self.author.id)

        # Ephemeral com "Embed enviada com sucesso." + botão "Conferir no canal"
        ok_view = discord.ui.View(timeout=300)
        if sent_message:
            try:
                ok_view.add_item(discord.ui.Button(
                    label=t["embed_conferir_canal"],
                    style=discord.ButtonStyle.link,
                    url=sent_message.jump_url,
                    emoji="🔗",
                ))
            except Exception:
                pass
        try:
            await interaction.response.send_message(
                t["embed_sent_ok"], view=ok_view, ephemeral=True,
            )
        except discord.HTTPException:
            await interaction.followup.send(embed=_notif_embed(t["embed_sent_ok"]), view=ok_view, ephemeral=True)

    async def _cancel(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        t = TRANSLATIONS[settings["language"]]
        if self.author.guild:
            _pop_embed_draft(self.author.guild.id, self.author.id)
        await interaction.response.edit_message(
            content=t["embed_cancelled"], embed=None, view=None
        )


async def _do_bulk_delete(ctx: commands.Context, amount: str = "100"):
    """Shared logic for n!nuke and n!clear — bulk-delete with progress embed."""
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    lang = settings["language"]
    t = TRANSLATIONS[lang]

    # Permissão: somente quem é autorizado pelo bot OU tem permissão de Manage Messages
    if not (is_authorized(ctx.author, settings)
            or ctx.author.guild_permissions.manage_messages):
        await ctx.reply(t["not_authorized"], delete_after=6)
        return

    # Parse amount
    raw = (amount or "100").lower().strip()
    if raw in ("all", "tudo", "max"):
        target = 1000  # cap at 1000
    else:
        try:
            target = int(raw)
        except ValueError:
            target = 100
    target = max(1, min(target, 1000))

    # Apaga o n!nuke do usuário imediatamente
    try:
        await ctx.message.delete()
    except (discord.Forbidden, discord.NotFound, discord.HTTPException):
        pass

    # Embed inicial
    progress_embed = discord.Embed(
        title="🧹  Limpeza de Mensagens" if lang == "pt-br" else "🧹  Message Cleanup",
        description=(
            "Deletando mensagens em lote..." if lang == "pt-br"
            else "Bulk deleting messages..."
        ),
        color=0x2B2D31,
    )
    progress_embed.add_field(name="Deletadas" if lang == "pt-br" else "Deleted",
                             value="`0`", inline=True)
    progress_embed.add_field(name="Progresso" if lang == "pt-br" else "Progress",
                             value="`0%`", inline=True)
    progress_embed.add_field(name="Tempo" if lang == "pt-br" else "Time",
                             value="`0s`", inline=True)
    progress_msg = await ctx.send(embed=progress_embed)

    start = datetime.now().timestamp()
    deleted_count = 0
    batch_size = 100  # Discord bulk delete limit
    remaining = target

    while remaining > 0:
        chunk = min(batch_size, remaining)
        try:
            deleted = await ctx.channel.purge(
                limit=chunk,
                before=progress_msg,
                bulk=True,
                reason=f"n!nuke por {ctx.author} ({ctx.author.id})",
            )
        except discord.Forbidden:
            await progress_msg.edit(embed=discord.Embed(
                description="<a:alerta:1518271939460857968> Sem permissão para deletar mensagens.",
                color=0xED4245,
            ))
            return
        except discord.HTTPException as e:
            print(f"[nuke] HTTPException: {e}")
            break

        if not deleted:
            break  # nothing more to delete
        deleted_count += len(deleted)
        remaining -= len(deleted)

        # Update progress embed
        elapsed = int(datetime.now().timestamp() - start)
        pct = int((deleted_count / target) * 100) if target else 0
        pct = min(pct, 100)
        updated = discord.Embed(
            title="🧹  Limpeza de Mensagens" if lang == "pt-br" else "🧹  Message Cleanup",
            description=(
                "Deletando mensagens em lote..." if lang == "pt-br"
                else "Bulk deleting messages..."
            ),
            color=0x2B2D31,
        )
        updated.add_field(name="Deletadas" if lang == "pt-br" else "Deleted",
                          value=f"`{deleted_count}`", inline=True)
        updated.add_field(name="Progresso" if lang == "pt-br" else "Progress",
                          value=f"`{pct}%`", inline=True)
        updated.add_field(name="Tempo" if lang == "pt-br" else "Time",
                          value=f"`{elapsed}s`", inline=True)
        try:
            await progress_msg.edit(embed=updated)
        except (discord.HTTPException, discord.NotFound):
            pass

        # Pequena pausa pra evitar rate limit
        await asyncio.sleep(0.5)

    # Embed final
    final_elapsed = int(datetime.now().timestamp() - start)
    final_pct = int((deleted_count / target) * 100) if target else 100
    final_pct = min(final_pct, 100)
    done = discord.Embed(
        title="🧹  Limpeza de Mensagens" if lang == "pt-br" else "🧹  Message Cleanup",
        description=(
            "<a:online:1518271945550856295> Limpeza concluída!" if lang == "pt-br"
            else "<a:online:1518271945550856295> Cleanup complete!"
        ),
        color=0x2B2D31,
    )
    done.add_field(name="Deletadas" if lang == "pt-br" else "Deleted",
                   value=f"`{deleted_count}`", inline=True)
    done.add_field(name="Progresso" if lang == "pt-br" else "Progress",
                   value=f"`{final_pct}%`", inline=True)
    done.add_field(name="Tempo" if lang == "pt-br" else "Time",
                   value=f"`{final_elapsed}s`", inline=True)
    try:
        await progress_msg.edit(embed=done, delete_after=10)
    except (discord.HTTPException, discord.NotFound):
        pass


class NukeConfirmView(discord.ui.View):
    """Confirmação para o comando n!nuke (recriar canal)."""
    def __init__(self, author: discord.Member, channel: discord.TextChannel, motivo: str | None):
        super().__init__(timeout=60)
        self.author = author
        self.channel = channel
        self.motivo = motivo
        self.value: bool | None = None

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            await interaction.response.send_message(
                "<a:alerta:1518271939460857968> Apenas quem usou o comando pode confirmar.",
                ephemeral=True,
            )
            return False
        return True

    @discord.ui.button(label="Confirmar", style=discord.ButtonStyle.danger)
    async def _confirm(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.value = True
        for item in self.children:
            item.disabled = True
        try:
            await interaction.response.edit_message(view=self)
        except discord.HTTPException:
            pass
        self.stop()

    @discord.ui.button(label="Cancelar", style=discord.ButtonStyle.secondary)
    async def _cancel(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.value = False
        for item in self.children:
            item.disabled = True
        try:
            await interaction.response.edit_message(
                content="<a:alerta:1518271939460857968> Nuke cancelado.",
                embed=None, view=self,
            )
        except discord.HTTPException:
            pass
        self.stop()


# =============================================================================
# Limite Call — n!call e /call
# =============================================================================

def _has_call_limit_perm(member: discord.Member, settings: dict) -> bool:
    """Retorna True se o membro pode usar o comando call (admin, autorizado ou cargo configurado)."""
    if member.guild_permissions.administrator:
        return True
    if is_authorized(member, settings):
        return True
    allowed = settings.get("call_limit_roles", [])
    if allowed and any(r.id in allowed for r in member.roles):
        return True
    return False


def _call_limit_embed(
    description: str,
    color: int,
    user,
    icon_url: str,
    channel: discord.VoiceChannel | None = None,
    n: int | None = None,
) -> discord.Embed:
    emb = discord.Embed(color=color)
    emb.set_author(
        name=f"Limite Call  •  {user.display_name}",
        icon_url=user.display_avatar.url,
    )
    emb.description = description

    if channel is not None:
        emb.add_field(name="Canal", value=channel.mention, inline=True)
    if n is not None:
        emb.add_field(name="Limite", value="∞" if n == 0 else str(n), inline=True)
    if channel is not None:
        atual = len([m for m in channel.members if not m.bot])
        emb.add_field(name="Membros", value=str(atual), inline=True)

    emb.set_footer(text=f"Solicitado por {user.name}", icon_url=icon_url)
    emb.timestamp = datetime.now()
    return emb


@bot.command(name="call")
async def call_limit_cmd(ctx: commands.Context, numero: str = ""):
    """Define o limite de usuários do canal de voz em que o membro está."""
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    t = TRANSLATIONS[settings["language"]]
    color = settings.get("embed_color", 0x2B2D31)
    icon_url = bot.user.display_avatar.url if bot.user else None

    if not isinstance(ctx.author, discord.Member) or not _has_call_limit_perm(ctx.author, settings):
        emb = _call_limit_embed(t["call_limit_no_perm"], 0xE53935, ctx.author, icon_url)
        await ctx.reply(embed=emb, delete_after=8)
        return

    voice = ctx.author.voice
    if voice is None or voice.channel is None:
        emb = _call_limit_embed(t["call_limit_no_voice"], 0xE53935, ctx.author, icon_url)
        await ctx.reply(embed=emb, delete_after=8)
        return

    # Pede o número se não foi passado como argumento
    if not numero:
        ask_emb = _call_limit_embed(t["call_limit_ask"], color, ctx.author, icon_url)
        ask_msg = await ctx.reply(embed=ask_emb)

        def check(m):
            return m.author == ctx.author and m.channel == ctx.channel

        try:
            msg = await bot.wait_for("message", check=check, timeout=60)
            numero = msg.content.strip()
            try:
                await msg.delete()
            except (discord.Forbidden, discord.NotFound):
                pass
        except asyncio.TimeoutError:
            try:
                await ask_msg.delete()
            except (discord.Forbidden, discord.NotFound):
                pass
            return
        try:
            await ask_msg.delete()
        except (discord.Forbidden, discord.NotFound):
            pass

    try:
        n = int(numero)
    except ValueError:
        emb = _call_limit_embed(t["call_limit_invalid"], 0xE53935, ctx.author, icon_url)
        await ctx.reply(embed=emb, delete_after=8)
        return

    if n < 0 or n > 99:
        emb = _call_limit_embed(t["call_limit_invalid"], 0xE53935, ctx.author, icon_url)
        await ctx.reply(embed=emb, delete_after=8)
        return

    try:
        await voice.channel.edit(user_limit=n, reason=f"Limite Call por {ctx.author}")
    except (discord.Forbidden, discord.HTTPException):
        emb = _call_limit_embed(t["call_limit_error"], 0xE53935, ctx.author, icon_url)
        await ctx.reply(embed=emb, delete_after=8)
        return

    if n == 0:
        emb = _call_limit_embed(t["call_limit_removed"], 0x2ECC71, ctx.author, icon_url, channel=voice.channel, n=0)
    else:
        emb = _call_limit_embed(t["call_limit_set"].format(n=n), 0x2ECC71, ctx.author, icon_url, channel=voice.channel, n=n)
    await ctx.reply(embed=emb)


