@bot.command(name="nuke")
async def nuke_cmd(ctx: commands.Context, *, motivo: str = ""):
    """Nuke — recria o canal (deleta e clona) com confirmação."""
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    lang = settings["language"]
    t = TRANSLATIONS[lang]

    # Permissão: autorizado pelo bot OU com permissão de Gerenciar Canais
    if not (is_authorized(ctx.author, settings)
            or ctx.author.guild_permissions.manage_channels):
        await ctx.reply(t["not_authorized"], delete_after=6)
        return

    channel = ctx.channel
    if not isinstance(channel, discord.TextChannel):
        await ctx.reply("<a:alerta:1518271939460857968> Este comando só funciona em canais de texto.", delete_after=8)
        return

    motivo_text = motivo.strip() or ("Nenhum motivo fornecido" if lang == "pt-br" else "No reason provided")

    # Apaga o n!nuke do usuário
    try:
        await ctx.message.delete()
    except (discord.Forbidden, discord.NotFound, discord.HTTPException):
        pass

    confirm_embed = discord.Embed(
        title="⚠️  Confirmação de Nuke" if lang == "pt-br" else "⚠️  Nuke Confirmation",
        description=(
            f"Você tem certeza que deseja recriar o canal **{channel.name}**?\n\n"
            f"**Motivo:** {motivo_text}\n\n"
            f"<a:alerta:1518271939460857968> **Esta ação é irreversível e todas as mensagens serão perdidas!**"
        ) if lang == "pt-br" else (
            f"Are you sure you want to recreate the channel **{channel.name}**?\n\n"
            f"**Reason:** {motivo_text}\n\n"
            f"<a:alerta:1518271939460857968> **This action is irreversible and all messages will be lost!**"
        ),
        color=0xED4245,
    )
    confirm_embed.set_footer(
        text=(
            "Clique em um dos botões abaixo para confirmar ou cancelar"
            if lang == "pt-br"
            else "Click one of the buttons below to confirm or cancel"
        )
    )
    confirm_embed.timestamp = datetime.now()

    view = NukeConfirmView(ctx.author, channel, motivo_text)
    confirm_msg = await ctx.send(embed=confirm_embed, view=view)

    # Aguarda confirmação
    timed_out = await view.wait()
    if view.value is None:
        # Timeout
        try:
            await confirm_msg.edit(
                content="<a:alerta:1518271939460857968> Tempo esgotado.",
                embed=None, view=None,
                delete_after=8,
            )
        except (discord.HTTPException, discord.NotFound):
            pass
        return
    if view.value is False:
        # Cancelado
        try:
            await confirm_msg.delete(delay=5)
        except (discord.Forbidden, discord.NotFound, discord.HTTPException):
            pass
        return

    # Confirmado → recriar canal
    try:
        position = channel.position
        category = channel.category
        new_channel = await channel.clone(
            name=channel.name,
            reason=f"n!nuke por {ctx.author} ({ctx.author.id}). Motivo: {motivo_text}",
        )
        # Move pra mesma posição
        try:
            await new_channel.edit(position=position)
        except (discord.Forbidden, discord.HTTPException):
            pass
        # Deleta o canal antigo
        try:
            await channel.delete(reason=f"n!nuke por {ctx.author}")
        except (discord.Forbidden, discord.HTTPException):
            pass

        # Embed de sucesso no canal NOVO
        label = "Canal recriado por" if lang == "pt-br" else "Channel recreated by"
        label2 = "Motivo" if lang == "pt-br" else "Reason"
        guild_name = ctx.guild.name if ctx.guild else ""
        success_embed = discord.Embed(
            color=0xF4A300,
            description=(
                f"<:atencao:1518272104368308304> | **{label}:** `{ctx.author.display_name}`\n"
                f"{label2}: {motivo_text} · {guild_name}"
            ),
        )
        success_embed.timestamp = datetime.now()
        try:
            await new_channel.send(embed=success_embed, delete_after=60)
        except (discord.Forbidden, discord.HTTPException):
            pass
    except discord.Forbidden:
        try:
            await ctx.author.send(
                "<a:alerta:1518271939460857968> Sem permissão para clonar/deletar o canal."
            )
        except (discord.Forbidden, discord.HTTPException):
            pass
    except discord.HTTPException as e:
        print(f"[nuke] HTTPException: {e}")


@bot.command(name="clear", aliases=["clean", "purge"])
async def clear_cmd(ctx: commands.Context, valor: str = ""):
    """Clear command — n!clear <valor> to delete specified amount."""
    if ctx.guild is None:
        return
    settings = get_settings(ctx.guild.id)
    lang = settings["language"]
    if not valor.strip():
        # Show usage in embed (auto-delete)
        p = ctx.prefix or settings.get("prefix", "n!")
        embed = discord.Embed(
            color=settings["embed_color"],
            description=(
                f"{ctx.author.mention}, uso correto:\n"
                f"`{p}clear <quantidade>` — deleta a quantidade especificada de mensagens.\n"
                f"Exemplos:\n`{p}clear 50`\n`{p}clear 200`\n`{p}clear all` (até 1000)"
            ),
        )
        try:
            await ctx.message.delete()
        except (discord.Forbidden, discord.NotFound):
            pass
        await ctx.send(
            embed=embed,
            allowed_mentions=discord.AllowedMentions(users=False),
            delete_after=12,
        )
        return
    await _do_bulk_delete(ctx, valor)


