@bot.tree.command(name="unban", description="Remova o banimento de um usuário")
@discord.app_commands.describe(
    usuario_id="ID do usuário a ser desbanido.",
    motivo="Motivo do desbanimento.",
)
async def unban_slash(interaction: discord.Interaction, usuario_id: str, motivo: str):
    if interaction.guild is None:
        return
    settings = get_settings(interaction.guild.id)
    user     = interaction.user

    if not (isinstance(user, discord.Member) and _has_unban_perm(user, settings)):
        await interaction.response.send_message("<a:alerta:1518271939460857968> **Sem permissão.**", ephemeral=True)
        return

    try:
        uid = int(usuario_id.strip())
    except ValueError:
        await interaction.response.send_message("<a:alerta:1518271939460857968> ID inválido.", ephemeral=True)
        return

    # Defer antes do unban + fetch_user (API calls) — evita timeout de 3s
    await interaction.response.defer()

    try:
        await interaction.guild.unban(discord.Object(id=uid), reason=f"{user} — {motivo}")
    except discord.NotFound:
        await interaction.followup.send("<a:alerta:1518271939460857968> **Usuário não está banido.**", ephemeral=True)
        return
    except (discord.Forbidden, discord.HTTPException) as e:
        await interaction.followup.send(f"<a:alerta:1518271939460857968> Erro: `{e}`", ephemeral=True)
        return

    date_str  = datetime.now().strftime("%d/%m/%Y")
    user_name = str(uid)
    for r in reversed(settings.get("ban_records", [])):
        if r["user_id"] == uid:
            user_name = r.get("user_name", str(uid))
            if r.get("active", False):
                r["active"]           = False
                r["unbanned_by_id"]   = user.id
                r["unbanned_by_name"] = str(user)
                r["unbanned_at"]      = date_str
            break
    save_settings_to_disk()

    # Tenta buscar avatar do usuário desbanido
    try:
        _unbanned_obj = await bot.fetch_user(uid)
        _user_avatar  = _unbanned_obj.display_avatar.url
        _user_display = str(_unbanned_obj)
    except Exception:
        _unbanned_obj = None
        _user_avatar  = None
        _user_display = user_name

    unban_count  = len([r for r in settings.get("ban_records", []) if r.get("unbanned_by_id") == user.id])
    unban_limit  = settings.get("ban_limit", 0)
    bot_avatar   = bot.user.display_avatar.url if bot.user else None
    server_thumb = (interaction.guild.icon.url if interaction.guild.icon else bot_avatar)
    guild_name   = interaction.guild.name

    _plural_u = "usuários" if unban_count != 1 else "usuário"
    if unban_limit > 0:
        footer_u = f"{user} já desbaniu {unban_count} {_plural_u}. | Limite de ban {unban_count}/{unban_limit}"
    else:
        footer_u = f"{user} já desbaniu {unban_count} {_plural_u}."

    _cv2_u        = discord.ui.LayoutView(timeout=None)
    _txt_title_u  = discord.ui.TextDisplay(f"**{guild_name} — Usuário Desbanido** <a:verificadoverde:1518272098290892810>")
    _title_sep_u  = discord.ui.Separator(visible=True)
    _txt_desban   = discord.ui.TextDisplay(
        f"**<:bot:1518326704735649983> Usuário Desbanido:**\n<@{uid}>\n-# `{_user_display}`"
    )
    _txt_autor_u  = discord.ui.TextDisplay(
        f"**<:Picsart_260523_224131777:1518272109925630042> Autor do Desbanimento:**\n{user.mention}\n-# `{user}`"
    )
    _motivo_sep_u = discord.ui.Separator(visible=True)
    _txt_motivo_u = discord.ui.TextDisplay(f"**<:emoji_52:1518272091898515608> Motivo:**\n-# `{motivo}`")
    _txt_footer_u = discord.ui.TextDisplay(f"-# {footer_u}")

    if server_thumb:
        _thumb_u     = discord.ui.Thumbnail(server_thumb)
        _section_u   = discord.ui.Section(_txt_desban, _txt_autor_u, accessory=_thumb_u)
        _container_u = discord.ui.Container(_txt_title_u, _title_sep_u, _section_u, _motivo_sep_u, _txt_motivo_u, _txt_footer_u, accent_colour=0x2ECC71)
    else:
        _container_u = discord.ui.Container(_txt_title_u, _title_sep_u, _txt_desban, _txt_autor_u, _motivo_sep_u, _txt_motivo_u, _txt_footer_u, accent_colour=0x2ECC71)

    _cv2_u.add_item(_container_u)
    try:
        await interaction.followup.send(view=_cv2_u)
        async def _del_unban():
            await asyncio.sleep(30)
            try:
                msg = await interaction.original_response()
                await msg.delete()
            except Exception:
                pass
        asyncio.create_task(_del_unban())
    except Exception:
        # LayoutView não suportado — envia embed clássico como fallback
        emb_fb_u = discord.Embed(title=f"{guild_name} — Usuário Desbanido", color=0x2ECC71)
        if server_thumb:
            emb_fb_u.set_thumbnail(url=server_thumb)
        emb_fb_u.add_field(name="<:bot:1518326704735649983> Usuário Desbanido:", value=f"<@{uid}>\n`{_user_display}`", inline=False)
        emb_fb_u.add_field(name="<:Picsart_260523_224131777:1518272109925630042> Autor do Desbanimento:", value=f"{user.mention}\n`{user}`", inline=False)
        emb_fb_u.add_field(name="<:emoji_52:1518272091898515608> Motivo:", value=motivo, inline=False)
