@bot.tree.command(name="url", description="Isenta (ou remove isenção de) um usuário da Verificação de URL")
async def urlexempt_slash(interaction: discord.Interaction, usuario: discord.Member):
    if not interaction.guild:
        await interaction.response.send_message("Comando apenas em servidores.", ephemeral=True)
        return
    settings = get_settings(interaction.guild.id)
    _url_allowed_roles = set(settings.get("verif_url_command_roles", []))
    _has_url_role = bool(_url_allowed_roles & {r.id for r in interaction.user.roles})
    if not interaction.user.guild_permissions.administrator and not _has_perm_category(interaction.user, "verificacao_url", settings) and not _has_url_role:
        await interaction.response.send_message(
            embed=discord.Embed(description="<a:alerta:1518271939460857968> **Sem permissão.**", color=0xED4245),
            ephemeral=True,
        )
        return
    exempt: list = settings.setdefault("verif_exempt_users", [])
    icon_url = bot.user.display_avatar.url if bot.user else None

    if usuario.id in exempt:
        exempt.remove(usuario.id)
        save_settings_to_disk()
        embed = discord.Embed(
            description=(
                f"<a:alerta:1518271939460857968> **Isenção removida**\n"
                f"{usuario.mention} voltará a ser verificado(a) normalmente pelo sistema de URL."
            ),
            color=0xED4245,
        )
    else:
        exempt.append(usuario.id)
        save_settings_to_disk()
        embed = discord.Embed(
            description=(
                f"<a:online:1518271945550856295> **Usuário isento**\n"
                f"{usuario.mention} **não** terá cargos removidos pela Verificação de URL."
            ),
            color=0x57F287,
        )
    embed.set_author(name="Verificação de URL — Isenção", icon_url=icon_url)
    embed.set_thumbnail(url=usuario.display_avatar.url)
    embed.set_footer(text=f"Total de isentos: {len(exempt)}")
    await interaction.response.send_message(embed=embed, ephemeral=True)


