@bot.tree.command(name="tempo", description="Veja o tempo em call de um usuário")
async def tempo_slash(interaction: discord.Interaction, usuario: discord.Member = None):
    if not interaction.guild:
        await interaction.response.send_message("Comando apenas em servidores.", ephemeral=True)
        return
    await interaction.response.defer()
    target = usuario or interaction.user
    gid    = interaction.guild.id
    data   = _get_user_vt(gid, target.id)
    _vt_rotate(data)
    sess   = _voice_sessions.get((gid, target.id))
    nts    = datetime.now().timestamp()
    extra  = nts - sess["join"] if sess else 0
    exmut  = (nts - sess["mute_start"]) if (sess and sess.get("mute_start")) else 0
    lw_s   = data.get("last_week_start") or ""
    card   = await _gen_tempo_card(
        target, interaction.guild,
        total_sec  = data.get("total_seconds", 0) + extra,
        week_sec   = data.get("week_seconds", 0)  + extra,
        week_mut   = data.get("week_muted_seconds", 0) + exmut,
        week_range = _vt_week_range(data.get("week_start") or _vt_week_start()),
        lw_sec     = data.get("last_week_seconds", 0),
        lw_mut     = data.get("last_week_muted_seconds", 0),
        lw_range   = _vt_week_range(lw_s) if lw_s else "sem semana anterior",
    )
    if card:
        _msg = await interaction.followup.send(file=discord.File(card, filename="tempo.png"))
        async def _del():
            await asyncio.sleep(60)
            try:
                await _msg.delete()
            except Exception:
                pass
        asyncio.create_task(_del())
    else:
        await interaction.followup.send(content=f"⏱️ **{target.display_name}** — Total: `{_fmt_vt(data.get('total_seconds', 0) + extra)}`")


