# ── /nuke — confirmação antes de executar ────────────────────────────────────

class NukeConfirmView(discord.ui.View):
    def __init__(self, author: discord.Member, channel: discord.TextChannel, motivo: str):
        super().__init__(timeout=30)
        self.author  = author
        self.channel = channel
        self.motivo  = motivo

        confirmar = discord.ui.Button(label="Confirmar", style=discord.ButtonStyle.danger, row=0)
        confirmar.callback = self._confirmar
        self.add_item(confirmar)

        cancelar = discord.ui.Button(label="Cancelar", style=discord.ButtonStyle.secondary, row=0)
        cancelar.callback = self._cancelar
        self.add_item(cancelar)

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author.id:
            await interaction.response.send_message("Apenas quem usou o comando pode confirmar.", ephemeral=True)
            return False
        return True

    async def _confirmar(self, interaction: discord.Interaction):
        settings = get_settings(interaction.guild.id)
        await interaction.response.edit_message(
            content="<a:online:1518271945550856295> **Nukeando...**", embed=None, view=None
        )
        try:
            new_ch = await self.channel.clone(reason=f"Nuke por {self.author} — {self.motivo}")
            await new_ch.edit(position=self.channel.position)
            await self.channel.delete(reason=f"Nuke por {self.author} — {self.motivo}")
            guild_name = self.channel.guild.name if self.channel.guild else ""
            nuke_emb = discord.Embed(color=0xF4A300)
            nuke_emb.description = (
                f"<:atencao:1518272104368308304> | **Canal recriado por:** `{self.author.display_name}`\n"
                f"Motivo: {self.motivo} · {guild_name}"
            )
            await new_ch.send(embed=nuke_emb, delete_after=60)
        except (discord.Forbidden, discord.HTTPException):
            pass

    async def _cancelar(self, interaction: discord.Interaction):
        await interaction.response.edit_message(
            content="<a:alerta:1518271939460857968> Nuke cancelado.", embed=None, view=None
        )


@bot.tree.command(name="nuke", description="Recrie o canal atual")
@discord.app_commands.describe(motivo="Motivo do nuke. (opcional)")
async def nuke_slash(interaction: discord.Interaction, motivo: str = "Nenhum motivo fornecido"):
    if interaction.guild is None:
        return
    settings = get_settings(interaction.guild.id)
    user     = interaction.user

    if not (isinstance(user, discord.Member) and _has_nuke_perm(user, settings)):
        await interaction.response.send_message("<a:alerta:1518271939460857968> **Sem permissão.**", ephemeral=True)
        return

    channel = interaction.channel
    if not isinstance(channel, discord.TextChannel):
        await interaction.response.send_message("<a:alerta:1518271939460857968> **Funciona apenas em canais de texto.**", ephemeral=True)
        return

    emb = discord.Embed(color=0xF4A300, title="⚠️ Confirmação de Nuke")
    emb.description = (
        f"Você tem certeza que deseja recriar o canal **{channel.name}**?\n\n"
        f"**Motivo:** {motivo}\n\n"
        f"<a:alerta:1518271939460857968> **Esta ação é irreversível e todas as mensagens serão perdidas!**\n"
        f"-# Clique em um dos botões abaixo para confirmar ou cancelar"
    )
    view = NukeConfirmView(user, channel, motivo)
    await interaction.response.send_message(embed=emb, view=view, ephemeral=True)


