_E_SERVER   = "<:servidor_:1518271981189992638>"
_E_SECURITY = "<:seguranca:1518271987393232936>"
_E_COMM     = "<:comunidade_:1518272016971595807>"
_E_TICKET   = "<:tickets:1518271952526250155>"
_E_APPEAR   = "<:aparncia_:1518271975317962895>"
_E_FINANC   = "<:financeiro_:1518272010688397432>"
_E_ENTRET   = "<:entretenimento_:1518271992191779038>"
_E_MOV_CHAT = "<:Mov_chat:1518271970008105031>"

# ── Sessões de admin autenticadas: discord_user_id → {nome, role, expires} ───
_dev_sessions: dict[int, dict] = {}
_DEV_SESSION_TTL = 4 * 60 * 60  # 4 horas


def _dev_session_get(user_id: int) -> dict | None:
    s = _dev_sessions.get(user_id)
    if not s:
        return None
    if time.time() > s.get("expires", 0):
        _dev_sessions.pop(user_id, None)
        ovr = _dev_guild_override.pop(user_id, None)
        if ovr:
            _dev_loaded_guilds.discard(ovr)  # permite re-carregar na próxima sessão
        return None
    return s


def _dev_session_set(user_id: int, owner: dict) -> None:
    _dev_sessions[user_id] = {**owner, "expires": time.time() + _DEV_SESSION_TTL}


async def _dev_verify_credentials(username: str, password: str) -> dict | None:
    """Verifica usuário/senha contra o dashboard. Retorna owner dict ou None."""
    try:
        async with aiohttp.ClientSession() as sess:
            async with sess.post(
                f"{_DASHBOARD_URL}/api/admin/verify-owner",
                json={"username": username, "password": password},
                headers={"Authorization": f"Bearer {_DASHBOARD_SECRET}"},
                timeout=aiohttp.ClientTimeout(total=10),
            ) as r:
                data = await r.json()
                return data if data.get("ok") else None
    except Exception:
        return None


def _dev_get_client_guilds() -> list[discord.Guild]:
    """Retorna guilds que o bot está, excluindo o servidor HYPE."""
    return [g for g in bot.guilds if g.id != _HYPE_GUILD_ID]


# ── Lista persistente de Discord user IDs autorizados a usar n!dev / /dev ──────
_dev_allowed_users: set[int] = set()
_DEV_ALLOWED_FILE = os.path.join(os.environ.get("DATA_DIR", "/tmp"), "dev_allowed.json")


def _dev_allowed_load() -> None:
    try:
        with open(_DEV_ALLOWED_FILE, encoding="utf-8") as f:
            data = json.load(f)
        _dev_allowed_users.update(int(x) for x in data)
        print(f"[dev] {len(_dev_allowed_users)} usuário(s) autorizado(s) carregado(s).")
    except (FileNotFoundError, json.JSONDecodeError, ValueError):
        pass


def _dev_allowed_save() -> None:
    try:
        with open(_DEV_ALLOWED_FILE, "w", encoding="utf-8") as f:
            json.dump(list(_dev_allowed_users), f)
    except Exception as e:
        print(f"[dev] erro ao salvar lista de autorizados: {e}")


def _dev_allowed_add(user_id: int) -> None:
    """Adiciona um Discord user ID à lista de autorizados e persiste."""
    if user_id not in _dev_allowed_users:
        _dev_allowed_users.add(user_id)
        _dev_allowed_save()


_dev_allowed_load()  # carrega ao iniciar o processo



async def _build_dev_embed() -> discord.Embed:
    """Monta o embed do Dev Panel com informações deste bot."""
    all_client_guilds = _dev_get_client_guilds()

    # Determina o guild principal:
    # Prioridade: override ativo da sessão > BOT_GUILD_ID fixo > único guild detectado
    client_guild: discord.Guild | None = None
    settings: dict = {}
    color = 0x2b2d31

    # Pega o override ativo de QUALQUER admin logado (primeiro encontrado)
    _active_ovr = next(
        (gid for uid, gid in _dev_guild_override.items() if _dev_session_get(uid)),
        0
    )
    if _active_ovr:
        client_guild = bot.get_guild(_active_ovr)
    elif _BOT_GUILD_ID:
        client_guild = bot.get_guild(_BOT_GUILD_ID)
    elif len(all_client_guilds) == 1:
        client_guild = all_client_guilds[0]

    if client_guild:
        settings = get_settings(client_guild.id)
        color    = settings.get("embed_color", 0x2b2d31)

    bot_name = bot.user.name if bot.user else "Bot"
    bot_id   = str(bot.user.id) if bot.user else "?"

    embed = discord.Embed(
        title=f"{_E_TOOLS}  Dev Panel  ·  {bot_name}",
        color=color,
    )
    if bot.user:
        embed.set_thumbnail(url=bot.user.display_avatar.url)

    # ── Linha 1: info do bot ─────────────────────────────────────────────────
    embed.add_field(name=f"{_E_SECURITY}  Bot ID",      value=f"`{bot_id}`",                  inline=True)
    embed.add_field(name=f"{_E_APPEAR}  Nome",          value=f"`{bot_name}`",                 inline=True)
    embed.add_field(name=f"{_E_FINANC}  Cliente ID",    value=f"`{_BOT_CUSTOMER_ID or '—'}`",  inline=True)

    # ── Linha 2+: servidor do cliente ────────────────────────────────────────
    if client_guild:
        s     = get_settings(client_guild.id)
        fixed = "✅ fixado" if _BOT_GUILD_ID else "🔍 auto"
        embed.add_field(
            name=f"{_E_SERVER}  Servidor  ({fixed})",
            value=f"**{client_guild.name}**\n`{client_guild.id}`",
            inline=False,
        )
        embed.add_field(name=f"{_E_COMM}  Membros",      value=f"`{client_guild.member_count}`",   inline=True)
        embed.add_field(name=f"{_E_MOV_CHAT}  Prefixo",  value=f"`{s.get('prefix', 'n!')}`",       inline=True)
        embed.add_field(name=f"{_E_ENTRET}  Idioma",     value=f"`{s.get('language', 'pt-br')}`",  inline=True)
        auth_count = len(s.get("authorized_members", []))
        raw_color  = s.get("embed_color", 0)
        embed.add_field(name=f"{_E_TICKET}  Autorizados", value=f"`{auth_count}`",               inline=True)
        embed.add_field(name=f"{_E_APPEAR}  Cor Embed",   value=f"`#{raw_color:06X}`",            inline=True)
        embed.add_field(name="​", value="​", inline=True)   # alinhamento

    elif len(all_client_guilds) > 1:
        guilds_txt = "\n".join(f"{_E_SERVER} **{g.name}** — `{g.id}`" for g in all_client_guilds[:8])
        embed.add_field(
            name=f"⚠️  {len(all_client_guilds)} servidores detectados — nenhum fixado",
            value=guilds_txt,
            inline=False,
        )
    else:
        embed.add_field(
            name=f"❌  Sem Servidor",
            value=(
                f"Bot não está em nenhum servidor do cliente ainda.\n"
                f"Adicione o bot ao servidor e use **Definir Servidor**."
            ),
            inline=False,
        )

    embed.set_footer(
        text=f"HYPE Dev Panel  ·  cliente: {_BOT_CUSTOMER_ID or '?'}  ·  apenas administradores",
        icon_url=bot.user.display_avatar.url if bot.user else None,
    )
    embed.timestamp = datetime.now()
    return embed


# ── Login Modal ───────────────────────────────────────────────────────────────

class DevLoginModal(discord.ui.Modal, title="🔐 Login — HYPE Dev Panel"):
    username = discord.ui.TextInput(
        label="Usuário",
        placeholder="Seu login do dashboard",
        required=True,
        max_length=50,
    )
    password = discord.ui.TextInput(
        label="Senha",
        placeholder="Sua senha do dashboard",
        required=True,
        max_length=100,
        style=discord.TextStyle.short,
    )

    def __init__(self, target_bot_id: int):
        super().__init__()
        self.target_bot_id = target_bot_id

    async def on_submit(self, interaction: discord.Interaction):
        await interaction.response.defer(ephemeral=True)
        owner = await _dev_verify_credentials(
            self.username.value.strip(),
            self.password.value,
        )
        if not owner:
            await interaction.followup.send(
                f"❌ Usuário ou senha incorretos.\nUse suas credenciais do dashboard.",
                ephemeral=True,
            )
            return
        _dev_session_set(interaction.user.id, owner)
        _dev_allowed_add(interaction.user.id)  # persiste Discord ID como autorizado
        # Detecta e seta o guild override na sessão para que todos os saves
        # (incluindo modais, que não passam pelo monkey-patch de views) usem o guild correto
        _detected_gid = 0
        if _BOT_GUILD_ID:
            _detected_gid = _BOT_GUILD_ID
        else:
            _cl_guilds = _dev_get_client_guilds()
            if len(_cl_guilds) == 1:
                _detected_gid = _cl_guilds[0].id
        if _detected_gid:
            _dev_guild_override[interaction.user.id] = _detected_gid
            _dev_load_client_settings(_detected_gid, force=True)
        embed = await _build_dev_embed()
        view  = DevPanelView(interaction.user.id)
        await interaction.followup.send(
            content=f"{_e_success()} Logado como **{owner['nome']}** (`{owner['role']}`) • sessão válida 4h",
            embed=embed,
            view=view,
            ephemeral=False,
        )


