class _DevPermUserSelect(discord.ui.UserSelect):
    def __init__(self, target_guild_id: int):
        self._tgid = target_guild_id
        super().__init__(
            placeholder="Selecione o membro para autorizar...",
            min_values=1,
            max_values=1,
            row=0,
        )

    async def callback(self, inter: discord.Interaction):
        user = self.values[0]
        s = get_settings(self._tgid)
        members = s.setdefault("authorized_members", [])
        if user.id in members:
            await inter.response.send_message(f"⚠️ **{user.display_name}** já está autorizado.", ephemeral=True)
            return
        members.append(user.id)
        save_settings_to_disk()
        await inter.response.send_message(
            f"{_e_success()} **{user.display_name}** (`{user.id}`) autorizado com sucesso!", ephemeral=True
        )


class _DevPermAddView(discord.ui.View):
    def __init__(self, target_guild_id: int):
        super().__init__(timeout=60)
        self.add_item(_DevPermUserSelect(target_guild_id))


class _DevPermRemoveSelect(discord.ui.Select):
    def __init__(self, target_guild_id: int, members: list):
        self._tgid    = target_guild_id
        self._members = members
        tg = bot.get_guild(target_guild_id)
        options = []
        for mid in members[:25]:
            m = tg.get_member(mid) if tg else None
            label = m.display_name[:100] if m else str(mid)
            options.append(discord.SelectOption(label=label, value=str(mid), description=f"ID: {mid}"))
        super().__init__(placeholder="Escolha quem remover...", options=options)

    async def callback(self, inter: discord.Interaction):
        mid = int(self.values[0])
        if mid in self._members:
            self._members.remove(mid)
            save_settings_to_disk()
        await inter.response.send_message(f"{_e_success()} Membro `{mid}` removido.", ephemeral=True)


class _DevPermRemoveView(discord.ui.View):
    def __init__(self, target_guild_id: int, members: list):
        super().__init__(timeout=60)
        self.add_item(_DevPermRemoveSelect(target_guild_id, members))


class DevPermView(discord.ui.View):
    def __init__(self, admin_id: int, target_guild_id: int):
        super().__init__(timeout=300)
        self.admin_id        = admin_id
        self.target_guild_id = target_guild_id
        self._build()

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.admin_id:
            await interaction.response.send_message("❌ Apenas quem abriu o painel.", ephemeral=True)
            return False
        return True

    def _build(self):
        self.clear_items()
        for label, emoji, cb, style, row in [
            ("Adicionar", "➕",    self._add,    discord.ButtonStyle.success,   0),
            ("Listar",    _E_COMM, self._list,   discord.ButtonStyle.secondary, 0),
            ("Remover",   "🗑️",   self._remove, discord.ButtonStyle.danger,    0),
            ("← Voltar",  "↩️",   self._back,   discord.ButtonStyle.secondary, 1),
        ]:
            btn = discord.ui.Button(label=label, style=style, emoji=emoji, row=row)
            btn.callback = cb
            self.add_item(btn)

    async def _add(self, i: discord.Interaction):
        await i.response.send_message(
            "Selecione quem autorizar:", view=_DevPermAddView(self.target_guild_id), ephemeral=True
        )

    async def _list(self, i: discord.Interaction):
        s = get_settings(self.target_guild_id)
        members = s.get("authorized_members", [])
        if not members:
            await i.response.send_message("Nenhum membro autorizado.", ephemeral=True)
            return
        tg = bot.get_guild(self.target_guild_id)
        lines = []
        for mid in members:
            m = tg.get_member(mid) if tg else None
            name = f"**{m.display_name}**" if m else f"ID: {mid}"
            lines.append(f"👤 {name} (`{mid}`)")
        embed = discord.Embed(
            title=f"🔑 Membros autorizados ({len(members)})",
            description="\n".join(lines),
            color=0x2b2d31,
        )
        await i.response.send_message(embed=embed, ephemeral=True)

    async def _remove(self, i: discord.Interaction):
        s = get_settings(self.target_guild_id)
        members: list = s.get("authorized_members", [])
        if not members:
            await i.response.send_message("Nenhum membro para remover.", ephemeral=True)
            return
        await i.response.send_message(
            "Selecione o membro para remover:",
            view=_DevPermRemoveView(self.target_guild_id, members),
            ephemeral=True,
        )

    async def _back(self, i: discord.Interaction):
        embed = await _build_dev_embed()
        view  = DevPanelView(self.admin_id)
        await i.response.edit_message(embed=embed, view=view)


