class DevGuildSelect(discord.ui.Select):
    """Dropdown para escolher em qual servidor fixar o bot."""

    def __init__(self, guilds: list[discord.Guild]):
        options = [
            discord.SelectOption(
                label=g.name[:100],
                value=str(g.id),
                description=f"ID: {g.id}  •  {g.member_count} membros",
                emoji=_E_SERVER,
            )
            for g in guilds[:25]
        ]
        super().__init__(
            placeholder="Escolha o servidor do cliente...",
            min_values=1,
            max_values=1,
            options=options,
            row=1,
        )

    async def callback(self, interaction: discord.Interaction):
        guild_id = self.values[0]
        cid      = _BOT_CUSTOMER_ID

        if not cid:
            await interaction.response.send_message(
                "❌ Não consegui identificar o ID do cliente neste bot. Configure manualmente no dashboard.",
                ephemeral=True,
            )
            return

        # Chama o dashboard API para salvar guild_id e reiniciar o bot
        await interaction.response.defer(ephemeral=True)
        try:
            async with aiohttp.ClientSession() as session:
                async with session.post(
                    f"{_DASHBOARD_URL}/api/admin/set-guild-id",
                    json={"cid": cid, "guild_id": guild_id},
                    headers={"Authorization": f"Bearer {_DASHBOARD_SECRET}"},
                    timeout=aiohttp.ClientTimeout(total=10),
                ) as resp:
                    data = await resp.json()
        except Exception as err:
            await interaction.followup.send(f"❌ Erro ao chamar o dashboard: `{err}`", ephemeral=True)
            return

        if data.get("ok"):
            guild = bot.get_guild(int(guild_id))
            gname = guild.name if guild else guild_id
            await interaction.followup.send(
                f"{_e_success()} Servidor **{gname}** definido como servidor do cliente!\n"
                f"O bot será reiniciado em instantes com `BOT_GUILD_ID={guild_id}`.",
                ephemeral=True,
            )
        else:
            await interaction.followup.send(
                f"❌ Erro ao salvar: `{data.get('error', '?')}`", ephemeral=True
            )


class DevPanelView(discord.ui.View):
    """Painel de administração remota — acessível só no servidor HYPE (login obrigatório)."""

    def __init__(self, admin_id: int):
        super().__init__(timeout=None)
        self.admin_id = admin_id
        self._build()

    # ── permissões ───────────────────────────────────────────────────────────
    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.admin_id:
            await interaction.response.send_message("❌ Apenas quem abriu o painel pode usar.", ephemeral=True)
            return False
        if not _dev_session_get(interaction.user.id):
            await interaction.response.send_message("❌ Sessão expirada.", ephemeral=True)
            return False
        return True

    # ── build dinâmico ────────────────────────────────────────────────────────
    def _build(self):
        self.clear_items()

        # Linha 0: Aparência | Permissões | Prefixo | Menu Completo
        for label, emoji, cb, style, row in [
            ("Aparência",      _E_APPEAR,    self._settings_appearance, discord.ButtonStyle.primary,   0),
            ("Permissões",     _E_TICKET,    self._settings_perm,       discord.ButtonStyle.primary,   0),
            ("Prefixo",        _E_MOV_CHAT,  self._prefix,              discord.ButtonStyle.secondary, 0),
            ("Menu Completo",  _E_TOOLS,     self._open_full_menu,      discord.ButtonStyle.success,   0),
        ]:
            btn = discord.ui.Button(label=label, style=style, emoji=emoji, row=row)
            btn.callback = cb
            self.add_item(btn)

        # "Trocar Servidor" — sempre visível quando bot está em múltiplos guilds
        # Permite ao dev gerenciar qualquer guild sem mudar BOT_GUILD_ID permanentemente
        client_guilds = _dev_get_client_guilds()
        if len(client_guilds) > 1:
            btn_switch = discord.ui.Button(label="Trocar Servidor", style=discord.ButtonStyle.secondary, emoji="🔀", row=1)
            btn_switch.callback = self._switch_guild
            self.add_item(btn_switch)

        if not _BOT_GUILD_ID and client_guilds:
            btn_fix = discord.ui.Button(label="Definir Servidor", style=discord.ButtonStyle.secondary, emoji="📌", row=1)
            btn_fix.callback = self._show_guild_select
            self.add_item(btn_fix)

        # Linha 1: Idioma (select) + Atualizar + Logout
        lang_select = DevLangSelect(
            _BOT_GUILD_ID or ((_dev_get_client_guilds() or [type('', (), {'id': 0})()])[0].id)
        )
        self.add_item(lang_select)

        btn_logout = discord.ui.Button(label="Logout", style=discord.ButtonStyle.danger, emoji="🔓", row=1)
        btn_logout.callback = self._logout
        self.add_item(btn_logout)

    def _get_target_guild(self, fallback_guild_id: int = 0) -> discord.Guild | None:
        """Retorna o guild alvo para gerenciamento remoto.
        Prioridade: guild da interação (=guild do cliente) > _BOT_GUILD_ID > guild único.
        fallback_guild_id: guild da interação/contexto — é sempre o guild do cliente."""
        # 1. Guild onde a interação aconteceu — é o guild do cliente (prioridade máxima)
        if fallback_guild_id and fallback_guild_id != _HYPE_GUILD_ID:
            fg = bot.get_guild(fallback_guild_id)
            if fg:
                return fg
        # 2. BOT_GUILD_ID configurado — fallback quando vem do servidor HYPE
        if _BOT_GUILD_ID:
            return bot.get_guild(_BOT_GUILD_ID)
        # 3. Guild único detectado
        guilds = _dev_get_client_guilds()
        return guilds[0] if guilds else None

    # ── callbacks ─────────────────────────────────────────────────────────────
    async def _refresh(self, interaction: discord.Interaction):
        # Força recarga do arquivo do cliente para mostrar dados sempre frescos
        ovr = _dev_guild_override.get(interaction.user.id, 0)
        if ovr:
            _dev_load_client_settings(ovr, force=True)
        self._build()
        embed = await _build_dev_embed()
        await interaction.response.edit_message(embed=embed, view=self, content=None)

    async def _logout(self, interaction: discord.Interaction):
        _dev_sessions.pop(interaction.user.id, None)
        ovr = _dev_guild_override.pop(interaction.user.id, None)
        if ovr:
            _dev_loaded_guilds.discard(ovr)  # permite re-carregar na próxima sessão
        await interaction.response.edit_message(
            content="🔓 Sessão encerrada.", embed=None, view=None
        )

    async def _prefix(self, interaction: discord.Interaction):
        tg = self._get_target_guild(interaction.guild.id if interaction.guild else 0)
        if not tg:
            await interaction.response.send_message("❌ Servidor do cliente não encontrado.", ephemeral=True)
            return
        await interaction.response.send_modal(DevPrefixModal(tg.id))

    async def _settings_appearance(self, interaction: discord.Interaction):
        tg = self._get_target_guild(interaction.guild.id if interaction.guild else 0)
        if not tg:
            await interaction.response.send_message("❌ Servidor do cliente não encontrado.", ephemeral=True)
            return
        s     = get_settings(tg.id)
        embed = discord.Embed(
            title=f"{_E_APPEAR}  Aparência — {tg.name}",
            color=s.get("embed_color", 0x2b2d31),
        )
        embed.add_field(name=f"{_E_MOV_CHAT} Prefixo",  value=f"`{s.get('prefix', 'n!')}`",          inline=True)
        embed.add_field(name="🌐 Idioma",                value=f"`{s.get('language', 'pt-br')}`",     inline=True)
        raw = s.get("embed_color", 0)
        embed.add_field(name=f"{_E_APPEAR} Cor",         value=f"`#{raw:06X}`",                       inline=True)
        banner = s.get("embed_banner_url", "") or "—"
        embed.add_field(name="🖼️ Banner", value=f"`{banner[:60]}`" if banner != "—" else "—", inline=False)
        view = DevAppearanceView(self.admin_id, tg.id)
        await interaction.response.edit_message(embed=embed, view=view, content=None)

    async def _settings_perm(self, interaction: discord.Interaction):
        tg = self._get_target_guild(interaction.guild.id if interaction.guild else 0)
        if not tg:
            await interaction.response.send_message("❌ Servidor do cliente não encontrado.", ephemeral=True)
            return
        s       = get_settings(tg.id)
        members = s.get("authorized_members", [])
        embed   = discord.Embed(
            title=f"{_E_TICKET}  Permissões — {tg.name}",
            color=s.get("embed_color", 0x2b2d31),
        )
        lines = [f"`{mid}`" for mid in members] or ["Nenhum"]
        embed.add_field(name=f"{_E_COMM} Membros autorizados ({len(members)})", value="\n".join(lines), inline=False)
        view = DevPermView(self.admin_id, tg.id)
        await interaction.response.edit_message(embed=embed, view=view, content=None)

    async def _open_full_menu(self, interaction: discord.Interaction):
        """Abre o menu completo do bot cliente, gerenciado remotamente do servidor HYPE."""
        tg = self._get_target_guild(interaction.guild.id if interaction.guild else 0)
        if not tg:
            await interaction.response.send_message(
                f"❌ Servidor do cliente não detectado.\n"
                f"Use **Definir Servidor** antes de abrir o menu completo.",
                ephemeral=True,
            )
            return

        # Registra o override de guild para este admin — todas as interações
        # futuras desse usuário usarão get_settings() com guild_id do cliente
        _dev_guild_override[interaction.user.id] = tg.id

        # Ativa ContextVar manualmente para esta chamada (monkey-patch ainda não
        # sabe que o override existe porque é definido agora, neste callback)
        token = _dev_guild_ctx.set(tg.id)
        try:
            # Força recarga do arquivo do cliente (sempre fresco, sem cache)
            _dev_load_client_settings(tg.id, force=True)
            s    = get_settings(tg.id)
            lang = s.get("language", "pt-br")
            embed = build_main_embed(interaction.user, lang)
            # Adiciona campo informando que é gerenciamento remoto
            embed.add_field(
                name=f"{_E_SERVER}  Gerenciando remotamente",
                value=f"**{tg.name}** — `{tg.id}`",
                inline=False,
            )
            view = MenuView(interaction.user.id, lang=lang)
            await interaction.response.edit_message(embed=embed, view=view, content=None)
        finally:
            _dev_guild_ctx.reset(token)

    async def _switch_guild(self, interaction: discord.Interaction):
        """Muda o guild alvo da sessão atual sem alterar BOT_GUILD_ID permanentemente."""
        guilds = _dev_get_client_guilds()
        if not guilds:
            await interaction.response.send_message("❌ Nenhum servidor encontrado.", ephemeral=True)
            return
        self.clear_items()

        # Dropdown temporário — só muda o override da sessão
        class _SwitchSelect(discord.ui.Select):
            def __init__(self_, gs):
                options = [
                    discord.SelectOption(
                        label=g.name[:100],
                        value=str(g.id),
                        description=f"ID: {g.id}  •  {g.member_count} membros",
                        emoji=_E_SERVER,
                    )
                    for g in gs[:25]
                ]
                super().__init__(
                    placeholder="Escolha o servidor para gerenciar...",
                    min_values=1, max_values=1,
                    options=options, row=1,
                )

            async def callback(self_, inter: discord.Interaction):
                gid = int(self_.values[0])
                tg  = bot.get_guild(gid)
                if not tg:
                    await inter.response.send_message("❌ Servidor não encontrado.", ephemeral=True)
                    return
                # Muda o override da sessão atual (não altera BOT_GUILD_ID)
                _dev_guild_override[inter.user.id] = gid
                _dev_load_client_settings(gid, force=True)
                self._build()
                embed = await _build_dev_embed()
                await inter.response.edit_message(
                    content=f"{_e_success()} Agora gerenciando **{tg.name}** (`{gid}`)",
                    embed=embed, view=self
                )

        self.add_item(_SwitchSelect(guilds))
        cancel = discord.ui.Button(label="Cancelar", style=discord.ButtonStyle.danger, emoji="✖️", row=2)
        async def _cancel(inter: discord.Interaction):
            self._build()
            await inter.response.edit_message(view=self, content=None)
        cancel.callback = _cancel
        self.add_item(cancel)
        await interaction.response.edit_message(
            content=f"{_E_SERVER} **Escolha o servidor para gerenciar nesta sessão:**", view=self
        )

    async def _show_guild_select(self, interaction: discord.Interaction):
        guilds = _dev_get_client_guilds()
        if not guilds:
            await interaction.response.send_message("❌ Nenhum servidor encontrado.", ephemeral=True)
            return
        self.clear_items()
        self.add_item(DevGuildSelect(guilds))
        cancel = discord.ui.Button(label="Cancelar", style=discord.ButtonStyle.danger, emoji="✖️", row=2)
        async def _cancel(inter: discord.Interaction):
            self._build()
            await inter.response.edit_message(view=self, content=None)
        cancel.callback = _cancel
        self.add_item(cancel)
        await interaction.response.edit_message(
            content=f"{_E_SERVER} **Escolha o servidor do cliente:**", view=self
        )


def _dev_try_lock(msg_id: int) -> bool:
    """Tenta adquirir lock exclusivo para responder a este n!dev.
    Usa O_EXCL (operação atômica) — garante que só UM processo responde.
    Retorna True se adquiriu o lock, False se outro processo já adquiriu."""
    lock_path = os.path.join(
        os.environ.get("DATA_DIR", "/tmp"),
        f"dev_lock_{msg_id}",
    )
    try:
        fd = os.open(lock_path, os.O_CREAT | os.O_EXCL | os.O_WRONLY)
        os.write(fd, str(os.getpid()).encode())
        os.close(fd)
        # Remove o lock após 5 segundos para não acumular arquivos
        async def _cleanup():
            await asyncio.sleep(5)
            try:
                os.unlink(lock_path)
            except OSError:
                pass
        asyncio.get_event_loop().create_task(_cleanup())
        return True
    except (FileExistsError, OSError):
        return False


@bot.command(name="migrar_emojis_cdn")
@commands.has_permissions(administrator=True)
async def cmd_migrar_emojis(ctx: commands.Context):
    """Copia emojis do CDN para o servidor atual. Só funciona no servidor HYPE."""
    if not ctx.guild or ctx.guild.id != _HYPE_GUILD_ID:
        return
    import re as _re
    msg = await ctx.send("Iniciando migracao de emojis...")
    bot_py = os.path.join(os.path.dirname(os.path.abspath(__file__)), "bot.py")
    try:
        with open(bot_py, encoding="utf-8") as _f:
            content = _f.read()
    except Exception:
        await msg.edit(content="Erro ao ler bot.py")
        return
    found = _re.findall(r"<(a?):(\w+):(\d+)>", content)
    emoji_map = {eid: (anim == "a", name) for anim, name, eid in found}
    existing = {e.name for e in ctx.guild.emojis}
    ok = skip = fail = 0
    for eid, (animated, name) in emoji_map.items():
        if name in existing:
            skip += 1
            continue
        ext = "gif" if animated else "png"
        url = f"https://cdn.discordapp.com/emojis/{eid}.{ext}?size=128"
        try:
            # Usa o session interno do discord.py (ja autenticado e configurado)
            async with bot.http._HTTPClient__session.get(url, headers={"User-Agent": "Mozilla/5.0"}) as r:
                if r.status != 200:
                    fail += 1
                    continue
                img = await r.read()
            await ctx.guild.create_custom_emoji(name=name, image=img, reason="Migracao de emojis")
            existing.add(name)
            ok += 1
            await asyncio.sleep(1.0)
        except discord.HTTPException as e:
            fail += 1
            if e.status == 429:
                await asyncio.sleep(5)
        except Exception:
            fail += 1
    await msg.edit(content=f"Concluido: {ok} copiados, {skip} ja existiam, {fail} erros.")


@bot.command(name="dev")
async def cmd_dev(ctx: commands.Context, bot_id: str = ""):
    """
    Abre o painel de dev de um bot cliente. Só funciona no servidor HYPE.
    Uso: n!dev <id_do_bot>
    """
    if not bot_id:
        await ctx.send(
            f"❌ Informe o ID do bot.\nUso: `{ctx.prefix}dev <id_do_bot>`",
            delete_after=10,
        )
        return

    try:
        target_id = int(bot_id.strip("<@!>"))
    except ValueError:
        await ctx.send("❌ ID inválido. Use apenas números.", delete_after=10)
        return

    if not bot.user or bot.user.id != target_id:
        return  # Outro bot vai responder silenciosamente

    # Anti-duplicata atômica
    if not _dev_try_lock(ctx.message.id):
        return

    # Verifica se o admin tem sessão ativa
    if _dev_session_get(ctx.author.id):
        # Já autenticado — detecta guild do cliente e abre /menu diretamente
        # Prioridade: guild onde o comando foi chamado (=guild do cliente) >
        #             BOT_GUILD_ID (fallback quando vem do servidor HYPE) >
        #             guild único detectado > DevPanelView
        ctx_guild_id = ctx.guild.id if ctx.guild else 0
        if ctx_guild_id and ctx_guild_id != _HYPE_GUILD_ID:
            # Usa o guild onde o dev rodou o comando — é sempre o guild do cliente
            tg = bot.get_guild(ctx_guild_id)
        elif _BOT_GUILD_ID:
            # Fallback: veio do servidor HYPE → usa o guild configurado no bot
            tg = bot.get_guild(_BOT_GUILD_ID)
        else:
            client_guilds = _dev_get_client_guilds()
            if len(client_guilds) == 1:
                tg = client_guilds[0]
            else:
                tg = None

        if tg:
            _dev_guild_override[ctx.author.id] = tg.id
            token = _dev_guild_ctx.set(tg.id)
            try:
                # Força recarga do arquivo do cliente (sempre fresco)
                _dev_load_client_settings(tg.id, force=True)
                s    = get_settings(tg.id)
                lang = s.get("language", "pt-br")
                embed = build_main_embed(ctx.author, lang)
                embed.add_field(
                    name=f"🔧 Gerenciando remotamente",
                    value=f"**{tg.name}** — `{tg.id}`",
                    inline=False,
                )
            finally:
                _dev_guild_ctx.reset(token)
            view = MenuView(ctx.author.id, lang=lang)
            await ctx.send(embed=embed, view=view)
        else:
            # Múltiplas guilds sem guild alvo claro — mostra DevPanelView para escolher
            embed = await _build_dev_embed()
            view  = DevPanelView(ctx.author.id)
            await ctx.send(embed=embed, view=view)
    else:
        # Precisa de login — envia botão que abre modal
        class _LoginView(discord.ui.View):
            def __init__(self):
                super().__init__(timeout=120)

            @discord.ui.button(label="🔐 Entrar com credenciais", style=discord.ButtonStyle.primary)
            async def do_login(self, inter: discord.Interaction, btn: discord.ui.Button):
                await inter.response.send_modal(DevLoginModal(target_id))

        embed = discord.Embed(
            title=f"{_E_SECURITY}  Acesso Restrito — Dev Panel",
            description=(
                f"O painel de administração requer autenticação com as **credenciais do dashboard**.\n\n"
                f"Clique no botão abaixo para inserir seu login e senha."
            ),
            color=0x2b2d31,
        )
        embed.set_footer(text="HYPE Dev Panel • apenas donos autorizados")
        await ctx.send(embed=embed, view=_LoginView())




