async def _delete_thread_raw(thread_id: int) -> bool:
    """Deleta um thread via raw HTTP DELETE. Retorna True se bem-sucedido."""
    import aiohttp as _ah_del
    _headers_del = {"Authorization": f"Bot {bot.http.token}"}
    try:
        async with _ah_del.ClientSession() as _sess:
            async with _sess.delete(
                f"https://discord.com/api/v10/channels/{thread_id}",
                headers=_headers_del,
            ) as _r:
                print(f"[delete_thread] id={thread_id} status={_r.status}", flush=True)
                return _r.status in (200, 204)
    except Exception as _e:
        print(f"[delete_thread] erro: {_e}", flush=True)
        return False


async def _fechar_ticket_thread(thread: discord.Thread, settings: dict, closer=None):
    """Avisa no thread, aguarda 5s, deleta e envia log."""
    color = settings.get("embed_color", 0x2B2D31)

    # Mensagem de aviso dentro do thread (raw HTTP — thread.send() falha em discord.py-self)
    import aiohttp as _ah_fechar
    _headers_f = {
        "Authorization": f"Bot {bot.http.token}",
        "Content-Type": "application/json",
    }
    _payload_fechar = {
        "flags": 32768,
        "components": [{
            "type": 17,
            "accent_color": color,
            "components": [
                {"type": 10, "content": "**<:tickets:1518271952526250155> Excluindo ticket**"},
                {"type": 14, "divider": True, "spacing": 1},
                {"type": 10, "content": "Este ticket será excluído em **5 segundos**."},
            ],
        }],
    }
    try:
        async with _ah_fechar.ClientSession() as _sess:
            await _sess.post(
                f"https://discord.com/api/v10/channels/{thread.id}/messages",
                headers=_headers_f,
                json=_payload_fechar,
            )
    except Exception:
        pass

    await asyncio.sleep(5)

    # Log no canal configurado
    log_ch_id = settings.get("ticket_log_channel")
    if log_ch_id and thread.guild:
        log_ch = thread.guild.get_channel(log_ch_id)
        if log_ch:
            embed = discord.Embed(
                title="🎫 Ticket Fechado",
                description=(
                    f"**Thread:** `{thread.name}`\n"
                    + (f"**Fechado por:** {closer.mention}" if closer else "")
                ),
                color=color,
            )
            embed.timestamp = datetime.now()
            try:
                await log_ch.send(embed=embed)
            except Exception:
                pass

    await _delete_thread_raw(thread.id)


def _is_ticket_staff(interaction: discord.Interaction) -> bool:
    """Retorna True se o usuário tem permissão para gerenciar tickets (cargo responsável ou admin)."""
    member = interaction.user
    guild  = interaction.guild
    if not guild or not isinstance(member, discord.Member):
        return False
    if guild.owner_id == member.id or member.guild_permissions.administrator:
        return True
    thread = interaction.channel
    if isinstance(thread, discord.Thread):
        settings = get_settings(guild.id)
        for panel in settings.get("ticket_panels", []):
            if panel.get("channel_id") == thread.parent_id:
                resp_ids: set[int] = set(panel.get("responsible_roles", []))
                for op in panel.get("menu_opcoes", []):
                    resp_ids |= set(op.get("responsible_roles", []))
                if resp_ids & {r.id for r in member.roles}:
                    return True
    return False


